ent.querySelector('.sidebar') as HTMLElement|null;  //seleccion por calses\r\nconst btnmenux = document.querySelector('#mobile-menux');\r\nconst barra = document.querySelector('.barra-mobile') as HTMLElement|null;\r\nconst nametop:HTMLElement|null = document.querySelector('.nametop');\r\ndeclare let Chart:any; //declare le indica a typescript que la variable chart viene de manera externa\r\ndeclare const Swal: any;\r\ndeclare var moment: any;\r\ndeclare let List: any; \r\ndeclare let bwipjs: any;\r\ndeclare const QRCode: any;\r\ndeclare const mediosPagoDB: MedioPago[];  //mediosPagoDB inyectada por medio de json desde la vista ventas/index.php interfaz en ventas.type.ts\r\ndeclare const clientesDB: Cliente[];\r\ndeclare let comisionTotalEmpleadosDB: number;\r\ndeclare let comisionTotalPagadaBusinessDB: number;\r\ndeclare const getParam:any;  //getParam inyectada por medio de json desde la vista ventas/index.php interfaz en ventas.type.ts\r\ndeclare const percentComisionUser:string;\r\ndeclare let deudatotalCiente:string;\r\n\r\n(window as any).POS = (window as any).POS || {};\r\n\r\n // Submódulos\r\n  if (!(window as any).POS.gestionarDescuentos) {\r\n    (window as any).POS.gestionarDescuentos = {};\r\n  }\r\n\r\nif(mobilemenu){\r\n    mobilemenu.addEventListener('click', function(){\r\n      if (sidebar && barra) {\r\n        sidebar.classList.toggle('mostrar');\r\n        barra.classList.toggle('ocultarmenu');\r\n      }\r\n    });\r\n}\r\nif(btnmenux){\r\n    btnmenux.addEventListener('click', function(){\r\n      if (sidebar && barra) {\r\n        sidebar.classList.toggle('mostrar');\r\n        barra.classList.toggle('ocultarmenu');\r\n      }\r\n    });\r\n}\r\n/////////////////////// animacion del sidebar toggle ///////////////////////////\r\ndocument.querySelector('.sidebartoggle')!.addEventListener('click', (e)=>{\r\n  if(sidebar)sidebar?.classList.toggle('minsidebar');\r\n  if(nametop)nametop.classList.toggle('noneElement');\r\n  $('.btnav').toggleClass('noneElement');\r\n});\r\n\r\n//------------------------------------------------------------------------------------------------------------------//\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES /////////////////////\r\nconst configdatatables = {\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA 25 REGISTROS /////////////////////\r\nconst configdatatables25reg = {\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA GENERAL /////////////////////\r\nconst configdatatablesgenerico = {\r\n  layout: {\r\n        topStart: {\r\n            buttons: [\r\n              {extend: 'copyHtml5', text: 'Copia'}, \r\n              {extend: 'excelHtml5', title: 'informe'}, \r\n              {extend: 'csvHtml5', title: 'informe'}, \r\n              {extend: 'pdfHtml5', title: 'informe'}, \r\n              {extend: 'print', title: 'informe', text: 'Imprimir'},\r\n              'colvis'\r\n            ],\r\n            pageLength: 'pageLength'\r\n        }\r\n  },\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA STOCK RAPIDO /////////////////////\r\nconst configdatatablesstockrapido = {\r\n  layout: {\r\n        topStart: {\r\n            buttons: [\r\n              {extend: 'copyHtml5', text: 'Copia'}, \r\n              {extend: 'excelHtml5', exportOptions: {columns: [1, 2, 3, 4, 5]}, title: 'Stock-inventario'}, \r\n              {extend: 'csvHtml5', exportOptions: {columns: [1, 2, 3, 4, 5]}, title: 'Stock-inventario'}, \r\n              {extend: 'pdfHtml5', exportOptions: {columns: [1, 2, 3, 4, 5]}, title: 'Stock-inventario'}, \r\n              {extend: 'print', exportOptions: {columns: [1, 3, 4]}, title: 'Stock-inventario', text: 'Imprimir'},\r\n              'colvis'\r\n            ],\r\n            pageLength: 'pageLength'\r\n        }\r\n  },\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// OBJETO DE CONFIGURACION DEL PLUGIN DATATABLES PARA AJUSTAR COSTOS /////////////////////\r\nconst configdatatablesajustarcostos = {\r\n  layout: {\r\n        topStart: {\r\n            buttons: [\r\n              {extend: 'copyHtml5', text: 'Copia'}, \r\n              {extend: 'excelHtml5', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto'}, \r\n              {extend: 'csvHtml5', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto'}, \r\n              {extend: 'pdfHtml5', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto'}, \r\n              {extend: 'print', exportOptions: {columns: [1, 3, 4, 5, 6]}, title: 'costo por producto', text: 'Imprimir'},\r\n              'colvis'\r\n            ],\r\n            pageLength: 'pageLength'\r\n        }\r\n  },\r\n  pageLength: 25,\r\n  \"paging\": true,\r\n  \"lengthChange\": true,\r\n  \"searching\": true,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n///////////////////// CONFIGURACION DEL PLUGIN DATATABLES PARA CAJA/////////////////////\r\nconst configdatatablescaja = {\r\n  \"paging\": false,\r\n  \"order\": [[ 4, 'desc' ]],\r\n  \"searching\": false,\r\n  \"ordering\": true,\r\n  \"info\": true,\r\n  \"autoWidth\": true,\r\n  \"responsive\": true,\r\n  \"deferRender\": true,\r\n  \"retrieve\": true,\r\n  \"processing\": true,\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      lengthMenu: '_MENU_ Entradas por pagina',\r\n      info: 'Mostrando 1 de _MAX_ registros',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  }\r\n}\r\n\r\n\r\n///////////////////// CONFIGURACION DEL PLUGIN DATATABLES PARA STOCK BAJO/////////////////////\r\nconst configdatatablesstockbajo = {\r\n  destroy: true,\r\n  lengthChange: false,\r\n  pageLength: 25,\r\n  //responsive: true,\r\n  order: [[ 3, 'asc' ]],\r\n  language: {\r\n      search: 'Busqueda',\r\n      emptyTable: 'No Hay datos disponibles',\r\n      zeroRecords:    \"No se encontraron registros coincidentes\",\r\n      info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n      infoEmpty: 'No hay entradas a mostrar',\r\n      infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n      paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n  },\r\n  layout: {\r\n      topStart: {\r\n          buttons: [\r\n              {extend: 'excelHtml5', title: 'Stock bajo'},  \r\n              {extend: 'pdfHtml5', title: 'Stock bajo'}, \r\n              {extend: 'print', title: 'Stock bajo', text: 'Imprimir'},\r\n              'colvis'\r\n          ],\r\n          pageLength: 'pageLength'\r\n      }\r\n  }\r\n}\r\n\r\n///////////////////// FUNCION QUE IMPRIME MENSAJE TIPO ALERTA /////////////////////\r\nfunction msjAlert(tipo:string, msj:string, divmsjalerta:HTMLElement):void{\r\n  divmsjalerta.insertAdjacentHTML('beforeend', `<div class=\"alerta alerta__${tipo}\">\r\n      <p><i class=\"fa-solid fa-circle-exclamation\"></i> ${msj}</p></div>`\r\n  );\r\n  borrarMsjAlert(divmsjalerta);\r\n}\r\n//////////////////// BORRAR MENSAJES TIPO ALERTA /////////////////////\r\n/*(borrarMsjAlert =()=>{  //se aplica de manera global\r\n  const msj = document.querySelector('#divmsjalerta');\r\n  if(document.querySelector('.alerta'))setTimeout(()=>{ while(msj.firstChild)msj.removeChild(msj.firstChild);}, 5000);\r\n})();*/\r\nfunction borrarMsjAlert(divmsj:HTMLElement):void{  //se aplica de manera global\r\n  //const msj = document.querySelector('#divmsjalerta')!;\r\n  if(document.querySelector('.alerta'))setTimeout(()=>{ while(divmsj.firstChild)divmsj.removeChild(divmsj.firstChild);}, 5000);\r\n}\r\n//////////////////// FUNCION QUE IMPRIME UN MENSAJE FORMATO TOAST ////////////////////\r\n//msjalertToast('error', '¡Error!', 'debe seleccionar una imagen')\r\nfunction msjalertToast(icono:string, tipo:string, msj:string){\r\n    Swal.fire({\r\n    icon: icono,  // Puedes cambiar el ícono (success, error, warning, info, etc.)\r\n    title: tipo,\r\n    text: msj,\r\n    toast: true,\r\n    position: 'top-end',  \r\n    showConfirmButton: false,  \r\n    timer: 2700  \r\n    });\r\n}\r\n\r\n/////////////////// FUNCION CONTADOR DE CARACTERES ////////////////////\r\n(function countchars():void{\r\n  const numinput = document.querySelectorAll('.count-charts') as NodeListOf<HTMLElement>;  \r\n  numinput.forEach(element =>{ //element es cada label\r\n      element.textContent = (parseInt(element.dataset.num!)-(element.previousElementSibling as HTMLInputElement).value.length).toString();\r\n      element.previousElementSibling?.addEventListener('input', (e)=>{ //seleccionamos el input o el textarea en donde se escribe y se le da el evento de teclas\r\n          element.textContent = parseInt(element.dataset.num!)-(e.target as HTMLInputElement).value.length+\"\";\r\n            \r\n          if(parseInt(element.dataset.num!)-(e.target as HTMLInputElement).value.length <= 0){\r\n              let cadena = (e.target as HTMLInputElement).value.slice(0, parseInt(element.dataset.num!));\r\n              (e.target as HTMLInputElement).value = cadena;\r\n              element.textContent =`${0}`;\r\n          }\r\n      });\r\n  });\r\n})();\r\n\r\n/////////////////// paginacion de negocio empleado, malla, config //////////////////\r\nif(document.querySelector('#tabulacion')){ // view/admin/adminconfig/index.php\r\n  const renderid = document.querySelector('#tabulacion input[type=\"radio\"]:checked')!.nextElementSibling as HTMLElement; //se selecciona el input cheked y luego su span q contiene el id de la pagina a mostrar\r\n  document.querySelector<HTMLElement>(`.${renderid.id}`)!.style.display = \"block\"; //mostramos la primera seccion\r\n  const btns_navtabs = document.querySelectorAll('.tabs span');\r\n  const paginas = document.querySelectorAll<HTMLElement>('.paginas'); //seleccionamos las secciones o paginas a mostrar\r\n  btns_navtabs.forEach(Element => {\r\n      Element.addEventListener('click', (e)=>{ //cada btn o enlace\r\n          const target = e.target as HTMLElement;\r\n          paginas.forEach(pagina =>pagina.style.display = \"none\"); ////quitamos la class mostrarseccion a todas las secciones\r\n          document.querySelector<HTMLElement>(`.${target.id}`)!.style.display = \"block\"; //añadimos la class mostrarseccion a la la seccion o pagina correspondiente\r\n      });\r\n  });\r\n}\r\n\r\nfunction mesyañoactual():[string, number]\r\n{\r\n  const fecha = new Date();\r\n  const mesTexto:string = fecha.toLocaleString('es-CO', { month: 'long' });\r\n  const año:number = fecha.getFullYear();\r\n  return [mesTexto, año];\r\n}\r\n\r\nfunction getDgv(nit: number): number {\r\n    const multiplicadores = [3, 7, 13, 17, 19, 23, 29, 37, 41, 43, 47, 53, 59, 67, 71];\r\n    const digitos = nit.toString().trim().split('').map(Number);\r\n    let suma = 0;\r\n    digitos.forEach((digito, indice) => {\r\n        const posicionMultiplicador = digitos.length - indice;\r\n        suma += digito * multiplicadores[posicionMultiplicador - 1];\r\n    }); \r\n    const modulo = suma%11;\r\n    return modulo > 1 ?(11 - modulo):modulo;\r\n}\r\n\r\n\r\nlet audioCtx: AudioContext;\r\nfunction beep(frecuencia = 800, duracion = 60) {\r\n  if (!audioCtx) audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();\r\n  const osc = audioCtx.createOscillator();\r\n  const gain = audioCtx.createGain();\r\n\r\n  osc.frequency.value = frecuencia;\r\n  osc.type = 'square';\r\n  gain.gain.value = 0.08;\r\n\r\n  osc.connect(gain);\r\n  gain.connect(audioCtx.destination);\r\n\r\n  osc.start();\r\n  osc.stop(audioCtx.currentTime + duracion / 1000);\r\n}\r\n\r\n\r\nfunction flashCantidad(element:HTMLElement, color:string) {\r\n    const clase = color === 'up'? 'bg-green-200': 'bg-red-200';\r\n    element.classList.add(clase);\r\n    setTimeout(() => element.classList.remove(clase), 120);\r\n}\r\n\r\n\r\nfunction bytesToBase64(data: string|Uint8Array) {\r\n    if (typeof data === 'string')\r\n      return btoa(data);\r\n\r\n    let binary = '';\r\n    if(data instanceof Uint8Array)\r\n      for (let i = 0; i < data.length; i++) \r\n          binary += String.fromCharCode(data[i]);\r\n    return btoa(binary);\r\n}","(function():void{\r\n  if(document.querySelector('.inicio')){\r\n    \r\n    async function ventasgraficas($url:string, $dato:string){\r\n      try{\r\n        const respuesta = await fetch($url); \r\n        const resultado = await respuesta.json();\r\n        if($dato == 'ventasVsGastos')graficaVentasVsGastos(resultado);\r\n        if($dato == 'ultimos7dias')ventas7dias(resultado);\r\n      }catch(error){\r\n            console.log(error);\r\n      }\r\n    }\r\n    ventasgraficas('/admin/api/ventasVsGastos', 'ventasVsGastos');\r\n    ventasgraficas('/admin/api/ultimos7dias', 'ultimos7dias');\r\n\r\n    // Ventas por horas (hoy) - ejemplo 24 horas o por horas de apertura (aquí 10 valores)\r\n    const ventasPorHoras = {\r\n      labels: [\"08:00\",\"09:00\",\"10:00\",\"11:00\",\"12:00\",\"13:00\",\"14:00\",\"15:00\",\"16:00\",\"17:00\"],\r\n      data:    [5, 12, 20, 35, 60, 48, 30, 22, 15, 10]\r\n    };\r\n\r\n\r\n    // Gastos por transacción (gráfico doughnut)\r\n    const gastosTransaccion = {\r\n      labels: [\"Comisiones\", \"Materia Primas\", \"Servicios\", \"Otros\"],\r\n      data:   [15, 50, 25, 10] // porcentajes o montos relativos\r\n    };\r\n\r\n\r\n    // ---------- Charts ----------\r\n\r\n    // Ventas por horas (line)\r\n    /*const ctxHoras = (document.getElementById('chartVentasHoras') as HTMLCanvasElement).getContext('2d');\r\n    new Chart(ctxHoras, {\r\n      type: 'line',\r\n      data: {\r\n        labels: ventasPorHoras.labels,\r\n        datasets: [{\r\n          label: 'Ventas (unidades)',\r\n          data: ventasPorHoras.data,\r\n          borderColor: '#6366F1',\r\n          backgroundColor: 'rgba(99,102,241,0.12)',\r\n          fill: true,\r\n          tension: 0.35,\r\n          pointRadius: 3\r\n        }]\r\n      },\r\n      options: {\r\n        responsive: true,\r\n        scales: {\r\n          y: { beginAtZero: true }\r\n        },\r\n        plugins: {\r\n          tooltip: {\r\n            callbacks: {\r\n              label: (ctx:any) => ` ${ctx.parsed.y} unidades`\r\n            }\r\n          },\r\n          legend: { display: false }\r\n        }\r\n      }\r\n    });*/\r\n\r\n    // Ingresos por día (bar)\r\n    function ventas7dias(resultado:{dia:string, ventas_totales:string}[]){\r\n      const ctxIngresosDias = (document.getElementById('chartIngresosDias') as HTMLCanvasElement).getContext('2d');\r\n      new Chart(ctxIngresosDias, {\r\n        type: 'bar',\r\n        data: {\r\n          labels: resultado.map(x=>x.dia),\r\n          datasets: [{\r\n            label: 'Ingresos',\r\n            data: resultado.map(x=>x.ventas_totales),\r\n            backgroundColor: '#10B981'\r\n          }]\r\n        },\r\n        options: {\r\n          responsive: true,\r\n          plugins: { legend: { display: false } },\r\n          scales: {\r\n            y: {\r\n              beginAtZero: true,\r\n            }\r\n          }\r\n        }\r\n      });\r\n    }\r\n\r\n    // Gastos por transacción (doughnut)\r\n    /*const ctxGastos = (document.getElementById('chartGastosTransaccion') as HTMLCanvasElement).getContext('2d');\r\n    new Chart(ctxGastos, {\r\n      type: 'doughnut',\r\n      data: {\r\n        labels: gastosTransaccion.labels,\r\n        datasets: [{\r\n          data: gastosTransaccion.data,\r\n          backgroundColor: ['#EF4444','#F59E0B','#3B82F6','#6B7280']\r\n        }]\r\n      },\r\n      options: {\r\n        responsive: true,\r\n        plugins: {\r\n          legend: { position: 'bottom' }\r\n        }\r\n      }\r\n    });*/\r\n\r\n    function graficaVentasVsGastos(resultado:{periodo:string[], ventastotales:string[], gastostotales:string[]}){\r\n      // Ventas vs Gastos (combinado: barras gastos + línea ventas)\r\n      const ctxVG = (document.getElementById('chartVentasGastos') as HTMLCanvasElement).getContext('2d');\r\n      new Chart(ctxVG, {\r\n        data: {\r\n          labels: resultado.periodo,\r\n          datasets: [\r\n            {\r\n              type: 'bar',\r\n              label: 'Ventas',\r\n              data: resultado.ventastotales,\r\n              backgroundColor: 'rgba(239,68,68,0.8)'\r\n            },\r\n            {\r\n              type: 'line',\r\n              label: 'Gastos',\r\n              data: resultado.gastostotales,\r\n              borderColor: '#4F46E5',\r\n              backgroundColor: 'rgba(79,70,229,0.15)',\r\n              tension: 0.3,\r\n              fill: true,\r\n              yAxisID: 'y1'\r\n            }\r\n          ]\r\n        },\r\n        options: {\r\n          responsive: true,\r\n          plugins: { legend: { position: 'bottom' } },\r\n          scales: {\r\n            y: {\r\n              beginAtZero: true,\r\n              position: 'left',\r\n              title: { display: true, text: 'Ventas (COP)' }\r\n            },\r\n            y1: {\r\n              beginAtZero: true,\r\n              position: 'right',\r\n              grid: { drawOnChartArea: false },\r\n              title: { display: true, text: 'Gastos (COP)' }\r\n            }\r\n          },\r\n        }\r\n      });\r\n    }\r\n    \r\n\r\n  }\r\n})();","type Align = 'left' | 'center' | 'right';\r\nconst canvas = document.createElement('canvas');\r\n\r\nclass EscPosBuilder {\r\n\r\n    protected content = '';\r\n    protected bytes: number[] = [];\r\n\r\n    protected write(...bytes: number[]) {\r\n        this.bytes.push(...bytes);\r\n    }\r\n\r\n   // Comando Reset: Limpia formatos previos\r\n    reset() {\r\n        // ESC @  version bytes\r\n        this.write(0x1B, 0x40);\r\n\r\n        this.content += '\\x1B\\x40';\r\n        this.setAlign('left');\r\n        // Bold OFF\r\n        this.boldOff();\r\n        // Tamaño normal\r\n        this.normalSize();\r\n    }\r\n\r\n    text(text: string = '') {\r\n        const encoder = new TextEncoder();\r\n        const encoded = encoder.encode(text);\r\n        this.bytes.push(...encoded);\r\n        this.write(0x0A); // salto línea\r\n\r\n        //version string\r\n        this.content += text + '\\n';\r\n    }\r\n\r\n    // Agregamos Tamaño de texto (Doble ancho y alto)\r\n    bigText(text: string, bold = false) {\r\n        if(bold)this.boldOn();\r\n        this.doubleSize();\r\n        this.text(text);\r\n        this.normalSize();\r\n        if(bold)this.boldOff();\r\n    }\r\n\r\n    line() {\r\n        this.text('-'.repeat(42));\r\n    }\r\n\r\n    // 1. Forzar que el centro sea una operación aislada y limpia\r\n    center(text: string) {\r\n        this.setAlign('center');         // Activar centro\r\n        this.text(text);                 // Escribir texto y saltar (imprime el buffer)\r\n        this.setAlign('left');           // Volver a izquierda INMEDIATAMENTE\r\n    }\r\n\r\n    setAlign(mode: 'left' | 'center' | 'right') {\r\n        const map = {\r\n            left: 0,\r\n            center: 1,\r\n            right: 2\r\n        };\r\n        // ESC a n  version bytes\r\n        this.write(0x1B, 0x61, map[mode]);\r\n        // ESC a n  version string\r\n        this.content += `\\x1B\\x61${String.fromCharCode(map[mode])}`;\r\n    }\r\n\r\n    boldOn(){\r\n        this.content += '\\x1B\\x45\\x01';  //version string\r\n        // ESC E 1\r\n        this.write(0x1B, 0x45, 0x01);  //version bytes\r\n    }\r\n\r\n    boldOff(){\r\n        this.content += '\\x1B\\x45\\x00'; //version string\r\n         // ESC E 0\r\n        this.write(0x1B, 0x45, 0x00);  //version bytes\r\n    }\r\n\r\n    bold(text: string) {\r\n        this.boldOn();\r\n        this.text(text);\r\n        this.boldOff();\r\n    }\r\n\r\n    normalSize(){\r\n        this.content += '\\x1D\\x21\\x00';  //version string\r\n        // GS ! 0\r\n        this.write(0x1D, 0x21, 0x00);  //version bytes\r\n    }\r\n\r\n    doubleHeight() {\r\n        this.content += '\\x1D\\x21\\x01';\r\n        this.write(0x1D, 0x21, 0x01);\r\n    }\r\n\r\n    doubleWidth() {\r\n        this.content += '\\x1D\\x21\\x10';\r\n        this.write(0x1D, 0x21, 0x10);\r\n    }\r\n\r\n    doubleSize() {\r\n        // GS ! 17\r\n        // doble ancho + doble alto\r\n        this.content += '\\x1D\\x21\\x11';\r\n        this.write(0x1D, 0x21, 0x11);\r\n    }\r\n\r\n    feed(lines: number = 3) {\r\n        this.content += '\\n'.repeat(lines); //version string\r\n        for(let i = 0; i < lines; i++)this.write(0x0A);  //version bytes\r\n    }\r\n\r\n    cut(feed:number = 5) {\r\n        this.feed(feed);\r\n        this.content += '\\x1D\\x56\\x00';  //version string\r\n        // GS V 0\r\n        this.write(0x1D, 0x56, 0x00);  //version bytes\r\n    }\r\n\r\n    row(left: string, right: string, width = 42) {\r\n        const spaces = width - left.length - right.length;\r\n        this.text(left+' '.repeat(Math.max(1, spaces))+right);\r\n    }\r\n\r\n    wrap(text: string, width = 42): string[] {\r\n        const words = text.split(' ');\r\n        const lines: string[] = [];\r\n        let current = '';\r\n        for(const word of words) {\r\n            if((current + word).length > width) {\r\n                lines.push(current.trim());\r\n                current = '';\r\n            }\r\n            current += word + ' ';\r\n        }\r\n        if(current.trim())lines.push(current.trim());\r\n        return lines;\r\n    }\r\n\r\n    column(text: string, width: number, align: 'left' | 'center' | 'right' = 'left'){\r\n        // evitar overflow\r\n        if(text.length > width) {\r\n            text = text.substring(0, width);\r\n        }\r\n        switch(align){\r\n            case 'left':\r\n                return text.padEnd(width, ' ');\r\n            case 'right':\r\n                return text.padStart(width, ' ');\r\n            case 'center':\r\n                const totalSpaces = width - text.length;\r\n                const left = Math.floor(totalSpaces / 2);\r\n                const right = totalSpaces - left;\r\n                return (' '.repeat(left)+text +' '.repeat(right));\r\n        }\r\n    }\r\n\r\n    row3(col1: string, col2: string, col3: string, align: Record<string, Align> = {col1: 'left', col2: 'right', col3: 'right'}, whidth:number[] = [8, 16, 18]){\r\n        const line = this.column(col1, whidth[0], align.col1) + this.column(col2, whidth[1], align.col2) + this.column(col3, whidth[2], align.col3);\r\n        this.text(line);\r\n    }\r\n\r\n\r\n    qr(data: string, size = 6, errorLevel: 'L' | 'M' | 'Q' | 'H' = 'M') { \r\n        const errorMap = { L: 48, M: 49, Q: 50, H: 51 }; \r\n        const store_len = data.length + 3; \r\n        const pL = store_len % 256; \r\n        const pH = Math.floor(store_len / 256); \r\n        //ENCODE DATA\r\n        const encoder = new TextEncoder(); \r\n        const encoded = encoder.encode(data); \r\n        /* ========================================= \r\n        TAMAÑO QR \r\n        ========================================= \r\n        */ \r\n        // GS ( k 3 0 49 67 n \r\n        // tamaño módulo \r\n        this.content +='\\x1D\\x28\\x6B\\x03\\x00\\x31\\x43'+String.fromCharCode(size); \r\n        this.write(0x1D, 0x28, 0x6B, 0x03, 0x00, 0x31, 0x43, size); //version bytes \r\n        /* ========================================= \r\n        NIVEL ERROR ========================================= \r\n        */ \r\n        // GS ( k 3 0 49 69 n \r\n        this.content +='\\x1D\\x28\\x6B\\x03\\x00\\x31\\x45'+String.fromCharCode(errorMap[errorLevel]); \r\n        this.write(0x1D, 0x28, 0x6B, 0x03, 0x00, 0x31, 0x45, errorMap[errorLevel]); //version bytes \r\n        /* ========================================= \r\n        ALMACENAR DATA \r\n        ========================================= \r\n        */ \r\n        this.content += '\\x1D\\x28\\x6B' + String.fromCharCode(pL) + String.fromCharCode(pH) + '\\x31\\x50\\x30' + data; \r\n        this.write(0x1D, 0x28, 0x6B, pL, pH, 0x31, 0x50, 0x30); //version bytes \r\n        this.bytes.push(...encoded); \r\n        /* ========================================= \r\n        IMPRIMIR QR \r\n        ========================================= \r\n        */ \r\n       this.content += '\\x1D\\x28\\x6B\\x03\\x00\\x31\\x51\\x30'; \r\n       this.write(0x1D, 0x28, 0x6B, 0x03, 0x00, 0x31, 0x51, 0x30); \r\n    }\r\n    \r\n\r\n    canvasToEscPos(canvas: HTMLCanvasElement) {\r\n        const ctx = canvas.getContext('2d')!;\r\n        const width = canvas.width;\r\n        const height = canvas.height;\r\n        const image = ctx.getImageData(0, 0, width, height);\r\n        const data = image.data;\r\n        const bytes = [];\r\n        bytes.push(0x1D, 0x76, 0x30, 0x00, width / 8, 0x00, height & 0xff, (height >> 8) & 0xff);\r\n        for (let y = 0; y < height; y++) {\r\n            for (let x = 0; x < width; x += 8) {\r\n                let byte = 0;\r\n                for (let bit = 0; bit < 8; bit++) {\r\n                    const px = x + bit;\r\n                    if (px >= width) continue;\r\n                    const i = (y * width + px) * 4;\r\n                    const r = data[i];\r\n                    const g = data[i + 1];\r\n                    const b = data[i + 2];\r\n                    const gray = r * 0.299 + g * 0.587 + b * 0.114;\r\n                    if (gray < 160) byte |= (1 << (7 - bit));\r\n                }\r\n                bytes.push(byte);\r\n            }\r\n        }\r\n        return bytes;\r\n    }\r\n\r\n\r\n    async qrRaster(text:string, correction:string = 'M'){\r\n        return new Promise<number[]>((resolve, reject)=>{\r\n             const self = this; // Guardamos la referencia\r\n            QRCode.toCanvas(\r\n                canvas,\r\n                text,\r\n                {\r\n                    width: 256,\r\n                    margin: 1,\r\n                    errorCorrectionLevel: correction\r\n                },\r\n                function (error:any) {\r\n                    if (error) {\r\n                        console.error(error);\r\n                        reject(error);\r\n                        return;\r\n                    }\r\n                    console.log('QR generado');\r\n                    const qrBytes = self.canvasToEscPos(canvas);\r\n                    resolve(qrBytes);\r\n                }\r\n            );\r\n        });\r\n    }\r\n\r\n\r\n    async image(src: string, options: { width?: number; align?: 'left' | 'center' | 'right'; } = {}){\r\n        const {\r\n            width = 256,\r\n            align = 'center'\r\n        } = options;\r\n\r\n        return new Promise<void>((resolve, reject) => {\r\n            const img = new Image();\r\n            img.crossOrigin = 'anonymous';\r\n            img.onload = () => {\r\n                // calcular alto proporcional\r\n                const ratio = img.height / img.width;\r\n                const height = Math.floor(width * ratio);\r\n                // canvas temporal\r\n                const canvas = document.createElement('canvas');\r\n                canvas.width = Math.ceil(width / 8) * 8;\r\n                canvas.height = height;\r\n                const ctx = canvas.getContext('2d');\r\n                if(!ctx){\r\n                    reject('No canvas context');\r\n                    return;\r\n                }\r\n                // fondo blanco\r\n                ctx.fillStyle = '#FFFFFF';\r\n                ctx.fillRect(0, 0, canvas.width, canvas.height);\r\n                // mejora contraste\r\n                ctx.filter = 'grayscale(100%) contrast(180%)';\r\n                // dibujar imagen\r\n                ctx.drawImage(img, 0, 0, canvas.width, canvas.height);\r\n                // alineación\r\n                this.setAlign(align);\r\n                // convertir a ESC/POS\r\n                const imgBytes = this.canvasToEscPos(canvas);\r\n                // agregar bytes\r\n                this.bytes.push(...imgBytes);\r\n                this.feed(1);\r\n                this.setAlign('left');\r\n                resolve();\r\n            };\r\n            img.onerror = reject;\r\n            img.src = src;\r\n        });\r\n    }\r\n\r\n\r\n    build(buildBytes:boolean): string | Uint8Array  {\r\n        if(buildBytes){\r\n            return new Uint8Array(this.bytes);\r\n        }else{\r\n            return this.content;\r\n        }\r\n    }\r\n}\r\n\r\n\r\nclass InvoiceTicketBuilder extends EscPosBuilder {\r\n\r\n    private invoice: DataInvoice;\r\n    constructor(invoice: DataInvoice) {\r\n        super();\r\n        this.reset();\r\n        this.invoice = invoice;\r\n    }\r\n\r\n    async generate(buildBytes:boolean):Promise<string | Uint8Array> {\r\n        await this.header();\r\n        if(this.invoice.tipoFactura === '1')this.customer(); //solo factura electronica\r\n        this.datosFactura();\r\n        this.cliente();\r\n        this.items();\r\n        this.totals();\r\n        this.payments();\r\n        if(this.invoice.tipoFactura === '1')this.infoResolution();  //solo factura electronica\r\n        await this.footer();\r\n        this.cut();\r\n        return this.build(buildBytes);\r\n    }\r\n\r\n    private async header() {\r\n        await this.image(`/build/img/${this.invoice.logo}`, {\r\n            width: 256,\r\n            align: 'center'\r\n        });\r\n        this.boldOn();\r\n        this.center(this.invoice.negocio.toUpperCase());\r\n        this.boldOff();\r\n        this.feed(1);\r\n        this.center(`NIT: ${this.invoice.nit.trim()}`);\r\n        this.center(`SEDE: ${this.invoice.sucursal.trim().toUpperCase()}`);\r\n        this.center(this.invoice.direccion.trim());\r\n        this.center(`TEL: ${this.invoice.telefono.trim()}`);\r\n        this.feed(1);\r\n    }\r\n\r\n    private customer() { //cliente factura electronica\r\n        this.center(`Cliente: ${this.invoice.consumidorfinal.name}`);\r\n        this.center(`NIT: ${this.invoice.consumidorfinal.identification_number}`);\r\n    }\r\n\r\n    private datosFactura(){\r\n        this.boldOn();\r\n        this.center(`${this.invoice.textFactura}`);\r\n        this.boldOff();\r\n        this.bold(`Factura: ${this.invoice.prefijo.trim()}${this.invoice.consecutivo.trim()}`);\r\n        this.text(`Fecha pago: ${this.invoice.fechaPago.trim()}`);\r\n        this.text(`Forma de pago: ${this.invoice.tipoventa.trim()}`);\r\n        this.text(`Caja: ${this.invoice.caja.trim()}`);\r\n        this.text(`Vendedor: ${this.invoice.vendedor.trim()}`);\r\n        this.line();\r\n    }\r\n\r\n    private cliente(){\r\n        this.feed(1);\r\n        this.center(`Cliente: ${this.invoice.cliente.nombre.trim()} ${this.invoice.cliente.apellido.trim()}`);\r\n        this.center(`Documento: ${this.invoice.cliente.identificacion?.trim()??''}`);\r\n        this.center(`Telefono: ${this.invoice.cliente.telefono.trim()}`);\r\n        this.center(`Direccion: ${this.invoice.cliente.data1?.trim()||' - '}`);\r\n        this.feed(1);\r\n    }\r\n\r\n    private items() {\r\n        this.line();\r\n        this.feed(1);\r\n        this.boldOn();\r\n        this.row3('CANT', 'UND', 'TOTAL', {col1:'left', col2:'right', col3:'right'}, [8, 16, 18]);\r\n        this.boldOff();\r\n        for(const item of this.invoice.items) {\r\n            for(const line of this.wrap(item.nombreproducto.trim()))this.center(line);\r\n            //this.row(`${item.cantidad}  x  $${item.valorunidad.toLocaleString()}`, '$'+item.total.toLocaleString());\r\n            this.row3(item.stock?.toString()||item.cantidad.toString(), '$'+item.valorunidad.toLocaleString(), '$'+item.total.toLocaleString(), {col1:'left', col2:'right', col3:'right'}, [8, 16, 18]);\r\n        }\r\n    }\r\n\r\n    private totals() {\r\n        this.line();\r\n        this.feed(1);\r\n        this.setAlign('right');\r\n        this.text(`SUBTOTAL: $${Number(this.invoice.subtotal.trim()).toLocaleString()}`);\r\n        this.text(`IMPUESTO: $${Number(this.invoice.valorimpuestototal.trim()).toLocaleString()}`);\r\n        this.bigText(`TOTAL: $${Number(this.invoice.total.trim()).toLocaleString()}`, true);\r\n    }\r\n\r\n    private payments() {\r\n        this.feed(2);\r\n        this.doubleHeight();\r\n        for(const pago of this.invoice.mediospago) {\r\n            //this.text(`${pago.mediopago}: $${pago.valor?.toLocaleString()}`);\r\n            this.row3(' ', pago.mediopago+':', ` $${pago.valor?.toLocaleString()}`, {col1:'right', col2:'right', col3:'left'}, [10, 17, 15]);\r\n        }\r\n        this.normalSize();\r\n        this.feed(1);\r\n        this.setAlign('left');\r\n        this.text(`Observacion: ${this.invoice.observacion}`);\r\n        this.line();\r\n        this.feed(2);\r\n    }\r\n\r\n    private infoResolution(){\r\n        this.setAlign('left');\r\n        this.text(`Resolucion: ${this.invoice.resolucion.resolucion}, Rango desde: ${this.invoice.resolucion.rangoinicial} hasta ${this.invoice.resolucion.rangofinal}`);\r\n        this.text(`CUFE: ${this.invoice.cufe || 'fe9c733f32770f5fcc4ef954f9ef663c54c752e6c07bdc144bb00627faadf9f648818da3e96ef8293547140fb1970d22'}`);\r\n        this.feed(2);\r\n    }\r\n\r\n    private async footer() {\r\n        this.setAlign('center');\r\n        //this.qr(this.invoice.link || 'www.j2softwarepos.com/', 8, 'M');\r\n        const qrBytes = await this.qrRaster(this.invoice.link || this.invoice.www, 'M');\r\n        this.bytes.push(...qrBytes);\r\n        this.feed(2);\r\n        this.boldOn();\r\n        this.center('GRACIAS POR SU COMPRA');\r\n        this.boldOff();\r\n        this.feed(2);\r\n        this.center(`© ${new Date().getFullYear()} J2 Software POS Multisucursal`);\r\n        this.center('www.j2softwarepos.com');\r\n    }\r\n    //copy /b ticket.bin \"\\\\localhost\\\\CAJA\"\r\n}\r\n\r\n\r\n\r\nclass InvoiceTicketBuilder2 extends EscPosBuilder {\r\n\r\n    private invoice: DataInvoice;\r\n    constructor(invoice: DataInvoice) {\r\n        super();\r\n        this.reset();\r\n        this.invoice = invoice;\r\n    }\r\n\r\n    async generate(buildBytes:boolean):Promise<string | Uint8Array> {\r\n        await this.header();\r\n        if(this.invoice.tipoFactura === '1')this.customer(); //solo factura electronica\r\n        this.datosFactura();\r\n        this.cliente();\r\n        this.items();\r\n        this.totals();\r\n        this.payments();\r\n        if(this.invoice.tipoFactura === '1')this.infoResolution();  //solo factura electronica\r\n        await this.footer();\r\n        this.cut(2);\r\n        return this.build(buildBytes);\r\n    }\r\n\r\n    private async header() {\r\n        await this.image(`/build/img/${this.invoice.logo}`, {\r\n            width: 220,\r\n            align: 'center'\r\n        });\r\n        this.boldOn();\r\n        this.center(this.invoice.negocio.toUpperCase());\r\n        this.boldOff();\r\n        this.feed(1);\r\n        this.center(`NIT: ${this.invoice.nit.trim()}`);\r\n        this.center(`SEDE: ${this.invoice.sucursal.trim().toUpperCase()}`);\r\n        this.center(this.invoice.direccion.trim());\r\n        this.center(`TEL: ${this.invoice.telefono.trim()}`);\r\n        //this.feed(1);\r\n    }\r\n\r\n    private customer() { //cliente factura electronica\r\n        this.center(`Cliente: ${this.invoice.consumidorfinal.name}`);\r\n        this.center(`NIT: ${this.invoice.consumidorfinal.identification_number}`);\r\n    }\r\n\r\n    private datosFactura(){\r\n        this.boldOn();\r\n        this.center(`${this.invoice.textFactura}`);\r\n        this.boldOff();\r\n        this.bold(`Factura: ${this.invoice.prefijo.trim()}${this.invoice.consecutivo.trim()}`);\r\n        this.text(`Fecha pago: ${this.invoice.fechaPago.trim()}`);\r\n        this.text(`Forma de pago: ${this.invoice.tipoventa.trim()}`);\r\n        //this.text(`Caja: ${this.invoice.caja.trim()}`);\r\n        this.text(`Vendedor: ${this.invoice.vendedor.trim()}`);\r\n        this.line();\r\n    }\r\n\r\n    private cliente(){\r\n        //this.feed(1);\r\n        this.center(`Cliente: ${this.invoice.cliente.nombre.trim()} ${this.invoice.cliente.apellido.trim()}`);\r\n        this.center(`Documento: ${this.invoice.cliente.identificacion?.trim()??''}`);\r\n        this.center(`Telefono: ${this.invoice.cliente.telefono.trim()}`);\r\n        this.center(`Direccion: ${this.invoice.cliente.data1?.trim()||' - '}`);\r\n        //this.feed(1);\r\n    }\r\n\r\n    private items() {\r\n        this.line();\r\n        //this.feed(1);\r\n        this.boldOn();\r\n        this.row3('CANT', 'UND', 'TOTAL', {col1:'left', col2:'right', col3:'right'}, [8, 16, 18]);\r\n        this.boldOff();\r\n        for(const item of this.invoice.items) {\r\n            for(const line of this.wrap(item.nombreproducto.trim()))this.center(line);\r\n            //this.row(`${item.cantidad}  x  $${item.valorunidad.toLocaleString()}`, '$'+item.total.toLocaleString());\r\n            this.row3(item.stock?.toString()||item.cantidad.toString(), '$'+item.valorunidad.toLocaleString(), '$'+item.total.toLocaleString(), {col1:'left', col2:'right', col3:'right'}, [8, 16, 18]);\r\n        }\r\n    }\r\n\r\n    private totals() {\r\n        this.line();\r\n        this.feed(1);\r\n        this.setAlign('right');\r\n        this.text(`SUBTOTAL: $${Number(this.invoice.subtotal.trim()).toLocaleString()}`);\r\n        this.text(`IMPUESTO: $${Number(this.invoice.valorimpuestototal.trim()).toLocaleString()}`);\r\n        this.bigText(`TOTAL: $${Number(this.invoice.total.trim()).toLocaleString()}`, true);\r\n    }\r\n\r\n    private payments() {\r\n        this.feed(1);\r\n        //this.doubleHeight();\r\n        this.normalSize();\r\n        for(const pago of this.invoice.mediospago) {\r\n            //this.text(`${pago.mediopago}: $${pago.valor?.toLocaleString()}`);\r\n            this.row3(' ', pago.mediopago+':', ` $${pago.valor?.toLocaleString()}`, {col1:'right', col2:'right', col3:'left'}, [10, 17, 15]);\r\n        }\r\n        //this.normalSize();\r\n        this.feed(1);\r\n        this.setAlign('left');\r\n        this.text(`Observacion: ${this.invoice.observacion}`);\r\n        this.line();\r\n        //this.feed(2);\r\n    }\r\n\r\n    private infoResolution(){\r\n        this.setAlign('left');\r\n        this.text(`Resolucion: ${this.invoice.resolucion.resolucion}, Rango desde: ${this.invoice.resolucion.rangoinicial} hasta ${this.invoice.resolucion.rangofinal}`);\r\n        this.text(`CUFE: ${this.invoice.cufe || 'fe9c733f32770f5fcc4ef954f9ef663c54c752e6c07bdc144bb00627faadf9f648818da3e96ef8293547140fb1970d22'}`);\r\n        this.feed(2);\r\n    }\r\n\r\n    private async footer() {\r\n        this.setAlign('center');\r\n        //this.qr(this.invoice.link || 'www.j2softwarepos.com/', 8, 'M');\r\n        const qrBytes = await this.qrRaster(this.invoice.link || this.invoice.www, 'M');\r\n        this.bytes.push(...qrBytes);\r\n        this.feed(1);\r\n        this.boldOn();\r\n        this.center('GRACIAS POR SU COMPRA');\r\n        this.boldOff();\r\n        this.feed(1);\r\n        this.center(`© ${new Date().getFullYear()} J2 Software POS Multisucursal`);\r\n        this.center('www.j2softwarepos.com');\r\n    }\r\n    //copy /b ticket.bin \"\\\\localhost\\\\CAJA\"\r\n}\r\n\r\n\r\n\r\n","\r\n\r\n// const mobilemenu1 = document.querySelector('#mobile-menu1')as HTMLButtonElement;\r\n// const miDialogomenumovil = document.querySelector('#miDialogomenumovil') as any;\r\n\r\n// mobilemenu1.addEventListener('click', ()=>{\r\n//     miDialogomenumovil.showModal();\r\n//     document.addEventListener('click', cerrarDialogoExterno);\r\n// });\r\n\r\n\r\n// function cerrarDialogoExterno(event:Event){\r\n//  const f = event.target;\r\n//  if(f === miDialogomenumovil){\r\n//     miDialogomenumovil.close();\r\n//  }\r\n// }\r\nconst mobilemenu1 = document.querySelector('#mobile-menu1') as HTMLButtonElement;\r\nconst miDialogomenumovil = document.querySelector('#miDialogomenumovil') as HTMLDialogElement;\r\n\r\n// aseguramos que al cargar la página el modal esté cerrado y oculto\r\nmiDialogomenumovil.close();\r\nmiDialogomenumovil.setAttribute('hidden', 'true');\r\n\r\nmobilemenu1.addEventListener('click', () => {\r\n  miDialogomenumovil.showModal();\r\n  miDialogomenumovil.removeAttribute('hidden');\r\n  document.addEventListener('click', cerrarDialogoExterno);\r\n});\r\n\r\nfunction cerrarDialogoExterno(event: Event) {\r\n  const f = event.target;\r\n  if (f === miDialogomenumovil) {\r\n    miDialogomenumovil.close();\r\n    miDialogomenumovil.setAttribute('hidden', 'true');\r\n    document.removeEventListener('click', cerrarDialogoExterno);\r\n  }\r\n}\r\n\r\n\r\n","(()=>{\r\n    if(document.querySelector('.perfil')){\r\n      const btnCambiarEmail = document.querySelector('#btnCambiarEmail');\r\n      const miDialogoUpEmail = document.querySelector('#miDialogoUpEmail') as any;\r\n      //const btnCerrarUpDireccion = document.querySelector('#btnCerrarUpDireccion') as HTMLButtonElement;\r\n      \r\n  \r\n      btnCambiarEmail?.addEventListener('click', (e):void=>{\r\n        miDialogoUpEmail.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }); \r\n\r\n      //btnCerrarUpDireccion.addEventListener('click', ()=>miDialogoUpDireccion.close());\r\n\r\n  \r\n      function cerrarDialogoExterno(event:Event) {\r\n        if (event.target === miDialogoUpEmail || (event.target as HTMLInputElement).value === 'salir') {\r\n          miDialogoUpEmail.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n    }\r\n  \r\n  })();","(()=>{\r\n    if(document.querySelector('.ajustarcostos')){\r\n        let tablaAjustarCostos:HTMLElement;\r\n\r\n        type conversionunidadesapi = {\r\n            id:string,\r\n            idproducto: string,\r\n            idsubproducto: string,\r\n            idunidadmedidabase: string,\r\n            idunidadmedidadestino: string,\r\n            nombreunidadbase: string,\r\n            nombreunidaddestino: string,\r\n            factorconversion: string,\r\n            //idservicios:{idempleado:string, idservicio:string}[]\r\n          };\r\n\r\n        let allConversionUnidades:conversionunidadesapi[] = [];\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json();\r\n                console.log(allConversionUnidades);\r\n                pirntUnidades();\r\n                tablaAjustarCostos = ($('#tablaAjustarCostos') as any).DataTable(configdatatablesajustarcostos);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        //tablaAjustarCostos = ($('#tablaAjustarCostos') as any).DataTable(configdatatables);\r\n        //indiceFila = (tablaAjustarCostos as any).row(1).data();\r\n\r\n        function pirntUnidades():void{\r\n            allConversionUnidades.forEach(subUnd =>{\r\n                let select = document.querySelector(`tr[data-idsubproducto=\"${subUnd.idsubproducto}\"]`)?.children[5].children[0];\r\n                if(select == undefined)select = document.querySelector(`tr[data-idproducto=\"${subUnd.idproducto}\"]`)?.children[5].children[0];\r\n                const option = document.createElement('option');\r\n                option.textContent = subUnd.nombreunidaddestino;\r\n                option.dataset.factor = subUnd.factorconversion;\r\n                select?.appendChild(option);\r\n            });\r\n        }\r\n \r\n\r\n        /*const fila = (tablaAjustarCostos as any).row((idx:number, data:any, node:HTMLElement)=>{\r\n            return node.dataset.idproducto === subUnd.idsubproducto;\r\n        }).data();*/\r\n        //console.log(fila[4]);\r\n      /*fila[4] = `<select class=\"formulario__select\" required>\r\n                        <option value=\"\" disabled selected>-Seleccionar-</option>\r\n                        <option value=\"\"> Unidad </option>\r\n                    </select>`;\r\n        (tablaAjustarCostos as any).row(2).data(fila).draw();*/\r\n\r\n        //tablaAjustarCostos = ($('#tablaAjustarCostos') as any).DataTable(configdatatables);\r\n        \r\n        document.querySelector('#tablaAjustarCostos')?.addEventListener('focusout', (e:Event)=>{\r\n            var input = e.target as HTMLInputElement;\r\n            let tipoelemento:string = '', idelemento:string = '';\r\n            if(input.classList.contains('inputAjustarCosto')){\r\n                \r\n                var tr = input.closest('tr');\r\n                const selectUnidad = tr?.querySelector('.formulario__select') as HTMLSelectElement;\r\n                const factor:number = Number(selectUnidad.options[selectUnidad.selectedIndex].dataset.factor);\r\n                \r\n                var trx = input.closest('.fila') as HTMLElement;  //fila padre\r\n                if(!trx)trx = tr?.previousSibling as HTMLElement;\r\n\r\n                if(trx.classList.contains('producto')){\r\n                    idelemento = trx.dataset.idproducto!;\r\n                    tipoelemento = '0'; //si es producto\r\n                }\r\n                else{\r\n                    idelemento = trx.dataset.idsubproducto!;\r\n                    tipoelemento = '1';  // si es un subproducto\r\n                }\r\n\r\n                ////////////// enviar datos por api para actualizar costos /////////////\r\n                if(Number(input.value) != Number(trx.dataset?.costo||0))\r\n                actualizarcostos(tipoelemento, idelemento, factor, input);\r\n            }\r\n        });\r\n\r\n\r\n        function actualizarcostos(tipoelemento:string, idelemento:string, factor:number, input:HTMLInputElement){\r\n            if(input.value=='')input.value = '0';\r\n            const costo = Number(input.value)/factor;\r\n            console.log(costo);\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('tipoelemento', tipoelemento); //1 = subproducto\r\n                datos.append('idelemento', idelemento);\r\n                datos.append('precio_compra', costo+'');\r\n                try {\r\n                    const url = \"/admin/api/actualizarcostos\";  //asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        input.style.color = \"#02db02\";\r\n                        input.style.fontWeight = \"500\";\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n    }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.cambioPrecios')){\r\n        let tablaAjustarPrecios:HTMLElement;\r\n\r\n        type conversionunidadesapi = {\r\n            id:string,\r\n            idproducto: string,\r\n            idsubproducto: string,\r\n            idunidadmedidabase: string,\r\n            idunidadmedidadestino: string,\r\n            nombreunidadbase: string,\r\n            nombreunidaddestino: string,\r\n            factorconversion: string,\r\n            //idservicios:{idempleado:string, idservicio:string}[]\r\n          };\r\n\r\n        let allConversionUnidades:conversionunidadesapi[] = [];\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json();\r\n                console.log(allConversionUnidades);\r\n                pirntUnidades();\r\n                tablaAjustarPrecios = ($('#tablaAjustarPrecios') as any).DataTable(configdatatablesajustarcostos);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        //tablaAjustarPrecios = ($('#tablaAjustarPrecios') as any).DataTable(configdatatables);\r\n        //indiceFila = (tablaAjustarPrecios as any).row(1).data();\r\n\r\n        function pirntUnidades():void{\r\n            allConversionUnidades.forEach(subUnd =>{\r\n                let select = document.querySelector(`tr[data-idproducto=\"${subUnd.idproducto}\"]`)?.children[5].children[0];\r\n                const option = document.createElement('option');\r\n                option.textContent = subUnd.nombreunidaddestino;\r\n                option.dataset.factor = subUnd.factorconversion;\r\n                select?.appendChild(option);\r\n            });\r\n        }\r\n \r\n\r\n        /*const fila = (tablaAjustarPrecios as any).row((idx:number, data:any, node:HTMLElement)=>{\r\n            return node.dataset.idproducto === subUnd.idsubproducto;\r\n        }).data();*/\r\n        //console.log(fila[4]);\r\n      /*fila[4] = `<select class=\"formulario__select\" required>\r\n                        <option value=\"\" disabled selected>-Seleccionar-</option>\r\n                        <option value=\"\"> Unidad </option>\r\n                    </select>`;\r\n        (tablaAjustarPrecios as any).row(2).data(fila).draw();*/\r\n\r\n        //tablaAjustarPrecios = ($('#tablaAjustarPrecios') as any).DataTable(configdatatables);\r\n        \r\n        document.querySelector('#tablaAjustarPrecios')?.addEventListener('focusout', (e:Event)=>{\r\n            var input = e.target as HTMLInputElement;\r\n            let idelemento:string = '';\r\n            if(input.classList.contains('inputAjustarPrecio')){\r\n                \r\n                var tr = input.closest('tr');\r\n                const selectUnidad = tr?.querySelector('.formulario__select') as HTMLSelectElement;\r\n                const factor:number = Number(selectUnidad.options[selectUnidad.selectedIndex].dataset.factor);\r\n                \r\n                var trx = input.closest('.fila') as HTMLElement;  //fila padre\r\n                if(!trx)trx = tr?.previousSibling as HTMLElement;\r\n\r\n                if(trx.classList.contains('producto')){\r\n                    idelemento = trx.dataset.idproducto!;\r\n                }\r\n\r\n                ////////////// enviar datos por api para actualizar precios /////////////\r\n                if(Number(input.value) != Number(trx.dataset?.precio||0))\r\n                actualizarPreciosVenta(idelemento, factor, input);\r\n            }\r\n        });\r\n\r\n\r\n        function actualizarPreciosVenta(idelemento:string, factor:number, input:HTMLInputElement){\r\n            if(input.value=='')input.value = '0';\r\n            const precio = Number(input.value)/factor;\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('idelemento', idelemento);\r\n                datos.append('precio_venta', precio+'');\r\n                try {\r\n                    const url = \"/admin/api/actualizarPreciosVenta\";  //asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        input.style.color = \"#02db02\";\r\n                        input.style.fontWeight = \"500\";\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n    }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.almacen')){\r\n        const btntrasladoinvnetario = document.querySelector('#btntrasladoinvnetario') as HTMLInputElement;\r\n        const btnMasOpciones = document.querySelector('#btnMasOpciones') as HTMLInputElement;\r\n        const btnviewProductsBajoStock = document.querySelector('#btnviewProductsBajoStock') as HTMLButtonElement;\r\n        const miDialogoTrasladoInvnetario = document.querySelector('#miDialogoTrasladoInvnetario') as any;\r\n        const miDialogoMasOpciones = document.querySelector('#miDialogoMasOpciones') as any;\r\n        const reinciarinv = document.querySelector('#reinciarinv') as HTMLButtonElement;\r\n        const miDialogoBajoStock = document.querySelector('#miDialogoBajoStock') as HTMLDialogElement;\r\n        const miDialogoStock = document.querySelector('#miDialogoStock') as any;\r\n        const modalStock = document.querySelector('#modalStock') as HTMLElement;\r\n        const selectStockRapidoUndmedida = document.querySelector('#selectStockRapidoUndmedida') as HTMLSelectElement;\r\n        let amount = document.querySelector('#cantidadStockRapido') as HTMLInputElement; //input cantidad de modal de stock rapido\r\n        let stockAux = document.querySelector('#stockAux') as HTMLInputElement; //input cantidad aux de modal de stock rapido\r\n\r\n        const miDialogoIngresarProduccion = document.querySelector('#miDialogoIngresarProduccion') as any;\r\n        const selectitemAproducir = document.querySelector('#itemAproducir') as HTMLSelectElement;\r\n        const btnsproduccion = document.querySelectorAll<HTMLButtonElement>('.btnproduccion');  //btns ingresar descontar ajustar produccion\r\n        const selectIngresarProduccionUnidadmedida = document.querySelector('#selectIngresarProduccionUnidadmedida') as HTMLSelectElement;\r\n        const amountProduccion = document.querySelector('#stockIngresarProduccion') as HTMLInputElement;  //input cantidad cuando se ingresa orden de produccion\r\n        let cantidadactual = 0, indiceFila=0, endponit:string='', factorC = 0, idUnidMedida:string, tipoelemento:string = '', idelemento:string = '', tablaStockRapido:HTMLElement, tablaInventarioSedes:HTMLTableElement;\r\n    \r\n        const sedes = document.querySelector('#sedes');\r\n        const tablaBajoStock = document.querySelector('#tablaBajoStock tbody') as HTMLBodyElement;\r\n\r\n        interface datosProducto { stock?: string, sku?:string, precio_compra: string, precio_venta: string }\r\n\r\n        type conversionunidadesapi = {\r\n            id:string,\r\n            idproducto:string,\r\n            idsubproducto: string,\r\n            idunidadmedidabase: string,\r\n            idunidadmedidadestino: string,\r\n            nombreunidadbase: string,\r\n            nombreunidaddestino: string,\r\n            factorconversion: string,\r\n          };\r\n\r\n          type productosXsucursal = {\r\n            productoid:string,\r\n            subproductoid: string,\r\n            nombreproducto:string,\r\n            sucursalid: string,\r\n            sucursal: string,\r\n            stock: string,\r\n          };\r\n\r\n        let allproductsXsucursal:productosXsucursal[]=[], allConversionUnidades:conversionunidadesapi[] = [];\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json();\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        //apertura de la ventana modal para las opcionesde traslado de inventario\r\n        btntrasladoinvnetario.addEventListener('click', ()=>{\r\n            miDialogoTrasladoInvnetario.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n        //apertura de la ventana modal para las opcionesde traslado de inventario\r\n        btnMasOpciones.addEventListener('click', ()=>{\r\n            miDialogoMasOpciones.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n\r\n        btnviewProductsBajoStock.addEventListener('click', ()=>{\r\n            getItemsBajoStock();\r\n            miDialogoBajoStock.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno); \r\n        });\r\n\r\n        async function getItemsBajoStock(){\r\n            try {\r\n                const url = \"/admin/api/getItemsBajoStock\";\r\n                const respuesta = await fetch(url); \r\n                const resultado:{productoid:string, nombre:string, idunidadmedida:string, sku:string, stock:string, stockminimo:string, tipoproducto:string, tipoproduccion:string, unidadmedida:string, visible:string}[] = await respuesta.json();\r\n                Object.assign(configdatatablesstockbajo, {\r\n                    data: resultado,\r\n                    columns: [\r\n                        {title: 'ID', data: 'productoid'},\r\n                        {title: 'NOMBRE', data: 'nombre'},\r\n                        {\r\n                            title: 'TIPO', \r\n                            data: null,\r\n                            orderable: false,\r\n                            searchable: false,\r\n                            render: (data: any, type: any, row: any) => {return row.tipoproducto== 1?'Compuesto':'Simple'}\r\n                        },\r\n                        {title: 'STOCK ACTUAL', data: 'stock'},\r\n                        {title: 'STOCK MIN', data: 'stockminimo'},\r\n                    ],\r\n                });\r\n                ($('#tablaBajoStock') as any).DataTable(configdatatablesstockbajo); \r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        }\r\n\r\n        reinciarinv.addEventListener('click', (e)=>{\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea reiniciar el inventario a cero?',\r\n                text: \"Todos los productos e insumos del inventario se reiniciaran a cero.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n                    (async ()=>{\r\n                        try {\r\n                            const url = \"/admin/api/reiniciarinv\"; //llamado a la API REST y se trae las direcciones segun cliente elegido\r\n                            const respuesta = await fetch(url); \r\n                            const resultado = await respuesta.json();\r\n                            (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n                            if(resultado.exito !== undefined){ \r\n                                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                                setTimeout(() => {\r\n                                window.location.reload();  \r\n                                }, 1270);\r\n                            }else{\r\n                                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();\r\n                }\r\n            });\r\n        });\r\n\r\n\r\n        sedes?.addEventListener('change', (e:Event)=>{\r\n            if((e.target as HTMLInputElement).checked){\r\n                (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n                (async ()=>{\r\n                    try {\r\n                        const url = \"/admin/api/getStockproductosXsucursal\"; //llamado a la API REST en el controlador almacencontrolador para treaer todos los productos con su respectiva sucursal y stock\r\n                        const respuesta = await fetch(url); \r\n                        allproductsXsucursal = await respuesta.json();\r\n                        printstockXsucursal();\r\n                        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();\r\n            }\r\n        });\r\n\r\n\r\n        /////////////////////////////////////  SOTCK RAPIDO ////////////////////////////////////////\r\n        /*document.querySelector('#stockproducto')?.addEventListener('click', (e)=>{\r\n            if((e.target as HTMLInputElement).checked){\r\n                 tablaStockRapido = ($('#tablaStockRapido') as any).DataTable(configdatatables);\r\n            }\r\n        })*/\r\n        tablaStockRapido = ($('#tablaStockRapido') as any).DataTable(configdatatablesstockrapido);\r\n\r\n        document.querySelector('#tablaStockRapido')?.addEventListener(\"click\", (e:Event)=>{ //evento click sobre toda la tabla\r\n            let options:string = '';\r\n            const target = e.target as HTMLElement;\r\n\r\n           if(target.closest('.btnsproducto')){\r\n                idelemento = target.closest('.btnsproducto')!.id;\r\n                tipoelemento = '0'; //si es producto\r\n                cantidadactual = Number((target.closest('.btnsproducto') as HTMLElement).dataset.stock);\r\n                document.querySelector('#nombreItemstockrapido')!.textContent = (target.closest('.btnsproducto') as HTMLElement).dataset.nombre!;\r\n            }\r\n            if(target.closest('.btnssubproducto')){\r\n                idelemento = target.closest('.btnssubproducto')!.id;\r\n                tipoelemento = '1'; //si es un subproducto\r\n                cantidadactual = Number((target.closest('.btnssubproducto') as HTMLElement).dataset.stock);\r\n                document.querySelector('#nombreItemstockrapido')!.textContent = (target.closest('.btnssubproducto') as HTMLElement).dataset.nombre!;\r\n            }\r\n\r\n            while(selectStockRapidoUndmedida.firstChild)selectStockRapidoUndmedida.removeChild(selectStockRapidoUndmedida.firstChild);\r\n            if(tipoelemento == '0'){\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == idelemento); \r\n                productounidades.forEach(u=>{\r\n                    options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`;\r\n                    idUnidMedida = u.idunidadmedidabase;\r\n                });\r\n                selectStockRapidoUndmedida.insertAdjacentHTML('afterbegin', options);\r\n            }\r\n            if(tipoelemento == '1'){\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == idelemento); \r\n                subproductounidades.forEach(u=>{\r\n                    options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`;\r\n                    idUnidMedida = u.idunidadmedidabase;\r\n                });\r\n                selectStockRapidoUndmedida.insertAdjacentHTML('afterbegin', options);\r\n            }\r\n            \r\n            if((e.target as HTMLElement)?.classList.contains(\"descontarStock\")||(e.target as HTMLElement).parentElement?.classList.contains(\"descontarStock\"))descontarStock(e);\r\n            if((e.target as HTMLElement)?.classList.contains(\"aumentarStock\")||(e.target as HTMLElement).parentElement?.classList.contains(\"aumentarStock\"))aumentarStock(e);\r\n            if((e.target as HTMLElement)?.classList.contains(\"ajustarStock\")||(e.target as HTMLElement).parentElement?.classList.contains(\"ajustarStock\"))ajustarStock(e);\r\n        });\r\n\r\n        //EDITAR STOCK\r\n        function descontarStock(e:Event){\r\n            modalStock.textContent = \"Descontar cantidad a inventario\"\r\n            endponit = \"descontarstock\";\r\n            indiceFila = (tablaStockRapido as any).row((e.target as HTMLElement).closest('tr')).index();\r\n            miDialogoStock.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n        function aumentarStock(e:Event){\r\n            modalStock.textContent = \"Ingreasar cantidad a inventario\"\r\n            endponit = \"aumentarstock\";\r\n            indiceFila = (tablaStockRapido as any).row((e.target as HTMLElement).closest('tr')).index();\r\n            miDialogoStock.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n        function ajustarStock(e:Event){\r\n            modalStock.textContent = \"Ajustar cantidad a inventario\"\r\n            endponit = \"ajustarstock\";\r\n            indiceFila = (tablaStockRapido as any).row((e.target as HTMLElement).closest('tr')).index();\r\n            miDialogoStock.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n\r\n        document.querySelector('#formStock')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            factorC = Number(selectStockRapidoUndmedida.options[selectStockRapidoUndmedida.selectedIndex].dataset.factor);\r\n            let info = (tablaStockRapido as any).page.info(), AmountItem:number = factorC*Number(amount.value), promediostock = 1, stockAuxiliar = Number(stockAux.value);\r\n            \r\n            if(endponit == \"descontarstock\")cantidadactual = cantidadactual-AmountItem;\r\n            if(endponit == \"aumentarstock\")cantidadactual = cantidadactual+AmountItem;\r\n            if(endponit == \"ajustarstock\")cantidadactual = AmountItem;\r\n\r\n            /*idUnidMedida === '1'\r\n                ?\r\n                (promediostock = cantidadactual>0?(stockAuxiliar/cantidadactual):0)\r\n                :\r\n                (promediostock = stockAuxiliar>0?(cantidadactual/stockAuxiliar):0);*/\r\n            promediostock = stockAuxiliar>0?(AmountItem/stockAuxiliar):0;\r\n\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('tipoitem', tipoelemento);\r\n                datos.append('iditem', idelemento);\r\n                datos.append('cantidad', AmountItem.toString());\r\n                datos.append('stockaux', stockAuxiliar.toString());\r\n                datos.append('promediostock', promediostock.toString());\r\n                try{\r\n                    const url = \"/admin/api/\"+endponit;  //asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                        ////// reset form ///////\r\n                        (document.querySelector('#formStock') as HTMLFormElement)?.reset();\r\n                        //actualizar fila\r\n                        //(tablaStockRapido as any).cell(indiceFila, 3).data(cantidadactual).draw();\r\n                        //(tablaStockRapido as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                        //actualiza tabla stock rapido\r\n                        actualizarStockRapido([resultado.item[0]], tipoelemento);\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                    miDialogoStock.close();\r\n                    document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                }catch(error){\r\n                    console.log(error);\r\n                }\r\n            })();//cierre de async()\r\n        });\r\n\r\n    //////////////////////////  UTILIDAD PRODUCTO  ///////////////////////////\r\n    ($('#utilidadProductos') as any).DataTable(configdatatablesstockrapido);  \r\n\r\n\r\n    //////////////////////////// SOTCK POR SUCURSAL //////////////////////\r\n    function printstockXsucursal(){\r\n        const sucursales = [...new Set(allproductsXsucursal.map(d => d.sucursal))]; //lista unica de sucursales\r\n        \r\n        // 2. Reorganizar por producto\r\n        const productos: Record<string, { nombreproducto: string; stocks: Record<string, string> }> = {};\r\n        allproductsXsucursal.forEach(d => {\r\n            if(d.productoid){\r\n                if (!productos['p'+d.productoid]) { //si el obj no es creado se crea con el nombre del producto pero el stock vacio\r\n                    productos['p'+d.productoid] = { nombreproducto: d.nombreproducto, stocks: {} };\r\n                }\r\n                productos['p'+d.productoid].stocks[d.sucursal] = d.stock; //aqui se llena el stock, que es un obj y sus propiedades son las sedes\r\n            }\r\n            if(d.subproductoid){\r\n                if (!productos['s'+d.subproductoid]) { //si el obj no es creado se crea con el nombre del producto pero el stock vacio\r\n                    productos['s'+d.subproductoid] = { nombreproducto: 'S-'+d.nombreproducto, stocks: {} };\r\n                }\r\n                productos['s'+d.subproductoid].stocks[d.sucursal] = d.stock; //aqui se llena el stock, que es un obj y sus propiedades son las sedes\r\n            }\r\n        });\r\n\r\n        // 3. Columnas dinámicas\r\n        const columnas = [{ title: \"Producto\", data: \"nombreproducto\" }];\r\n        sucursales.forEach(s => {\r\n            columnas.push({ title: s, data: s });\r\n        });\r\n\r\n        // 4. Dataset\r\n        const dataset = Object.values(productos).map(prod => {\r\n            const fila: any = { nombreproducto: prod.nombreproducto };\r\n            sucursales.forEach(s => {\r\n                fila[s] = prod.stocks[s] ?? 0; //fila es un obj, se crea la propieadad con el nombre de la sucursal y se iguala al objeto stock copn propiedad sucursal.\r\n            });\r\n            return fila;\r\n        });\r\n\r\n        tablaInventarioSedes = ($('#tablaInventarioSedes') as any).DataTable({\r\n            data: dataset,\r\n            columns: columnas,\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                    {extend: 'copyHtml5', text: 'Copia'}, \r\n                    {extend: 'excelHtml5', title: 'InventarioXsede'}, \r\n                    {extend: 'pdfHtml5', title: 'InventarioXsede'}, \r\n                    {extend: 'print', title: 'InventarioXsede', text: 'Imprimir'},\r\n                    'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n            pageLength: 25,\r\n            paging: true,\r\n            lengthChange: true,\r\n            searching: true,\r\n            ordering: true,\r\n            info: true,\r\n            autoWidth: true,\r\n            responsive: true,\r\n            deferRender: true,\r\n            //retrieve: true,\r\n            processing: true,\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando 1 de _MAX_ registros',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            destroy: true, // importante si recargas la tabla\r\n        });\r\n\r\n    }\r\n\r\n\r\n    ///////////////////////////// INGRESAR ORDEN DE PRODUCCION /////////////////////////////////\r\n        \r\n        //SELECT2 DE itemAproducir\r\n        ($('#itemAproducir') as any).select2({\r\n            maximumSelectionLength: 1,\r\n        });\r\n\r\n        ////// evento al select del producto a producir ////// \r\n        $(\"#itemAproducir\").on('change', (e)=>{\r\n            const idproducto = (e.target as HTMLOptionElement).value;\r\n            const selectedOption = $(\"#itemAproducir option:selected\");\r\n            if(idproducto){\r\n                const prodund = allConversionUnidades.filter(x =>x.idproducto == idproducto);\r\n                mostrarSelectUnidades(prodund);\r\n                let producto: datosProducto; //inicializamos el objeto de tipo interfaz \r\n                producto = {\r\n                    stock: selectedOption.data('stock'),\r\n                    precio_compra: selectedOption.data('precio_compra'),\r\n                    precio_venta: selectedOption.data('precio_venta')\r\n                }\r\n                mostrarInfoItem(producto);\r\n            }\r\n        });\r\n\r\n        /////////// CARGAR LAS UNIDADES DE MEDIDA EN EL SELECT unidadmedida  ////////////\r\n        function mostrarSelectUnidades(prodund:conversionunidadesapi[]):void{\r\n            while(selectIngresarProduccionUnidadmedida?.firstChild)selectIngresarProduccionUnidadmedida.removeChild(selectIngresarProduccionUnidadmedida?.firstChild);\r\n            prodund.forEach(und =>{\r\n              const option = document.createElement('option');\r\n              option.textContent = und.nombreunidaddestino;\r\n              option.value = und.id;  //und.id  =  es el id de la tabla conversionunidades\r\n              option.dataset.factor = und.factorconversion;\r\n              selectIngresarProduccionUnidadmedida.appendChild(option);\r\n            });\r\n        }\r\n\r\n        btnsproduccion.forEach((btnproduccion, index) =>{\r\n            btnproduccion.addEventListener('click', (e)=>{\r\n               if(selectitemAproducir.value){    \r\n                    document.querySelector('#nombreItemAProducir')!.textContent = selectitemAproducir.options[selectitemAproducir.selectedIndex].textContent;\r\n                    if(index === 0){\r\n                        endponit = \"aumentarstock\";\r\n                        document.querySelector('#modalIngresarProduccion')!.textContent = \"Ingreasar produccion a inventario\";\r\n                    }\r\n                    if(index === 1){\r\n                        endponit = \"descontarstock\";\r\n                        document.querySelector('#modalIngresarProduccion')!.textContent = \"Descontar catnidad de inventario\";\r\n                    }\r\n                    if(index === 2){\r\n                        endponit = \"ajustarstock\";\r\n                        document.querySelector('#modalIngresarProduccion')!.textContent = \"Ajustar cantidad de inventario\";\r\n                    }\r\n                    miDialogoIngresarProduccion.showModal();\r\n                    document.addEventListener(\"click\", cerrarDialogoExterno);\r\n                }\r\n            });\r\n        });\r\n\r\n\r\n        document.querySelector('#formIngresarProduccion')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            factorC = Number(selectIngresarProduccionUnidadmedida.options[selectIngresarProduccionUnidadmedida.selectedIndex].dataset.factor);\r\n            let AmountItemProduccion:number = factorC*Number(amountProduccion.value);\r\n\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('tipoitem', '0'); //0 = producto,  1 = subproducto\r\n                datos.append('iditem', selectitemAproducir.value);\r\n                datos.append('cantidad', AmountItemProduccion.toString());\r\n                datos.append('construccion', '1');  //se indica al backend que es construccion y se debe descontar sus insumos\r\n                try{\r\n                    const url = \"/admin/api/\"+endponit;  //endpoint = aumentarstock para produccion, asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                        ////// reset form ///////\r\n                        (document.querySelector('#formIngresarProduccion') as HTMLFormElement)?.reset();\r\n                        //mostrar contaidad actual\r\n                        mostrarInfoItem(resultado.item[0]); //producto\r\n                        //actualizar tabla stock rapido\r\n                        if(resultado.insumos !== undefined)actualizarStockRapido(resultado.insumos[0], '1'); //subproductos\r\n                        //actualizar el selecto de los productos/insumos a producir\r\n                        $(\"#itemAproducir option:selected\").data('stock', resultado.item[0].stock);\r\n                        \r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                    miDialogoIngresarProduccion.close();\r\n                    document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                }catch(error){\r\n                    console.log(error);\r\n                }\r\n            })();//cierre de async()\r\n        });\r\n\r\n\r\n        function mostrarInfoItem(producto:{stock?:string, precio_compra:string, precio_venta:string}){\r\n            document.querySelector('#stock')!.textContent = Number(producto.stock).toLocaleString();\r\n            document.querySelector('#costoProduccion')!.textContent = \"$\"+Number(producto.precio_compra).toLocaleString();\r\n            document.querySelector('#precioVenta')!.textContent = \"$\"+Number(producto.precio_venta).toLocaleString();\r\n        }\r\n\r\n\r\n        function actualizarStockRapido(insumosProductos:{id:string, productoid:string, subproductoid:string, sucursalid:string, stock:string, stockminimo:string, stockaux?:string}[], tipoItem:string){\r\n            insumosProductos.forEach(element => {\r\n                (tablaStockRapido as any).rows().every(function (this: any){\r\n                    const rowNode = this.node() as HTMLTableRowElement;\r\n                    let id_element = element.subproductoid, idAttr = rowNode.getAttribute('data-idsubproducto');\r\n                    if(tipoItem == '0'){\r\n                        idAttr = rowNode.getAttribute('data-idproducto');\r\n                        id_element = element.productoid;\r\n                    }\r\n                    if (idAttr && idAttr === id_element){\r\n                        this.cell(this.index(), 3).data(`<div class=\"text-center px-3 py-4 rounded-lg\">${element.stock}</div>`);\r\n                        this.cell(this.index(), 5).data(`${element.stockaux}`);\r\n\r\n                        // Obtén el <td> real\r\n                        const td = (tablaStockRapido as any).cell(this.index(), 3).node() as HTMLTableCellElement;\r\n                        if(Number(element.stock) <= Number(element.stockminimo)){\r\n                            td.firstElementChild?.classList.remove('bg-cyan-50', 'text-cyan-600');\r\n                            td.firstElementChild?.classList.add('bg-red-50', 'text-red-800');\r\n                        }else{\r\n                            td.firstElementChild?.classList.remove('bg-red-50', 'text-red-800');\r\n                            td.firstElementChild?.classList.add('bg-cyan-50', 'text-cyan-600');\r\n                        }\r\n                    } \r\n                });\r\n            })\r\n        }\r\n\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n            if (f === miDialogoTrasladoInvnetario || f === miDialogoMasOpciones || f === miDialogoStock || f === miDialogoIngresarProduccion || f===miDialogoBajoStock || (f as HTMLInputElement).value === 'salir' || (f as HTMLElement).id == 'btnXCerrarTrasladoInvnetario' || (f as HTMLElement).id == 'btnXCerrarMasOpciones' || (f as HTMLElement).id == 'btnCerrarTotalBajoStock') {\r\n                miDialogoStock.close();\r\n                miDialogoIngresarProduccion.close();\r\n                miDialogoTrasladoInvnetario.close();\r\n                miDialogoMasOpciones.close();\r\n                miDialogoBajoStock.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n            }\r\n        }\r\n\r\n\r\n        ///////////////////////////// GENERAR CODIGOS DE BARRAS /////////////////////////////////\r\n        let productoCodeBar: datosProducto|undefined;\r\n        let imagenBarcode: string | undefined;\r\n\r\n        ($('#itemCodeBar') as any).select2({\r\n            width: '100%',\r\n            maximumSelectionLength: 1,\r\n        });\r\n\r\n        ////// evento al select del producto a producir ////// \r\n        $(\"#itemCodeBar\").on('change', (e)=>{\r\n            const idproducto = (e.target as HTMLSelectElement).value;\r\n            const selectedOption = $(\"#itemCodeBar option:selected\");\r\n            if(idproducto){\r\n                productoCodeBar = {\r\n                    sku: selectedOption.data('sku'),\r\n                    precio_compra: selectedOption.data('precio_compra'),\r\n                    precio_venta: selectedOption.data('precio_venta'),\r\n                };\r\n                (document.querySelector('#codigoBarras') as HTMLInputElement).value = productoCodeBar.sku??'';\r\n            }\r\n        });\r\n\r\n        ///////btn para generar codigo de barras\r\n        document.querySelector('#formGenerarCodeBar')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            \r\n            if(!productoCodeBar || !productoCodeBar.sku){\r\n                alert('Producto no seleccionado o no tiene codigo de barras');\r\n                return;\r\n            }\r\n\r\n            const printPrecio = document.querySelector('#precioCodeBar') as HTMLSelectElement;\r\n\r\n            const canvas = document.querySelector('#barcode') as HTMLCanvasElement;\r\n            const options:any = {\r\n                bcid: 'code128',       // tipo de código\r\n                text: productoCodeBar.sku+'',     // valor (SKU o código)\r\n                scale: 3,\r\n                height: 10,\r\n                includetext: false,\r\n                textsize: 8,\r\n                textyoffset: 2,\r\n                textxalign: 'center'\r\n            }\r\n\r\n            if(printPrecio.value == '1'){\r\n                 options.alttext = '$'+Number(productoCodeBar.precio_venta).toLocaleString();\r\n            }else{\r\n                delete options.alttext;\r\n            }\r\n\r\n            bwipjs.toCanvas(canvas, options);\r\n            imagenBarcode = canvas.toDataURL(\"image/png\");\r\n\r\n        });\r\n        \r\n\r\n        document.querySelector('#btnImprimir')?.addEventListener('click', () => {\r\n            if(!imagenBarcode){\r\n                alert('Primero genere el código de barras');\r\n                return;\r\n            }\r\n            const ventana = window.open('', '_blank');\r\n            if(ventana){\r\n                ventana?.document.write(`\r\n                    <html>\r\n                    <head>\r\n                        <title>Etiqueta</title>\r\n                        <style>\r\n                            @page {\r\n                                size: 60mm 40mm;\r\n                                margin: 0;\r\n                            }\r\n                            body{\r\n                                margin:0;\r\n                                \r\n                            }\r\n\r\n                            .etiqueta{\r\n                                text-align:center;\r\n                                width:60mm;\r\n                                height:40mm;\r\n                            }\r\n\r\n                            img{\r\n                                width:100%;\r\n                            }\r\n                        </style>\r\n                    </head>\r\n\r\n                    <body>\r\n                        <div class=\"etiqueta\">\r\n                            <img src=\"${imagenBarcode}\" />\r\n                        </div>\r\n                    </body>\r\n                    </html>\r\n                `);\r\n                ventana.document.close();\r\n                ventana.onload = ()=>{\r\n                    ventana?.focus();\r\n                    ventana?.print();\r\n                    setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n                };\r\n            }\r\n        });\r\n\r\n\r\n    }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.categorias')){\r\n    const crearCategoria = document.querySelector('#crearCategoria');\r\n    const miDialogoCategoria = document.querySelector('#miDialogoCategoria') as any;\r\n    let indiceFila=0, control=0, tablaCategorias:HTMLElement;\r\n\r\n    type productsapi = {\r\n      id:string,\r\n      idcategoria: string,\r\n      nombre: string,\r\n      foto: string,\r\n      marca: string,\r\n      codigo: string,\r\n      descripcion: string,\r\n      peso: string,\r\n      medidas: string,\r\n      color: string,\r\n      funcion: string,\r\n      uso:string,\r\n      fabricante: string,\r\n      garantia: string,\r\n      stock: string,\r\n      categoria: string,\r\n      precio_compra: string,\r\n      precio_venta: string,\r\n      fecha_ingreso: string,\r\n      //idservicios:{idempleado:string, idservicio:string}[]\r\n    };\r\n\r\n    let products:productsapi[]=[], unproducto:productsapi;\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaCategorias = ($('#tablaCategorias') as any).DataTable(configdatatables25reg);\r\n\r\n    crearCategoria?.addEventListener('click', (e):void=>{\r\n      control = 0;\r\n      limpiarformdialog();\r\n      document.querySelector('#modalCategoria')!.textContent = \"Crear categoria\";\r\n      (document.querySelector('#btnEditarCrearCategoria') as HTMLInputElement).value = \"Crear\";\r\n      miDialogoCategoria.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    document.querySelector('#tablaCategorias')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarCategoria\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarCategoria\"))editarCategoria(e);\r\n      if(target?.classList.contains(\"eliminarCategoria\")||target.parentElement?.classList.contains(\"eliminarCategoria\"))eliminarCategoria(e);\r\n    });\r\n\r\n    function editarCategoria(e:Event){\r\n      control = 1;\r\n      let idcategoria = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idcategoria = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      //(document.querySelector('#formCrearUpdateCategoria') as HTMLFormElement).action = \"/admin/almacen/actualizar_categoria\";\r\n      document.querySelector('#modalCategoria')!.textContent = \"Actualizar categoria\";\r\n      (document.querySelector('#btnEditarCrearCategoria') as HTMLInputElement)!.value = \"Actualizar\";\r\n      (document.querySelector('#idcategoria') as HTMLInputElement).value = idcategoria;\r\n      (document.querySelector('#categoria') as HTMLInputElement).value = ((e.target as HTMLElement).closest('.acciones-btns') as HTMLElement)?.dataset.categoria!; \r\n      indiceFila = (tablaCategorias as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoCategoria.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar categoria  //////////////////////\r\n    document.querySelector('#formCrearUpdateCategoria')?.addEventListener('submit', e=>{\r\n      if(control){\r\n        e.preventDefault();\r\n        var info = (tablaCategorias as any).page.info();\r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', $('#idcategoria').val() as string);\r\n          datos.append('nombre', $('#categoria').val()as string);\r\n          try {\r\n              const url = \"/admin/api/actualizar_categoria\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json(); \r\n              console.log(resultado); \r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                ///////// cambiar la fila completa, su contenido //////////\r\n                const datosActuales = (tablaCategorias as any).row(indiceFila+=info.start).data();\r\n                /*Nombre categoria*/datosActuales[2] = $('#categoria').val();\r\n                /*data-categoria*/datosActuales[4] = `<div class=\"acciones-btns\" id=\"${$('#idcategoria').val()}\" data-categoria=\"${$('#categoria').val()}\"><button class=\"btn-md btn-turquoise editarCategoria\"><i class=\"fa-solid fa-pen-to-square\"></i></button><button class=\"btn-md btn-red eliminarCategoria\"><i class=\"fa-solid fa-trash-can\"></i></button></div>`;//$('#categoria').val();\r\n                \r\n                (tablaCategorias as any).row(indiceFila).data(datosActuales).draw();\r\n                (tablaCategorias as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n              document.addEventListener(\"click\", cerrarDialogoExterno);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n      } //fin if(control)\r\n    });\r\n\r\n    function eliminarCategoria(e:Event){\r\n      let idcategoria = (e.target as HTMLElement).parentElement!.id, info = (tablaCategorias as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idcategoria = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaCategorias as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar la categoria?',\r\n          text: \"La categoria y sus productos asociados, seran eliminados definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idcategoria);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarCategoria\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();\r\n                      if(resultado.length || resultado.exito !== undefined){\r\n                        (tablaCategorias as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaCategorias as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCategoria') as HTMLFormElement)?.reset();\r\n      (document.querySelector('#formCrearUpdateCategoria') as HTMLFormElement).action = \"/admin/almacen/crear_categoria\";\r\n      (document.querySelector('#idcategoria') as HTMLInputElement).value = '0';\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoCategoria || (event.target as HTMLInputElement).value === 'Salir' || (event.target as HTMLInputElement).value === 'Actualizar') {\r\n        miDialogoCategoria.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n  }\r\n\r\n})();","\r\n(()=>{\r\n    if(document.querySelector('.compras')){\r\n        const proveedor = document.querySelector('#proveedor') as HTMLSelectElement;\r\n        const impuesto = document.querySelector('#inputimpuesto') as HTMLInputElement;\r\n        const nfactura = document.querySelector('#nfactura') as HTMLInputElement;\r\n        const fecha = document.querySelector('#fecha') as HTMLDataElement;\r\n        const origenPago = document.querySelector('#origenPago') as HTMLSelectElement;\r\n        const origenCaja = document.querySelector('#origenCaja') as HTMLSelectElement;\r\n        const origenBanco = document.querySelector('#origenBanco') as HTMLSelectElement;\r\n        const formapago = document.querySelector('#formapago') as HTMLSelectElement;\r\n        const observacion = document.querySelector('#observacion') as HTMLInputElement;\r\n        const btnvaciar = document.querySelector('#btnvaciar');\r\n        const miDialogoVaciar = document.querySelector('#miDialogoVaciar') as any;\r\n        const miDialogoRegistrarcompra = document.querySelector('#miDialogoRegistrarcompra') as any;\r\n        const tablaCompras = document.querySelector('#tablaCompras tbody');\r\n\r\n        type conversionunidadesapi = {\r\n        id:string,\r\n        idproducto: string,\r\n        idsubproducto: string,\r\n        idunidadmedidabase: string,\r\n        idunidadmedidadestino: string,\r\n        nombreunidadbase: string,\r\n        nombreunidaddestino: string,\r\n        factorconversion: string,\r\n        //idservicios:{idempleado:string, idservicio:string}[]\r\n        };\r\n\r\n        let carrito:{iditem:string, idpx:string, idsx:string, tipocosto:string, tipo: string, nombreitem:string, unidad:string, stock: number, cantidad: number, cantidadcomprado: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra: number, valorcompra: number}[]=[];\r\n        let allConversionUnidades:conversionunidadesapi[] = [];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json();\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, tipoproduccion: string, sku:string, unidadmedida:string}[] = await respuesta.json();\r\n                console.log(resultado);\r\n                filteredData = resultado.filter(item => item.tipoproduccion=='0'||item.tipoproduccion==null).map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n\r\n        impuesto?.addEventListener('input', ()=>resumen());\r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#articulo') as any).select2({ \r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n                /*\r\n                templateResult: function (data:{id:string, text:string, tipo:string}) {\r\n                    // Personalizar cómo se muestra cada opción en el dropdown\r\n                    if (!data.id) { return data.text; }  // Si no hay id, solo mostrar el texto\r\n                    const html = `\r\n                        <div class=\"custom-option\">\r\n                            <span class=\"item-name\">${data.text}</span> \r\n                            <span class=\"item-type\">${data.tipo}</span>  <!-- Mostrar tipo adicional -->\r\n                        </div>`;\r\n                    return $(html);  // Devolver el HTML personalizado\r\n                }*/\r\n            });\r\n        }\r\n\r\n\r\n        //////////  ELEGIR ORIGEN DEL PAGO DE LA COMPRA, CAJA O BANCO ///////////\r\n        origenPago.addEventListener('change', (e:Event)=>{\r\n            if((e.target as HTMLOptionElement).value == '0'){ //0 = origen caja\r\n                document.querySelector('#divBanco')?.classList.add('hidden');\r\n                document.querySelector('#divBanco')?.removeAttribute(\"required\");\r\n            }else{  //1 = origen banco\r\n                document.querySelector('#divBanco')?.classList.remove('hidden');\r\n                document.querySelector('#divBanco')?.setAttribute(\"required\", \"\");\r\n            }\r\n        });\r\n\r\n\r\n        ////// EVENTO AL SELECT ARTICULOS O ITEMS PARA SELECCIONAR EL ITEM Y AÑADIR AL CARRITO ////// \r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.iditem==datos.id&&x.tipo==datos.tipo);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!; //products es el arreglo de todos los productos traido por api\r\n                    const item:{iditem: string, idpx: string, idsx: string, tipocosto:string, tipo: string, nombreitem: string, unidad: string, stock: number, cantidad: number, cantidadcomprado: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra:number, valorcompra: number} = {\r\n                        iditem: itemselected?.id!,\r\n                        idpx: itemselected.tipo=='0'?itemselected.id:'NULL',\r\n                        idsx: itemselected.tipo=='1'?itemselected.id:'NULL',\r\n                        tipocosto: '1',\r\n                        tipo: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = producto principal compuesto o subproducto\r\n                        nombreitem: itemselected.text,\r\n                        unidad: itemselected.unidadmedida,\r\n                        stock: 1,\r\n                        cantidad: 1,\r\n                        cantidadcomprado: 1,\r\n                        factor: 1,\r\n                        impuesto: 0,\r\n                        valorunidad: 0,\r\n                        subtotal: 0,\r\n                        precio_compra: 0,\r\n                        valorcompra: 0,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(datos.id, datos.tipo, datos.unidadmedida);\r\n                }\r\n            }\r\n        });\r\n\r\n\r\n        function printItemTable(id:string, tipo:string, unidadmedida:string){\r\n            let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            const unItem = filteredData.find(x=>x.id==id&&x.tipo==tipo)!;\r\n            if(tipo=='1'){   //si es un subproducto\r\n                options = \"\";\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == id); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            if(tipo=='0'){\r\n                options = \"\";\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.dataset.tipo = `${tipo}`;\r\n            tr.insertAdjacentHTML('afterbegin', `<td class=\"!px-0 !py-2 text-xl text-gray-500 leading-5\">${unItem?.text}</td> \r\n            <td class=\"!p-2 text-xl text-gray-500 leading-5\">\r\n                <select class=\"formulario__select selectunidad\">\r\n                    ${options}  \r\n                </select>\r\n            </td>\r\n            <td class=\"!px-0 !py-2\"><div class=\"flex\"><button type=\"button\"><span class=\"menos material-symbols-outlined\">remove</span></button><input type=\"text\" class=\"inputcantidad w-20 px-2 text-center\" value=\"1\" oninput=\"this.value = parseInt(this.value.replace(/[,.]/g, '')||1)\"><button type=\"button\"><span class=\"mas material-symbols-outlined\">add</span></button></div></td>\r\n            <td class=\"!p-2 text-xl text-gray-500 leading-5\"><input type=\"text\" placeholder=\"Ingresa Valor Total Producto\" class=\"inputcompra text-base sm:text-lg md:text-xl lg:text-2xl placeholder:text-sm sm:placeholder:text-base md:placeholder:text-lg lg:placeholder:text-xl bg-gray-50 border border-gray-300 text-gray-900 rounded-lg focus:border-indigo-600 block w-full p-2.5 dark:bg-gray-600 dark:border-gray-500 dark:placeholder-gray-400 dark:text-white h-14 focus:outline-none focus:ring-1\" value=\"\" oninput=\"this.value = parseInt(this.value.replace(/[,.]/g, '')||0)\"></td>\r\n            <td class=\"accionestd\"><div class=\"acciones-btns\"><button class=\"btn-md btn-red eliminarItem\"><i class=\"fa-solid fa-trash-can\"></i></button></div></td>`);\r\n            tablaCompras?.appendChild(tr);\r\n        }\r\n        \r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaCompras?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n\r\n            const itemCarrito = carrito.find(x=>x.iditem==iditem&&x.tipo==tipoitem)!;\r\n\r\n            if((e.target as HTMLElement).classList.contains('selectunidad')){\r\n                if((e.target as HTMLElement).dataset.event != \"eventSelect\"){\r\n                    e.target?.addEventListener('change', (e:Event)=>{\r\n                        const unit = e.target as HTMLSelectElement;\r\n                        itemCarrito.factor = Number(unit.options[unit.selectedIndex].dataset.factor);\r\n                    });\r\n                    (e.target as HTMLElement).dataset.event = \"eventSelect\"; //se marca al input que ya tiene evento añadido\r\n                }\r\n            }\r\n            \r\n            if((e.target as HTMLElement).classList.contains('menos')){\r\n                itemCarrito.cantidadcomprado--;\r\n                if(itemCarrito.cantidadcomprado<0)itemCarrito.cantidadcomprado = 0;\r\n            }\r\n\r\n            if((e.target as HTMLElement).classList.contains('inputcantidad')){\r\n                if((e.target as HTMLElement).dataset.event != \"eventInput\"){\r\n                    e.target?.addEventListener('input', (e:Event)=>{\r\n                        itemCarrito.cantidadcomprado = Number((e.target as HTMLInputElement).value);\r\n                        itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n                        itemCarrito.stock = itemCarrito.cantidad;\r\n                    });\r\n                    (e.target as HTMLElement).dataset.event = \"eventInput\"; //se marca al input que ya tiene evento añadido\r\n                }\r\n            }\r\n\r\n            if((e.target as HTMLElement).classList.contains('mas'))itemCarrito.cantidadcomprado++;\r\n            \r\n            //////// INPUT CANTIDAD DE LA TABLA DE ITEMS DE COMPRA, SE ACTUALIZA CADA VEZ QUE SE DE CLICK EN MENOS O MAS\r\n            (tablaCompras?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"] .inputcantidad`) as HTMLInputElement).value = itemCarrito?.cantidadcomprado+'';\r\n\r\n            /////// EVENTO AL INPUT VALOR DE COMPRA DE LA TABLA DE ITEMS DE COMPRA  ///////\r\n            if((e.target as HTMLElement).classList.contains('inputcompra')){\r\n                if((e.target as HTMLElement).dataset.event != \"eventInput\"){\r\n                    e.target?.addEventListener('input', (e:Event)=>{\r\n                        itemCarrito.valorcompra = Number((e.target as HTMLInputElement).value);\r\n                        itemCarrito.precio_compra = itemCarrito.valorcompra/itemCarrito.cantidad;\r\n                        resumen();\r\n                    });\r\n                    (e.target as HTMLElement).dataset.event = \"eventInput\"; //se marca al input que ya tiene evento añadido\r\n                }\r\n            }\r\n\r\n            if((e.target as HTMLElement).classList.contains('eliminarItem') || (e.target as HTMLElement).tagName == \"I\"){\r\n                carrito = carrito.filter(x=> {\r\n                    if(x.iditem==iditem){\r\n                        if(x.tipo==tipoitem){\r\n                            return false;\r\n                        }else{\r\n                            return true;\r\n                        }\r\n                    }else{\r\n                        return true;\r\n                    }\r\n                });\r\n                tablaCompras?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"]`)?.remove();\r\n                resumen();\r\n            }\r\n\r\n            itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n            itemCarrito.stock = itemCarrito.cantidad;\r\n        });\r\n\r\n\r\n        btnvaciar?.addEventListener('click', ()=>{\r\n            if(carrito.length){\r\n              miDialogoVaciar.showModal();\r\n              document.addEventListener(\"click\", cerrarDialogoExterno);\r\n            }\r\n        });\r\n\r\n        document.querySelector('#formComprar')?.addEventListener('submit', e=>{\r\n            e.preventDefault();\r\n            miDialogoRegistrarcompra.showModal();\r\n            (document.querySelector('#numOrden') as HTMLSpanElement).textContent = nfactura.value;\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n  \r\n        async function procesarpedido(estado:string){\r\n            const datos = new FormData();\r\n            datos.append('idproveedor', proveedor.options[proveedor.selectedIndex].value);\r\n            //datos.append('idformapago', formapago.options[formapago.selectedIndex].value);\r\n            datos.append('idorigencaja', origenCaja.options[origenCaja.selectedIndex].value);\r\n            datos.append('idorigenbanco', origenBanco.options[origenBanco.selectedIndex].value);\r\n            datos.append('nombreproveedor', proveedor.options[proveedor.selectedIndex].textContent!);\r\n            //datos.append('formapago', formapago.options[formapago.selectedIndex].text);\r\n            datos.append('nfactura', nfactura.value);\r\n            datos.append('impuesto', impuesto.value);\r\n            datos.append('origenpago', origenPago.options[origenPago.selectedIndex].value); //0 = si el origen viene de la caja,  1 = banco\r\n            datos.append('nombreorigenpago', origenPago.options[origenPago.selectedIndex].textContent+''); //caja o banco\r\n            datos.append('nombreorigencaja', origenCaja.options[origenCaja.selectedIndex].textContent+'');\r\n            datos.append('nombreorigenbanco', origenBanco.options[origenBanco.selectedIndex].value?origenBanco.options[origenBanco.selectedIndex].textContent+'':'');\r\n            datos.append('cantidaditems', carrito.reduce((total, item)=>item.cantidad+total, 0)+'');\r\n            datos.append('observacion', observacion.value);\r\n            datos.append('estado', estado);\r\n            datos.append('subtotal', carrito.reduce((total, item)=>item.valorcompra+total, 0)+'');\r\n            datos.append('valortotal', carrito.reduce((total, item)=>item.valorcompra+total, 0)+'');\r\n            datos.append('fechacompra', fecha.value);\r\n            datos.append('carrito', JSON.stringify(carrito));  ////arreglo de objetos de producto simple y subproducto\r\n            datos.append('subID', JSON.stringify(carrito.map(item=>{if(item.idsx){return item.idsx}}))); //envia solo los id de los subproductos\r\n            try {\r\n                const url = \"/admin/api/registrarCompra\";  //va al controlador ventascontrolador\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json();\r\n                if(resultado.exito !== undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    //imprimir detalle de compra\r\n                    if((document.querySelector('#imprimirComprobanteCompra') as HTMLInputElement).checked){\r\n                        printComprobanteCompra(resultado.idcompra);\r\n                    }\r\n                    /////// reinciar campos de la compra\r\n                    vaciarcompra();\r\n                    (document.querySelector('#formComprar') as HTMLFormElement)?.reset();\r\n                }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        }\r\n\r\n\r\n        function printComprobanteCompra(idcompra:string){\r\n            setTimeout(() => {\r\n                window.open(\"/admin/printComprobanteCompraPDF?id=\" + idcompra, \"_blank\");  //llama a printcontrolador\r\n            }, 1000);\r\n        }\r\n\r\n        function validarValorCompra():boolean{\r\n            return carrito.some(item=>Number.isNaN(item.valorcompra)||item.valorcompra==0);\r\n        }\r\n\r\n        function resumen():void{\r\n            document.querySelector('#impuesto')!.textContent = '% '+impuesto.value;\r\n            document.querySelector('#total')!.textContent = '$ '+carrito.reduce((total, item)=>item.valorcompra+total, 0).toLocaleString()+'';\r\n        \r\n        }\r\n\r\n        function vaciarcompra():void\r\n        {\r\n            carrito.length = 0;\r\n            while(tablaCompras?.firstChild)tablaCompras.removeChild(tablaCompras?.firstChild);\r\n            document.querySelector('#impuesto')!.textContent = '% 0';\r\n            document.querySelector('#total')!.textContent = '$ 0';\r\n        }\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n            if (f === miDialogoVaciar || f === miDialogoRegistrarcompra || (f as HTMLInputElement).closest('.novaciar') || (f as HTMLInputElement).closest('.sivaciar') || (f as HTMLInputElement).closest('.nocomprar') || (f as HTMLInputElement).closest('.sicomprar')) {\r\n              miDialogoVaciar.close();\r\n              miDialogoRegistrarcompra.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              if((f as HTMLInputElement).closest('.sicomprar')){\r\n                if(!validarValorCompra()){\r\n                    procesarpedido('paga');\r\n                }else{\r\n                    msjalertToast('error', '¡Error!', 'Verifica el valor de compra de la lista de productos');\r\n                }\r\n              }\r\n              if((f as HTMLInputElement).closest('.sivaciar'))vaciarcompra();\r\n            }\r\n        }\r\n        \r\n    }\r\n\r\n})();","(()=>{\r\n    \r\n    if(document.querySelector('.ensamblaje')){\r\n        const listaSubproductos = document.querySelector('.listaSubproductos');\r\n        //const subproducto:HTMLSelectElement = document.querySelector('#subproducto')!;\r\n        const selectUnidadMedida = document.querySelector('#unidadmedida')! as HTMLSelectElement;\r\n        let amount = document.querySelector('#cantidad') as HTMLInputElement; //input cantidad\r\n\r\n        type conversionunidadesapi = {\r\n            id:string,\r\n            idsubproducto: string,\r\n            idunidadmedidabase: string,\r\n            idunidadmedidadestino: string,\r\n            nombreunidadbase: string,\r\n            nombreunidaddestino: string,\r\n            factorconversion: string,\r\n            //idservicios:{idempleado:string, idservicio:string}[]\r\n          };\r\n\r\n        let allConversionUnidades:conversionunidadesapi[] = [], factorC = 0;\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n                const respuesta = await fetch(url); \r\n                allConversionUnidades = await respuesta.json(); \r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        \r\n        ($('#subproducto') as any).select2({\r\n            maximumSelectionLength: 1,\r\n        });\r\n\r\n\r\n        ////// EVENTO AL SUBPRODUCTO PARA CARGAR LAS UNIDADES DE MEDIDA EQUIVALENTES ////// \r\n        $(\"#subproducto\").on('change', (e)=>{\r\n            const idsub = (e.target as HTMLOptionElement).value;\r\n            const subund = allConversionUnidades.filter(x =>x.idsubproducto == idsub);\r\n            mostrarSelectUnidades(subund);\r\n        });\r\n\r\n        /////////// CARGAR LAS UNIDADES DE MEDIDA EN EL SELECT unidadmedida  ////////////\r\n        function mostrarSelectUnidades(subund:conversionunidadesapi[]):void{\r\n            while(selectUnidadMedida?.firstChild)selectUnidadMedida.removeChild(selectUnidadMedida?.firstChild);\r\n            subund.forEach(und =>{\r\n              const option = document.createElement('option');\r\n              option.textContent = und.nombreunidaddestino;\r\n              option.value = und.id;  //und.id  =  es el id de la tabla conversionunidades\r\n              //option.dataset.idunidadmedidabase = und.idunidadmedidabase;\r\n              //option.dataset.nombreunidadbase = und.nombreunidadbase;\r\n              selectUnidadMedida.appendChild(option);\r\n            });\r\n            calcularFactor();\r\n        }\r\n\r\n        ////////// EVENTO AL SELECT DE UNIDAD DE MEDIDA ///////////\r\n        selectUnidadMedida.addEventListener('change', calcularFactor);\r\n\r\n        (document.querySelector('#cantidad') as HTMLInputElement).addEventListener('input', (e:Event)=>{\r\n            calcularFactor();\r\n        });\r\n\r\n        function calcularFactor():void{\r\n            const idConversionUnidad:string|undefined = selectUnidadMedida.options[selectUnidadMedida.selectedIndex]?.value;\r\n            const reg = allConversionUnidades.find(x=>x.id == idConversionUnidad);\r\n            factorC = Number(reg?.factorconversion);\r\n        }\r\n\r\n        //////////////  EVENTO AL INPUT RENDIMIENTO ESTANDAR /////////////////\r\n        document.querySelector('#rendimientoestandar')?.addEventListener('input', (e:Event)=>{\r\n            const inputRendimiendoEstandar = (e.target as HTMLInputElement);\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('id', (document.querySelector('#idproducto') as HTMLInputElement).value);\r\n                datos.append('rendimientoestandar', inputRendimiendoEstandar.value);\r\n                try {\r\n                    const url = \"/admin/api/setrendimientoestandar\";\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        inputRendimiendoEstandar.style.color = \"#02db02\";\r\n                        inputRendimiendoEstandar.style.fontWeight = \"500\";\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        \r\n        });\r\n\r\n        ///////////////// EVENTO AL FORMULARIO ASOCIAR SUBPRODUCTO //////////////////\r\n        document.querySelector('#formAddSubproducto')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            const subproducto = $('#subproducto').find('option:selected');\r\n            const unidadmedida:string = $('#unidadmedida').find('option:selected').text();\r\n            let AmountSubpx:number = factorC*Number(amount.value);\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('id_producto', (document.querySelector('#idproducto') as HTMLInputElement).value);\r\n                datos.append('id_subproducto', $('#subproducto').val()as string);\r\n                datos.append('cantidadsubproducto', AmountSubpx.toString());\r\n                datos.append('costo', (Number(subproducto.data('costo'))*AmountSubpx)+'');\r\n                try {\r\n                    const url = \"/admin/api/ensamblar\";  //asocia el producto con el sub producto en la tabla productos_sub\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                      msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                        /////validar si es el mismo subproducto, y actualizar \r\n                        validarSubproducto($('#subproducto').val()as string, unidadmedida, subproducto.data('subproducto'));\r\n                        ////// reset form ///////\r\n                        ($('#subproducto') as any).val([]).trigger('change');\r\n                        //$(`#subproducto option[value=\"${$('#subproducto').val()}\"]`).remove();\r\n                        (document.querySelector('#formAddSubproducto') as HTMLFormElement)?.reset();\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();//cierre de async()\r\n        });\r\n\r\n\r\n        function validarSubproducto(idsubproducto:string, unidadmedida:string, subproducto:string){\r\n            const sub = document.querySelector(`.listaSubproductos div[id=\"${idsubproducto}\"]`);\r\n            if(sub){\r\n                sub.querySelector('strong')!.textContent = amount.value+' '+unidadmedida;\r\n            }else{\r\n                listaSubproductos?.insertAdjacentHTML('beforeend', `\r\n                <div id=\"${idsubproducto}\" class=\"mb-4 flex items-center justify-between p-4 text-blue-600 bg-blue-100 rounded-lg shadow-md shadow-blue-500/30\" role=\"alert\">\r\n                    <p class=\"m-0\"><strong>${amount.value} ${unidadmedida}</strong>.  ${subproducto}</p>\r\n                    <button type=\"button\"><span id=\"${idsubproducto}\" class=\"material-symbols-outlined\">cancel</span></button>\r\n                </div>`\r\n                );\r\n            }\r\n        }\r\n\r\n\r\n        listaSubproductos?.addEventListener('click', (e:Event)=>{\r\n            const btn = (e.target as HTMLSpanElement);\r\n            if(btn.tagName == \"SPAN\")desasociarSubproducto((document.querySelector('#idproducto') as HTMLInputElement).value, btn.id);\r\n        });\r\n\r\n\r\n        function desasociarSubproducto(idproducto:string, idsubproducto:string){\r\n            const sub = document.querySelector(`.listaSubproductos div[id=\"${idsubproducto}\"]`);\r\n            (async ()=>{\r\n                try {\r\n                  const url = \"/admin/api/desasociarsubproducto?idproducto=\"+idproducto+\"&idsubproducto=\"+idsubproducto; //llamado a la API REST para desasociar subproducto del producto principal\r\n                  const respuesta = await fetch(url); \r\n                  const resultado = await respuesta.json();\r\n                  if(resultado.exito !== undefined){\r\n                    sub?.remove();\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                  }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n\r\n\r\n    }\r\n\r\n})();","(():void=>{\r\n  if(document.querySelector('.gestionproveedores')){\r\n    const crearProveedor = document.querySelector('#crearProveedor') as HTMLButtonElement;\r\n    const miDialogoProveedor = document.querySelector('#miDialogoProveedor') as any;\r\n\r\n    let indiceFila=0, control=0, tablaProveedores:HTMLElement;\r\n\r\n    type proveedoresapi = {\r\n        id:string,\r\n        nit: string,\r\n        nombre: string,\r\n        telefono: string,\r\n        email: string,\r\n        direccion: string,\r\n        pais: string,\r\n        ciudad: string,\r\n        created_at: string\r\n      };\r\n  \r\n      let proveedores:proveedoresapi[]=[], unproveedor:proveedoresapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allproveedores\"; //llamado a la API REST y se trae todos los proveedores\r\n            const respuesta = await fetch(url); \r\n            proveedores = await respuesta.json(); \r\n            console.log(proveedores);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaProveedores = ($('#tablaProveedores') as any).DataTable(configdatatables);\r\n\r\n    crearProveedor.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalProveedor')!.textContent = \"Crear proveedor\";\r\n        (document.querySelector('#btnEditarCrearProveedor') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoProveedor.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaProveedores')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarProveedor\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarProveedor\"))editarProveedor(e);\r\n      if(target?.classList.contains(\"eliminarProveedor\")||target.parentElement?.classList.contains(\"eliminarProveedor\"))eliminarProveedor(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar proveedor  //////////////////////\r\n    function editarProveedor(e:Event){\r\n      let idproveedor = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idproveedor = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalProveedor')!.textContent = \"Actualizar proveedor\";\r\n      (document.querySelector('#btnEditarCrearProveedor') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unproveedor = proveedores.find(x => x.id==idproveedor); //me trae a la proveedor seleccionada\r\n      (document.querySelector('#nit')as HTMLInputElement).value = unproveedor?.nit!;\r\n      (document.querySelector('#nombreProveedor')as HTMLInputElement).value = unproveedor?.nombre!;\r\n      \r\n      indiceFila = (tablaProveedores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoProveedor.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar proveedor  //////////////////////\r\n    document.querySelector('#formCrearUpdateProveedor')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearProveedor\";\r\n      if(control)urlApi = \"actualizarProveedor\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaProveedores as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unproveedor?.id?unproveedor?.id:'');\r\n          datos.append('nit', $('#nit').val()as string);\r\n          datos.append('nombre', $('#nombreProveedor').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoProveedor.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de los proveedores ///\r\n                  proveedores = [...proveedores, resultado.proveedor];\r\n                  (tablaProveedores as any).row.add([\r\n                      (tablaProveedores as any).rows().count() + 1,\r\n                      resultado.proveedor.nit,\r\n                      resultado.proveedor.nombre,\r\n                      resultado.proveedor.created_at,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.proveedor.id}\" data-proveedor=\"${resultado.proveedor.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarProveedor\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarProveedor\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de proveedores ///\r\n                  proveedores.forEach(a=>{if(a.id == unproveedor?.id)a = Object.assign(a, resultado.proveedor[0]);});\r\n                  const datosActuales = (tablaProveedores as any).row(indiceFila+=info.start).data();\r\n                  /*NIT*/       datosActuales[1] = resultado.proveedor[0].nit;\r\n                  /*PROVEEDOR*/ datosActuales[2] = resultado.proveedor[0].nombre;\r\n                  (tablaProveedores as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaProveedores as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar proveedor  //////////////////////\r\n    function eliminarProveedor(e:Event){\r\n      let idproveedor = (e.target as HTMLElement).parentElement!.id, info = (tablaProveedores as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idproveedor = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaProveedores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el proveedor?',\r\n          text: \"el proveedor sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idproveedor);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarProveedor\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaProveedores as any).row(indiceFila).remove().draw(); \r\n                        (tablaProveedores as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoProveedor || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoProveedor.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateProveedor') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.productos')){\r\n    const crearProducto = document.querySelector('#crearProducto');\r\n    const btnUploadExcel = document.querySelector('#btnUploadExcel');\r\n    const miDialogoProducto = document.querySelector('#miDialogoProducto') as any;\r\n    const miDialogoImportarExcel = document.querySelector('#miDialogoImportarExcel') as any;\r\n    const btnXCerrarModalproducto = document.querySelector('#btnXCerrarModalproducto') as HTMLButtonElement;\r\n    const inputupImage = document.querySelector('#upImage') as HTMLInputElement;  //input para cargar el archivo imagen\r\n    const btncustomUpImage = document.querySelector('#customUpImage');\r\n    const imginputfile = document.querySelector('#imginputfile') as HTMLImageElement;  //img\r\n    const tipoproducto = document.querySelector('#tipoproducto') as HTMLSelectElement;\r\n    const contentnuevosprecios = document.querySelector('#contentnuevosprecios') as HTMLElement;\r\n    let indiceFila=0, control=0, tablaProductos:HTMLElement;\r\n    \r\n\r\n    type productsapi = {\r\n      id:string,\r\n      idcategoria: string,\r\n      idunidadmedida: string,\r\n      nombre: string,\r\n      foto: string,\r\n      impuesto: string,\r\n      marca: string,\r\n      tipoproducto: string,\r\n      tipoproduccion: string,\r\n      sku: string,\r\n      unidadmedida: string;\r\n      descripcion: string,\r\n      peso: string,\r\n      medidas: string,\r\n      color: string,\r\n      funcion: string,\r\n      uso:string,\r\n      fabricante: string,\r\n      garantia: string,\r\n      stock: string,\r\n      stockminimo: string,\r\n      categoria: string,\r\n      precio_compra: string,\r\n      precio_venta: string,\r\n      percentcomision: string,\r\n      prioridadcomision: string,\r\n      fecha_ingreso: string,\r\n      preciosadicionales: {id:string, idproductoid:string, precio:string, estado:string, created_at:string}[]\r\n      //idservicios:{idempleado:string, idservicio:string}[]\r\n    };\r\n\r\n    let products:productsapi[]=[], unproducto:productsapi;\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/allproducts\"; //llamado a la API REST y se trae todos los productos\r\n          const respuesta = await fetch(url); \r\n          products = await respuesta.json(); \r\n          console.log(products);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n    const divAlert = document.querySelector('.divmsjalerta0') as HTMLElement;\r\n    if(divAlert)borrarMsjAlert(divAlert);\r\n\r\n    ///////// Habilita el select precio de compra, y deshabilita el select de tipo de produccion si es producto simple, si es compuesto lo deshabilita y habilita el select de tipo de produccion\r\n    tipoproducto?.addEventListener('change', (e:Event)=>{\r\n      const targetDom = e.target as HTMLSelectElement;\r\n      const preciocompra = document.querySelector('.preciocompra') as HTMLElement;\r\n      const stock = document.querySelector('.stock') as HTMLElement;\r\n      const habtipoproduccion = document.querySelector('.habtipoproduccion') as HTMLElement;\r\n      if(targetDom.value == '0'){  //  0 = simple\r\n        stock.style.display = 'flex';\r\n        preciocompra.style.display = 'flex';\r\n        habtipoproduccion.style.display = \"none\";\r\n        document.querySelector('#preciocompra')?.setAttribute(\"required\", \"\");\r\n        document.querySelector('#tipoproduccion')?.removeAttribute(\"required\");\r\n      }\r\n      else{\r\n        stock.style.display = 'none';\r\n        preciocompra.style.display = 'none';\r\n        habtipoproduccion.style.display = \"flex\";\r\n        document.querySelector('#preciocompra')?.removeAttribute(\"required\");\r\n        document.querySelector('#tipoproduccion')?.setAttribute(\"required\", \"\");\r\n      }\r\n    });\r\n\r\n\r\n    btnXCerrarModalproducto.addEventListener('click', (e)=>{\r\n        miDialogoProducto.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    //AÑADOR INPUTS PARA PRECIOS PERSONALIZADOS\r\n    const btnAddNewPrice = document.querySelector('#btnAddNewPrice') as HTMLButtonElement;\r\n    if(btnAddNewPrice){\r\n        let i=1;\r\n        btnAddNewPrice.addEventListener('click', (e:Event)=>{\r\n          let clone = (e.target as HTMLButtonElement).previousElementSibling?.cloneNode(true) as HTMLInputElement;  \r\n          //console.log(clone.children[1].name = `niveles[nombrenivel${++i}]`);\r\n          clone.removeAttribute('id');\r\n          clone.required = false;\r\n          clone.value='';\r\n          clone.name = `nuevosprecios[]`;\r\n          clone.classList.add('nuevosprecios');\r\n          contentnuevosprecios.appendChild(clone);\r\n          console.log(clone);\r\n        });\r\n    }\r\n\r\n\r\n    btnUploadExcel?.addEventListener('click', ()=>{\r\n      miDialogoImportarExcel.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaProductos = ($('#tablaProductos') as any).DataTable(configdatatables);\r\n\r\n    //btn para crear producto\r\n    crearProducto?.addEventListener('click', (e):void=>{\r\n      control = 0;\r\n      limpiarformdialog();\r\n      while(contentnuevosprecios.firstChild)contentnuevosprecios.removeChild(contentnuevosprecios.firstChild);\r\n      document.querySelector('#modalProducto')!.textContent = \"Crear producto\";\r\n      (document.querySelector('#btnEditarCrearProducto') as HTMLInputElement).value = \"Crear\";\r\n      (document.querySelector('.stock')as HTMLInputElement).style.display = \"block\";\r\n      (document.querySelector('.preciocompra')as HTMLInputElement).style.display = \"block\";\r\n      miDialogoProducto.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    //evento a la tabla\r\n    document.querySelector('#tablaProductos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarProductos\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarProductos\"))editarProductos(e);\r\n      if(target?.classList.contains(\"bloquearProductos\")||target.parentElement?.classList.contains(\"bloquearProductos\"))bloquearProductos(e);\r\n      if(target?.classList.contains(\"eliminarProductos\")||target.parentElement?.classList.contains(\"eliminarProductos\"))eliminarProductos(e);\r\n    });\r\n\r\n    function editarProductos(e:Event){\r\n      let idproducto = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idproducto = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      control = 1;\r\n      document.querySelector('#modalProducto')!.textContent = \"Actualizar producto\";\r\n      (document.querySelector('#btnEditarCrearProducto') as HTMLInputElement)!.value = \"Actualizar\";\r\n      unproducto = products.find(x=>x.id === idproducto)!; //obtengo el producto.\r\n      $('#categoria').val(unproducto?.idcategoria??'');\r\n      (document.querySelector('#nombre')as HTMLInputElement).value = unproducto?.nombre!;\r\n      $('#tipoproducto').val(unproducto?.tipoproducto??'0');  //0 = simple,  1 = compuesto\r\n      $('#idunidadmedida').val(unproducto?.idunidadmedida??'1');\r\n      (document.querySelector('.stock')as HTMLInputElement).style.display = \"block\";\r\n      (document.querySelector('.preciocompra')as HTMLInputElement).style.display = \"block\";\r\n      (document.querySelector('.habtipoproduccion') as HTMLElement).style.display = \"none\";\r\n      if(unproducto?.tipoproducto == '1'){\r\n        (document.querySelector('.stock')as HTMLInputElement).style.display = \"none\";\r\n        (document.querySelector('.preciocompra')as HTMLInputElement).style.display = \"none\";\r\n        (document.querySelector('.habtipoproduccion') as HTMLElement).style.display = \"block\";\r\n        $('#tipoproduccion').val(unproducto.tipoproduccion);\r\n      }\r\n      (document.querySelector('#stock')as HTMLInputElement).value = unproducto?.stock??'';\r\n      (document.querySelector('#preciocompra')as HTMLInputElement).value = unproducto?.precio_compra??'';\r\n      (document.querySelector('#precioventa')as HTMLInputElement).value = unproducto?.precio_venta??'';\r\n      (document.querySelector('#precioventa')as HTMLInputElement).dataset.idproductoid = unproducto.id;\r\n      (document.querySelector('#percentcomision')as HTMLInputElement).value = unproducto.percentcomision;\r\n      (document.querySelector('#prioridadcomision')as HTMLInputElement).value = unproducto.prioridadcomision;\r\n      imprimirpreciosadicionales(unproducto.preciosadicionales);\r\n      (document.querySelector('#sku')as HTMLInputElement).value = unproducto?.sku??'';\r\n      (document.querySelector('#impuesto')as HTMLInputElement).value = unproducto?.impuesto??'';\r\n      (document.querySelector('#stockminimo')as HTMLInputElement).value = unproducto?.stockminimo??'';\r\n      imginputfile.src = \"/build/img/\"+unproducto?.foto;\r\n      indiceFila = (tablaProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoProducto.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function imprimirpreciosadicionales(preciosadicionales:{id:string, idproductoid:string, precio:string, estado:string, created_at:string}[]){\r\n      while(contentnuevosprecios.firstChild)contentnuevosprecios.removeChild(contentnuevosprecios.firstChild);\r\n      preciosadicionales.forEach(z =>{\r\n        contentnuevosprecios.insertAdjacentHTML('afterbegin', `<input \r\n          data-id=\"${z.id}\"\r\n          class=\"nuevosprecios bg-gray-50 border border-gray-300 text-gray-900 rounded-lg focus:border-indigo-600 block w-full p-2.5 dark:bg-gray-600 dark:border-gray-500 dark:placeholder-gray-400 dark:text-white h-14 text-xl focus:outline-none focus:ring-1\"\r\n          type=\"number\" \r\n          min=\"0\" \r\n          step=\"0.01\"\r\n          placeholder=\"Precio de venta incluido el impuesto\" \r\n          name=\"nuevosprecios[]\" \r\n          value=\"${z.precio}\" \r\n          >`);\r\n      });\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar producto  //////////////////////\r\n    document.querySelector('#formCrearUpdateProducto')?.addEventListener('submit', e=>{\r\n\r\n      let w = document.querySelectorAll<HTMLInputElement>('.nuevosprecios');\r\n      //console.log(Array.from(w).map(input=>({id: input.dataset.id, precio: parseFloat(input.value) })).filter(x=>x.precio>0));\r\n      if(control){\r\n        e.preventDefault();\r\n        var imgFile:(string|File), info = (tablaProductos as any).page.info();\r\n        imgFile=unproducto.foto;\r\n        if(!imginputfile.src.includes(unproducto.foto)){ //se lee la etiqueta img para cambio de imagen\r\n          imgFile = ((e.target as HTMLFormElement).elements.namedItem(\"upImage\") as HTMLInputElement).files?.[0]!; //obtengo el archivo\r\n          if(imgFile){\r\n            if(imgFile.type!==\"image/png\"&&imgFile.type!==\"image/jpeg\"){\r\n              msjAlert('error', 'No es un formato valido para la foto', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n              return;\r\n            }\r\n            if(imgFile.size>31000000){ //si es mayor a 31MB\r\n              msjAlert('error', 'La imagen no debe superar los 500KB', document.querySelector('#divmsjalerta1')!);\r\n              return;\r\n            }\r\n          }\r\n        }\r\n        (async ()=>{\r\n          const datos = new FormData();\r\n          datos.append('id', unproducto!.id);\r\n          datos.append('idcategoria', $('#categoria').val()as string);\r\n          datos.append('nombre', $('#nombre').val()as string);\r\n          datos.append('foto', imgFile); //en el backend no se lee con $_POST, se lee con $_FILES\r\n          datos.append('tipoproducto', $('#tipoproducto').val()as string);  //0=simple o 1=compuesto\r\n          datos.append('idunidadmedida', $('#idunidadmedida').val()as string);\r\n          datos.append('unidadmedida', $('#idunidadmedida option:selected').text());\r\n          datos.append('stock', $('#stock').val()as string);\r\n          datos.append('precio_compra', $('#preciocompra').val()as string);\r\n          datos.append('precio_venta', $('#precioventa').val()as string);\r\n          datos.append('nuevosprecios', JSON.stringify(Array.from(w).map(input=>({id: input.dataset.id, idproductoid: input.dataset.idproductoid, precio: parseFloat(input.value), estado:1 })).filter(x=>x.precio>=0)));\r\n          datos.append('idprecionsadicionales', JSON.stringify(Array.from(w).filter(input => input.dataset.id && parseFloat(input.value) > 0).map( input=>input.dataset.id ))); //solo los ids de la tabla precios_personalizados\r\n          datos.append('sku', $('#sku').val()as string);\r\n          datos.append('tipoproduccion', ($('#tipoproduccion').val()as string)==null?'0':($('#tipoproduccion').val()as string));\r\n          datos.append('impuesto', $('#impuesto').val()as string);\r\n          datos.append('stockminimo', $('#stockminimo').val()as string);\r\n          datos.append('percentcomision', $('#percentcomision').val()as string);\r\n          datos.append('prioridadcomision', $('#prioridadcomision').val() as string);\r\n          try {\r\n              const url = \"/admin/api/actualizarproducto\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json(); \r\n              console.log(resultado); \r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                /// actualizar el arregle del producto ///\r\n                products.forEach(a=>{if(a.id == unproducto.id)a = Object.assign(a, resultado.producto[0]);});\r\n                ///////// cambiar la fila completa, su contenido //////////\r\n                const datosActuales = (tablaProductos as any).row(indiceFila).data();\r\n                /*img*/datosActuales[1] = `<div class=\"text-center\"><img class=\"inline\" style=\"width: 50px;\" src=\"/build/img/${resultado.producto[0].foto}\" alt=\"\"></div>`;\r\n                /*NOMBRE*/datosActuales[2] ='<div class=\"w-80 whitespace-normal\">'+$('#nombre').val()+'</div>';\r\n                /*CATEGORIA*/datosActuales[3] = $('#categoria option:selected').text();\r\n                /*MARCA*/datosActuales[4] = '';\r\n                /*CODIGO*/datosActuales[5] = $('#sku').val();\r\n                /*PRECIOVENTA*/datosActuales[6] = $('#precioventa').val();\r\n                \r\n                (tablaProductos as any).row(indiceFila).data(datosActuales).draw();\r\n                (tablaProductos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n              miDialogoProducto.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n      } //fin if(control)\r\n    });\r\n\r\n\r\n    function bloquearProductos(e:Event){\r\n      let reg = (e.target as HTMLElement).parentElement, info = (tablaProductos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'SPAN')reg = (e.target as HTMLElement).parentElement!.parentElement;\r\n      indiceFila = (tablaProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      (async ()=>{\r\n\r\n          const datos = new FormData();\r\n          datos.append('id', reg!.id);\r\n          try {\r\n              const url = \"/admin/api/cambiarestadoproducto\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                \r\n                const s1 = `<div class=\"acciones-btns my-[0.7rem]\" id=\"${reg!.id}\">\r\n                              ${resultado.tipoproducto[0] == 1?`<a class=\"btn-xs btn-blue\" title=\"Agregar Materia Prima\" href=\"/admin/almacen/componer?id=${reg!.id}\"><i class=\"fa-solid fa-subscript text-[17px] leading-none\"></i></a>`:''}\r\n                              <button class=\"btn-xs btn-lima\" title=\"Más opciones\"><i class=\"fa-solid fa-circle-plus text-[17px] leading-none\"></i></button>\r\n                              <button class=\"btn-xs btn-turquoise editarProductos\" title=\"Actualizar Producto\"><i class=\"fa-solid fa-pen-to-square text-[17px] leading-none\"></i></button>\r\n                              <button class=\"btn-xs ${resultado.estado[0]==1?'btn-light':'btn-orange'} bloquearProductos\" title=\"Bloquear Producto\"><span class=\"material-symbols-outlined text-[18px] leading-none\">hide_source</span></button>\r\n                              <button class=\"btn-xs btn-red eliminarProductos\" title=\"Eliminar Producto\"><i class=\"fa-solid fa-trash-can text-[17px] leading-none\"></i></button>\r\n                            </div>`;\r\n                            \r\n                (tablaProductos as any).cell((tablaProductos as any).row(indiceFila), 7).data(s1).draw(); //se modifica solo la columna con la fila correspondiente, y destruye la que habai antes\r\n                (tablaProductos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              }else{\r\n                  Swal.fire(resultado.error[0], '', 'error')\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n      })();\r\n    }\r\n\r\n    function eliminarProductos(e:Event){\r\n      let idproducto = (e.target as HTMLElement).parentElement!.id, info = (tablaProductos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idproducto = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el prducto?',\r\n          text: \"El prducto sera eliminado definitivamente de todas las SEDES.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idproducto);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarProducto\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaProductos as any).row(indiceFila).remove().draw(); \r\n                        (tablaProductos as any).page(info.page).draw('page');\r\n                        Swal.fire(resultado.exito[0], '', 'success') \r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    //////////////////// Cargar imagen como preview  //////////////////////\r\n    btncustomUpImage?.addEventListener('click', ()=>inputupImage?.click());\r\n    inputupImage?.addEventListener('change', function(){\r\n      const file = this.files?.[0];\r\n      if(file){\r\n        const reader = new FileReader();\r\n        reader.onload = function(){\r\n          const resrult = reader.result;\r\n          if(typeof resrult == \"string\")imginputfile.src = resrult;\r\n        } \r\n        reader.readAsDataURL(file);\r\n      }\r\n    });\r\n\r\n    function limpiarformdialog():void{\r\n      (document.querySelector('#formCrearUpdateProducto') as HTMLFormElement)?.reset();\r\n      imginputfile.src = '';\r\n    }\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoImportarExcel || (event.target as HTMLInputElement).value === 'salir' || (event.target as HTMLInputElement).value === 'Cancelar') {\r\n        miDialogoProducto.close();\r\n        miDialogoImportarExcel.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.subproductos')){\r\n      const crearSubProducto = document.querySelector('#crearSubProducto');\r\n      const miDialogoSubProducto = document.querySelector('#miDialogoSubProducto') as any;\r\n      let indiceFila=0, control=0, tablaSubProductos:HTMLElement;\r\n      \r\n      type subproductsapi = {\r\n        id:string,\r\n        id_unidadmedida: string,\r\n        unidadmedida: string,\r\n        nombre: string,\r\n        sku: string,\r\n        proveedor: string,\r\n        descripcion: string,\r\n        medidas: string,\r\n        color: string,\r\n        uso:string,\r\n        stock: string,\r\n        stockminimo: string,\r\n        precio_compra: string,\r\n        fecha_ingreso: string,\r\n      };\r\n  \r\n      let subproducts:subproductsapi[]=[], unsubproducto:subproductsapi;\r\n  \r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allsubproducts\"; //llamado a la API REST\r\n            const respuesta = await fetch(url); \r\n            subproducts = await respuesta.json(); \r\n            console.log(subproducts);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n  \r\n      //////////////////  TABLA //////////////////////\r\n      tablaSubProductos = ($('#tablaSubProductos') as any).DataTable(configdatatables);\r\n  \r\n      crearSubProducto?.addEventListener('click', (e):void=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalSubProducto')!.textContent = \"Crear sub producto\";\r\n        (document.querySelector('#btnEditarCrearSubProducto') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoSubProducto.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n  \r\n      ///////////// EVENTOS A LA TABLA SUBPRODUCTOS /////////////\r\n      document.querySelector('#tablaSubProductos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n        const target = e.target as HTMLElement;\r\n        if(target?.classList.contains(\"editarSubProductos\")||target.parentElement?.classList.contains(\"editarSubProductos\"))editarSubProductos(e);\r\n        if(target?.classList.contains(\"eliminarSubProductos\")||target.parentElement?.classList.contains(\"eliminarSubProductos\"))eliminarSubProductos(e);\r\n      });\r\n  \r\n      function editarSubProductos(e:Event){\r\n        let idsubproducto = (e.target as HTMLElement).parentElement?.id!;\r\n        if((e.target as HTMLElement)?.tagName === 'I')idsubproducto = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n        control = 1;\r\n        document.querySelector('#modalSubProducto')!.textContent = \"Actualizar producto\";\r\n        (document.querySelector('#btnEditarCrearSubProducto') as HTMLInputElement)!.value = \"Actualizar\";\r\n        unsubproducto = subproducts.find(x=>x.id === idsubproducto)!;\r\n        $('#unidadmedida').val(unsubproducto?.id_unidadmedida??'');\r\n        (document.querySelector('#nombre')as HTMLInputElement).value = unsubproducto?.nombre!;\r\n        (document.querySelector('#sku')as HTMLInputElement).value = unsubproducto?.sku!;\r\n        (document.querySelector('#preciocompra')as HTMLInputElement).value = unsubproducto?.precio_compra??'';\r\n        (document.querySelector('#stockminimo')as HTMLInputElement).value = unsubproducto?.stockminimo??'';\r\n        \r\n        indiceFila = (tablaSubProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n        miDialogoSubProducto.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n  \r\n      ////////////////////  Actualizar/Editar producto  //////////////////////\r\n      document.querySelector('#formCrearUpdateSubProducto')?.addEventListener('submit', e=>{\r\n        if(control){\r\n          e.preventDefault();\r\n          var info = (tablaSubProductos as any).page.info();\r\n          \r\n          (async ()=>{ \r\n            const datos = new FormData();\r\n            datos.append('id', unsubproducto!.id);\r\n            datos.append('id_unidadmedida', $('#unidadmedida').val()as string);\r\n            datos.append('unidadmedida', $('#unidadmedida').find('option:selected').text());\r\n            datos.append('nombre', $('#nombre').val()as string);\r\n            datos.append('sku', $('#sku').val()as string);\r\n            datos.append('precio_compra', $('#preciocompra').val()as string);\r\n             datos.append('stockminimo', $('#stockminimo').val()as string);\r\n            try {\r\n                const url = \"/admin/api/actualizarsubproducto\";\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json(); \r\n                console.log(resultado); \r\n                if(resultado.exito !== undefined){\r\n                  msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  /// actualizar el arregle del subproducto ///\r\n                  subproducts.forEach(a=>{if(a.id == unsubproducto.id)a = Object.assign(a, resultado.subproducto[0]);});\r\n                  ///////// cambiar la fila completa, su contenido //////////\r\n                  const datosActuales = (tablaSubProductos as any).row(indiceFila+=info.start).data();\r\n                  /*NOMBRE*/datosActuales[1] ='<div class=\"w-80 whitespace-normal\">'+$('#nombre').val()+'</div>';\r\n                  /*proveedor*/datosActuales[2] = '';\r\n                  /*SKU*/datosActuales[3] = $('#sku').val();\r\n                  /*UNIDADMEDIDA*/datosActuales[4] = $('#unidadmedida option:selected').text();\r\n                  /*PRECIOCOMPRA*/datosActuales[5] = '$'+Number($('#preciocompra').val())?.toLocaleString();\r\n                  (tablaSubProductos as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaSubProductos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }else{\r\n                  msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n                document.addEventListener(\"click\", cerrarDialogoExterno);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n          })();//cierre de async()\r\n        } //fin if(control)\r\n      });\r\n  \r\n      function eliminarSubProductos(e:Event){\r\n        let idsubproducto = (e.target as HTMLElement).parentElement!.id, info = (tablaSubProductos as any).page.info();\r\n        if((e.target as HTMLElement).tagName === 'I')idsubproducto = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n        indiceFila = (tablaSubProductos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n        Swal.fire({\r\n            customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n            icon: 'question',\r\n            title: 'Desea eliminar el sub prducto?',\r\n            text: \"El sub prducto sera eliminado definitivamente.\",\r\n            showCancelButton: true,\r\n            confirmButtonText: 'Si',\r\n            cancelButtonText: 'No',\r\n        }).then((result:any) => {\r\n            if (result.isConfirmed) {\r\n                (async ()=>{ \r\n                    const datos = new FormData();\r\n                    datos.append('id', idsubproducto);\r\n                    try {\r\n                        const url = \"/admin/api/eliminarSubProducto\";\r\n                        const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                        const resultado = await respuesta.json();  \r\n                        if(resultado.exito !== undefined){\r\n                          (tablaSubProductos as any).row(indiceFila).remove().draw(); \r\n                          (tablaSubProductos as any).page(info.page).draw('page');\r\n                          Swal.fire(resultado.exito[0], '', 'success') \r\n                        }else{\r\n                            Swal.fire(resultado.error[0], '', 'error')\r\n                        }\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();//cierre de async()\r\n            }\r\n        });\r\n      }\r\n\r\n  \r\n      function limpiarformdialog(){\r\n        (document.querySelector('#formCrearUpdateSubProducto') as HTMLFormElement)?.reset();\r\n        (document.querySelector('#formCrearUpdateSubProducto') as HTMLFormElement).action = \"/admin/almacen/crear_subproducto\";\r\n      }\r\n      function cerrarDialogoExterno(event:Event) {\r\n        if (event.target === miDialogoSubProducto || (event.target as HTMLInputElement).value === 'salir' || (event.target as HTMLInputElement).value === 'Actualizar') {\r\n            miDialogoSubProducto.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n    }\r\n  \r\n  })();","(()=>{\r\n\r\n    if(document.querySelector('.unidadesmedida')){\r\n        const btnCrearUnidadMedida = document.querySelector('#btnCrearUnidadMedida');\r\n        const miDialogoUnidadMedida = document.querySelector('#miDialogoUnidadMedida') as any;\r\n        let tablaUnidadesMedida:HTMLElement;\r\n\r\n        tablaUnidadesMedida = ($('#tablaUnidadesMedida') as any).DataTable(configdatatables);\r\n\r\n        ///////////////BTN PARA CREAR UNIDAD DE MEDIDA////////////////\r\n        btnCrearUnidadMedida?.addEventListener('click', (e):void=>{\r\n            limpiarformdialog();\r\n            document.querySelector('#modalUnidadMedida')!.textContent = \"Crear unidad de medida\";\r\n            (document.querySelector('#btnEditarCrearUnidadMedida') as HTMLInputElement).value = \"Crear\";\r\n            miDialogoUnidadMedida.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n        document.querySelector('#tablaUnidadesMedida')?.addEventListener('click', (e:Event)=>{\r\n            var btn = e.target as HTMLElement;\r\n            if(btn?.classList.contains('editarUnidadMedida')||btn.parentElement?.classList.contains(\"editarUnidadMedida\"))editarUnidadMedida(e);\r\n            if(btn?.classList.contains('eliminarUnidadMedida')||btn.parentElement?.classList.contains(\"eliminarUnidadMedida\"))eliminarUnidadMedida(e);   \r\n        });\r\n\r\n\r\n        ///////////////EDITAR UNIDAD DE MEDIDA////////////////\r\n        function editarUnidadMedida(e:Event){\r\n            let idunidadmedida = (e.target as HTMLElement).parentElement?.id!;\r\n            if((e.target as HTMLElement)?.tagName === 'I')idunidadmedida = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n            (document.querySelector('#formCrearUpdateUnidad') as HTMLFormElement).action = \"/admin/almacen/editarunidademedida\";\r\n            document.querySelector('#modalUnidadMedida')!.textContent = \"Actualizar unidad de medida\";\r\n            (document.querySelector('#btnEditarCrearUnidadMedida') as HTMLInputElement)!.value = \"Actualizar\";\r\n            (document.querySelector('#idunidadmedida') as HTMLInputElement).value = idunidadmedida;\r\n            (document.querySelector('#unidad') as HTMLInputElement).value = ((e.target as HTMLElement).closest('.acciones-btns') as HTMLElement)?.dataset.unidadmedida!; \r\n            miDialogoUnidadMedida.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n\r\n        function eliminarUnidadMedida(e:Event):void{\r\n            let form = (e.target as HTMLElement).parentElement!;\r\n            if((e.target as HTMLElement).tagName === 'I')form = form.parentElement!;\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar la unidad de medida?',\r\n                text: \"La unidad de medida sera eliminado definitivamente.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed)(form as HTMLFormElement).submit();\r\n            });\r\n        }\r\n\r\n        /*document.querySelector('.eliminarUnidadMedida')?.addEventListener('submit', (e:Event)=>{\r\n            console.log(55);\r\n            e.preventDefault();\r\n        });*/\r\n\r\n        /*function eliminarUnidadMedida(e:Event):void{\r\n            let idunidadmedida = (e.target as HTMLElement).parentElement?.id!;\r\n            if((e.target as HTMLElement)?.tagName === 'I')idunidadmedida = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n            console.log(idunidadmedida);\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar la unidad de medida?',\r\n                text: \"La unidad de medida sera eliminado definitivamente.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {*/\r\n                    /*(async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('id', idproducto);\r\n                        try {\r\n                            const url = \"/admin/api/eliminarProducto\";\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                              (tablaProductos as any).row(indiceFila+info.start).remove().draw(); \r\n                              (tablaProductos as any).page(info.page).draw('page');\r\n                              Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();*///cierre de async()\r\n                /*}\r\n            });\r\n        }*/\r\n        \r\n        function limpiarformdialog(){\r\n            (document.querySelector('#formCrearUpdateUnidad') as HTMLFormElement)?.reset();\r\n            (document.querySelector('#formCrearUpdateUnidad') as HTMLFormElement).action = \"/admin/almacen/crear_unidadmedida\";\r\n        }\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n        if (f === miDialogoUnidadMedida || (f as HTMLInputElement).value === 'Salir' || (f as HTMLInputElement).value === 'Actualizar') {\r\n            miDialogoUnidadMedida.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n        }\r\n    }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.clientes')){\r\n      const btncrearCliente = document.querySelector('#crearCliente');\r\n      const btncrearDireccion = document.querySelector('#crearDireccion');\r\n      const miDialogoCliente = document.querySelector('#miDialogoCliente') as any;\r\n      const miDialogoCrearDireccion = document.querySelector('#miDialogoCrearDireccion') as any;\r\n      const miDialogoUpDireccion = document.querySelector('#miDialogoUpDireccion') as any;\r\n      const selectdirecciones = document.querySelector('#selectdirecciones') as HTMLSelectElement;\r\n      const btnCerrarUpDireccion = document.querySelector('#btnCerrarUpDireccion') as HTMLButtonElement;\r\n      let select2Init = false, indiceFila=0, control=0, tablaClientes:HTMLElement;\r\n      \r\n      type direccionesapi = {\r\n        id:string,\r\n        idcliente:string,\r\n        idtarifa:string,\r\n        tarifa:{id:string, idcliente:string, nombre:string, valor:string},\r\n        direccion:string,\r\n        ciudad:string,\r\n        departamento:string\r\n      };\r\n      let direcciones:direccionesapi[]=[];\r\n  \r\n      type clientesapi = {\r\n        id:string,\r\n        nombre: string,\r\n        apellido: string,\r\n        tipodocumento: string,\r\n        identificacion: string,\r\n        telefono: string,\r\n        email: string,\r\n        fecha_nacimiento: string,\r\n        total_compras: string,\r\n        ultima_compra: string;\r\n        data1: string,\r\n        //idservicios:{idempleado:string, idservicio:string}[]\r\n      };\r\n  \r\n      let clientes:clientesapi[]=[], uncliente:clientesapi;\r\n  \r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allclientes\"; //llamado a la API REST y se trae todos los productos\r\n            const respuesta = await fetch(url); \r\n            clientes = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n  \r\n      \r\n  \r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      //////////////////  TABLA //////////////////////\r\n      tablaClientes = ($('#tablaClientes') as any).DataTable(configdatatables);\r\n  \r\n      btncrearCliente?.addEventListener('click', (e):void=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalCliente')!.textContent = \"Crear cliente\";\r\n        (document.querySelector('#btnEditarCrearCliente') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoCliente.showModal();\r\n      });\r\n\r\n\r\n      btncrearDireccion?.addEventListener('click', (e):void=>{\r\n        control = 0;\r\n        document.querySelector('#modalDireccion')!.textContent = \"Crear direccion\";\r\n        (document.querySelector('#btnEditarCrearDireccion') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoCrearDireccion.showModal();\r\n        activarSelect2();\r\n      });\r\n\r\n\r\n      function activarSelect2(){\r\n        if(select2Init)return;\r\n        ($('#selectcliente') as any).select2({\r\n          dropdownParent: $('#miDialogoCrearDireccion'),\r\n          placeholder: \"Seleccionar el cliente\",\r\n          maximumSelectionLength: 1\r\n        });\r\n        select2Init = true;\r\n      }\r\n  \r\n      document.querySelector('#tablaClientes')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n        const target = e.target as HTMLElement;\r\n        if((e.target as HTMLElement)?.classList.contains(\"editarClientes\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarClientes\"))editarClientes(e);\r\n        if(target?.classList.contains(\"eliminarClientes\")||target.parentElement?.classList.contains(\"eliminarClientes\"))eliminarClientes(e);\r\n        if(target?.classList.contains(\"editarEliminarDireccion\")||target.parentElement?.classList.contains(\"editarEliminarDireccion\"))upRemoveDir(e);\r\n      });\r\n  \r\n      function editarClientes(e:Event){\r\n        let idcliente = (e.target as HTMLElement).parentElement?.id!;\r\n        if((e.target as HTMLElement)?.tagName === 'I')idcliente = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n        control = 1;\r\n        document.querySelector('#modalCliente')!.textContent = \"Actualizar cliente\";\r\n        (document.querySelector('#btnEditarCrearCliente') as HTMLInputElement)!.value = \"Actualizar\";\r\n        uncliente = clientes.find(x=>x.id === idcliente)!;\r\n        (document.querySelector('#nombre')as HTMLInputElement).value = uncliente?.nombre!;\r\n        (document.querySelector('#apellido')as HTMLInputElement).value = uncliente?.apellido!;\r\n        $('#tipodocumento').val(uncliente?.tipodocumento??'');\r\n        (document.querySelector('#identificacion')as HTMLInputElement).value = uncliente?.identificacion??'';\r\n        (document.querySelector('#telefono')as HTMLInputElement).value = uncliente?.telefono??'';\r\n        (document.querySelector('#email')as HTMLInputElement).value = uncliente?.email??'';\r\n        (document.querySelector('#fecha_nacimiento')as HTMLInputElement).value = uncliente?.fecha_nacimiento??'';\r\n        \r\n        miDialogoCliente.showModal();\r\n      }\r\n  \r\n      ////////////////////  Actualizar/Editar clientes  //////////////////////\r\n      document.querySelector('#formCrearUpdateCliente')?.addEventListener('submit', e=>{\r\n        if(control){\r\n          e.preventDefault();\r\n          var info = (tablaClientes as any).page.info();\r\n          \r\n          (async ()=>{ \r\n            const datos = new FormData();\r\n            datos.append('idcliente', uncliente!.id);\r\n            datos.append('nombre', $('#nombre').val()as string);\r\n            datos.append('apellido', $('#apellido').val()as string);\r\n            datos.append('tipodocumento', $('#tipodocumento').val()as string);\r\n            datos.append('identificacion', $('#identificacion').val()as string);\r\n            datos.append('telefono', $('#telefono').val()as string);\r\n            datos.append('email', $('#email').val()as string);\r\n            datos.append('fecha_nacimiento', $('#fecha_nacimiento').val()as string);\r\n            try {\r\n                const url = \"/admin/api/actualizarCliente\";\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json(); \r\n                if(resultado.exito !== undefined){\r\n                  msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  /// actualizar el arregle de clientes ///\r\n                  clientes.forEach(a=>{if(a.id == uncliente.id)a = Object.assign(a, resultado.cliente[0]);});\r\n                  ///////// cambiar la fila completa, su contenido //////////\r\n                  const datosActuales = (tablaClientes as any).row(indiceFila).data();\r\n                  /*NOMBRE*/datosActuales[1] = $('#nombre').val();\r\n                  /*APELLIDO*/datosActuales[2] = $('#apellido').val();\r\n                  /*TELEFONO*/datosActuales[3] = $('#telefono').val();\r\n                  /*EMAIL*/datosActuales[4] = $('#email').val();\r\n                  \r\n                  (tablaClientes as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaClientes as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }else{\r\n                  msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n                miDialogoCliente.close();\r\n                \r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n          })();//cierre de async()\r\n        } //fin if(control)\r\n      });\r\n  \r\n\r\n      function upRemoveDir(e:Event){ //actualizar o eliminar direccion\r\n        let idcliente = (e.target as HTMLElement).parentElement!.id, info = (tablaClientes as any).page.info();\r\n        if((e.target as HTMLElement).tagName === 'I')idcliente = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n        (async ()=>{\r\n          try {\r\n            const url = \"/admin/api/clientes/direccionesXcliente?id=\"+idcliente; //llamado a la API REST y se trae las direcciones segun cliente elegido\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json();\r\n            direcciones = resultado;\r\n            addDireccionSelect(resultado.direcciones);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();\r\n        miDialogoUpDireccion.showModal();\r\n      }\r\n\r\n\r\n       ////// añade direccion al select de direcciones al miDialogoUpDireccion, cuando se desea actualizar o eliminar la direccion de un cliente\r\n      function addDireccionSelect<T extends {id:string, idcliente:string, idtarifa:string, tarifa:{id:string, idcliente:string, nombre:string, valor:string}, direccion:string, ciudad:string, departamento:string}>(addrs: T[]):void{\r\n        while(selectdirecciones?.firstChild)selectdirecciones.removeChild(selectdirecciones?.firstChild);\r\n        addrs.forEach(dir =>{\r\n          const option = document.createElement('option');\r\n          option.textContent = dir.direccion;\r\n          option.value = dir.id;\r\n          option.dataset.idcliente = dir.idcliente;\r\n          option.dataset.idtarifa = dir.idtarifa;\r\n          selectdirecciones.appendChild(option);\r\n        });\r\n        $('#uptarifa').val(addrs[0].idtarifa);\r\n        (document.querySelector('#updepartamento') as HTMLInputElement).value = addrs[0].departamento;\r\n        (document.querySelector('#upciudad') as HTMLInputElement).value = addrs[0].ciudad;\r\n        (document.querySelector('#updireccion') as HTMLInputElement).value = addrs[0].direccion;\r\n      }\r\n\r\n\r\n      ///////// Evento al select de direcciones en el modal actualizar direciones de cada cliente ////////////\r\n      selectdirecciones?.addEventListener('change', (e)=>{\r\n        const select = (e.target as HTMLSelectElement);\r\n        const idDir:string = select.options[select.selectedIndex].value;\r\n        const objDireccion = direcciones.find(x=>x.id == idDir)!;\r\n        $('#uptarifa').val(objDireccion?.idtarifa??1);\r\n        (document.querySelector('#updepartamento') as HTMLInputElement).value = objDireccion.departamento;\r\n        (document.querySelector('#upciudad') as HTMLInputElement).value = objDireccion.ciudad;\r\n        (document.querySelector('#updireccion') as HTMLInputElement).value = objDireccion.direccion;\r\n      });\r\n\r\n\r\n      document.querySelector('#formUpDireccion')?.addEventListener('submit', e=>{\r\n          e.preventDefault();\r\n          // verificar si se oprimio el btn eliminar o actualizar del modal actualizar direccion\r\n        });\r\n        \r\n\r\n      function eliminarClientes(e:Event){\r\n        let idcliente = (e.target as HTMLElement).parentElement!.id, info = (tablaClientes as any).page.info();\r\n        if((e.target as HTMLElement).tagName === 'I')idcliente = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n        indiceFila = (tablaClientes as any).row((e.target as HTMLElement).closest('tr')).index();\r\n        Swal.fire({\r\n            customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n            icon: 'question',\r\n            title: 'Desea eliminar el cliente?',\r\n            text: \"El cliente sera eliminado por completo.\",\r\n            showCancelButton: true,\r\n            confirmButtonText: 'Si',\r\n            cancelButtonText: 'No',\r\n        }).then((result:any) => {\r\n            if (result.isConfirmed) {\r\n                (async ()=>{ \r\n                    const datos = new FormData();\r\n                    datos.append('id', idcliente);\r\n                    try {\r\n                        const url = \"/admin/api/eliminarCliente\";\r\n                        const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                        const resultado = await respuesta.json();  \r\n                        if(resultado.exito !== undefined){\r\n                          (tablaClientes as any).row(indiceFila+info.start).remove().draw(); \r\n                          (tablaClientes as any).page(info.page).draw('page');\r\n                          Swal.fire(resultado.exito[0], '', 'success') \r\n                        }else{\r\n                            Swal.fire(resultado.error[0], '', 'error')\r\n                        }\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();//cierre de async()\r\n            }\r\n        });\r\n      }\r\n\r\n\r\n      btnCerrarUpDireccion.addEventListener('click', ()=>miDialogoUpDireccion.close());\r\n  \r\n  \r\n      function limpiarformdialog(){\r\n        (document.querySelector('#formCrearUpdateCliente') as HTMLFormElement)?.reset();\r\n      }\r\n      function cerrarDialogoExterno(event:Event) {\r\n        if (event.target === miDialogoCliente || event.target === miDialogoCrearDireccion || event.target === miDialogoUpDireccion || (event.target as HTMLInputElement).value === 'salir') {\r\n          miDialogoCliente.close();\r\n          miDialogoCrearDireccion.close();\r\n          miDialogoUpDireccion.close();\r\n          \r\n        }\r\n      }\r\n    }\r\n  \r\n  })();","\r\n(():void=>{\r\n\r\n    if(document.querySelector('.detallecliente')){\r\n\r\n        const btnTotalCuotas = document.querySelector('#btnTotalCuotas') as HTMLButtonElement;\r\n        const btnPagoDeudaTotal = document.querySelector('#btnPagoDeudaTotal') as HTMLButtonElement;\r\n        const miDialogoTotalCuotas = document.querySelector('#miDialogoTotalCuotas') as HTMLDialogElement;\r\n        const miDialogoPagoTotal = document.querySelector('#miDialogoPagoTotal') as HTMLDialogElement;\r\n        const miDialogoAbono = document.querySelector('#miDialogoAbono') as HTMLDialogElement;\r\n        const tablaCuotas = document.querySelector('#tablaCuotas tbody') as HTMLBodyElement;\r\n\r\n        let idcredito:string|undefined, montocuota:string = '', saldopendienteCredito:string='0', indiceFila:HTMLDivElement;\r\n        let printerBT:string = getParam.impresora_principal_de_CAJA_para_Android_por_BT.valor_final;\r\n\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n\r\n        function clientesGraficas($url:string, $dato:string){\r\n            if(id!=null&&!Number.isNaN(id))\r\n                (async ()=>{\r\n                    try {\r\n                        const url = $url+id;\r\n                        const respuesta = await fetch(url); \r\n                        const resultado = await respuesta.json();\r\n                        if($dato == 'comprasXMes')comprasXMesXCliente(resultado);\r\n                        if($dato == 'ventasXCategorias')ventasXCategoriasXCliente(resultado);\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();\r\n        }\r\n\r\n        clientesGraficas('/admin/api/clientes/comprasXMesXCliente?id=', 'comprasXMes');\r\n        clientesGraficas('/admin/api/clientes/ventasXCategoriasXCliente?id=', 'ventasXCategorias');\r\n        \r\n\r\n        function comprasXMesXCliente(resultado:{periodo:string, ventas_totales:string}[]){\r\n            // Compras por mes\r\n            const ctxMes = (document.getElementById(\"chartComprasMes\") as HTMLCanvasElement).getContext('2d');\r\n            if (ctxMes) {\r\n                new Chart(ctxMes, {\r\n                type: \"line\",\r\n                data: {\r\n                    labels: resultado.map(x=>x.periodo),\r\n                    datasets: [{\r\n                    label: \"Compras\",\r\n                    data: resultado.map(x=>x.ventas_totales),\r\n                    borderColor: \"rgba(99, 102, 241, 1)\",\r\n                    backgroundColor: \"rgba(99, 102, 241, 0.2)\",\r\n                    tension: 0.4,\r\n                    fill: true,\r\n                    }]\r\n                },\r\n                options: { responsive: true }\r\n                });\r\n            }\r\n        }\r\n\r\n        function ventasXCategoriasXCliente(resultado:{categoria:string, idcategoria:string, unidades_vendidas:string, venta_total_categoria:string}[]){\r\n            // Categorías más compradas\r\n            const ctxCat = (document.getElementById(\"chartCategorias\") as HTMLCanvasElement).getContext('2d');\r\n            if (ctxCat) {\r\n                new Chart(ctxCat, {\r\n                type: \"doughnut\",\r\n                data: {\r\n                    labels: resultado.map(x=>x.categoria),\r\n                    datasets: [{\r\n                        data: resultado.map(x=>x.unidades_vendidas),\r\n                        backgroundColor: [\r\n                            \"rgba(99, 102, 241, 0.8)\",   // Indigo\r\n                            \"rgba(16, 185, 129, 0.8)\",   // Emerald\r\n                            \"rgba(249, 115, 22, 0.8)\",   // Orange\r\n                            \"rgba(107, 114, 128, 0.8)\"   // Gray\r\n                        ],\r\n                    }]\r\n                },\r\n                options: { responsive: true }\r\n                });\r\n            }\r\n        }\r\n\r\n\r\n        btnTotalCuotas.addEventListener('click', ()=>{\r\n            miDialogoTotalCuotas.showModal();\r\n            imprimirTotalCuotasXcliente();\r\n        });\r\n\r\n\r\n        btnPagoDeudaTotal.addEventListener('click', ()=>{\r\n            if(!Number.isNaN(deudatotalCiente) && Number(deudatotalCiente)>0)\r\n            miDialogoPagoTotal.showModal();\r\n        });\r\n\r\n\r\n        document.querySelector('#formPagoTotalDeuda')?.addEventListener('submit', async (e:Event)=>{\r\n            e.preventDefault();\r\n            if(id!=null&&!Number.isNaN(id)){\r\n                const datos = new FormData();\r\n                datos.append('idcliente', id);\r\n                datos.append('idcaja', $('#PagoTotal_caja').val() as string);\r\n                datos.append('idmediodepago', $('#PagoTotal_mediopago').val() as string);\r\n                datos.append('valorDeudaTotal', deudatotalCiente);\r\n                try {\r\n                    const url = \"/admin/api/creditos/pagarDeudaTotal\";  //api en creditoscontrolador\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                        document.querySelector('#totalDeudaText')!.textContent = '$0';\r\n                        document.querySelectorAll<HTMLTableCellElement>('.pendiente').forEach(td=>{\r\n                            const tr = td.parentElement;\r\n                            if(tr){\r\n                                tr.children[5].textContent = '$0';\r\n                                tr?.children[5].classList.remove('text-red-500');\r\n                                tr.children[6].textContent = 'Finalizado';\r\n                            }\r\n                        });\r\n                        miDialogoPagoTotal.close();\r\n                        Swal.fire(resultado.exito[0], '', 'success');\r\n                    }else{\r\n                        Swal.fire(resultado.error[0], '', 'error');\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            }\r\n        });\r\n\r\n\r\n\r\n        async function imprimirTotalCuotasXcliente(){\r\n            if(id!=null&&!Number.isNaN(id)){\r\n                try {\r\n                    const url = `/admin/api/totalCuotasXcliente?id=${id}`; //llamado a la API REST ventascontrolador, detalle producto compuesto\r\n                    const respuesta = await fetch(url); \r\n                    const resultado:{capital:string, fechafin:string, fechainicio:string, fechapagado:string, idestadocreditos:string, interestotal:string, num_orden:string, numerocuota:string, valorpagado:string}[] = await respuesta.json();\r\n\r\n                    while(tablaCuotas.firstChild)tablaCuotas.removeChild(tablaCuotas.firstChild);\r\n                    resultado.forEach(c=>{\r\n                        const tr = document.createElement('tr') as HTMLTableRowElement;\r\n                        tr.innerHTML = `<td class=\"text-center\">${c.num_orden}</td>\r\n                                        <td class=\"text-center\">$ ${(Number(c.capital)+Number(c.interestotal)).toLocaleString()}</td>\r\n                                        <td class=\"text-center\">${c.numerocuota}</td>\r\n                                        <td class=\"text-center\">$ ${Number(c.valorpagado).toLocaleString()}</td>\r\n                                        <td class=\"text-center\">${c.fechapagado}</td>\r\n                                        <td class=\"text-center\">${c.idestadocreditos=='1'?'Finalizado':c.idestadocreditos=='2'?'Abierto':'Anulado'}</td>`;\r\n                        tablaCuotas.prepend(tr);\r\n                    });\r\n\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            }\r\n        }\r\n\r\n\r\n        ////////////// Evento a la tabla cuotas ///////////////\r\n        document.querySelector('#tablaCreditos')?.addEventListener(\"click\", (e:Event)=>{ //evento click sobre toda la tabla\r\n            const target = e.target as HTMLButtonElement;\r\n            if(target?.classList.contains(\"abonarCredito\") || target?.parentElement?.classList.contains(\"abonarCredito\") )abonarCredito(target);\r\n            if(target?.classList.contains(\"anularCredito\") || target?.parentElement?.classList.contains(\"anularCredito\"))anularCredito(target);\r\n        });\r\n\r\n\r\n        function abonarCredito(target: HTMLButtonElement){\r\n            const element = target.closest('div');\r\n            if(!element)return;\r\n            idcredito = element?.id;\r\n            montocuota = element?.dataset.montocuota||'0';\r\n            if(idcredito == undefined || Number.isNaN(idcredito))return\r\n            saldopendienteCredito = element?.dataset.saldopendiente!;\r\n            if(Number.isNaN(saldopendienteCredito) || Number(saldopendienteCredito)<=0)return;\r\n            miDialogoAbono.showModal();\r\n            document.querySelector('#numCredito')!.textContent = \"Credito N°: \"+idcredito;\r\n            document.querySelector('#saldopendiente')!.textContent = \"Saldo pendiente: \"+saldopendienteCredito;\r\n            indiceFila = (element.parentElement?.parentElement) as HTMLTableRowElement;\r\n        }\r\n\r\n        document.querySelector('#formrealizarAbono')?.addEventListener('submit', async (e:Event)=>{\r\n            e.preventDefault();\r\n            const imprimirAbono = document.querySelector('#imprimirAbono') as HTMLInputElement;\r\n            const valorabono = (document.querySelector('#abono') as HTMLInputElement).value;\r\n            const datos = new FormData();\r\n            datos.append('id_credito', idcredito||'');\r\n            datos.append('cajaid', $('#abono_caja').val() as string);\r\n            datos.append('mediopagoid', $('#abono_mediopago').val() as string);\r\n            datos.append('valorpagado', valorabono);\r\n            datos.append('montocuota', montocuota);\r\n            try {\r\n                const url = \"/admin/api/creditos/registrarAbonoFromCli\";  //api en creditoscontrolador\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json();\r\n                if(resultado.exito !== undefined){\r\n                    deudatotalCiente = (Number(deudatotalCiente)-Number(valorabono))+'';\r\n                    saldopendienteCredito = (Number(saldopendienteCredito)-Number(valorabono))+'';\r\n                    document.querySelector('#totalDeudaText')!.textContent = '$'+deudatotalCiente;\r\n                    indiceFila.children[5].textContent = '$'+saldopendienteCredito;\r\n                    indiceFila.children[6].textContent = (Number(saldopendienteCredito))== 0 ?'Finalizado':'Abierto';\r\n                    (indiceFila.children[7].children[0] as HTMLDivElement).dataset.saldopendiente = saldopendienteCredito;\r\n                    miDialogoAbono.close();\r\n                    Swal.fire(resultado.exito[0], '', 'success');\r\n                    if(resultado.idcuota && imprimirAbono.checked)printPOSComprobanteAbono(resultado.idcuota);\r\n                }else{\r\n                    miDialogoAbono.close();\r\n                    Swal.fire(resultado.error[0], '', 'error');\r\n                }\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        });\r\n\r\n\r\n        async function printPOSComprobanteAbono(idabono:string|undefined){\r\n            if(idabono==undefined)return;\r\n            try{\r\n                const url = \"/admin/api/creditos/getAbono?id=\"+idabono; //llamado a la API REST - creditocontrolador \r\n                const respuesta = await fetch(url); \r\n                const resultado = await respuesta.json();\r\n                const isAndroid = /Android/i.test(navigator.userAgent);\r\n                if(printerBT === '1'){\r\n                const builder = new ticketAbonoBuilder(resultado);\r\n                const ticket = await builder.generate(true); //true para version buffer bytes\r\n                const base64 = bytesToBase64(ticket);\r\n                if(isAndroid)window.location.href = `rawbt:base64,${base64}`;\r\n                //descargar .bin a equipo\r\n                /*const blob = new Blob([ticket], { type: 'application/octet-stream' });\r\n                const url = URL.createObjectURL(blob);\r\n                const a = document.createElement('a');\r\n                a.href = url;\r\n                a.download = 'ticket.bin';\r\n                a.click();\r\n                URL.revokeObjectURL(url);*/\r\n                }\r\n            }catch(error){\r\n                console.log(error);\r\n            }\r\n\r\n            if(!isNaN(Number(idabono)))\r\n                window.open(\"/admin/printPDFAbonoCredito?id=\" + idabono, \"_blank\"); //controlador printcontrolador\r\n        }\r\n\r\n\r\n        function anularCredito(target: HTMLButtonElement){\r\n            const idabono = target.parentElement?.id;\r\n            const fila = target.closest('tr');\r\n            if(idabono==undefined)return;\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea anular el credito',\r\n                text: \"El credito, seran anulado definitivamente.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    /*(async ()=>{ \r\n                        try {\r\n                            const url = \"/admin/api/creditos/anularAbono?id=\"+idabono;\r\n                            const respuesta = await fetch(url); \r\n                            const resultado = await respuesta.json();\r\n                            if(resultado.exito !== undefined){\r\n                                fila?.remove();\r\n                                Swal.fire(resultado.exito[0], '', 'success');\r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error');\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()*/\r\n                }\r\n            });\r\n        }\r\n\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n            if (f=== miDialogoTotalCuotas || f === miDialogoPagoTotal || f === miDialogoAbono || (f as HTMLElement).id === 'btnCerrarTotalCuotas' || (f as HTMLElement).id === 'btnCerrarPagoTotal' || (f as HTMLElement).id === 'btnXCerrarModalAbono' || (f as HTMLButtonElement).value == 'Salir'){\r\n                miDialogoTotalCuotas.close();\r\n                miDialogoPagoTotal.close();\r\n                miDialogoAbono.close();\r\n            }\r\n        }\r\n\r\n    }\r\n\r\n})();","(()=>{\r\n    \r\n    if(document.querySelector('.preciosXCliente')){\r\n        const listaProductos = document.querySelector('.listaProductos');\r\n        //const subproducto:HTMLSelectElement = document.querySelector('#subproducto')!;\r\n        let precioPersonalizado = document.querySelector('#precioPersonalizado') as HTMLInputElement; //input cantidad\r\n\r\n        \r\n\r\n        \r\n        ($('#productos') as any).select2({\r\n            width: '100%',\r\n            maximumSelectionLength: 1,\r\n        });\r\n\r\n\r\n\r\n        ///////////////// EVENTO AL FORMULARIO ASOCIAR PRODUCTO //////////////////\r\n        document.querySelector('#formAddProducto')?.addEventListener('submit', (e)=>{\r\n            e.preventDefault();\r\n            const producto = $('#productos').find('option:selected');\r\n            let valor:number = Number(precioPersonalizado.value);\r\n\r\n            (async ()=>{ \r\n                const datos = new FormData();\r\n                datos.append('idcliente', (document.querySelector('#idcliente') as HTMLInputElement).value);\r\n                datos.append('idproducto', $('#productos').val()as string);\r\n                datos.append('precioxcliente', valor.toString());\r\n                try {\r\n                    const url = \"/admin/api/clientes/preciospersonalizados\";  //asocia el precio personalizado al cliente\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                      msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                        /////validar si es el mismo subproducto, y actualizar \r\n                        validarProducto($('#productos').val()as string, producto.data('producto'));\r\n                        ////// reset form ///////\r\n                        ($('#productos') as any).val([]).trigger('change');\r\n                        //$(`#subproducto option[value=\"${$('#subproducto').val()}\"]`).remove();\r\n                        (document.querySelector('#formAddProducto') as HTMLFormElement)?.reset();\r\n                    }else{\r\n                      msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();//cierre de async()\r\n        });\r\n\r\n\r\n        function validarProducto(idproducto:string, producto:string){\r\n            const pro = document.querySelector(`.listaProductos div[id=\"${idproducto}\"]`);\r\n            if(pro){\r\n                pro.querySelector('strong')!.textContent = '$'+Number(precioPersonalizado.value).toLocaleString();\r\n            }else{\r\n                listaProductos?.insertAdjacentHTML('beforeend', `\r\n                <div id=\"${idproducto}\" class=\"mb-4 flex items-center justify-between p-4 text-blue-600 bg-blue-100 rounded-lg shadow-md shadow-blue-500/30\" role=\"alert\">\r\n                    <p class=\"m-0\"><strong>$${Number(precioPersonalizado.value).toLocaleString()}</strong>. - ${producto}</p>\r\n                    <button type=\"button\"><span id=\"${idproducto}\" class=\"material-symbols-outlined\">cancel</span></button>\r\n                </div>`\r\n                );\r\n            }\r\n        }\r\n\r\n\r\n        listaProductos?.addEventListener('click', (e:Event)=>{\r\n            const btn = (e.target as HTMLSpanElement); //contiene el id del producto\r\n            if(btn.tagName == \"SPAN\")eliminarPrecioPersonalizado((document.querySelector('#idcliente') as HTMLInputElement).value, btn.id);\r\n        });\r\n\r\n\r\n        function eliminarPrecioPersonalizado(idcliente:string, idproducto:string){\r\n            const pro = document.querySelector(`.listaProductos div[id=\"${idproducto}\"]`);\r\n            (async ()=>{\r\n                try {\r\n                  const url = \"/admin/api/clientes/eliminarPrecioPersonalizado?idcliente=\"+idcliente+\"&idproducto=\"+idproducto; //llamado a la API REST para eliminar precio personlizado a cliente\r\n                  const respuesta = await fetch(url); \r\n                  const resultado = await respuesta.json();\r\n                  if(resultado.exito !== undefined){\r\n                    pro?.remove();\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                  }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n\r\n\r\n    }\r\n\r\n})();","(():void=>{\r\n  if(document.querySelector('.caja')){\r\n    const modalGastosIngresos:any = document.querySelector(\"#gastosIngresos\");\r\n    const modalcambioMedioPago:any = document.querySelector(\"#cambioMedioPago\");\r\n    const miDialogoAbrirCaja:any = document.querySelector(\"#miDialogoAbrirCaja\");\r\n    const btnGastosingresos = document.querySelector<HTMLButtonElement>(\"#btnGastosingresos\");\r\n    const btnAbrirCajon = document.querySelector<HTMLButtonElement>(\"#btnAbrirCajon\");\r\n    const operacion = document.querySelector('#operacion') as HTMLSelectElement;\r\n    const origengasto = document.querySelectorAll<HTMLInputElement>('input[name=\"origengasto\"]');\r\n    const mediosPago = document.querySelectorAll<HTMLInputElement>('.mediopago'); //todos los medios de pago del modal\r\n    const totalPagado = document.querySelector('#totalPagado') as HTMLSpanElement;\r\n    const numfactura = document.querySelector('#numfactura') as HTMLLabelElement;\r\n    const inputAbrirCaja = document.querySelector('#inputAbrirCaja') as HTMLInputElement;\r\n    const formGastosingresos = document.querySelector('#formGastosingresos') as HTMLFormElement;\r\n    const btnEnviargastosingresos = document.querySelector('#btnEnviargastosingresos') as HTMLInputElement;\r\n\r\n    let printerBT:string = getParam.impresora_principal_de_CAJA_para_Android_por_BT.valor_final;\r\n    let tablaListaPedidos:HTMLElement;\r\n    let estadofactura:string, contentMP:HTMLElement, idfactura:string = '0';\r\n    let mediospagoDB:{id:string, idmediopago:string, id_factura:string, valor:string}[];\r\n    let nuevosMediosPago:{idmediopago:string, valor: string}[]=[];  // guardar los medios de pago a enviar a backend\r\n    const setMediosPagoDB = new Set();\r\n    const mapMediospago = new Map();\r\n    let totalpagadointerno = 0;\r\n\r\n    tablaListaPedidos = ($('#tablaListaPedidos') as any).DataTable(configdatatablescaja);\r\n\r\n\r\n    interface clavesApi {\r\n      clave:string,\r\n      valor_default:string|null,\r\n      valor_final:string|null,\r\n      valor_local:string|null\r\n    };\r\n\r\n    let claveAbrirCajon:clavesApi[];\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          claveAbrirCajon = resultado;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n\r\n    //////// clic al btn gastos/ingresos\r\n    btnGastosingresos?.addEventListener('click', ():void=>{\r\n      modalGastosIngresos.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    formGastosingresos.addEventListener('submit', (e:Event)=>{\r\n      btnEnviargastosingresos.disabled = true;\r\n      btnEnviargastosingresos.textContent = \"Enviando...\";\r\n    });\r\n\r\n    ///////// cambio de tipo de operacion si ingreso o gasto, si es gasto habilita el select de los tipos de gastos\r\n    operacion?.addEventListener('change', (e:Event)=>{\r\n      const targetDom = e.target as HTMLSelectElement;\r\n      const tipodegasto = document.querySelector('.tipodegasto') as HTMLElement;\r\n\r\n      if(targetDom.value == 'gasto'){\r\n        tipodegasto.style.display = 'flex';\r\n        document.querySelector('#tipodegasto')?.setAttribute(\"required\", \"\"); //categoria de los gastos\r\n        document.querySelector('#origengasto')?.classList.remove('hidden');  //origen del gasto ya sea por caja o banco\r\n        document.querySelector('#origengasto')?.classList.add('flex');\r\n        showCajasBancos();\r\n      }\r\n      else{ // ingreso a caja\r\n        tipodegasto.style.display = 'none';\r\n        document.querySelector('#tipodegasto')?.removeAttribute(\"required\");\r\n        document.querySelector('#origengasto')?.classList.add('hidden');\r\n        document.querySelector('#origengasto')?.classList.remove('flex');\r\n        document.querySelector('#showcajas')?.classList.remove('hidden'); //mostar caja\r\n        document.querySelector('#showbancos')?.classList.add('hidden'); //oculta banco\r\n        document.querySelector('#banco')?.removeAttribute(\"required\");\r\n      }\r\n    });\r\n\r\n    /// evento a los inputs type radio para elegir origne del gasto = caja o bancos\r\n    origengasto.forEach(element =>element.addEventListener('click', showCajasBancos));\r\n\r\n\r\n    function showCajasBancos(){\r\n      const selectorigen = document.querySelector('input[name=\"origengasto\"]:checked');\r\n      if(selectorigen?.id == 'gastocaja'){\r\n        document.querySelector('#showcajas')?.classList.remove('hidden');\r\n        document.querySelector('#showbancos')?.classList.add('hidden');\r\n        document.querySelector('#banco')?.removeAttribute(\"required\");\r\n      }else{\r\n        document.querySelector('#showbancos')?.classList.remove('hidden');\r\n        document.querySelector('#banco')?.setAttribute(\"required\", \"\");\r\n      }\r\n    }\r\n\r\n\r\n    //////// clic al btn abrir cajon monedero\r\n    btnAbrirCajon?.addEventListener('click', ():void=>{\r\n      miDialogoAbrirCaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    //evento al boton confirmar para eliminar orden\r\n    document.querySelector('.siAbrirCajon')?.addEventListener('click', (event:Event)=>{\r\n      const v:number = validarPasswordDcto();\r\n      if(!v)return;\r\n      if((event.target as HTMLInputElement).closest('.siAbrirCajon'))abrirCajonMonedero();\r\n    });\r\n\r\n    const abrirCajonMonedero = async():Promise<void>=>{\r\n        try {\r\n            const url = \"http://localhost:3100/api/printPOS/openCashDrawer/CAJA\";  //api llama servidor de impresion local.\r\n            const respuesta = await fetch(url);\r\n            const resultado = await respuesta.json();\r\n            console.log(resultado);\r\n            if(resultado){\r\n              msjalertToast('success', '¡Éxito!', 'Apertura de cajon enviada');\r\n              miDialogoAbrirCaja.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', 'Error en el cajon monedero');\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    ////////////// Evento a la tabla lista de pedidos ///////////////\r\n    document.querySelector('#tablaListaPedidos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"mediosdepago\")||target.parentElement?.classList.contains(\"mediosdepago\"))cambiomediopago(target);\r\n      if(target?.classList.contains(\"printPOS\")||target.parentElement?.classList.contains(\"printPOS\"))printPOS(target);\r\n      if(target?.classList.contains(\"printPDF\")||target.parentElement?.classList.contains(\"printPDF\"))printPDF(target);\r\n    });\r\n\r\n\r\n    //////////// Modal para el cambio de medio de pago ////////////\r\n    function cambiomediopago(target:HTMLElement){\r\n      idfactura = target.id;\r\n      contentMP = target;\r\n      estadofactura = target.dataset.estado??'';\r\n      totalPagado.textContent = Number(target.dataset.totalpagado??'0').toLocaleString();\r\n      if(target.tagName == \"BUTTON\"){\r\n        idfactura = target.parentElement!.id;\r\n        contentMP = target.parentElement!;\r\n        estadofactura = target.parentElement?.dataset.estado??'';\r\n        totalPagado.textContent = Number(target.parentElement!.dataset.totalpagado??'0').toLocaleString();\r\n      }\r\n      facturamediospago();     //muestra los valores de los medios de pago de cada factura\r\n      if(estadofactura == \"Eliminada\")document.querySelector('#btnEnviarCambioMedioPago')?.classList.add('!hidden');\r\n      if(estadofactura == \"Paga\")document.querySelector('#btnEnviarCambioMedioPago')?.classList.remove('!hidden');\r\n      modalcambioMedioPago.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function facturamediospago(){  //muestra los valores de los medios de pago de cada factura\r\n      numfactura.textContent = 'Factura N° : '+idfactura;\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/mediospagoXfactura?id=\"+idfactura; //llamado a la API REST y se trae los medios de pago segun factura\r\n          const respuesta = await fetch(url); \r\n          mediospagoDB = await respuesta.json(); \r\n          //console.log(mediospagoDB);\r\n          //const setMediosPagoDB = new Set(mediospagoDB.map(x=>x.idmediopago));\r\n          //console.log(setMediosPagoDB);\r\n\r\n          //agrupar por idmediopago y sumar su valor\r\n          totalpagadointerno = 0;\r\n          mediospagoDB = Object.values(mediospagoDB.reduce<Record<string, {id:string, idmediopago:string, id_factura:string, valor:string}>>((obj, x)=>{\r\n            totalpagadointerno+=Number(x.valor);\r\n            const k = x.idmediopago;\r\n            if(!obj[k])obj[k] = {...x, valor: '0'}\r\n            obj[k].valor = (Number(obj[k].valor) + Number(x.valor))+'';\r\n            return obj;\r\n          }, {}));\r\n          console.log(totalpagadointerno);\r\n\r\n          mediospagoDB.forEach(x => setMediosPagoDB.add(x.idmediopago));//se llena el set con los medios de pago de la DB\r\n          mediosPago.forEach(mediopago =>{  //se llena los inputs medios de pago con los medios de pago de la DB\r\n            mediopago.value = '0';\r\n            for(let i=0; i<mediospagoDB.length; i++)\r\n              if(mediopago.id == mediospagoDB[i].idmediopago){\r\n                mediopago.value =  Number(mediospagoDB[i].valor).toLocaleString();\r\n                mapMediospago.set(mediopago.id, Number(mediospagoDB[i].valor));\r\n                break;\r\n              }\r\n          });\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n\r\n    mediosPago.forEach(mp =>{\r\n      mp.addEventListener('input', (e)=>{\r\n        let totalmediospago = 0;\r\n        mediosPago.forEach((item, index)=>{ //sumar todos los medios de pago\r\n          totalmediospago += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        });\r\n\r\n        if(totalmediospago<=parseInt(totalPagado.textContent!.replace(/[,.]/g, ''))){\r\n          mapMediospago.set((e.target as HTMLInputElement).id, parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, '')));\r\n          document.querySelector('#diferencia')!.textContent = (parseInt(totalPagado.textContent!.replace(/[,.]/g, ''))-totalmediospago).toLocaleString();\r\n        }else{\r\n          if(mapMediospago.has((e.target as HTMLInputElement).id)){\r\n            (e.target as HTMLInputElement).value = mapMediospago.get((e.target as HTMLInputElement).id).toLocaleString();\r\n          }else{ (e.target as HTMLInputElement).value = '0'; }\r\n        }\r\n      });\r\n    });\r\n\r\n\r\n    async function printPOS(target: HTMLElement){\r\n      let idfactura = target.parentElement!.id;\r\n      if(target.tagName === 'I')idfactura = target.parentElement!.parentElement!.id;\r\n      //obtener factura por fetch\r\n      try{\r\n        const url = \"/admin/api/getInvoice?id=\"+idfactura; //llamado a la API REST - cajacontrolador y se trae detalle de factura \r\n        const respuesta = await fetch(url); \r\n        const resultado:DataInvoice = await respuesta.json();\r\n        const isAndroid = /Android/i.test(navigator.userAgent);\r\n        if(printerBT === '1'){\r\n          const builder = new InvoiceTicketBuilder2(resultado);\r\n          const ticket = await builder.generate(true); //true para version buffer bytes\r\n          const base64 = bytesToBase64(ticket);\r\n          if(isAndroid)window.location.href = `rawbt:base64,${base64}`;\r\n          //descargar .bin a equipo\r\n          /*const blob = new Blob([ticket], { type: 'application/octet-stream' });\r\n          const url = URL.createObjectURL(blob);\r\n          const a = document.createElement('a');\r\n          a.href = url;\r\n          a.download = 'ticket.bin';\r\n          a.click();\r\n          URL.revokeObjectURL(url);*/\r\n        }\r\n        window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");  //controlador printcontrolador\r\n      }catch(error){\r\n        console.log(error);\r\n      }\r\n    }\r\n\r\n    function printPDF(target: HTMLElement){\r\n      let idfactura = target.parentElement!.id;\r\n      let cotizacion:string = target.parentElement?.dataset.cotizacion!;\r\n      let urlprintPDF:string = \"/printfacturacarta?id=\";\r\n      if(target.tagName === 'I'){\r\n        idfactura = target.parentElement!.parentElement!.id;\r\n        cotizacion = target.parentElement!.parentElement?.dataset.cotizacion!;\r\n      }\r\n      if(cotizacion === '1')urlprintPDF = \"/printcotizacion?id=\";\r\n      const ventana = window.open(urlprintPDF + idfactura, \"_blank\");  //cajacontrolador\r\n      if(ventana){\r\n        ventana.onload = ()=>{\r\n          ventana?.focus();\r\n          ventana?.print();\r\n          setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n        };\r\n      }\r\n    }\r\n\r\n    ////////////////// evento al bton para cambiar medios de pago //////////////////////\r\n    document.querySelector('#formCambioMedioPago')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      let totalotrosmedios = 0;\r\n      nuevosMediosPago.length = 0;\r\n      mediosPago.forEach((item, index)=>{ \r\n        totalotrosmedios += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, '')); //sumar todos los medios de pago de los inputs\r\n        if(item.value != '0')\r\n          nuevosMediosPago = [...nuevosMediosPago, {idmediopago: item.id, valor: item.value.replace(/[,.]/g, '')}];  //obtengo los nuevos medios de pago difente a cero\r\n      });\r\n\r\n      if(totalotrosmedios != parseInt(totalPagado.textContent!.replace(/[,.]/g, '')) && totalotrosmedios!=totalpagadointerno){\r\n        msjAlert('error', 'Valor diferente al pagado', (document.querySelector('#divmsjalerta2') as HTMLElement));\r\n        return;\r\n      }\r\n      actualizarMediosPago();\r\n    });\r\n\r\n\r\n    async function actualizarMediosPago(){\r\n      const setNuevosMediosPago = new Set(nuevosMediosPago.map(x=>x.idmediopago));\r\n      ////cruzar los datos de los medios de pago de la DB y de los nuevos medios de pago////\r\n      //////// medios de pago iguales o compartidos ///////////\r\n      const mediospagocompartidos = mediospagoDB.filter(x=>setNuevosMediosPago.has(x.idmediopago));\r\n      //////// nuevos medios de pago que no estan en DB, crear o agregar\r\n      const nuevosMediosPagoNoEnDB = nuevosMediosPago.filter(x=>!setMediosPagoDB.has(x.idmediopago));\r\n      //////// medios de pago de la DB que no estan en los nuevos medios de pago, eliminar\r\n      const mediosPagoDBNoEnNuevos = mediospagoDB.filter(x=>!setNuevosMediosPago.has(x.idmediopago));\r\n\r\n      const datos = new FormData();\r\n      datos.append('id_factura', idfactura);\r\n      datos.append('efectivoDB', mediospagoDB.find(x=>x.idmediopago=='1')?.valor??'0'+'');\r\n      datos.append('nuevoEfectivo', nuevosMediosPago.find(x=>x.idmediopago=='1')?.valor??'0'+'');\r\n      datos.append('mediospagocompartidos', JSON.stringify(mediospagocompartidos));\r\n      datos.append('nuevosMediosPagoNoEnDB', JSON.stringify(nuevosMediosPagoNoEnDB));\r\n      datos.append('mediosPagoDBNoEnNuevos', JSON.stringify(mediosPagoDBNoEnNuevos));\r\n      datos.append('nuevosMediosPago', JSON.stringify(nuevosMediosPago));  \r\n      try {\r\n          const url = \"/admin/api/cambioMedioPago\";  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            updateMP(resultado.mediosPagoUpdate);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n      modalcambioMedioPago.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function updateMP(mediosPagoUpdate:{id:string, idmediopago:string, id_factura:string, valor:string, mediopago:string}[]){\r\n      while(contentMP.firstChild)contentMP.removeChild(contentMP.firstChild);\r\n      mediosPagoUpdate.forEach(btnMP=>{\r\n        const button = document.createElement('button');\r\n        button.classList.add('btn-xs', 'btn-light', 'mr-2');\r\n        button.textContent = btnMP.mediopago;\r\n        contentMP.appendChild(button);\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if (f === modalGastosIngresos || f === modalcambioMedioPago || f === miDialogoAbrirCaja || (f as HTMLInputElement).closest('.noAbrirCajon') || (f as HTMLInputElement).value === 'cancelar') {\r\n          modalGastosIngresos.close();\r\n          modalcambioMedioPago.close();\r\n          miDialogoAbrirCaja.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n    \r\n    function validarPasswordDcto():number{\r\n      const clave = claveAbrirCajon.find(c => c.clave=='clave_para_abrir_cajón_monedero');\r\n      if(clave?.valor_final!==null && inputAbrirCaja.value !== clave?.valor_final){\r\n        msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalerta3') as HTMLElement));\r\n        return 0;\r\n      }\r\n      return 1;\r\n    }\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.categoriasgastos')){\r\n        const btnCrearCategoriaGasto = document.querySelector('#btnCrearCategoriaGasto');\r\n        const miDialogoCategoriaGasto = document.querySelector('#miDialogoCategoriaGasto') as any;\r\n        let tablaCategoriasGastos:HTMLElement;\r\n\r\n        tablaCategoriasGastos = ($('#tablaCategoriasGastos') as any).DataTable(configdatatables25reg);\r\n\r\n        ///////////////BTN PARA CREAR CATEGORIA DE GASTO////////////////\r\n        btnCrearCategoriaGasto?.addEventListener('click', (e):void=>{\r\n            limpiarformdialog();\r\n            document.querySelector('#modalCategoriaGasto')!.textContent = \"Crear categoria de gasto\";\r\n            (document.querySelector('#btnEditarCrearCategoriaGasto') as HTMLInputElement).value = \"Crear\";\r\n            miDialogoCategoriaGasto.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        });\r\n\r\n        document.querySelector('#tablaCategoriasGastos')?.addEventListener('click', (e:Event)=>{\r\n            var btn = e.target as HTMLElement;\r\n            if(btn?.classList.contains('editarCategoriaGasto')||btn.parentElement?.classList.contains(\"editarCategoriaGasto\"))editarCategoriaGasto(e);\r\n            if(btn?.classList.contains('eliminarCategoriaGasto')||btn.parentElement?.classList.contains(\"eliminarCategoriaGasto\"))eliminarCategoriaGasto(e);   \r\n        });\r\n\r\n\r\n        ///////////////EDITAR CATEGORIA DE GASTO////////////////\r\n        function editarCategoriaGasto(e:Event){\r\n            let idcategoriagasto = (e.target as HTMLElement).parentElement?.id!;\r\n            if((e.target as HTMLElement)?.tagName === 'I')idcategoriagasto = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n            (document.querySelector('#formCrearUpdateCategoriaGasto') as HTMLFormElement).action = \"/admin/caja/editarcategoriagasto\";\r\n            document.querySelector('#modalCategoriaGasto')!.textContent = \"Actualizar categoria de gasto\";\r\n            (document.querySelector('#btnEditarCrearCategoriaGasto') as HTMLInputElement)!.value = \"Actualizar\";\r\n            (document.querySelector('#idCategoriaGasto') as HTMLInputElement).value = idcategoriagasto;\r\n            (document.querySelector('#nombre') as HTMLInputElement).value = ((e.target as HTMLElement).closest('.acciones-btns') as HTMLElement)?.dataset.categoriagasto!; \r\n            miDialogoCategoriaGasto.showModal();\r\n            document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n\r\n\r\n        function eliminarCategoriaGasto(e:Event):void{\r\n            let form = (e.target as HTMLElement).parentElement!;\r\n            if((e.target as HTMLElement).tagName === 'I')form = form.parentElement!;\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar la categoria de gasto?',\r\n                text: \"La categoria de gasto sera eliminado definitivamente.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed)(form as HTMLFormElement).submit();\r\n            });\r\n        }\r\n        \r\n        function limpiarformdialog(){\r\n            (document.querySelector('#formCrearUpdateCategoriaGasto') as HTMLFormElement)?.reset();\r\n            (document.querySelector('#formCrearUpdateCategoriaGasto') as HTMLFormElement).action = \"/admin/caja/crear_categoriaGasto\";\r\n        }\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n        if (f === miDialogoCategoriaGasto || (f as HTMLInputElement).value === 'Salir' || (f as HTMLInputElement).value === 'Actualizar') {\r\n            miDialogoCategoriaGasto.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n        }\r\n    }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.cerrarcaja')){\r\n    const modalArqueocaja:any = document.querySelector(\"#modalArqueocaja\");\r\n    const Modalcerrarcaja:any = document.querySelector(\"#Modalcerrarcaja\");\r\n    const modalCambiarCaja:any = document.querySelector(\"#modalCambiarCaja\");\r\n    const btnArqueocaja = document.querySelector<HTMLButtonElement>(\"#btnArqueocaja\");\r\n    const btnCerrarcaja = document.querySelector<HTMLButtonElement>(\"#btnCerrarcaja\");\r\n    const btnImprimirDetalleCaja = document.querySelector('#btnImprimirDetalleCaja') as HTMLButtonElement;\r\n    const btnCambiarCaja = document.querySelector<HTMLButtonElement>(\"#btnCambiarCaja\");\r\n    const btnVerCierreWeb = document.querySelector('#btnVerCierreWeb') as HTMLButtonElement;\r\n    const inputsmediospago = document.querySelectorAll<HTMLInputElement>('.inputmediopago');\r\n    const formArqueocaja = document.querySelector('#formArqueocaja') as HTMLFormElement;\r\n    const formCambiarCaja = document.querySelector('#formCambiarCaja') as HTMLFormElement;\r\n\r\n    btnArqueocaja?.addEventListener('click', ():void=>{\r\n      modalArqueocaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    btnCerrarcaja?.addEventListener('click', ():void=>{\r\n      Modalcerrarcaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    btnCambiarCaja?.addEventListener('click', ():void=>{\r\n      modalCambiarCaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n    \r\n\r\n    //////////////////     Arqueo de caja      //////////////////////\r\n    formArqueocaja?.addEventListener('submit', (e:Event)=>{\r\n      e.preventDefault();\r\n      sumatoriaDenominaciones();\r\n      const datos = new FormData(formArqueocaja);\r\n      datos.append('idcierrecaja', document.querySelector('#idCierrecaja')?.textContent!);\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/arqueocaja\";  //api llamada en cajacontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              modalArqueocaja.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n      \r\n    });\r\n\r\n    function sumatoriaDenominaciones():void{\r\n      const ef = document.querySelector('#Efectivo') as HTMLInputElement;\r\n      const inputsDenominaciones = Array.from( document.querySelectorAll<HTMLInputElement>('.denominacion'));\r\n      const sum = inputsDenominaciones.reduce((total, denominaicon)=>(Number(denominaicon.dataset.moneda)*Number(denominaicon.value))+total, 0);\r\n      ef.value = sum+'';\r\n      const eventInput = new Event('input');  //crea un evento\r\n      ef.dispatchEvent(eventInput); // se dispara el evento de manera manual, --->abajo<--, es decir cuando se introduce un valor en el campo efectivo se dispara el evento.\r\n    }\r\n\r\n    ///////////  eventos a los inputs medios de pago de declarar valores /////////////\r\n    inputsmediospago.forEach(m=>{\r\n      m.addEventListener('input', (e)=>{  \r\n        const inputmediopago = (e.target as HTMLInputElement);\r\n        const valormediopagodeclarado:number =  parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        (async ()=>{\r\n          const datos = new FormData();\r\n          datos.append('id_mediopago', inputmediopago.dataset.idmediopago+'');\r\n          datos.append('nombremediopago', inputmediopago.name);\r\n          datos.append('valordeclarado', valormediopagodeclarado+'');\r\n          datos.append('idcierrecaja', document.querySelector('#idCierrecaja')?.textContent!);\r\n          try {\r\n              const url = \"/admin/api/declaracionDinero\";  //api llamada en cajacontrolador.php\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito !== undefined){\r\n                inputmediopago.style.color = \"#02db02\";\r\n                inputmediopago.style.fontWeight = \"500\";\r\n                actualizarAnalisis(inputmediopago.dataset.idmediopago!, valormediopagodeclarado+'', inputmediopago.name);\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();\r\n      });\r\n    }); \r\n\r\n\r\n    function actualizarAnalisis(id: string, valordeclarado: string, mediopago:string):void{\r\n      const coldeclarado = document.querySelector(`.coldeclarado[data-mediopagoid=\"${id}\"]`);\r\n      if(coldeclarado){\r\n        const coldif = coldeclarado.nextElementSibling;\r\n        coldeclarado.textContent = Number(valordeclarado).toLocaleString('es-ES', { useGrouping: true });\r\n        const colsistem = coldeclarado.previousElementSibling?.textContent?.replace(/[.,]/g, '');\r\n        coldif!.textContent = ((Number(valordeclarado) - Number(colsistem))).toLocaleString('es-ES', { useGrouping: true }); \r\n      }else{\r\n        const cuerpoanalisis = document.querySelector('.cuerpoanalisis');\r\n        cuerpoanalisis?.insertAdjacentHTML('beforeend', `\r\n          <tr class=\"${mediopago=='Efectivo'?'!border-2 !border-indigo-600':''}\">\r\n            <td class=\"\">${mediopago}</td> \r\n            <td class=\"colsistem\">0</td>\r\n            <td class=\"coldeclarado\" data-mediopagoid=\"${id}\">${Number(valordeclarado).toLocaleString('es-ES', { useGrouping: true })}</td>\r\n            <td class=\"coldif\">${Number(valordeclarado).toLocaleString('es-ES', { useGrouping: true })}</td>\r\n          </tr>`\r\n        );\r\n      }\r\n    }\r\n\r\n    function confirmarcierre(){\r\n      const datos = new FormData();\r\n      \r\n      datos.append('idcierrecaja', document.querySelector('#idCierrecaja')?.textContent!);\r\n      \r\n      (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n      Modalcerrarcaja.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      (async ()=>{\r\n        try {\r\n\r\n            const url = \"/admin/api/cierrecajaconfirmado\";  //api llamada en cajacontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              setTimeout(() => {\r\n                (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n                window.location.href = `/admin/caja/detallecierrecaja?id=${resultado.ultimocierre[0]}`;\r\n              }, 1600);\r\n            }else{\r\n              (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n\r\n    const idimprimircierrecaja = document.querySelector('#idCierrecaja')?.textContent;\r\n    ///////// imprimir detalle cierre\r\n    btnImprimirDetalleCaja?.addEventListener('click', ()=>{\r\n        const ventana = window.open('/printdetallecierre?id='+idimprimircierrecaja, '_blank');\r\n        if(ventana){\r\n          ventana.onload = ()=>{\r\n            ventana?.focus();\r\n            ventana?.print();\r\n            setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n          };\r\n        }\r\n    });\r\n    ///////// ver detalle cierre en web\r\n    btnVerCierreWeb?.addEventListener('click', ()=>{\r\n        const ventana = window.open('/printdetallecierre?id='+idimprimircierrecaja, '_blank');\r\n        if(ventana)ventana.onload = ()=>ventana?.focus();\r\n    });\r\n\r\n    //////////////////     Cambio de caja      //////////////////////\r\n    formCambiarCaja?.addEventListener('submit', (e:Event)=>{\r\n      e.preventDefault();\r\n      const datos = new FormData();\r\n      datos.append('idcaja', $('#CambiarCaja').val()as string); //select del modal de cambio de caja\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/datoscajaseleccionada\";  //api llamada en cajacontrolador.php para traer datos de venta de la caja seleccionada \r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              modalCambiarCaja.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              console.log(resultado);\r\n              //cambiar el id del cierre de caja en id=\"#idCierrecaja\"\r\n              document.querySelector('#nombreCaja')!.textContent = $('#CambiarCaja option:selected').text();\r\n              document.querySelector('#idCierrecaja')!.textContent = resultado.ultimocierre.id;\r\n              //mostar datos de la caja seleccionada\r\n              printdiscriminarmediospago(resultado.discriminarmediospagos);\r\n              printindicadores(resultado.ultimocierre);\r\n              //printdetalleimpuesto();\r\n              //printgastosdelacaja();\r\n              //printdiscriminadoabonos();\r\n              printsobrantesfaltantes(resultado.sobrantefaltante);\r\n              printventasxusuarios(resultado.ventasxusuarios);\r\n              printventas(resultado.facturas);\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n      \r\n    });\r\n\r\n    function printdiscriminarmediospago(array: {idmediopago:string, mediopago:string, valor:string}[]){\r\n      const tbodyMediosPago = document.querySelector('#tablaMediosPago tbody') as HTMLTableElement;\r\n      while(tbodyMediosPago.firstChild)tbodyMediosPago.removeChild(tbodyMediosPago.firstChild);\r\n      array.forEach(row=>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${row.mediopago}</td> \r\n                        <td class=\"\"><strong>$ </strong>${Number(row.valor).toLocaleString()}</td>\r\n                      `;\r\n        tbodyMediosPago.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function printindicadores(obj:{id:string, idcaja:string, id_usuario:string, nombrecaja:string, nombreusuario:string, fechainicio:string, fechacierre:string, ncambiosaventa:string, totalcotizaciones:string, totalfacturas:string, facturaselectronicas:string, facturaspos:string, valorfe:string, descuentofe:string, valorpos:string, descuentopos:string, basecaja:string, ventasenefectivo:string, creditocapital:string, creditos:string, abonostotales:string, abonosenefectivo:string, abonoscreditos:string, abonosseparados:string, gastoscaja:string, gastosbanco:string, dineroencaja:string, domicilios:string, ndomicilios:string, realencaja:string, ingresoventas:string, totaldescuentos:string, realventas:string, valorimpuestototal:string, basegravable:string, estado:string}){\r\n      const basecaja = Number(obj.basecaja);\r\n      const ventasenefectivo = Number(obj.ventasenefectivo);\r\n      const gastoscaja = Number(obj.gastoscaja);\r\n      const domicilios = Number(obj.domicilios);\r\n      const ingresoventas = Number(obj.ingresoventas);\r\n      const totaldescuentos = Number(obj.totaldescuentos);\r\n      const abonosenefectivo = Number(obj.abonosenefectivo);\r\n      const abonostotales = Number(obj.abonostotales);\r\n\r\n      document.querySelector('#basecajaResumen')!.textContent = '$'+basecaja.toLocaleString();\r\n      document.querySelector('#gastoscajaResumen')!.textContent = '$'+gastoscaja.toLocaleString();\r\n      document.querySelector('#domiciliosResumen')!.textContent = '$'+domicilios.toLocaleString();\r\n      document.querySelector('#ingresoventasResumen')!.textContent = '$'+(ingresoventas).toLocaleString();\r\n      document.querySelector('#totalfacturasResumen')!.textContent = obj.totalfacturas;\r\n      document.querySelector('#totalcotizacionesResumen')!.textContent = obj.totalcotizaciones;\r\n\r\n      document.querySelector('#baseIngresoCaja')!.textContent = '+ $'+basecaja.toLocaleString();\r\n      document.querySelector('#ventasEfectivo')!.textContent = '+ $'+ventasenefectivo.toLocaleString();\r\n      document.querySelector('#abonosEfectivo')!.textContent = '+ $'+abonosenefectivo.toLocaleString();\r\n      document.querySelector('#gastosCaja')!.textContent = '- $'+gastoscaja.toLocaleString();\r\n      document.querySelector('#dineroCaja')!.textContent = '= $'+(basecaja+ventasenefectivo-gastoscaja).toLocaleString();\r\n      document.querySelector('#domicilios')!.textContent = '- $'+domicilios.toLocaleString();\r\n      document.querySelector('#realCaja')!.textContent = '= $'+(basecaja+ventasenefectivo-gastoscaja-domicilios).toLocaleString();\r\n      document.querySelector('#ingresoVentasTotal')!.textContent = '+ $'+ingresoventas.toLocaleString();\r\n      document.querySelector('#abonosTotales')!.textContent = '+ $'+abonostotales.toLocaleString();\r\n      document.querySelector('#totalGastosCaja')!.textContent = '- $'+gastoscaja.toLocaleString();\r\n      document.querySelector('#totalDescuentos')!.textContent = '- $'+totaldescuentos.toLocaleString();\r\n      document.querySelector('#totalDomicilios')!.textContent = '= $'+(domicilios).toLocaleString();\r\n      document.querySelector('#realVentas')!.textContent = '= $'+(ingresoventas-totaldescuentos-domicilios-gastoscaja).toLocaleString();\r\n      document.querySelector('#totalBaseGravable')!.textContent = '+ $'+Number(obj.basegravable).toLocaleString();\r\n      document.querySelector('#impuestoTotal')!.textContent = '+ $'+Number(obj.valorimpuestototal).toLocaleString();\r\n      document.querySelector('#otrosGastosBancarios')!.textContent = '+ $'+Number(obj.gastosbanco).toLocaleString();\r\n      document.querySelector('#cantidadFacturasFE')!.textContent = obj.facturaselectronicas;\r\n      document.querySelector('#cantidadFacturasPOS')!.textContent = obj.facturaspos;\r\n    }\r\n\r\n    function printsobrantesfaltantes(array: {id_mediopago:string, idcierrecajaid:string, nombremediopago:string, valordeclarado:number, valorsistema:number}[]){\r\n      const sobranteFaltante = document.querySelector('#sobranteFaltante tbody') as HTMLTableElement;\r\n      while(sobranteFaltante.firstChild)sobranteFaltante.removeChild(sobranteFaltante.firstChild);\r\n      array.forEach(row=>{\r\n        const tr = document.createElement('tr');\r\n        if(row.nombremediopago=='Efectivo')tr.classList.add('!border-2', '!border-indigo-600');\r\n        tr.innerHTML = `<td class=\"\">${row.nombremediopago}</td> \r\n                        <td class=\"colsistem\">${row.valorsistema.toLocaleString()}</td>\r\n                        <td class=\"coldeclarado\" data-mediopagoid=\"${row.id_mediopago}\">${row.valordeclarado.toLocaleString()}</td>\r\n                        <td class=\"coldif\">${(row.valordeclarado - row.valorsistema).toLocaleString()}</td>\r\n                      `;\r\n        sobranteFaltante.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function printventasxusuarios(array: {Nombre:string, N_ventas:string, ventas:string}[]){\r\n      const ventasxusuarios = document.querySelector('#ventasXUsuario tbody') as HTMLTableElement;\r\n      while(ventasxusuarios.firstChild)ventasxusuarios.removeChild(ventasxusuarios.firstChild);\r\n      array.forEach(row=>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${row.Nombre}</td>\r\n                        <td class=\"\">${row.N_ventas}</td>\r\n                        <td class=\"\"><strong>$ </strong>${Number(row.ventas).toLocaleString()}</td>\r\n                      `;\r\n        ventasxusuarios.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function printventas(array: {id:string, idcliente:string, idvendedor:string, idcaja:string, idconsecutivo:string, iddireccion:string, idtarifazona:string, idcierrecaja:string, cliente:string, vendedor:string, caja:string, tipofacturador:string, mediosdepago:{id:string, id_factura:string, mediopago:string, valor:string}[], direccion:string, tarifazona:string, totalunidades:string, recibido:string, transaccion:string, tipoventa:string, cotizacion:string, estado:string, cambioaventa:string, subtotal:string, base:string, valorimpuestototal:string, dctox100:string, descuento:string, total:string, observacion:string, departamento:string, ciudad:string, entrega:string, valortarifa:string, fechacreacion:string, fechapago:string}[]){\r\n      const tablaVentas = document.querySelector('#tablaVentas tbody') as HTMLTableElement;\r\n      while(tablaVentas.firstChild)tablaVentas.removeChild(tablaVentas.firstChild);\r\n      array.forEach((row, i)=>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${i}</td>        \r\n                        <td class=\"\">${row.fechapago}</td> \r\n                        <td class=\"\">${row.cliente}</td> \r\n                        <td class=\"\">${row.id}</td>\r\n                        <td>\r\n                            <div data-estado=\"${row.estado}\" data-totalpagado=\"${row.total}\" id=\"${row.id}\" class=\"mediosdepago max-w-full flex flex-wrap gap-2\">\r\n                                ${row.mediosdepago.map(mp=>`<button class=\"btn-xs btn-light\">${mp.mediopago}</button>`).join(' ')}\r\n                            </div>\r\n                        </td>\r\n                        <td class=\"${row.estado=='Paga'?'btn-xs btn-lima':'btn-xs btn-blueintense'}\">${row.estado}</td>\r\n                        <td class=\"\">$ ${Number(row.subtotal).toLocaleString()}</td>\r\n                        <td class=\"\">$ ${Number(row.total).toLocaleString()}</td>\r\n                        <td class=\"accionestd\"><div class=\"acciones-btns\" id=\"${row.id}\">\r\n                                <a class=\"btn-xs btn-turquoise\" href=\"/admin/caja/ordenresumen?id=${row.id}\">Ver</a> <button class=\"btn-xs btn-light\"><i class=\"fa-solid fa-print\"></i></button>\r\n                            </div>\r\n                        </td>\r\n                      `;\r\n        tablaVentas.appendChild(tr);\r\n      });\r\n    }\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === modalArqueocaja || event.target === Modalcerrarcaja || event.target === modalCambiarCaja || (event.target as HTMLInputElement).value === 'Cancelar' || (event.target as HTMLElement).closest('.salircerrarcaja') || (event.target as HTMLElement).closest('.finCerrarcaja')) {\r\n          modalArqueocaja.close();\r\n          Modalcerrarcaja.close();\r\n          modalCambiarCaja.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n          if((event.target as HTMLElement).closest('.finCerrarcaja')){  //Cuando se hace el cierre de caja\r\n            confirmarcierre();\r\n          }\r\n      }\r\n    }\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.detallecierrecaja')){\r\n    const btnImprimirDetalleCaja = document.querySelector('#btnImprimirDetalleCaja') as HTMLButtonElement;\r\n    const btnVerCierreWeb = document.querySelector('#btnVerCierreWeb') as HTMLButtonElement;\r\n    const btnVerCierreWs = document.querySelector('#btnVerCierreWs') as HTMLButtonElement;\r\n\r\n    let printerBT:string = getParam.impresora_principal_de_CAJA_para_Android_por_BT.valor_final;\r\n    //capturar el id del cierre de caja por la url\r\n    const parametrosURL = new URLSearchParams(window.location.search);\r\n    const id:string = parametrosURL.get('id')??'';\r\n\r\n    if(id==''||id==null||isNaN(Number(id)))return;\r\n\r\n    ///////// imprimir detalle cierre\r\n    btnImprimirDetalleCaja?.addEventListener('click', ()=>{\r\n      if(id!=''){\r\n          const ventana = window.open('/printdetallecierre?id='+id, '_blank');\r\n          if(ventana){\r\n              ventana.onload = ()=>{\r\n                  ventana?.focus();\r\n                  ventana?.print();\r\n                  setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n              };\r\n          }\r\n      }else{\r\n        msjalertToast('error', '¡Error!', 'Error al generar detalle de cierre.');\r\n      }\r\n    });\r\n\r\n\r\n    ///////// ver detalle cierre en web\r\n    btnVerCierreWeb?.addEventListener('click', ()=>{\r\n        const ventana = window.open('/printdetallecierre?id='+id, '_blank');\r\n        if(ventana)ventana.onload = ()=>ventana?.focus();\r\n    });\r\n\r\n\r\n    ///////// ver y enviar detalle de cierre por whatsapp\r\n    btnVerCierreWs?.addEventListener('click', async()=>{\r\n        const url = \"/admin/api/ws/sendtextDetalleCierreCaja?id=\"+id; //llamado a la API REST para enviar detalle de cierre por ws\r\n        try {\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          if(resultado && resultado.code === 200 && !resultado.error){\r\n            msjalertToast('success', '¡Éxito!', 'Mensaje detalle de cierre de caja enviado');\r\n          }else{\r\n            msjalertToast('error', '¡Error!', 'Error al enviar mensaje de cierre de caja');\r\n          }\r\n        } catch (error) {\r\n          console.log(error);\r\n        }\r\n    });\r\n\r\n\r\n    ////////////// Evento a la tabla lista de pedidos ///////////////\r\n    document.querySelector('#tablaListaPedidos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      //if(target?.classList.contains(\"mediosdepago\")||target.parentElement?.classList.contains(\"mediosdepago\"))cambiomediopago(target);\r\n      if(target?.classList.contains(\"printPOS\")||target.parentElement?.classList.contains(\"printPOS\"))printPOS(target);\r\n    });\r\n\r\n\r\n    async function printPOS(target: HTMLElement){\r\n      let idfactura = target.parentElement!.id;\r\n      if(target.tagName === 'I')idfactura = target.parentElement!.parentElement!.id;\r\n      //obtener factura por fetch\r\n      try{\r\n        const url = \"/admin/api/getInvoice?id=\"+idfactura; //llamado a la API REST - cajacontrolador y se trae detalle de factura \r\n        const respuesta = await fetch(url); \r\n        const resultado:DataInvoice = await respuesta.json();\r\n        const isAndroid = /Android/i.test(navigator.userAgent);\r\n        if(printerBT === '1'){\r\n          const builder = new InvoiceTicketBuilder(resultado);\r\n          const ticket = await builder.generate(true); //true para version buffer bytes\r\n          const base64 = bytesToBase64(ticket);\r\n          if(isAndroid)window.location.href = `rawbt:base64,${base64}`;\r\n          //descargar .bin a equipo\r\n          /*const blob = new Blob([ticket], { type: 'application/octet-stream' });\r\n          const url = URL.createObjectURL(blob);\r\n          const a = document.createElement('a');\r\n          a.href = url;\r\n          a.download = 'ticket.bin';\r\n          a.click();\r\n          URL.revokeObjectURL(url);*/\r\n        }\r\n        window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");  //controlador printcontrolador\r\n      }catch(error){\r\n        console.log(error);\r\n      }\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.fechazetadiario')){\r\n\r\n    const btnsmultiselect = document.querySelectorAll<HTMLElement>('.btnmultiselect');\r\n    const selectedcajas = document.querySelectorAll<HTMLLIElement>('.caja');\r\n    const consultarZDiario = document.querySelector('#consultarZDiario') as HTMLButtonElement;\r\n    const tbodyMediosPago = document.querySelector('#tablaMediosPago tbody') as HTMLTableElement;\r\n    const base = document.querySelector('#base') as HTMLElement;\r\n    const valorImpuestoTotal = document.querySelector('#valorImpuestoTotal') as HTMLElement;\r\n    const ingresoVentas = document.querySelector('#ingresoVentas') as HTMLElement;\r\n    const totalDescuentos = document.querySelector('#totalDescuentos') as HTMLElement;\r\n    const realVentas = document.querySelector('#realVentas') as HTMLElement;\r\n    const cantidadElectronicas = document.querySelector('#cantidadElectronicas') as HTMLElement;\r\n    const cantidadPOS = document.querySelector('#cantidadPOS') as HTMLElement;\r\n    const valorElectronicas = document.querySelector('#valorElectronicas') as HTMLElement;\r\n    const valorPOS = document.querySelector('#valorPOS') as HTMLElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\";\r\n\r\n    //evento a los select drop dawn para abrir y cerrar\r\n    btnsmultiselect.forEach((btnmultiselect, index) =>{\r\n      btnmultiselect.addEventListener('click', (e:Event)=>{\r\n        cerrarlosmultiselect(index);\r\n        btnmultiselect.classList.toggle('open');\r\n      });\r\n    });\r\n    function cerrarlosmultiselect(index:number){\r\n      btnsmultiselect.forEach((element, i) =>{\r\n        if(i != index || !element.classList.contains('open'))element.classList.remove('open');\r\n      });\r\n    }\r\n    document.querySelector('.fechazetadiario')?.addEventListener('click', (e:Event)=>{\r\n      if(!(e.target as HTMLElement).closest('.btnmultiselect')&&!(e.target as HTMLElement).closest('.list-items')){\r\n        const btnmultiselect = document.querySelector('.open');\r\n        if(btnmultiselect)btnmultiselect.classList.toggle('open');\r\n      }\r\n    });\r\n    // mostrar el nombre de las cajas,segun se selecciona\r\n    selectedcajas.forEach(c=>{c.addEventListener('click', cajas_seleccionadas);});\r\n\r\n    function cajas_seleccionadas(){\r\n      const inputscaja = document.querySelectorAll<HTMLInputElement>('input.caja[type=\"checkbox\"]:checked');\r\n      const cajastext = document.querySelector('#cajastext') as HTMLElement;\r\n      cajastext.textContent = \". \";\r\n      inputscaja.forEach((inputcaja, i) =>{\r\n        if(i<inputscaja.length-1){\r\n          cajastext.textContent += inputcaja.nextElementSibling?.textContent!+' - ';\r\n        }else{\r\n          cajastext.textContent += inputcaja.nextElementSibling?.textContent!;\r\n        }\r\n      });\r\n    }\r\n\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        (document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        (document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    consultarZDiario.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      const cajas = document.querySelectorAll<HTMLInputElement>('input.caja[type=\"checkbox\"]:checked');\r\n      const facturadores = document.querySelectorAll<HTMLInputElement>('input.facturador[type=\"checkbox\"]:checked');\r\n      \r\n      const valuecajas:string[] = Array.from(cajas).map(c=>c.value);\r\n      const valuefacturadores:string[] = Array.from(facturadores).map(f=>f.value);\r\n\r\n      (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n      (async ()=>{\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', fechainicio);\r\n        datos.append('fechafin', fechafin);\r\n        datos.append('cajas', JSON.stringify(valuecajas));\r\n        datos.append('facturadores', JSON.stringify(valuefacturadores));\r\n        try {\r\n            const url = \"/admin/api/consultafechazetadiario\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            console.log(resultado);\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n           reiniciarTablas();\r\n           imprimirtablaMediosPago(resultado.datosmediospago);\r\n           imprimirIngresos(resultado.datosventa);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n    });\r\n\r\n\r\n    function imprimirtablaMediosPago(datosmediospago:{id:string, nombre:string, valor:string}[]){\r\n      datosmediospago.forEach(mp =>{\r\n        const tr = document.createElement('tr');\r\n        tr.innerHTML = `<td class=\"\">${mp.nombre}</td> \r\n                        <td class=\"\">$${Number(mp.valor).toLocaleString()}</td>`;\r\n        tbodyMediosPago.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    function imprimirIngresos(datosventa:{subtotalventa:string, base:string, valorimpuestototal:string, totalventa:string, ELECTRONICAS:string, POS:string, total_ELECTRONICAS:string, total_POS:string}){\r\n      base.textContent = '$'+Number(datosventa.base).toLocaleString();\r\n      valorImpuestoTotal.textContent = '$'+Number(datosventa.valorimpuestototal).toLocaleString();\r\n      ingresoVentas.textContent = '$'+Number(datosventa.subtotalventa).toLocaleString();\r\n      totalDescuentos.textContent = '$'+(Number(datosventa.subtotalventa)-Number(datosventa.totalventa)).toLocaleString();\r\n      realVentas.textContent = '$'+Number(datosventa.totalventa).toLocaleString();\r\n      cantidadElectronicas.textContent = datosventa.ELECTRONICAS;\r\n      cantidadPOS.textContent = datosventa.POS;\r\n      valorElectronicas.textContent = '$'+Number(datosventa.total_ELECTRONICAS).toLocaleString();\r\n      valorPOS.textContent = '$'+Number(datosventa.total_POS).toLocaleString();\r\n    }\r\n\r\n    function reiniciarTablas(){\r\n      while(tbodyMediosPago.firstChild)tbodyMediosPago.removeChild(tbodyMediosPago.firstChild);\r\n      ingresoVentas.textContent = '';\r\n      totalDescuentos.textContent = \"\";\r\n      realVentas.textContent = \"\";\r\n      cantidadElectronicas.textContent = '';\r\n      cantidadPOS.textContent = '';\r\n      valorElectronicas.textContent = '';\r\n      valorPOS.textContent = '';\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n    if(document.querySelector('.ordenresumen')){\r\n      const POS = (window as any).POS;\r\n      const miDialogoFacturar:any = document.querySelector(\"#miDialogoFacturar\");\r\n      const miDialogoEliminarOrden = document.querySelector('#miDialogoEliminarOrden') as any;\r\n      const btnfacturar = document.querySelector<HTMLButtonElement>(\"#btnfacturar\");\r\n      const btneliminarorden = document.querySelector('#btneliminarorden') as HTMLButtonElement;\r\n      const btnSelectVendedor = document.querySelector('#btnSelectVendedor') as HTMLButtonElement;\r\n      const btnCaja = document.querySelector('#caja') as HTMLSelectElement;\r\n      const btnTipoFacturador = document.querySelector('#facturador') as HTMLSelectElement;\r\n      const mediospago = document.querySelectorAll('.mediopago');\r\n      const btnsdevolverinv = document.querySelectorAll<HTMLInputElement>('input[name=\"devolverinventario\"]'); //radio buttom\r\n      const inputsInv = document.querySelectorAll<HTMLInputElement>('.inputInv');\r\n      const printcarta = document.querySelector('#printcarta');\r\n      const printcotizacion = document.querySelector('#printcotizacion');\r\n      const btnDespachar = document.querySelector<HTMLButtonElement>(\"#btnDespachar\");\r\n      const btnMasOpciones = document.querySelector('#btnMasOpciones') as HTMLInputElement;\r\n      const btnImprimirTirilla = document.querySelector('#btnImprimirTirilla') as HTMLInputElement;\r\n      const btnOrdenEnvio = document.querySelector('#btnOrdenEnvio') as HTMLInputElement;\r\n      const miDialogoMasOpciones = document.querySelector('#miDialogoMasOpciones') as any;\r\n      const numOrden = document.querySelector('#numOrden');\r\n      const referenciaFactura = document.querySelector('#referenciaFactura');\r\n      const miDialogoRemision = document.querySelector('#miDialogoRemision') as HTMLDialogElement;\r\n      const miDialogoSelectUser = document.querySelector('#miDialogoSelectUser') as HTMLDialogElement;\r\n      const enviarEmail = document.querySelector('#enviarEmail') as HTMLButtonElement;\r\n      const miDialogoEnviarEmailCliente = document.querySelector('#miDialogoEnviarEmailCliente') as any;\r\n      //const miDialogoDespachar = document.querySelector('#miDialogoDespachar') as any;\r\n      const miDialogoProductoCompuesto = document.querySelector('#miDialogoProductoCompuesto') as any;\r\n      const inputEliminarClave = document.querySelector('#inputEliminarClave') as HTMLInputElement;\r\n      const tablaDetalleInsumos = document.querySelector('#tablaDetalleInsumos tbody') as HTMLBodyElement;\r\n\r\n      const valorTotal = {subtotal: 0, impuesto: 0, dctox100: 0, descuento: 0, idtarifa: 0, valortarifa: 0, total: 0}; //datos global de la venta\r\n      const mapMediospago = new Map();\r\n\r\n      interface clavesApi {\r\n        clave:string,\r\n        valor_default:string|null,\r\n        valor_final:string|null,\r\n        valor_local:string|null\r\n      };\r\n\r\n      let claveEliminarOrden:clavesApi[];\r\n      const idorden = (document.querySelector('#idorden') as HTMLElement).dataset.idorden;\r\n\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json(); \r\n            claveEliminarOrden = resultado;\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n  \r\n      valorTotal.subtotal = Number(document.querySelector('#subTotal')?.textContent);\r\n      valorTotal.total = Number(document.querySelector('#total')?.textContent?.replace(/[^\\d]/g, ''));\r\n      \r\n      selectFacturadorSegunCaja(btnCaja);\r\n    \r\n      btnCaja.addEventListener('change', (e:Event)=>selectFacturadorSegunCaja(e.target as HTMLSelectElement));\r\n    \r\n      function selectFacturadorSegunCaja(z:HTMLSelectElement){\r\n        $('#facturador').val(z.options[z.selectedIndex].dataset.idfacturador??'1');\r\n      }\r\n\r\n      printcarta?.addEventListener('click', ()=>{\r\n        //leer parametros de url\r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n        if(id==''||id==null||isNaN(Number(id)))return;\r\n        const ventana = window.open('/printfacturacarta?id='+id, '_blank');\r\n        if(ventana){\r\n          ventana.onload = ()=>{\r\n            ventana?.focus();\r\n            ventana?.print();\r\n            setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n          };\r\n        }\r\n      });\r\n\r\n      printcotizacion?.addEventListener('click', ()=>{\r\n        //leer parametros de url\r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n        if(id==''||id==null||isNaN(Number(id)))return;\r\n        const ventana = window.open('/printcotizacion?id='+id, '_blank');\r\n        if(ventana){\r\n          ventana.onload = ()=>{\r\n            ventana?.focus();\r\n            ventana?.print();\r\n            setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n          };\r\n        }\r\n      });\r\n\r\n      btnfacturar?.addEventListener('click', ()=>{\r\n        /*if(modalidadEntrega.textContent === \": Domicilio\" && (selectCliente.value =='1' || selectCliente.value =='2' || !dirEntrega.value)){\r\n          msjAlert('error', 'Cliente o direccion no seleccionado', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n          return;\r\n        }*/\r\n        /*if(carrito.length){*/\r\n          subirModalPagar();\r\n          miDialogoFacturar.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        //}\r\n      });\r\n      \r\n\r\n      btneliminarorden?.addEventListener('click', ()=>{\r\n          miDialogoEliminarOrden.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n\r\n      enviarEmail?.addEventListener('click', ()=>{\r\n        miDialogoEnviarEmailCliente.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n\r\n      document.querySelector('#formEnviarEmailCliente')?.addEventListener('submit', (e:Event)=>{\r\n        e.preventDefault();\r\n        if(idorden!=null && Number(idorden)>0){\r\n          const datos = new FormData();\r\n          datos.append('id', idorden);\r\n          datos.append('email', (document.querySelector('#inputEmail') as HTMLInputElement).value);\r\n          miDialogoEnviarEmailCliente.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          (async ()=>{\r\n            try {\r\n              const url = \"/admin/api/sendOrdenEmailToCustemer\";  //va al controlador cajacontrolador para enviar detalle de orden por email.\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos});\r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito!=undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n          })();\r\n        }\r\n      });\r\n\r\n\r\n      btnDespachar?.addEventListener('click', ()=>{\r\n        if(Number.isNaN(idorden))return;\r\n        Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea despachar la orden?',\r\n          text: \"La orden sera registrada como despachada y entregada.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n            (async ()=>{\r\n              try {\r\n                const url = \"/admin/api/caja/despacharOrden?id=\"+idorden; //llamado a la API REST\r\n                const respuesta = await fetch(url); \r\n                const resultado = await respuesta.json();\r\n                if(resultado.exito !== undefined){\r\n                  msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                  (document.querySelector('#textEstado') as HTMLParagraphElement).textContent = \"Domicilio entregado\";\r\n                }else{\r\n                  msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n              } catch (error) {\r\n                  console.log(error);\r\n              }\r\n            })();\r\n          }\r\n        });\r\n      });\r\n\r\n\r\n      //apertura de la ventana modal para las opcionesde traslado de inventario\r\n      btnMasOpciones.addEventListener('click', ()=>{\r\n          miDialogoMasOpciones.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n\r\n      btnImprimirTirilla.addEventListener('click', ()=>{\r\n        if(Number.isNaN(idorden))return;\r\n        miDialogoMasOpciones.close();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        window.open(\"/admin/printPDFPOS?id=\" + idorden, \"_blank\");  //controlador printcontrolador\r\n      });\r\n\r\n\r\n      btnOrdenEnvio?.addEventListener('click', ()=>{\r\n        miDialogoRemision.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n      /////////  CAMBIAR USUARIO VENDEDOR Y COMISION  /////////////\r\n      btnSelectVendedor.addEventListener('click', (e)=>{\r\n        miDialogoSelectUser.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      });\r\n\r\n      document.querySelector('#btnEditarCrearSelectUser')?.addEventListener('submit', (e:Event)=>{\r\n        e.preventDefault();\r\n        /*try {\r\n            const url = `/admin/api/ventas/detalleProductoCompuesto?idproducto=${idproducto}&idfactura=${idventa}`; //llamado a la API REST ventascontrolador, detalle producto compuesto\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json();\r\n            detalleInsumos(resultado);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }*/\r\n      });\r\n\r\n\r\n      ///////////////////// Logica botones devolver inventario ////////////////////////\r\n      btnsdevolverinv.forEach(inv=>{ //evento a los radiobutton\r\n        inv.addEventListener('change', (e:Event)=>{\r\n          document.querySelector('#productsInv')?.classList.toggle('hidden');\r\n          if((e.target as HTMLInputElement).value === \"1\"){\r\n            document.querySelectorAll('.inputInv').forEach(x=>x.setAttribute('required', ''));\r\n          }else{\r\n            document.querySelectorAll('.inputInv').forEach(x=>x.removeAttribute('required'));\r\n          }\r\n        });\r\n      });\r\n\r\n      inputsInv.forEach(inputinv =>{\r\n        inputinv.addEventListener('input', e=>{\r\n          const qty = (e.target as HTMLInputElement);\r\n          if(qty.value != qty.parentElement?.dataset.qty){\r\n            qty.classList.add('border-2', 'border-rose-600');\r\n            if(!document.querySelector('.alerta'))\r\n              msjAlert('error', 'Cantidad diferente a devolver a inventario', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n          }else{\r\n            qty.classList.remove('border-2', 'border-rose-600');\r\n            document.querySelector('.alerta')?.remove();\r\n          }\r\n        });\r\n      });\r\n\r\n      /////////////////////  logica del modal de pago  //////////////////////////\r\n      function subirModalPagar(){\r\n        document.querySelector('#totalPagar')!.textContent = `${valorTotal.total.toLocaleString()}`;\r\n        //como se puede cerrar el modal y aumentar los productos, hay calcular los inputs\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{\r\n          if(index>0)totalotrosmedios += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        });\r\n\r\n        if(valorTotal.total<totalotrosmedios){\r\n          totalotrosmedios = 0;\r\n          mapMediospago.clear();\r\n          $('.mediopago').val(0);\r\n        }\r\n        (document.querySelector('.Efectivo')! as HTMLInputElement).value =  `${(valorTotal.total-totalotrosmedios).toLocaleString()}`;\r\n        mapMediospago.set('1', valorTotal.total-totalotrosmedios);\r\n        if(valorTotal.total-totalotrosmedios == 0 && mapMediospago.has('1'))mapMediospago.delete('1');\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n      }\r\n  \r\n      //eventos a los inputs medios de pago\r\n      mediospago.forEach(m=>{m.addEventListener('input', (e)=>{ calcularmediospago(e);});}); \r\n\r\n      function calcularmediospago(e:Event){\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{ //sumar todos los medios de pago menos el efectivo\r\n          if(index>0)totalotrosmedios += parseInt((item as HTMLInputElement).value.replace(/[,.]/g, ''));\r\n        });\r\n        if(totalotrosmedios<=valorTotal.total){\r\n          mapMediospago.set('1', valorTotal.total-totalotrosmedios);\r\n          if(valorTotal.total-totalotrosmedios == 0 && mapMediospago.has('1'))mapMediospago.delete('1');\r\n          mapMediospago.set((e.target as HTMLInputElement).id, parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, '')));\r\n          if((e.target as HTMLInputElement).value == '0' && mapMediospago.has((e.target as HTMLInputElement).id))mapMediospago.delete((e.target as HTMLInputElement).id);\r\n        }else{ //si la suma de los medios de pago superan el valor total, toma el ultimo input digitado y lo reestablece a su ultimo valor\r\n          if(mapMediospago.has((e.target as HTMLInputElement).id)){\r\n            (e.target as HTMLInputElement).value = mapMediospago.get((e.target as HTMLInputElement).id).toLocaleString();\r\n          }else{\r\n            (e.target as HTMLInputElement).value = '0';\r\n          }\r\n        }\r\n        (mediospago[0] as HTMLInputElement).value = (mapMediospago.get('1')??0).toLocaleString();\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n      }\r\n\r\n      /////////////////////  evento al input recibido  //////////////////////////\r\n      document.querySelector<HTMLInputElement>('#recibio')?.addEventListener('input', (e)=>{\r\n        calcularCambio((e.target as HTMLInputElement).value);\r\n      });\r\n      function calcularCambio(recibido:string):void{\r\n        recibido = recibido.replace(/[,.]/g, '');\r\n        if(Number(recibido)>mapMediospago.get('1')){\r\n          (document.querySelector('#cambio') as HTMLElement).textContent = (Number(recibido)-mapMediospago.get('1')).toLocaleString()+'';\r\n          return;\r\n        }\r\n        (document.querySelector('#cambio') as HTMLElement).textContent = '0';\r\n      }\r\n\r\n\r\n      ////////////////// evento al bton pagar del modal facturar //////////////////////\r\n      document.querySelector('#formfacturarCotizacion')?.addEventListener('submit', e=>{\r\n        e.preventDefault();\r\n        procesarpedido('Guardado');\r\n      });\r\n\r\n      async function procesarpedido(estado:string){ //////PROCESAR PAGO DE COTIZACION SiN CAMBIAR DATOS DE LOS PRODUCTOS//////\r\n        const imprimir = document.querySelector('input[name=\"imprimir\"]:checked') as HTMLInputElement;\r\n        const datos = new FormData();\r\n        datos.append('id', idorden!);\r\n        //datos.append('idcliente', (document.querySelector('#selectCliente') as HTMLSelectElement).value);\r\n        //datos.append('idvendedor', (document.querySelector('#vendedor') as HTMLInputElement).dataset.idvendedor!);\r\n        datos.append('idcaja', btnCaja.value);\r\n        datos.append('idconsecutivo', btnTipoFacturador.value);\r\n        //datos.append('iddireccion', dirEntrega.value);\r\n        //datos.append('idtarifazona', valorTotal.idtarifa+'');\r\n        //datos.append('cliente', selectCliente.options[selectCliente.selectedIndex].textContent!);\r\n        //datos.append('vendedor', (document.querySelector('#vendedor') as HTMLInputElement).value);\r\n        datos.append('caja', (document.querySelector('#caja option:checked') as HTMLSelectElement).textContent!);\r\n        datos.append('tipofacturador', btnTipoFacturador.options[btnTipoFacturador.selectedIndex].textContent!);\r\n        //datos.append('direccion', dirEntrega.options[dirEntrega.selectedIndex].text);\r\n        //datos.append('tarifazona', nombretarifa||'');\r\n        //datos.append('carrito', JSON.stringify(carrito));\r\n        //datos.append('totalunidades', totalunidades.textContent!);\r\n        //datos.append('mediosPago', JSON.stringify(Object.fromEntries(mapMediospago)));\r\n        datos.append('mediosPago', JSON.stringify(Array.from(mapMediospago, ([idmediopago, valor])=>({idmediopago, id_factura:0, valor}))));\r\n        datos.append('recibido', document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n        datos.append('transaccion', '');\r\n        datos.append('estado', estado);\r\n        datos.append('cambioaventa', '1');  //cambioaventa por defecto es 0\r\n        //datos.append('subtotal', valorTotal.subtotal+'');\r\n        //datos.append('impuesto', valorTotal.impuesto+'');\r\n        //datos.append('dctox100',valorTotal.dctox100+'');\r\n        //datos.append('descuento',valorTotal.descuento+'');\r\n        //datos.append('total', valorTotal.total.toString());\r\n        datos.append('observacion', document.querySelector<HTMLTextAreaElement>('#observacion')!.value);\r\n        //datos.append('departamento', '');\r\n        //datos.append('ciudad', (document.querySelector('#ciudadEntrega') as HTMLInputElement).value);\r\n        //datos.append('entrega', modalidadEntrega.textContent!.replace(': ', ''));\r\n        //datos.append('valortarifa', valorTotal.valortarifa+'');\r\n        //datos.append('datosAdquiriente', JSON.stringify(POS.gestionarAdquiriente.datosAdquiriente));\r\n        //datos.append('opc1', '');\r\n        //datos.append('opc2', '');\r\n        try {\r\n            const url = \"/admin/api/facturarCotizacion\";  //va al controlador ventascontrolador\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              /////// reinciar modulo de ventas\r\n              ordenpagada();\r\n              miDialogoFacturar.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              if(resultado.idfactura && imprimir.value === '1')printTicketPOS(resultado.idfactura);\r\n              if(btnTipoFacturador.options[btnTipoFacturador.selectedIndex].dataset.idtipofacturador == '1'){ \r\n                const resDian = await POS.sendInvoiceAPI.sendInvoice(resultado.idfactura); //llama a la funcion que esta en ts/ventas/ventas.sendinvoice.ts\r\n                console.log(resDian);\r\n              }\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      }\r\n  \r\n      function printTicketPOS(idfactura:string){\r\n        setTimeout(() => {\r\n          window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");\r\n        }, 1200);\r\n      }\r\n\r\n      function ordenpagada(){\r\n        if(btnfacturar)btnfacturar.style.display = \"none\";\r\n        (document.querySelector('#abrirOrden') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#estadoOrden') as HTMLElement).textContent = \"Paga\";\r\n      }\r\n  \r\n      function cerrarDialogoExterno(event:Event) {\r\n        const f = event.target;\r\n        if (f === miDialogoFacturar || f === miDialogoEliminarOrden || f === miDialogoEnviarEmailCliente || f === miDialogoMasOpciones || f === miDialogoRemision || f === miDialogoSelectUser || f === miDialogoProductoCompuesto || (f as HTMLElement).id == 'btnXCerrarMasOpciones' || (f as HTMLElement).id == 'btnXCerrarRemision' || (f as HTMLInputElement).value === 'cancelar' || (f as HTMLInputElement).value === 'Salir' || (f as HTMLInputElement).closest('.noeliminar') || (f as HTMLElement).id == 'btnXCerrarModalProductoCompuesto' || (f as HTMLElement).id == 'btnXCerrarModalSelectUser') {\r\n            miDialogoFacturar.close();\r\n            miDialogoEliminarOrden.close();\r\n            miDialogoEnviarEmailCliente.close();\r\n            miDialogoMasOpciones.close();\r\n            miDialogoRemision.close();\r\n            miDialogoProductoCompuesto.close();\r\n            miDialogoSelectUser.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n\r\n      //evento al boton confirmar para eliminar orden\r\n      document.querySelector('.sieliminar')?.addEventListener('click', (event:Event)=>{\r\n        const f = event.target;\r\n        if((f as HTMLInputElement).closest('.sieliminar'))eliminarorden();\r\n      });\r\n\r\n\r\n      function eliminarorden():void{\r\n        ///////*** crear arreglo de obj de los productos y sus cantidades ***///////\r\n        type producto = {id:string, idproducto:string, nombre:string, tipoproducto:string, tipoproduccion:string, rendimientoestandar:string, cantidad: string , promediostock: string};\r\n        var products:producto[] = [];\r\n\r\n        const v:number = validarPasswordDcto();\r\n        if(!v)return;\r\n\r\n        inputsInv.forEach(inputinv =>{\r\n          const v = inputinv as HTMLInputElement;\r\n          products = [...products, {id: v.id, idproducto: v.id, nombre: v.dataset.nombre??'', tipoproducto: v.dataset.tipoproducto!, tipoproduccion: v.dataset.tipoproduccion!, rendimientoestandar: v.dataset.rendimientoestandar!, cantidad: v.value, promediostock: v.dataset.promediostock??'0'}];\r\n        });\r\n\r\n        (async ()=>{\r\n          const datos = new FormData();\r\n          datos.append('id', idorden!); //id de la factura\r\n          datos.append('observacioneliminacion', (document.querySelector('#observacionEliminacion') as HTMLTextAreaElement).value);\r\n          datos.append('inv', JSON.stringify(products));\r\n          datos.append('devolverinv', (document.querySelector('input[name=\"devolverinventario\"]:checked') as HTMLInputElement).value);\r\n          //datos.append('domicilio', 0);\r\n          try {\r\n              const url = \"/admin/api/eliminarOrden\";  //api llamada en ventascontrolador.php\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                miDialogoEliminarOrden.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                btneliminarorden.style.display = \"none\";\r\n                enviarEmail.style.display = \"none\";\r\n                (document.querySelector('#estadoOrden') as HTMLElement).textContent = \"Eliminada\";\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();\r\n      }\r\n\r\n\r\n      document.querySelector('#tablaDetalleProductos')?.addEventListener('click', async(e:Event)=>{\r\n        while(tablaDetalleInsumos.firstChild)tablaDetalleInsumos.removeChild(tablaDetalleInsumos.firstChild);\r\n        const target = e.target as HTMLElement;\r\n        if(target.classList.contains('productoCompuesto')){\r\n          const nombreProductoCompuesto = target.textContent;\r\n          const parametrosURL = new URLSearchParams(window.location.search);\r\n          const idventa = parametrosURL.get('id');\r\n          if(idventa==''||idventa==null||isNaN(Number(idventa)))return;\r\n          const idproducto = target.id;\r\n          document.querySelector('#nombreProducto')!.textContent = nombreProductoCompuesto;\r\n          miDialogoProductoCompuesto.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n          try {\r\n            const url = `/admin/api/ventas/detalleProductoCompuesto?idproducto=${idproducto}&idfactura=${idventa}`; //llamado a la API REST ventascontrolador, detalle producto compuesto\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json();\r\n            detalleInsumos(resultado);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        }\r\n      });\r\n\r\n\r\n      function detalleInsumos(resultado:{cantidadcalculada:string, costo:string, disponibilidad:string, nombre:string, precio_compra:string, simbolo:string, sku:string, stockminimo:string, unidadmedida:string}[]){\r\n        resultado.forEach(ins=>{\r\n          const tr = document.createElement('tr') as HTMLTableRowElement;\r\n          //tr.classList.add('productselect');\r\n          //tr.dataset.idproducto = `${item.idproducto}`;\r\n          tr.innerHTML = `<td class=\"text-center\">${ins.nombre}</td>\r\n                          <td class=\"text-center\">${ins.cantidadcalculada}</td>\r\n                          <td class=\"text-center\">${ins.unidadmedida}</td>\r\n                          <td class=\"text-center\">${ins.disponibilidad} ${ins.simbolo}</td>`;\r\n          tablaDetalleInsumos.prepend(tr);\r\n        });\r\n      }\r\n\r\n\r\n      function validarPasswordDcto():number{\r\n        const clave = claveEliminarOrden.find(c => c.clave=='clave_para_eliminar_factura');\r\n        if(clave?.valor_final!==null && inputEliminarClave.value !== clave?.valor_final){\r\n          msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n          return 0;\r\n        }\r\n        return 1;\r\n      }\r\n\r\n    }\r\n  \r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.pedidosguardados')){\r\n\r\n    let indiceFila=0, control=0, tablaPedidosGuardados:HTMLElement;\r\n/*\r\n    type cajasapi = {\r\n        id:string,\r\n        idtipoconsecutivo: string,\r\n        nombre: string,\r\n        negocio: string\r\n      };\r\n  \r\n      let cajas:cajasapi[]=[], unacaja:cajasapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allcajas\"; //llamado a la API REST y se trae todos los productos\r\n            const respuesta = await fetch(url); \r\n            cajas = await respuesta.json(); \r\n            console.log(cajas);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaPedidosGuardados = ($('#tablaPedidosGuardados') as any).DataTable(configdatatables);\r\n\r\n    document.querySelector('#tablaPedidosGuardados')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"eliminarPedidoGuardado\")||target.parentElement?.classList.contains(\"eliminarPedidoGuardado\"))eliminarPedidoGuardado(e);\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar cotizacion por completo del sistema  //////////////////////\r\n    function eliminarPedidoGuardado(e:Event){\r\n      let idpedidoguardado = (e.target as HTMLElement).parentElement!.id, info = (tablaPedidosGuardados as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idpedidoguardado = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaPedidosGuardados as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: `Desea eliminar la orden guardado #${idpedidoguardado}?`,\r\n          text: \"La orden/cotizacion guardado sera eliminado definitivamente del sistema.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idpedidoguardado);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarPedidoGuardado\"; // llama controlador cajacontrolador.php\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaPedidosGuardados as any).row(indiceFila).remove().draw(); \r\n                        (tablaPedidosGuardados as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n    \r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCaja') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.pendienteDespacho')){\r\n\r\n    Object.assign(configdatatables25reg, { order: [[ 1, 'desc' ]] });\r\n    ($('#tabladespachosPendientes') as any).DataTable(configdatatables25reg);\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.adicionarProducto')){\r\n        \r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const btnUpdateCreditoSeparado = document.querySelector('#btnUpdateCreditoSeparado') as HTMLButtonElement;\r\n\r\n        interface i_itemDetalle {\r\n            id:string, //id del registro de la tabla productosseparados\r\n            idcredito:string,\r\n            idproducto: string,\r\n            idunidadmedida:string,\r\n            tipoproducto:string,\r\n            tipoproduccion:string,\r\n            promediostock:number,\r\n            rendimientoestandar?:string,\r\n            factor?:number,\r\n            nombreproducto:string,\r\n            unidadmedida:string,\r\n            preciopersonalizado:string,\r\n            sku:string,\r\n            stockminimo?:string,\r\n\r\n            capital?:number,            //DATOS DEL CREDITO\r\n            abonoinicial?:number,      //abono inicial en el credito\r\n            saldopendiente?:number,\r\n            cantidadcuotas?:number,\r\n            interes?:string,           // 1 = si interes en el credito, 0 = no interes en el credito\r\n            interestotal?:number,      //interes total dlecredito en porcentaje\r\n            valorinterestotal?:number, //valor del interes total de credito\r\n            montototal?:number,\r\n            descuentocredito?:number,  //descuneto general en el credito\r\n            \r\n            costo:number,\r\n            valorunidad:number,\r\n            descuento:number,  //se calcula para productos nuevos agregados\r\n            cantidad:number,   //se calcula para productos nuevos agregados\r\n            stock?:number,\r\n            base:number,       //se calcula para productos nuevos agregados\r\n            impuesto:string,\r\n            valorimp:number,   //se calcula para productos nuevos agregados\r\n            subtotal:number,   //se calcula para productos nuevos agregados\r\n            total:number,      //se calcula para productos nuevos agregados\r\n        }\r\n\r\n        interface i_allProducts {\r\n            id:string,  //id del producto\r\n            idunidadmedida:string, \r\n            nombre:string,\r\n            impuesto:string,\r\n            tipoproducto:string, \r\n            tipoproduccion:string, \r\n            sku:string, \r\n            unidadmedida:string,\r\n            promediostock:number,\r\n            preciopersonalizado:string,\r\n            rendimientoestandar:string, \r\n            stockminimo:string,\r\n            precio_compra:number,\r\n            precio_venta:number\r\n            habilitarventa:string, \r\n            visible:string,\r\n        }\r\n\r\n        interface Item {\r\n            id_impuesto: number,\r\n            facturaid: number,\r\n            basegravable: number,\r\n            valorimpuesto: number\r\n        }\r\n\r\n\r\n        let factimpuestos:Item[] = [];\r\n        let carrito:i_itemDetalle[]=[];\r\n        let allproducts:i_allProducts[] = [];\r\n        let filteredData: {id:string, text:string, tipo:string, tipoproducto:string, tipoproduccion:string, sku:string, unidadmedida:string, promediostock:number}[];   //tipoproducto = 0 es producto simple,  1 = compuesto,  si no viene es subproducto, tipo=0 es producto(simple o compuesto), tipo=1 es subproducto\r\n        const valorTotal = {subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, total: 0}; //datos global de la venta\r\n        const dataCredit = {capital:0, abonoinicial:0, saldopendiente:0, cantidadcuotas:0, interes:'0', interestotal:0, valorinterestotal:0, montototal:0, descuentocredito: 0};\r\n\r\n        const constImp: {[key:string]: number} = {};\r\n        constImp['excluido'] = 0;\r\n        constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n        constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n        constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n        constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n        constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allproducts\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y compuestos\r\n                const respuesta = await fetch(url);\r\n                const resultado:i_allProducts[] = await respuesta.json();\r\n                filteredData = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1').map(item => ({ id: item.id, text: item.nombre, tipo:item.tipoproducto??'1', tipoproducto: item.tipoproducto, tipoproduccion: item.tipoproduccion, sku: item.sku, unidadmedida: item.unidadmedida, promediostock: item.promediostock }));\r\n                activarselect2();\r\n                allproducts = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1');\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n        \r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const idcreditoURL = parametrosURL.get('id');\r\n        if(idcreditoURL!=null && /^\\d+$/.test(idcreditoURL) && Number(idcreditoURL) >= 1){\r\n            (async ()=>{\r\n                try {\r\n                    const url = \"/admin/api/detalleProductosCredito?id=\"+idcreditoURL; //llamado a la API REST y trae el detalle de los productos de credito/separado\r\n                    const respuesta = await fetch(url); \r\n                    const resultado:i_itemDetalle[] = await respuesta.json();\r\n                    console.log(resultado);\r\n                    carrito = resultado.map(item =>{\r\n                        \r\n                        return {\r\n                            id: item.id,\r\n                            idcredito: item.idcredito,\r\n                            idproducto:item.idproducto,\r\n                            idunidadmedida: item.idunidadmedida,\r\n                            tipoproducto: item.tipoproducto, \r\n                            tipoproduccion: item.tipoproduccion,\r\n                            promediostock: Number(item.promediostock),\r\n                            rendimientoestandar: item.rendimientoestandar,\r\n                            nombreproducto: item.nombreproducto, \r\n                            unidadmedida: item.unidadmedida,\r\n                            preciopersonalizado: item.preciopersonalizado,\r\n                            sku: item.sku,\r\n                            costo: Number(item.costo),\r\n                            valorunidad: Number(item.valorunidad),\r\n                            descuento: Number(item.descuento), //descuento del producto\r\n                            cantidad: Number(item.cantidad),\r\n                            stock: Number(item.cantidad),\r\n                            base: Number(item.base),\r\n                            impuesto: item.impuesto,\r\n                            valorimp: Number(item.valorimp),\r\n                            subtotal: Number(item.subtotal),\r\n                            total: Number(item.total),\r\n                            factor: 1\r\n                        }\r\n                    });\r\n                    carrito.forEach(c =>printItemTable(c.idproducto, c.unidadmedida, c.cantidad, c.nombreproducto, c.valorunidad, c.total));\r\n                    //obtener datos del credito\r\n\r\n                    dataCredit.capital = Number(resultado[0].capital);\r\n                    dataCredit.abonoinicial = Number(resultado[0].abonoinicial!);\r\n                    dataCredit.saldopendiente = Number(resultado[0].saldopendiente);\r\n                    dataCredit.cantidadcuotas = Number(resultado[0].cantidadcuotas);\r\n                    dataCredit.interes = resultado[0].interes!;\r\n                    dataCredit.interestotal = resultado[0].interestotal!;\r\n                    dataCredit.valorinterestotal = Number(resultado[0].valorinterestotal!);\r\n                    dataCredit.montototal = Number(resultado[0].montototal);\r\n                    dataCredit.descuentocredito = Number(resultado[0].descuentocredito!);\r\n                    \r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n        \r\n        \r\n\r\n        function activarselect2(){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });  \r\n        }\r\n\r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos)(document.querySelector('#unidadmedida') as HTMLInputElement).value = datos.unidadmedida;\r\n        });\r\n\r\n        btnAddItem.addEventListener('click', (e)=>{\r\n            let cantidad = parseFloat((document.querySelector('#cantidad') as HTMLInputElement).value);\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            console.log(datos);\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.idproducto==datos.id);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    //const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!;\r\n                    const productSelected = allproducts.find(x=>x.id==datos.id)!;\r\n\r\n                    const productototal = Number(productSelected.precio_venta)*cantidad;\r\n                    const productovalorimp = productototal*constImp[productSelected.impuesto??'0']; //si producto.impuesto es null toma el valor de cero\r\n\r\n                    const item:i_itemDetalle = {\r\n                        id: '',\r\n                        idcredito: idcreditoURL!,\r\n                        idproducto:productSelected.id,\r\n                        idunidadmedida: productSelected.idunidadmedida,\r\n                        //tipo: itemselected.tipo,  ////tipo = 0 es producto (simple o compuesto produccion),  1 = subproducto\r\n                        tipoproducto: productSelected.tipoproducto, \r\n                        tipoproduccion: productSelected.tipoproduccion,\r\n                        promediostock: Number(productSelected.promediostock),\r\n                        rendimientoestandar: productSelected.rendimientoestandar,\r\n                        nombreproducto: productSelected.nombre, \r\n                        unidadmedida: productSelected.unidadmedida,\r\n                        preciopersonalizado: productSelected.preciopersonalizado,\r\n                        sku: productSelected.sku,\r\n                        costo: Number(productSelected.precio_compra),\r\n                        valorunidad: Number(productSelected.precio_venta),\r\n                        descuento: 0,\r\n                        cantidad: cantidad,\r\n                        stock: cantidad,\r\n                        base: productototal-productovalorimp,\r\n                        impuesto: productSelected.impuesto,\r\n                        valorimp: productovalorimp,\r\n                        subtotal: productototal,\r\n                        total: productototal,\r\n                        factor: 1,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(productSelected.id, productSelected.unidadmedida, cantidad, productSelected.nombre, productSelected.precio_venta, item.total);\r\n                    valorCarritoTotal();\r\n                }else{\r\n                    carrito[index].cantidad = cantidad;\r\n                    carrito[index].subtotal = (carrito[index].valorunidad)*carrito[index].cantidad;\r\n                    carrito[index].total = carrito[index].subtotal;\r\n                    //calculo del impuesto y base por producto en el carrito deventas\r\n                    carrito[index].valorimp = parseFloat((carrito[index].total*constImp[carrito[index].impuesto??0]).toFixed(3));\r\n                    carrito[index].base = parseFloat((carrito[index].total-carrito[index].valorimp).toFixed(3));\r\n                    //calcular valores\r\n                    const tr = document.querySelector(`[data-id=\"${carrito[index].idproducto}\"]`)!;\r\n                    tr.children[1].textContent = carrito[index].cantidad+'';\r\n                    valorCarritoTotal();\r\n                }\r\n\r\n            }\r\n        });\r\n\r\n        function printItemTable(id:string, unidadmedida:string, cantidad:number, nombre:string, valorunidad:number, total:number){\r\n            //let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            /*\r\n            options = \"\";\r\n            const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n            productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            */\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.insertAdjacentHTML('afterbegin', \r\n                `<td class=\"p-4\">${nombre}</td>\r\n                <td class=\"p-4\">${cantidad}</td>\r\n                <td class=\"p-4\">${unidadmedida}</td>\r\n                <td class=\"p-4\">$ ${valorunidad.toLocaleString()}</td>\r\n                <td class=\"p-4\">$ ${total.toLocaleString()}</td>\r\n                <td class=\"p-4 flex items-center justify-center gap-2\">\r\n                    <button class=\"flex items-center gap-1 px-3 py-1 text-base text-indigo-600 border border-indigo-200 rounded-lg hover:bg-indigo-50\">\r\n                        👁 Ver\r\n                    </button>\r\n                    <button class=\"eliminarItem w-11 h-11 flex items-center justify-center text-rose-600 border border-rose-200 rounded-full hover:bg-rose-50 text-xl\">❌</button>\r\n                </td>`);\r\n            tablaItems?.appendChild(tr);\r\n        }\r\n\r\n\r\n        function valorCarritoTotal(){\r\n            //calcular el impuesto discriminado por tarifa\r\n            const idimpuesto: Record<string, number> = {'0': 1, '5': 2, '16': 3, '19': 4, 'excluido': 5, '8': 6 };\r\n            const objbase:{'0':number, '5':number, '16':number, '19':number, 'excluido':number, '8':number} = {'0': 0, '5': 0, '16': 0, '19': 0, 'excluido':0, '8': 0};\r\n\r\n            const mapImpuesto = new Map();\r\n            carrito.forEach(x=>{\r\n                if(x.impuesto){\r\n                if(mapImpuesto.has(x.impuesto)){\r\n                    const valor = mapImpuesto.get(x.impuesto) + x.total*constImp[x.impuesto];\r\n                    mapImpuesto.set(x.impuesto, valor);\r\n                }else{\r\n                    mapImpuesto.set(x.impuesto, x.total*constImp[x.impuesto]);\r\n                }\r\n                }\r\n                if(x.impuesto == null)x.impuesto = \"excluido\";\r\n                objbase[x.impuesto as keyof typeof objbase] += x.base;\r\n                const impValor = mapImpuesto.get(x.impuesto)??0;\r\n                const index = factimpuestos.findIndex(Obj=>Obj.id_impuesto == idimpuesto[x.impuesto]);\r\n                if(index!=-1){ //si existe remplazar obj\r\n                    factimpuestos[index] = {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor};\r\n                }else{\r\n                    factimpuestos = [...factimpuestos, {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor}];\r\n                }\r\n            });\r\n\r\n            //Valor del impuesto total de todos los productos, es decir de la factura;\r\n            let valorTotalImp:number = 0;\r\n            for(let valorImp of mapImpuesto.values())valorTotalImp += valorImp;\r\n            \r\n            valorTotal.valorimpuestototal = parseFloat(valorTotalImp.toFixed(3));  //valor del impuesto total factura de todos los productos\r\n            valorTotal.subtotal = carrito.reduce((total, x)=>x.total+total, 0);\r\n            valorTotal.base = valorTotal.subtotal - valorTotal.valorimpuestototal;  //valor de la base total factura de todos los productos\r\n            valorTotal.total = valorTotal.subtotal+dataCredit.valorinterestotal-dataCredit.descuentocredito-dataCredit.abonoinicial;\r\n            //console.log(valorTotal);\r\n            //console.log(factimpuestos);\r\n            document.querySelector('#subTotal')!.textContent = '$'+valorTotal.subtotal.toLocaleString();\r\n            (document.querySelector('#impuesto') as HTMLElement).textContent = '$'+valorTotalImp.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n            document.querySelector('#total')!.textContent = '$ '+(valorTotal.total).toLocaleString(); //+ interes - descuneto - abonoinicial\r\n            \r\n        }\r\n\r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaItems?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            //const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n        \r\n            if((e.target as HTMLElement).classList.contains('eliminarItem')){ //se trae todoscon true menos el que coincida con iditem y tipoitem\r\n                carrito = carrito.filter(x => x.idproducto!==iditem);\r\n                tablaItems?.querySelector(`TR[data-id=\"${iditem}\"]`)?.remove();\r\n            }\r\n            valorCarritoTotal();\r\n            //itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n\r\n        btnUpdateCreditoSeparado.addEventListener('click', ()=>{\r\n            //validar que el montototal no sea menor a lo abonado hasta la fecha\r\n            if(valorTotal.total< (dataCredit.montototal-dataCredit.saldopendiente)){\r\n                Swal.fire('El valor del credito es inferior de lo que se ha abonado.', '', 'error')\r\n                return;\r\n            }\r\n\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Esta seguro de actualizar la orden?',\r\n                text: \"Se procesara la orden con todos los productos del separado\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('idcredito', idcreditoURL!);\r\n                        datos.append('ids', JSON.stringify(carrito.map(x=>x.id)));\r\n                        datos.append('nuevosproductos', JSON.stringify(carrito));\r\n\r\n                        datos.append('factimpuestos', JSON.stringify(factimpuestos));\r\n                        datos.append('capital', valorTotal.subtotal+'');\r\n                        datos.append('saldopendiente', (dataCredit.saldopendiente+valorTotal.total-dataCredit.montototal)+'');\r\n                        datos.append('montocuota', (Math.ceil((valorTotal.total/dataCredit.cantidadcuotas)*100)/100)+'');\r\n                        datos.append('montototal', valorTotal.total+'');\r\n                        datos.append('totalunidades', carrito.reduce((total, x)=>x.cantidad+total, 0)+'');\r\n                        \r\n                        datos.append('base', valorTotal.base.toFixed(3));  //base global del credito\r\n                        datos.append('valorimpuestototal', valorTotal.valorimpuestototal+''); //valor total del impuesto dle credito. \r\n                        datos.append('dctox100', valorTotal.dctox100+'');\r\n                        datos.append('descuento', dataCredit.descuentocredito+''); //descuento global de credito\r\n                    \r\n                        try {\r\n                            const url = \"/admin/api/editarOrdenCreditoSeparado\";  //api llamada a trasladosinvcontrolador\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                                /*setTimeout(() => {\r\n                                    window.location.href = `/admin/almacen/trasladarinventario`;\r\n                                }, 1600);*/\r\n                                Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()\r\n                }\r\n            });\r\n        });\r\n\r\n    }\r\n})();","(()=>{\r\n  if(document.querySelector('.detallecredito')){\r\n\r\n     \r\n    const btnajustarCredito = document.querySelector('#ajustarCredito') as HTMLButtonElement;\r\n    const btnDetalleProductos = document.querySelector('#btnDetalleProductos') as HTMLButtonElement;\r\n    const btnAbonar = document.querySelector('#btnAbonar') as HTMLButtonElement;\r\n    const btnEditarCrearAbono = document.querySelector('#btnEditarCrearAbono') as HTMLInputElement;\r\n    const btnEditarCrearPagoTotal = document.querySelector('#btnEditarCrearPagoTotal') as HTMLInputElement;\r\n    const btnPagarTodo = document.querySelector('#btnPagarTodo') as HTMLButtonElement;\r\n    const miDialogoAjustarCredito = document.querySelector('#miDialogoAjustarCredito') as any;\r\n    const miDialogoAbono = document.querySelector('#miDialogoAbono') as any;\r\n    const miDialogoPagoTotal = document.querySelector('#miDialogoPagoTotal') as any;\r\n    const miDialogoDetalleProducto = document.querySelector('#miDialogoDetalleProducto') as any;\r\n    const modalcambioMedioPago:any = document.querySelector(\"#cambioMedioPago\");\r\n    //const pagarTodo = document.querySelector('#pagarTodo') as HTMLButtonElement;\r\n    const totalPagado = document.querySelector('#totalPagado') as HTMLSpanElement;\r\n    const numCuota = document.querySelector('#numCuota') as HTMLLabelElement;\r\n    const selectMediopago = document.querySelector('#selectMediopago') as HTMLSelectElement;\r\n    const inputPasswordAjustarCredito = document.querySelector('#inputPasswordAjustarCredito') as HTMLInputElement;\r\n    let contentMP:HTMLButtonElement, idcuota:string = '0', idcredito:string = '0', totalpagado:string = '0', idmediopago:string = '0', mediopagado:string = '0';\r\n    \r\n    let printerBT:string = getParam.impresora_principal_de_CAJA_para_Android_por_BT.valor_final;\r\n    let indiceFila=0, tablacuotas:HTMLElement;\r\n\r\n    interface clavesApi {\r\n      clave:string,\r\n      valor_default:string|null,\r\n      valor_final:string|null,\r\n      valor_local:string|null\r\n    };\r\n\r\n    let password:clavesApi[];\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          password = resultado;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n    \r\n    document.addEventListener(\"click\", cerrarDialogoExterno);\r\n     \r\n    //////////////////  TABLA //////////////////////\r\n    tablacuotas = ($('#tablacuotas') as any).DataTable(configdatatables);\r\n\r\n\r\n    btnajustarCredito?.addEventListener('click', ():void=>{\r\n      miDialogoAjustarCredito.showModal();\r\n    });\r\n\r\n    btnDetalleProductos?.addEventListener('click', ():void=>{\r\n      miDialogoDetalleProducto.showModal();\r\n    });\r\n\r\n    //btn para abonar credito\r\n    btnAbonar?.addEventListener('click', ():void=>{\r\n      miDialogoAbono.showModal();\r\n    });\r\n\r\n    //btn para abonar credito\r\n    btnPagarTodo?.addEventListener('click', ():void=>{\r\n      miDialogoPagoTotal.showModal();\r\n    });\r\n\r\n\r\n    btnEditarCrearAbono.addEventListener('click', ()=>{\r\n      btnEditarCrearAbono.disabled = true;\r\n      (document.querySelector('#formCrearUpdateAbono') as HTMLFormElement).submit();\r\n    });\r\n    btnEditarCrearPagoTotal.addEventListener('click', ()=>{\r\n      btnEditarCrearPagoTotal.disabled = true;\r\n      (document.querySelector('#formCrearUpdatePagoTotal') as HTMLFormElement).submit();\r\n    });\r\n    \r\n\r\n    const saldopendiente = (document.querySelector('#saldopendiente') as HTMLInputElement).value;\r\n    document.querySelector('#abonoTotalAntiguo')?.addEventListener(\"input\", (e:Event)=>{\r\n      const abonoTotalAntiguo = (e.target as HTMLInputElement);\r\n      if(Number(abonoTotalAntiguo.value)>Number(saldopendiente))abonoTotalAntiguo.value = '';\r\n    });\r\n\r\n    ////////////// Evento a la tabla cuotas ///////////////\r\n    document.querySelector('#tablacuotas')?.addEventListener(\"click\", (e:Event)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLButtonElement;\r\n      if(target?.classList.contains(\"mediosdepago\")||target.parentElement?.classList.contains(\"mediosdepago\"))cambiomediopago(target);\r\n      if(target?.classList.contains(\"anularAbono\"))anularAbono(target);\r\n      if(target?.classList.contains(\"printPOSAbono\"))printPOSComprobanteAbono(target.parentElement?.id);\r\n    });\r\n\r\n\r\n    function cambiomediopago(target:HTMLButtonElement){\r\n      document.querySelector('#textMP')!.textContent = 'Pago por '+target.textContent+': ';\r\n      idcuota = target.id;\r\n      totalpagado = target.dataset.totalpagado??'0';\r\n      idcredito = target.dataset.idcredito??'0';\r\n      idmediopago = target.dataset.idmediopago??'0';\r\n      mediopagado = target.dataset.mediopagado??'0';\r\n      contentMP = target;\r\n      totalPagado.textContent = '$ '+Number(mediopagado).toLocaleString();\r\n      numCuota.textContent = 'Credito N° : '+idcredito;\r\n      selectMediopago.value = idmediopago;\r\n      modalcambioMedioPago.showModal();\r\n    }\r\n\r\n\r\n    document.querySelector('#formCambioMedioPago')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      actualizarMediosPago();\r\n    });\r\n\r\n\r\n    async function actualizarMediosPago(){\r\n      const datos = new FormData();\r\n      datos.append('id', idcuota);\r\n      datos.append('idmediopago', idmediopago);\r\n      datos.append('id_credito', idcredito);\r\n      datos.append('idnuevomediopago', selectMediopago.value);\r\n      datos.append('valor', mediopagado);\r\n      try {\r\n          const url = \"/admin/api/cuota/cambioMedioPagoSeparado\";  //va al controlador creditoscontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            updateMP(resultado.mediosPagoUpdate);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n      modalcambioMedioPago.close();\r\n    }\r\n\r\n\r\n    function updateMP(mediosPagoUpdate:{id:string, idcuota:string, mediopago_id:string, valor:string}){\r\n      const {mediopago_id} = mediosPagoUpdate;\r\n      contentMP.textContent = selectMediopago.options[selectMediopago.selectedIndex].textContent;\r\n      contentMP.dataset.idmediopago = mediopago_id;\r\n    }\r\n\r\n\r\n\r\n    document.querySelector('#formAjustarCredito')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      const v:number = validarPasswordDcto();\r\n      if(!v)return;\r\n      ajustarCreditoAntiguo();\r\n    });\r\n\r\n    function validarPasswordDcto():number{\r\n      const clave = password.find(c => c.clave=='clave_para_ajustar_credito');\r\n      if(inputPasswordAjustarCredito && clave?.valor_final!==null && inputPasswordAjustarCredito.value !== clave?.valor_final){\r\n        msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalertaClaveAjustarCredito') as HTMLElement));\r\n        return 0;\r\n      }\r\n      return 1;\r\n    }\r\n\r\n\r\n    async function ajustarCreditoAntiguo(){\r\n      const id:string = (document.querySelector('#idcredito') as HTMLInputElement).value;\r\n      const abonototalantiguo = (document.querySelector('#abonoTotalAntiguo') as HTMLInputElement).value||'0';\r\n      const recargo = (document.querySelector('#recargo') as HTMLInputElement).value||'0';\r\n      const datos = new FormData();\r\n      datos.append('id', id);\r\n      datos.append('recargo', recargo);\r\n      datos.append('abonototalantiguo', abonototalantiguo);\r\n      datos.append('fechainicio', (document.querySelector('#ajustarFechaInicio') as HTMLInputElement).value);\r\n      try {\r\n          const url = \"/admin/api/ajustarCreditoAntiguo\";  //va al controlador creditoscontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            ajustarIndicadores(abonototalantiguo, recargo);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n      miDialogoAjustarCredito.close();\r\n    }\r\n\r\n\r\n    function ajustarIndicadores(abonototalantiguo:string, recargo:string){\r\n      const capital:number = Number((document.querySelector('#capital') as HTMLInputElement).value);\r\n      const abonoinicial:number = Number((document.querySelector('#abonoinicial') as HTMLInputElement).value);\r\n      const montototal:number = Number((document.querySelector('#montototal') as HTMLInputElement).value);\r\n      const saldopendiente:number = Number((document.querySelector('#saldopendiente') as HTMLInputElement).value);\r\n      document.querySelector('#abonoInicialText')!.textContent = '$ '+abonototalantiguo;\r\n      document.querySelector('#interesText')!.textContent = '$ '+recargo;\r\n      document.querySelector('#creditoTotalText')!.textContent = '$ '+(capital - abonoinicial + Number(recargo)).toLocaleString();\r\n      document.querySelector('#saldopendientetext')!.textContent = '$ '+(capital+Number(recargo)-abonoinicial-Number(abonototalantiguo)).toLocaleString();\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if (f=== miDialogoAjustarCredito || f === miDialogoAbono || f === miDialogoDetalleProducto || f === modalcambioMedioPago || (f as HTMLInputElement).value === 'salir' || (f as HTMLInputElement).value === 'Cancelar' \r\n          || (f as HTMLElement).id == 'btnXCerrarModalDetalleProducto' || (f as HTMLElement).id == 'btnXCerrarModalAbono' || f === miDialogoPagoTotal\r\n          || (f as HTMLElement).id == 'btnXCerrarModalPagoTotal' ) {\r\n        miDialogoAbono.close();\r\n        miDialogoPagoTotal.close();\r\n        miDialogoDetalleProducto.close();\r\n        modalcambioMedioPago.close();\r\n        miDialogoAjustarCredito.close();\r\n      }\r\n    }\r\n\r\n\r\n    function anularAbono(target: HTMLButtonElement){\r\n      const idabono = target.parentElement?.id;\r\n      const fila = target.closest('tr');\r\n      if(idabono==undefined)return;\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea anular el abono registrado',\r\n          text: \"El abono, seran anulado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  try {\r\n                      const url = \"/admin/api/creditos/anularAbono?id=\"+idabono;\r\n                      const respuesta = await fetch(url); \r\n                      const resultado = await respuesta.json();\r\n                      if(resultado.exito !== undefined){\r\n                        fila?.remove();\r\n                        Swal.fire(resultado.exito[0], '', 'success');\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error');\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    async function printPOSComprobanteAbono(idabono:string|undefined){\r\n      if(idabono==undefined)return;\r\n      try{\r\n        const url = \"/admin/api/creditos/getAbono?id=\"+idabono; //llamado a la API REST - creditocontrolador \r\n        const respuesta = await fetch(url); \r\n        const resultado = await respuesta.json();\r\n        const isAndroid = /Android/i.test(navigator.userAgent);\r\n        if(printerBT === '1'){\r\n          const builder = new ticketAbonoBuilder(resultado);\r\n          const ticket = await builder.generate(true); //true para version buffer bytes\r\n          const base64 = bytesToBase64(ticket);\r\n          if(isAndroid)window.location.href = `rawbt:base64,${base64}`;\r\n          //descargar .bin a equipo\r\n          /*const blob = new Blob([ticket], { type: 'application/octet-stream' });\r\n          const url = URL.createObjectURL(blob);\r\n          const a = document.createElement('a');\r\n          a.href = url;\r\n          a.download = 'ticket.bin';\r\n          a.click();\r\n          URL.revokeObjectURL(url);*/\r\n        }\r\n      }catch(error){\r\n        console.log(error);\r\n      }\r\n\r\n      if(!isNaN(Number(idabono)))\r\n        window.open(\"/admin/printPDFAbonoCredito?id=\" + idabono, \"_blank\"); //controlador printcontrolador\r\n    }\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.creditos')){\r\n\r\n    type creditsapi = {\r\n      id:string,\r\n      id_fksucursal: string,\r\n      factura_id: string,\r\n      cliente_id: string,\r\n      nombrecliente: string,\r\n      capital: string,\r\n      abonoinicial: string,\r\n      saldopendiente: string,\r\n      numcuota: string,\r\n      cantidadcuotas: string,\r\n      montocuota: string,\r\n      frecuenciapago: string,\r\n      fechainicio: string,\r\n      interes: string,\r\n      interesxcuota: string,\r\n      interestotal: string,\r\n      valorinteresxcuota: string,\r\n      valorinterestotal: string,\r\n      montototal: string,\r\n      fechavencimiento: string,\r\n      productoentregado: string,\r\n      estado: string,\r\n      created_at: string,\r\n    };\r\n    \r\n    /*interface Item {\r\n      id_impuesto: number,\r\n      facturaid: number,\r\n      basegravable: number,\r\n      valorimpuesto: number\r\n    }\r\n    let factimpuestos:Item[] = [];*/\r\n\r\n    let printerBT:string = getParam.impresora_principal_de_CAJA_para_Android_por_BT.valor_final;\r\n    let credits:creditsapi[]=[], uncredito:creditsapi;\r\n    let indiceFila=0, control=0;\r\n\r\n\r\n    /*(async ()=>{\r\n      try {\r\n          const url = \"/admin/api/allcredits\"; //llamado a la API REST y se trae todos los productos\r\n          const respuesta = await fetch(url); \r\n          credits = await respuesta.json(); \r\n          console.log(credits);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();*/\r\n\r\n\r\n\r\n    \r\n    //////////////////  TABLA //////////////////////\r\n    Object.assign(configdatatablesgenerico, {order: [[ 0, 'desc' ]]});\r\n    let tablaCreditos = ($('#tablaCreditos') as any).DataTable(configdatatablesgenerico);\r\n\r\n\r\n    //evento a la tabla\r\n    document.querySelector('#tablaCreditos tbody')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"anularCredito\")||(e.target as HTMLElement).parentElement?.classList.contains(\"anularCredito\"))anularCredito(e);\r\n      if(target?.classList.contains(\"printPOSSeparado\"))printPOSSeparado(target.id);\r\n    });\r\n\r\n\r\n    function anularCredito(e:Event){\r\n      let idcredito = (e.target as HTMLElement).parentElement?.id!, info = (tablaCreditos as any).page.info();\r\n      if((e.target as HTMLElement)?.tagName === 'I')idcredito = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      indiceFila = (tablaCreditos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      \r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el credito',\r\n          text: \"El credito, seran anulado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idcredito);\r\n                  try {\r\n                      const url = \"/admin/api/anularSeparado\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();\r\n                      if(resultado.exito !== undefined){\r\n                        const datosActuales = (tablaCreditos as any).row(indiceFila).data();\r\n                        datosActuales[8] = '<div class=\" text-red-500 font-semibold\">Anulado</div>';\r\n                        datosActuales[9] = `<a class=\"btn-xs btn-bluedark\" href=\"/admin/creditos/detallecredito?id=${idcredito}\" title=\"Ver estadisticas del cliente\"><i class=\"fa-solid fa-chart-simple\"></i></a>`;\r\n                        (tablaCreditos as any).row(indiceFila).data(datosActuales).draw();\r\n                        (tablaCreditos as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success');\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error');\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    async function printPOSSeparado(idcredito:string){\r\n      //printTicketPOS(resultado.idfactura, resultado.dataInvoice);\r\n\r\n      try{\r\n        const url = \"/admin/api/getCreditoSeparado?id=\"+idcredito; //llamado a la API REST - creditocontrolador \r\n        const respuesta = await fetch(url); \r\n        const resultado = await respuesta.json();\r\n        const isAndroid = /Android/i.test(navigator.userAgent);\r\n        if(printerBT === '1'){\r\n          const builder = new ticketCreditoSeparadoBuilder(resultado);\r\n          const ticket = await builder.generate(true); //true para version buffer bytes\r\n          const base64 = bytesToBase64(ticket);\r\n          if(isAndroid)window.location.href = `rawbt:base64,${base64}`;\r\n          //descargar .bin a equipo\r\n          /*const blob = new Blob([ticket], { type: 'application/octet-stream' });\r\n          const url = URL.createObjectURL(blob);\r\n          const a = document.createElement('a');\r\n          a.href = url;\r\n          a.download = 'ticket.bin';\r\n          a.click();\r\n          URL.revokeObjectURL(url);*/\r\n        }\r\n        //window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");  //controlador printcontrolador\r\n      }catch(error){\r\n        console.log(error);\r\n      }\r\n\r\n      if(!isNaN(Number(idcredito)))\r\n        window.open(\"/admin/printPDFPOSSeparado?id=\" + idcredito, \"_blank\"); //controlador printcontrolador\r\n    }\r\n\r\n    \r\n    async function printTicketPOS(idfactura:string, datainvoice:DataInvoice){\r\n      \r\n      /*try {\r\n        const url = \"http://localhost:3100/api/printPOS/ticket1/CAJA\"; //llamado a la API REST apidiancontrolador.php\r\n        const respuesta = await fetch(url, {\r\n          method: 'POST',\r\n          headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n          body: JSON.stringify(datainvoice)\r\n        });\r\n        const resultado = await respuesta.json();\r\n        console.log(resultado);\r\n      } catch (error) {\r\n        console.log(error);\r\n      }*/\r\n    }\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.crearseparado')){\r\n\r\n    const POS = (window as any).POS;\r\n     \r\n    const btnCrearSeparado = document.querySelector('#btnCrearSeparado');\r\n    const miDialogoFacturar = document.querySelector('#miDialogoFacturar') as any;\r\n    const tablaSeparado = document.querySelector('#tablaSeparado tbody');\r\n    const btnPagar = document.getElementById('btnPagar') as HTMLInputElement;\r\n    const btnCaja = document.querySelector('#caja') as HTMLSelectElement; //select de la caja en el modal pagar\r\n\r\n\r\n    type conversionunidadesapi = {\r\n      id:string,\r\n      idproducto: string,\r\n      idsubproducto: string,\r\n      idunidadmedidabase: string,\r\n      idunidadmedidadestino: string,\r\n      nombreunidadbase: string,\r\n      nombreunidaddestino: string,\r\n      factorconversion: string,\r\n    };\r\n\r\n    interface Item {\r\n      id_impuesto: number,\r\n      facturaid: number,\r\n      basegravable: number,\r\n      valorimpuesto: number\r\n    }\r\n\r\n    let allConversionUnidades:conversionunidadesapi[] = [];\r\n    let filteredData: {id:string, text:string, tipo:string, tipoproduccion:string, impuesto:string, sku:string, unidadmedida:string, promediostock: string, rendimientoestandar:string, precio_compra:string, precio_venta:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n    let carrito:{id:string, idproducto:string,  tipoproducto: string, tipoproduccion:string, foto:string,costo:number, valorunidad:string, nombreproducto:string,  rendimientoestandar:string, unidad:string, stock: number, promediostock: number, factor: number, precio_venta: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total: number, precio_compra: number}[]=[];\r\n    const valorTotal = {subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, idtarifa: 0, valortarifa: 0, total: 0}; //datos global de la venta\r\n    let factimpuestos:Item[] = [], tipoventa:string=\"Contado\";\r\n    const mapMediospago = new Map();\r\n    \r\n    const constImp: {[key:string]: number} = {};\r\n    constImp['excluido'] = 0;\r\n    constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n    constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n    constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n    constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n    constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n    ($('#cliente') as any).select2({ placeholder: \"Seleccionar el cliente\", maximumSelectionLength: 1});\r\n    ($('#frecuenciapago') as any).select2({ placeholder: \"Seleccionar el cliente\", maximumSelectionLength: 1});\r\n\r\n     document.addEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n    (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allproducts\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n            const respuesta = await fetch(url); \r\n            const resultado:{id:string, nombre:string, tipoproducto:string, tipoproduccion:string, impuesto:string, sku:string, unidadmedida:string, promediostock:string, rendimientoestandar:string, precio_compra:string, precio_venta:string, visible:string, habilitarventa:string}[] = await respuesta.json();\r\n            filteredData = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1').map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'0', tipoproduccion: item.tipoproduccion??'0', impuesto: item.impuesto, sku: item.sku, unidadmedida: item.unidadmedida, promediostock: item.promediostock, rendimientoestandar: item.rendimientoestandar, precio_compra: item.precio_compra, precio_venta: item.precio_venta }));\r\n            activarselect2(filteredData);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    })();\r\n\r\n    (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allConversionesUnidades\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas las conversiones de unidades\r\n            const respuesta = await fetch(url); \r\n            allConversionUnidades = await respuesta.json();\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    })();\r\n\r\n    //DESACTIVADO EL CANAL DE VENTA\r\n    document.querySelector('#contenedorCanalVenta')?.classList.add('hidden');\r\n    document.querySelector('#canalVenta')?.removeAttribute('required');\r\n\r\n    function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string, promediostock:string}[]){\r\n      ($('#articulo') as any).select2({ \r\n          data: filteredData,\r\n          placeholder: \"Selecciona un item\",\r\n          maximumSelectionLength: 1,\r\n          /*\r\n          templateResult: function (data:{id:string, text:string, tipo:string}) {\r\n              // Personalizar cómo se muestra cada opción en el dropdown\r\n              if (!data.id) { return data.text; }  // Si no hay id, solo mostrar el texto\r\n              const html = `\r\n                  <div class=\"custom-option\">\r\n                      <span class=\"item-name\">${data.text}</span> \r\n                      <span class=\"item-type\">${data.tipo}</span>  <!-- Mostrar tipo adicional -->\r\n                  </div>`;\r\n              return $(html);  // Devolver el HTML personalizado\r\n          }*/\r\n      });\r\n    }\r\n\r\n    ////// EVENTO AL SELECT ARTICULOS O ITEMS PARA SELECCIONAR EL ITEM Y AÑADIR AL CARRITO ////// \r\n    $(\"#articulo\").on('change', (e)=>{\r\n        let datos = ($('#articulo') as any).select2('data')[0];\r\n        if(datos){\r\n          let cantidad = 1, itemselected = carrito.find(x=>x.idproducto==datos.id);\r\n          if(itemselected != undefined)cantidad += itemselected.stock;\r\n          actualizarCarrito(datos.id, cantidad, true);\r\n          $(\"#articulo\").val('null').trigger('change');\r\n        }\r\n    });\r\n\r\n    function actualizarCarrito(id:string, cantidad:number = 1, stateinput:boolean){\r\n      const index = carrito.findIndex(x=>x.idproducto==id);\r\n      if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n          const itemselected = filteredData.find(x=>x.id==id)!; //products es el arreglo de todos los productos traido por api\r\n          \r\n          const productototal = Number(itemselected.precio_venta)*cantidad;\r\n          const productovalorimp = productototal*constImp[itemselected.impuesto??'0']; //si producto.impuesto es null toma el valor de cero\r\n          \r\n          const item:{id: string, idproducto: string, tipoproducto: string, tipoproduccion:string, foto:string, costo:number, valorunidad:string, nombreproducto: string, rendimientoestandar:string, unidad: string, stock: number, promediostock: number, factor: number, precio_venta: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total: number, precio_compra:number} = {\r\n              id: '',\r\n              idproducto: itemselected?.id!,\r\n              tipoproducto: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n              tipoproduccion: itemselected.tipoproduccion,\r\n              foto: '',\r\n              costo: Number(itemselected.precio_compra),\r\n              valorunidad: itemselected.precio_venta,\r\n              nombreproducto: itemselected.text,\r\n              rendimientoestandar: itemselected.rendimientoestandar,\r\n              unidad: itemselected.unidadmedida,\r\n              stock: 1,\r\n              promediostock: Number(itemselected.promediostock),\r\n              factor: 1,\r\n              impuesto: itemselected.impuesto,\r\n              precio_venta: productototal,\r\n              subtotal: productototal,\r\n              base: productototal-productovalorimp,\r\n              valorimp: productovalorimp,\r\n              descuento: 0,\r\n              total: Number(itemselected.precio_venta),\r\n              precio_compra: Number(itemselected.precio_compra),\r\n          }\r\n          carrito = [...carrito, item];\r\n          POS.carrito = carrito;\r\n          printItemTable(id);\r\n      }else{  //si ya existe en el carrito, sumar\r\n        if(cantidad <= 0){\r\n          cantidad = 0;\r\n          carrito[index].total = 0;\r\n          //carrito = carrito.filter(x=>x.iditem != id);\r\n        }\r\n        \r\n        carrito[index].stock = cantidad;\r\n        /*const total:number = carrito[index].stock*carrito[index].precio_venta;\r\n        carrito[index].subtotal = total;\r\n        carrito[index].total = total;*/\r\n        carrito[index].subtotal = (carrito[index].precio_venta)*carrito[index].stock;\r\n        carrito[index].total = carrito[index].subtotal;\r\n        //calculo del impuesto y base por producto en el carrito deventas\r\n        carrito[index].valorimp = parseFloat((carrito[index].total*constImp[carrito[index].impuesto??0]).toFixed(3));\r\n        carrito[index].base = parseFloat((carrito[index].total-carrito[index].valorimp).toFixed(3));\r\n\r\n        if(stateinput)\r\n          (tablaSeparado?.querySelector(`TR[data-id=\"${id}\"] .inputcantidad`) as HTMLInputElement).value = carrito[index].stock+'';\r\n        (tablaSeparado?.querySelector(`TR[data-id=\"${id}\"]`)?.children?.[3] as HTMLElement).textContent = \"$\"+carrito[index].total.toLocaleString();\r\n        valorCarritoTotal();\r\n      }\r\n      //console.log(carrito);\r\n      /*if(cantidad<1){\r\n          carrito = carrito.filter(x=>x.iditem != id);\r\n      }*/\r\n    }\r\n\r\n    function printItemTable(id:string){\r\n        const uncarrito = carrito.find(x=>x.idproducto==id)!;\r\n        let options:string = '';\r\n\r\n        const productounidades = allConversionUnidades.filter(x => x.idproducto === id); \r\n        productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n\r\n        const tr = document.createElement('TR');\r\n        tr.classList.add('productselect');\r\n        tr.dataset.id = `${id}`;\r\n        //tr.dataset.tipo = `${item.tipo}`;\r\n        tr.insertAdjacentHTML('afterbegin', `\r\n          <td class=\"!p-2 !py-0 text-xl text-gray-500 leading-5\">${uncarrito.nombreproducto}</td> \r\n          <td class=\"!p-2 !py-0 text-xl text-gray-500 leading-5\"><select class=\"formulario__select selectunidad\">${options}</select></td>\r\n          <td class=\"!p-2 !py-0\"><div class=\"flex\"><button type=\"button\"><span class=\"menos material-symbols-outlined\">remove</span></button><input type=\"text\" class=\"inputcantidad w-20 px-2 text-center\" name=\"inputcantidad\" value=\"${uncarrito.stock}\"><button type=\"button\"><span class=\"mas material-symbols-outlined\">add</span></button></div></td>\r\n          <td class=\"!p-2 !py-0 text-xl text-gray-500 leading-5\">${uncarrito.precio_venta*uncarrito.stock}</td>\r\n          <td class=\"accionestd\"><div class=\"acciones-btns\"><button class=\"btn-md btn-red eliminarProducto\"><i class=\"fa-solid fa-trash-can\"></i></button></div></td>`);\r\n        tablaSeparado?.appendChild(tr);\r\n        valorCarritoTotal();\r\n    }\r\n\r\n    function valorCarritoTotal(){\r\n       //calcular el impuesto discriminado por tarifa\r\n      const idimpuesto: Record<string, number> = {'0': 1, '5': 2, '16': 3, '19': 4, 'excluido': 5, '8': 6 };\r\n      const objbase:{'0':number, '5':number, '16':number, '19':number, 'excluido':number, '8':number} = {'0': 0, '5': 0, '16': 0, '19': 0, 'excluido':0, '8': 0};\r\n\r\n      const mapImpuesto = new Map();\r\n      carrito.forEach(x=>{\r\n        if(x.impuesto){\r\n          if(mapImpuesto.has(x.impuesto)){\r\n            const valor = mapImpuesto.get(x.impuesto) + x.total*constImp[x.impuesto];\r\n            mapImpuesto.set(x.impuesto, valor);\r\n          }else{\r\n            mapImpuesto.set(x.impuesto, x.total*constImp[x.impuesto]);\r\n          }\r\n        }\r\n        if(x.impuesto == null)x.impuesto = \"excluido\";\r\n          objbase[x.impuesto as keyof typeof objbase] += x.base;\r\n          const impValor = mapImpuesto.get(x.impuesto)??0;\r\n          const index = factimpuestos.findIndex(Obj=>Obj.id_impuesto == idimpuesto[x.impuesto]);\r\n          if(index!=-1){ //si existe remplazar obj\r\n            factimpuestos[index] = {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor};\r\n          }else{\r\n            factimpuestos = [...factimpuestos, {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor}];\r\n          }\r\n      });\r\n\r\n      //Valor del impuesto total de todos los productos, es decir de la factura;\r\n      let valorTotalImp:number = 0;\r\n      for(let valorImp of mapImpuesto.values())valorTotalImp += valorImp;\r\n      \r\n      valorTotal.valorimpuestototal = parseFloat(valorTotalImp.toFixed(3));  //valor del impuesto total factura de todos los productos\r\n      valorTotal.subtotal = carrito.reduce((total, x)=>x.total+total, 0);\r\n      valorTotal.base = valorTotal.subtotal - valorTotal.valorimpuestototal;  //valor de la base total factura de todos los productos\r\n      valorTotal.total = valorTotal.subtotal + valorTotal.valortarifa - valorTotal.descuento;\r\n      //console.log(valorTotal);\r\n      //console.log(factimpuestos);\r\n      document.querySelector('#subTotal')!.textContent = '$'+valorTotal.subtotal.toLocaleString();\r\n      (document.querySelector('#impuesto') as HTMLElement).textContent = '$'+valorTotalImp.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n      document.querySelector('#total')!.textContent = '$ '+valorTotal.total.toLocaleString();\r\n      (document.querySelector('#montocuota') as HTMLInputElement).value = valorTotal.total+'';\r\n      //valorTotal.total = Number((document.querySelector('#abonoinicial') as HTMLInputElement).value);\r\n      //POS.gestionSubirModalPagar.valoresCredito\r\n      POS.valorTotal = valorTotal;\r\n      POS.mapMediospago = mapMediospago;\r\n      //**** recalcular valores del credito\r\n      POS.gestionSubirModalPagar.calculoTasaInteres();\r\n    }\r\n\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaSeparado?.addEventListener('click', (e:Event)=>{\r\n      const elementProduct = (e.target as HTMLElement)?.closest('.productselect');\r\n      const idProduct = (elementProduct as HTMLElement).dataset.id!;\r\n      //const precio = (elementProduct as HTMLElement).dataset.precio!;\r\n      const productoCarrito = carrito.find(x=>x.idproducto==idProduct);\r\n      if((e.target as HTMLElement).classList.contains('menos')){\r\n        actualizarCarrito(idProduct, productoCarrito!.stock-1, true);\r\n      }\r\n      \r\n      if((e.target as HTMLElement).classList.contains('inputcantidad')){\r\n        if((e.target as HTMLElement).dataset.event != \"eventInput\"){\r\n          e.target?.addEventListener('input', (e)=>{\r\n            let val = (e.target as HTMLInputElement).value;\r\n            val = val.replace(/[^0-9.]/g, '');\r\n            const partes = val.split('.');\r\n            if(partes.length > 2)val = partes[0]+'.'+partes.slice(1).join('');\r\n            if (val.startsWith('.'))val = '1';\r\n            if (val === '' || isNaN(parseFloat(val))) val = '0';\r\n\r\n            (e.target as HTMLInputElement).value = val;\r\n            actualizarCarrito(idProduct, Number((e.target as HTMLInputElement).value), false);\r\n          });\r\n          (e.target as HTMLElement).dataset.event = \"eventInput\"; //se marca al input que ya tiene evento añadido\r\n        }\r\n      }\r\n\r\n      if((e.target as HTMLElement).classList.contains('mas')){\r\n        actualizarCarrito(idProduct, productoCarrito!.stock+1, true);\r\n      }\r\n      \r\n      if((e.target as HTMLElement).classList.contains('eliminarProducto') || (e.target as HTMLElement).tagName == \"I\"){\r\n        carrito = carrito.filter(x=>x.idproducto != idProduct);\r\n        valorCarritoTotal();\r\n        tablaSeparado?.querySelector(`TR[data-id=\"${idProduct}\"]`)?.remove();\r\n      }\r\n    });\r\n\r\n\r\n    //btn para abrir modal de pago\r\n    btnCrearSeparado?.addEventListener('click', (e)=>{\r\n      e.preventDefault();\r\n      if((document.querySelector('#cliente') as HTMLSelectElement).value === ''){\r\n        msjAlert('error', 'Debe seleccionar el cliente.', (document.querySelector('#divmsjalerta') as HTMLElement));\r\n        return;\r\n      }\r\n      if((document.querySelector('#cantidadcuotas') as HTMLSelectElement).value === ''){\r\n        msjAlert('error', 'Debe indicar la cantidad de cuotas.', (document.querySelector('#divmsjalerta') as HTMLElement));\r\n        return;\r\n      }\r\n      if(carrito.length){\r\n        document.querySelector('.Efectivo')?.removeAttribute('readonly');\r\n        //document.querySelector('#inputscreditos')?.remove();  //elimina los inputs de credito en el modal de procesar pago.\r\n        document.querySelector('#campoabonoinicial')?.remove();\r\n        document.querySelector('#campocantidadcuotas')?.remove();\r\n        document.querySelector('#campomontocuota')?.remove();\r\n        document.querySelector('#abonoTotal')?.classList.remove('hidden');\r\n        document.querySelector('#textPrint')!.textContent = '¿Desea imprimir comprobante?';\r\n        tipoventa = \"Credito\";\r\n        //mapMediospago.clear();\r\n        POS.tipoventa = tipoventa;\r\n        //POS.valorTotal = valorTotal;\r\n        //POS.mapMediospago = mapMediospago;\r\n        POS.gestionSubirModalPagar.subirModalPagar();\r\n        miDialogoFacturar.showModal();\r\n      }\r\n    });\r\n\r\n\r\n    document.querySelector('#formfacturar')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      if(valorTotal.total <= 0 || valorTotal.subtotal <= 0){\r\n        msjAlert('error', 'Medio de pago no indicado', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n      //calcular si el totoal de los medios de pago es menor al abono inicial, abortar pago...\r\n      let totalMediosPago:number = 0;\r\n      for(let value of mapMediospago.values())totalMediosPago+=value;\r\n      if(totalMediosPago<POS.gestionSubirModalPagar.valoresCredito.abonoinicial){\r\n        msjAlert('error', 'Valor a pagar no corresponde', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n\r\n      btnPagar.disabled = true;\r\n      btnPagar.value = 'Procesando...';\r\n      procesarSeparado();\r\n    });\r\n\r\n\r\n    async function procesarSeparado(){\r\n      const imprimir = document.querySelector('input[name=\"imprimir\"]:checked') as HTMLInputElement;\r\n      const valoresCredito = POS.gestionSubirModalPagar.valoresCredito;\r\n      valoresCredito.cliente_id = (document.querySelector('#cliente') as HTMLSelectElement).value;\r\n      valoresCredito.valorpagado = valoresCredito.abonoinicial;\r\n      valoresCredito.cajaid = btnCaja.value;\r\n      valoresCredito.totalunidades = carrito.reduce((total, producto)=>producto.stock+total, 0)+'';\r\n      valoresCredito.base = valorTotal.base.toFixed(3);\r\n      valoresCredito.valorimpuestototal = valorTotal.valorimpuestototal+'';\r\n      valoresCredito.dctox100 = valorTotal.dctox100+'';\r\n      valoresCredito.descuento = valorTotal.descuento+'';\r\n      valoresCredito.nota = (document.querySelector('#nota') as HTMLInputElement).value;\r\n\r\n      const datos = new FormData();\r\n      datos.append('cliente_id', $('#cliente').val()as string);\r\n      datos.append('abonoinicial', $('#abonoinicial').val()as string);\r\n      datos.append('cantidadcuotas', $('#cantidadcuotas').val()as string);\r\n      datos.append('montocuota', $('#montocuota').val()as string);\r\n      datos.append('frecuenciapago', $('#frecuenciapago').val()as string);\r\n      datos.append('carrito', JSON.stringify(carrito.filter(x=>x.stock>0)));  //envio de todos los productos con sus cantidades\r\n      datos.append('mediospago', JSON.stringify(Array.from(mapMediospago, ([mediopago_id, valor])=>({mediopago_id, idcuota:0, valor}))));\r\n      datos.append('valorefectivo', mapMediospago.get('1')??'0');\r\n      datos.append('factimpuestos', JSON.stringify(factimpuestos));\r\n      datos.append('valoresCredito', JSON.stringify(valoresCredito));\r\n\r\n      datos.append('totalunidades', carrito.reduce((total, producto)=>producto.stock+total, 0)+'');\r\n      datos.append('base', valorTotal.base.toFixed(3));\r\n      datos.append('valorimpuestototal', valorTotal.valorimpuestototal+''); //valor total del impuesto. \r\n      datos.append('dctox100', valorTotal.dctox100+'');\r\n      datos.append('descuento', valorTotal.descuento+'');\r\n      //datos.append('nota', (document.querySelector('#nota') as HTMLInputElement).value);\r\n      try {\r\n          const url = \"/admin/api/crearSeparado\";  //va al controlador creditoscontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            /////// reinciar modulo de ventas\r\n            //vaciarventa();\r\n            btnPagar.disabled = false;\r\n            btnPagar.value = 'Pagar';\r\n            miDialogoFacturar.close();\r\n            \r\n            if(resultado.idcredito && imprimir.value === '1')\r\n              await printTicketSeparado(resultado.idcredito);\r\n            \r\n            setTimeout(() => { window.location.href = \"/admin/creditos\"; }, 900);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n    function printTicketSeparado(idcredito:string): Promise<void>{\r\n      return new Promise<void>((resolve, reject) => {\r\n        setTimeout(() => {\r\n          window.open(\"/admin/printPDFPOSSeparado?id=\" + idcredito, \"_blank\");\r\n          resolve();\r\n        }, 700);\r\n      })\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const miDialogoDescuento = POS.gestionarDescuentos.miDialogoDescuento;\r\n      const f = event.target;\r\n      if (f === miDialogoFacturar || f === miDialogoDescuento || (f as HTMLInputElement).closest('.salir') || (f as HTMLInputElement).value === 'salir' || (f as HTMLInputElement).value === 'Cancelar') {\r\n        miDialogoFacturar.close();\r\n        miDialogoDescuento.close();\r\n      }\r\n    }\r\n\r\n\r\n    POS.cerrarDialogoExterno = cerrarDialogoExterno;\r\n  }\r\n\r\n})();","\r\nclass ticketCreditoSeparadoBuilder extends EscPosBuilder{\r\n    private invoice: creditoSeparado;\r\n    constructor(invoice: creditoSeparado) {\r\n        super();\r\n        this.reset();\r\n        this.invoice = invoice;\r\n    }\r\n\r\n    async generate(buildBytes:boolean):Promise<string | Uint8Array> {\r\n        await this.header();\r\n        //if(this.invoice.tipoFactura === '1')this.customer(); //solo factura electronica\r\n        this.datosCreditoSeparado();\r\n        this.cliente();\r\n        this.items();\r\n        this.totals();\r\n        this.payments();\r\n        //if(this.invoice.tipoFactura === '1')this.infoResolution();  //solo factura electronica\r\n        await this.footer();\r\n        this.cut();\r\n        return this.build(buildBytes);\r\n    }\r\n\r\n    private async header() {\r\n        await this.image(`/build/img/${this.invoice.logo}`, {\r\n            width: 256,\r\n            align: 'center'\r\n        });\r\n        this.boldOn();\r\n        this.center(this.invoice.negocio.toUpperCase());\r\n        this.boldOff();\r\n        this.feed(1);\r\n        this.center(`NIT: ${this.invoice.nit.trim()}`);\r\n        this.center(`SEDE: ${this.invoice.sucursal.trim().toUpperCase()}`);\r\n        this.center(this.invoice.direccion.trim());\r\n        this.center(`TEL: ${this.invoice.telefono.trim()}`);\r\n        this.center(`Email: ${this.invoice.email.trim()}`);\r\n        this.feed(1);\r\n    }\r\n\r\n    /*private customer() { //cliente factura electronica\r\n        this.center(`Cliente: ${this.invoice.consumidorfinal.name}`);\r\n        this.center(`NIT: ${this.invoice.consumidorfinal.identification_number}`);\r\n    }*/\r\n\r\n    private datosCreditoSeparado(){\r\n        this.line();\r\n        this.setAlign('center');\r\n        this.text(`Fecha inicio: ${this.invoice.fechainicio.trim()}`);\r\n        this.text(`Fcha de finalizacion: ${this.invoice.fechafin.trim()}`);\r\n        this.text(`Vendedor: ${this.invoice.usuario?.nombre.trim()} ${this.invoice.usuario?.apellido.trim()}`);\r\n        this.bold(`CREDITO No: ${this.invoice.num_orden.trim()}`);\r\n        this.line();\r\n    }\r\n\r\n    private cliente(){\r\n        this.feed(1);\r\n        this.center(`Cliente: ${this.invoice.cliente.nombre.trim()} ${this.invoice.cliente.apellido.trim()}`);\r\n        this.center(`Documento: ${this.invoice.cliente.identificacion?.trim()??''}`);\r\n        this.center(`Telefono: ${this.invoice.cliente.telefono.trim()}`);\r\n        this.center(`Direccion: ${this.invoice?.direccionCliente?.direccion?.trim()||' - '}`);\r\n        this.feed(1);\r\n    }\r\n\r\n    private items() {\r\n        this.feed(1);\r\n        this.boldOn();\r\n        this.row3('CANT', 'UND', 'TOTAL', {col1:'left', col2:'right', col3:'right'}, [8, 16, 18]);\r\n        this.boldOff();\r\n        for(const item of this.invoice.productos) {\r\n            for(const line of this.wrap(item.nombreproducto.trim()))this.center(line);\r\n            //this.row(`${item.cantidad}  x  $${item.valorunidad.toLocaleString()}`, '$'+item.total.toLocaleString());\r\n            this.row3(item.cantidad.toString(), '$'+Number(item.valorunidad).toLocaleString(), '$'+Number(item.total).toLocaleString(), {col1:'left', col2:'right', col3:'right'}, [8, 16, 18]);\r\n        }\r\n    }\r\n\r\n    private totals() {\r\n        this.line();\r\n        this.feed(1);\r\n        this.setAlign('right');\r\n        this.text(`CREDITO TOTAL: $${Number(this.invoice.capital.trim()).toLocaleString()}`);\r\n        this.text(`Interes: $${Number(this.invoice.valorinterestotal.trim()).toLocaleString()}`);\r\n        this.text(`TOTAL ABONOS: $${Number(this.invoice.abonodecuotas.trim()).toLocaleString()}`);\r\n        this.text(`Descuento: $${Number(this.invoice.descuento.trim()).toLocaleString()}`);\r\n        this.line();\r\n        this.boldOn();\r\n        this.center(`SALDO PENDIENTE: $${Number(this.invoice.saldopendiente.trim()).toLocaleString()}`);\r\n        this.boldOff();\r\n    }\r\n\r\n    private payments() {\r\n        this.feed(2);\r\n        this.setAlign('center');\r\n        this.text('PAGOS');\r\n        for(const cuota of this.invoice.cuotas)\r\n            this.text(`${cuota.fechapagado}: $${cuota.valorpagado?.toLocaleString()}`);\r\n        \r\n        this.normalSize();\r\n        this.feed(1);\r\n        this.setAlign('left');\r\n        this.text(`Observacion: ${this.invoice.nota}`);\r\n        this.feed(2);\r\n    }\r\n\r\n    /*private infoResolution(){\r\n        this.setAlign('left');\r\n        this.text(`Resolucion: ${this.invoice.resolucion.resolucion}, Rango desde: ${this.invoice.resolucion.rangoinicial} hasta ${this.invoice.resolucion.rangofinal}`);\r\n        this.text(`CUFE: ${this.invoice.cufe || 'fe9c733f32770f5fcc4ef954f9ef663c54c752e6c07bdc144bb00627faadf9f648818da3e96ef8293547140fb1970d22'}`);\r\n        this.feed(2);\r\n    }*/\r\n\r\n    private async footer() {\r\n        this.setAlign('center');\r\n        this.feed(2);\r\n        this.text('***Para poder realizar un reclamo o devolución debe de presentar este ticket ***');\r\n        this.boldOn();\r\n        this.feed(1);\r\n        this.center('GRACIAS POR SU COMPRA');\r\n        this.boldOff();\r\n        this.feed(2);\r\n    }\r\n}\r\n\r\n\r\n\r\n//////////////////  DISEÑO DE TICKET PARA COMPROBANTE DE ABONOS  ///////////////////\r\nclass ticketAbonoBuilder extends EscPosBuilder{\r\n    private invoice: creditoSeparado;\r\n    constructor(invoice: creditoSeparado) {\r\n        super();\r\n        this.reset();\r\n        this.invoice = invoice;\r\n    }\r\n\r\n    async generate(buildBytes:boolean):Promise<string | Uint8Array> {\r\n        await this.header();\r\n        this.cliente();\r\n        this.totals();\r\n        await this.footer();\r\n        return this.build(buildBytes);\r\n    }\r\n\r\n    private async header() {\r\n        await this.image(`/build/img/${this.invoice.logo}`, {\r\n            width: 256,\r\n            align: 'center'\r\n        });\r\n        this.boldOn();\r\n        this.center(this.invoice.negocio.toUpperCase());\r\n        this.boldOff();\r\n        this.feed(1);\r\n        this.center(`NIT: ${this.invoice.nit.trim()}`);\r\n        this.center(`SEDE: ${this.invoice.sucursal.trim().toUpperCase()}`);\r\n        this.center(this.invoice.direccion.trim());\r\n        this.center(`TEL: ${this.invoice.telefono.trim()}`);\r\n        this.center(`Email: ${this.invoice.email.trim()}`);\r\n        this.feed(1);\r\n        this.line();\r\n    }\r\n\r\n    private cliente(){\r\n        this.feed(1);\r\n        this.center(`Cliente: ${this.invoice.cliente.nombre.trim()} ${this.invoice.cliente.apellido.trim()}`);\r\n        this.center(`Documento: ${this.invoice.cliente.identificacion?.trim()??''}`);\r\n        this.center(`Telefono: ${this.invoice.cliente.telefono.trim()}`);\r\n        this.center(`Direccion: ${this.invoice?.direccionCliente?.direccion?.trim()||' - '}`);\r\n        this.feed(1);\r\n    }\r\n\r\n    private totals() {\r\n        this.line();\r\n        this.feed(1);\r\n        this.setAlign('center');\r\n        this.bold(`CREDITO No: ${this.invoice.num_orden.trim()}`);\r\n        this.feed(2);\r\n        for(const cuota of this.invoice.cuotas){\r\n            this.text(`${cuota.fechapagado}  -  Abono No: ${cuota.numerocuota.trim()}`);\r\n            this.text(`Valor pagado: $${cuota.valorpagado?.toLocaleString()}`);\r\n        }\r\n    }\r\n\r\n    private async footer() {\r\n        this.normalSize();\r\n        this.cut();\r\n    }\r\n\r\n}\r\n\r\n","(()=>{\r\n    if(!document.querySelector('.comisiones'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const selectEmpleado = document.querySelector('#selectEmpleado') as HTMLSelectElement;\r\n    const tipo = document.querySelector('#tipo') as HTMLSelectElement;\r\n    const comisiontotalUser = document.querySelector('#comisiontotalUser') as HTMLParagraphElement;\r\n    const comisionTotalUserPagada = document.querySelector('#comisionTotalUserPagada') as HTMLParagraphElement;\r\n    const comisionUserPendiente = document.querySelector('#comisionUserPendiente') as HTMLParagraphElement;\r\n    const btnLiquidar = document.querySelector('#btnLiquidar') as HTMLButtonElement;\r\n    const miDialogoLiquidar = document.querySelector('#miDialogoLiquidar') as HTMLDialogElement;\r\n    const miDialogoDetalleComision = document.querySelector('#miDialogoDetalleComision') as HTMLDialogElement;\r\n    const inputValorLiquidar = (document.querySelector('#valorLiquidar') as HTMLInputElement);\r\n    const origenRetiro = document.querySelectorAll<HTMLInputElement>('input[name=\"origenRetiro\"]');\r\n    let tablaMovimientosComisiones:HTMLElement, comisionPendienteUser = 0, comisionPagadaUser = 0;\r\n    const tablaItemsComision = document.querySelector('#tablaItemsComision tbody') as HTMLBodyElement;\r\n\r\n    interface ComisionTotalUser {\r\n        comisiontotal: number;\r\n    }\r\n    interface HistorialPagos {\r\n        movimientos: any[]; // mejor reemplazar por un tipo específico si lo conoces\r\n        totalPagado: number;\r\n    }\r\n    interface ResponseComision {\r\n        comisionTotaluser: ComisionTotalUser;\r\n        historialPagos: HistorialPagos;\r\n    }\r\n\r\n\r\n    document.addEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n    //api para traer valores del usuario a consultar\r\n    async function callApiReporte(dateinicio:string, datefin:string){\r\n        if(selectEmpleado.value === ''){\r\n            msjalertToast('error', '¡Error!', \"Seleccionar un empleado de la lista\");\r\n            return;\r\n        }\r\n\r\n        (document.querySelector('#textNameUser') as HTMLElement).textContent = \"Detalle de Movimientos - \"+$('#selectEmpleado option:selected').text();\r\n\r\n        //(document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin);\r\n        datos.append('idempleado', selectEmpleado.value);\r\n        try {\r\n            const url = \"/admin/api/comisiones/comisionesXUser\"; //llama a la api que esta en comisionescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            printWidgetsUser(resultado);\r\n            \r\n            //(document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    function printWidgetsUser(resultado:ResponseComision){\r\n        comisionPagadaUser = resultado.historialPagos.totalPagado;\r\n        comisionPendienteUser = resultado.comisionTotaluser.comisiontotal-comisionPagadaUser;\r\n\r\n        comisiontotalUser.textContent = '$'+Number(resultado.comisionTotaluser.comisiontotal).toLocaleString('es-CO', {minimumFractionDigits:2, maximumFractionDigits:2});\r\n        comisionTotalUserPagada.textContent = '$'+comisionPagadaUser.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n        comisionUserPendiente.textContent = '$'+comisionPendienteUser.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n        printTableMovimientosComisiones(resultado.historialPagos.movimientos);\r\n    }\r\n\r\n\r\n    btnLiquidar.addEventListener('click', ()=>{ miDialogoLiquidar.showModal(); });\r\n\r\n\r\n    /// evento a los inputs type radio para elegir origne del gasto = caja o bancos\r\n    origenRetiro.forEach(element =>element.addEventListener('click', showCajasBancos));\r\n\r\n    function showCajasBancos(){\r\n      const selectorigen = document.querySelector('input[name=\"origenRetiro\"]:checked');\r\n      if(selectorigen?.id == 'gastocaja'){\r\n        document.querySelector('#showbancos')?.classList.add('hidden');\r\n        document.querySelector('#banco')?.removeAttribute(\"required\");\r\n      }else{\r\n        document.querySelector('#showbancos')?.classList.remove('hidden');\r\n        document.querySelector('#banco')?.setAttribute(\"required\", \"\");\r\n      }\r\n    }\r\n\r\n\r\n    document.querySelector('#formCrearUpdateLiquidar')?.addEventListener('submit', async(e:Event)=>{\r\n        e.preventDefault();\r\n        const imprimir = document.querySelector('input[name=\"printComprobante\"]') as HTMLInputElement;\r\n        //validar que no supere el monto total a liquidar comision del usuario\r\n        if(selectEmpleado.value === '' || Number(inputValorLiquidar.value) <= 0 || Number(inputValorLiquidar.value)>Number(comisionPendienteUser)){\r\n            msjalertToast('error', '¡Error!', \"Seleccionar un empleado de la lista o valor a liquidar no es valido\");\r\n            return;\r\n        }\r\n        const datos = new FormData();\r\n        datos.append('fkusuarioid', selectEmpleado.value);\r\n        datos.append('valor', inputValorLiquidar.value);\r\n        datos.append('mediopago', (document.querySelector('#mediopago') as HTMLInputElement).value);\r\n        datos.append('tipo', tipo.value);\r\n        datos.append('referencia', (document.querySelector('#observacion') as HTMLInputElement).value);\r\n        datos.append('origengasto', document.querySelector<HTMLInputElement>('input[name=\"origenRetiro\"]:checked')!.value);\r\n        datos.append('idcaja', document.querySelector<HTMLInputElement>('#caja')!.value);\r\n        datos.append('idbanco', document.querySelector<HTMLInputElement>('#banco')?.value??'');\r\n        try {\r\n            const url = \"/admin/api/comisiones/liquidarComision\"; //llama a la api que esta en comisionescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito != undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                const nuevoMovimiento = {\r\n                    fecha: new Date().toISOString(),\r\n                    tipo: `<div class=\"\"> ${tipo.value} <p class=\" text-slate-600 text-sm mt-2\">${(document.querySelector('#mediopago') as HTMLInputElement).value}</p></div>`,\r\n                    entrada: 0,\r\n                    salida: Number(inputValorLiquidar.value),\r\n                    id: resultado.id\r\n                };\r\n                (tablaMovimientosComisiones as any).row.add(nuevoMovimiento).draw();\r\n                //actualizar widget del usuario\r\n                comisionPagadaUser += nuevoMovimiento.salida;\r\n                comisionPendienteUser -= nuevoMovimiento.salida;\r\n                comisionTotalUserPagada.textContent = '$'+comisionPagadaUser.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n                comisionUserPendiente.textContent = '$'+comisionPendienteUser.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n                //actualizar widget business\r\n                comisionTotalPagadaBusinessDB+=nuevoMovimiento.salida;\r\n                (document.querySelector('#comisionTotalPagadaGlobal') as HTMLParagraphElement).textContent = \" - $\"+(comisionTotalPagadaBusinessDB.toLocaleString());\r\n                (document.querySelector('#comisionPendienteGlobal') as HTMLParagraphElement).textContent = \"$\"+(comisionTotalEmpleadosDB-comisionTotalPagadaBusinessDB).toLocaleString();\r\n                if(imprimir.checked)await printComprobantePago(resultado.id);\r\n                (e.target as HTMLFormElement).reset();\r\n                document.querySelector('#showbancos')?.classList.add('hidden');\r\n                document.querySelector('#banco')?.removeAttribute(\"required\");\r\n            }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n            miDialogoLiquidar.close();\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    });\r\n\r\n\r\n    function printComprobantePago(idPagoComision:string): Promise<void>{\r\n      return new Promise<void>((resolve, reject) => {\r\n        setTimeout(() => {\r\n          window.open(\"/admin/printPDFPOSPagoComision?id=\" + idPagoComision, \"_blank\");\r\n          resolve();\r\n        }, 700);\r\n      })\r\n    }\r\n\r\n\r\n    printTableMovimientosComisiones([]);\r\n    function printTableMovimientosComisiones(movimientos:any){\r\n        tablaMovimientosComisiones = ($('#tablaMovimientosComisiones') as any).DataTable({\r\n            \"responsive\": true,\r\n            pageLength: 25,\r\n            destroy: true, // importante si recargas la tabla\r\n            data: movimientos,\r\n            order: [[0, \"desc\"]],\r\n            columns: [\r\n                {title: 'Fecha', data: 'fecha'}, \r\n                {title: 'Concepto', data: 'tipo', render: (data: any, type: any, row: any) => `<div class=\"\"> ${row.tipo}<p class=\" text-slate-600 text-sm mt-2\">${row.concepto!==undefined?row.concepto:''}</p></div>`},\r\n                {title: 'Crédito (+)', data: 'entrada', render: (data:number, type: any, row: any) => `<div class=\"${Number(row.entrada)>0?'text-green-500':''}\"><button class=\"btn-detalle\" data-idfactura=\"${row.id}\"> + $${Number(row.entrada).toLocaleString()} </button></div>`},\r\n                {title: 'Débito (-)', data: 'salida', render: (data: any, type: any, row: any) => `<div class=\"${row.salida>0?'text-red-500':''}\"> - $${row.salida.toLocaleString()}</div>`},\r\n                {title: 'Acciones', data: null, render: (data: any, type: any, row: any) => `<button class=\"btn-eliminar\" data-id=\"${row.entrada == 0&&row.salida!=0?row.id:''}\">${row.entrada == 0&&row.salida!=0?'⛔':' - '}</button>`},\r\n            ],\r\n            \r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                    {extend: 'excelHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                    'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            }\r\n        });\r\n    }\r\n\r\n\r\n    //EVENTO A LA TABLA DE MOVIMIENTOS DE COMISIONES\r\n    document.querySelector('#tablaMovimientosComisiones')?.addEventListener(\"click\", (e)=>{\r\n        const target = e.target as HTMLButtonElement;\r\n        let idmovimento = target?.dataset.id;\r\n        if(target?.classList.contains(\"btn-detalle\")){\r\n            detalleFacturaComision(target?.dataset.idfactura);\r\n            miDialogoDetalleComision.showModal();\r\n        }\r\n\r\n        if(target?.classList.contains(\"btn-eliminar\")){\r\n            if(!idmovimento || isNaN(Number(idmovimento))){\r\n                msjalertToast('error', '¡Error!', \"id del movimiento no es valido\");\r\n                return;\r\n            }\r\n            eliminarMovimientoComision(idmovimento, target);\r\n        }\r\n    });\r\n\r\n\r\n    async function detalleFacturaComision(idfactura:string|undefined){\r\n        while(tablaItemsComision.firstChild)tablaItemsComision.removeChild(tablaItemsComision.firstChild);\r\n        try {\r\n            const url = \"/admin/api/comisiones/detalleFacturaComision?id=\"+idfactura; //llamado a la API REST \r\n            const respuesta = await fetch(url);\r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){ \r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                (document.querySelector('#numFactura') as HTMLParagraphElement).textContent = `factura: ${resultado.factura.prefijo}-${resultado.factura.num_consecutivo}`;\r\n                (document.querySelector('#valorVenta') as HTMLParagraphElement).textContent = `venta: $${Number(resultado.factura.total).toLocaleString()}`;\r\n                (document.querySelector('#nombreCaja') as HTMLParagraphElement).textContent = `${resultado.factura.caja}`;\r\n                (document.querySelector('#fechaPago') as HTMLParagraphElement).textContent = `${resultado.factura.fechapago}`;\r\n                (document.querySelector('#vendedor') as HTMLParagraphElement).textContent = `${resultado.vendedor.nombre} ${(resultado.vendedor.apellido)??''}`;\r\n\r\n                resultado.productos.forEach((ins: CarritoItem)=>{\r\n                    const tr = document.createElement('tr') as HTMLTableRowElement;\r\n                    tr.innerHTML = `<td class=\"text-center\">${ins.idproducto}</td>\r\n                                    <td class=\"text-center\">${ins.nombreproducto}</td>\r\n                                    <td class=\"text-center\">${ins.cantidad}</td>\r\n                                    <td class=\"text-center\">$${Number(ins.valorunidad).toLocaleString()}</td>\r\n                                    <td class=\"text-center\">$${Number(ins.total).toLocaleString()}</td>\r\n                                    <td class=\"text-center\">${ins.percentcomision}%</td>\r\n                                    <td class=\"text-center\">$${Number(ins.valorcomision).toLocaleString()}</td>`;\r\n                    tablaItemsComision.prepend(tr);\r\n                });\r\n            }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    function eliminarMovimientoComision(idmovimento:string, target:HTMLButtonElement){\r\n        const fila = (tablaMovimientosComisiones as any).row(target.closest('tr'));\r\n        Swal.fire({\r\n            customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n            icon: 'question',\r\n            title: 'Desea eliminar el egreso de comision?',\r\n            text: \"La comision sera eliminado por completo del sistema.\",\r\n            showCancelButton: true,\r\n            confirmButtonText: 'Si',\r\n            cancelButtonText: 'No',\r\n        }).then((result:any) => {\r\n            if (result.isConfirmed) {\r\n                (async ()=>{\r\n                    try {\r\n                        const url = \"/admin/api/comisiones/eliminarMovimientoComision?id=\"+idmovimento; //llamado a la API REST en reportescontrolador para eliminar un ingreso\r\n                        const respuesta = await fetch(url);\r\n                        const resultado = await respuesta.json();\r\n                        if(resultado.exito !== undefined){ \r\n                            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                            fila.remove().draw(false);\r\n                            //actualizar widget del usuario\r\n                            comisionPagadaUser -= Number(resultado.valor);\r\n                            comisionPendienteUser += Number(resultado.valor);\r\n                            comisionTotalUserPagada.textContent = '$'+comisionPagadaUser.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n                            comisionUserPendiente.textContent = '$'+comisionPendienteUser.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n                            //actualizar widget business\r\n                            comisionTotalPagadaBusinessDB-=Number(resultado.valor);\r\n                            (document.querySelector('#comisionTotalPagadaGlobal') as HTMLParagraphElement).textContent = \"$\"+comisionTotalPagadaBusinessDB.toLocaleString();\r\n                            (document.querySelector('#comisionPendienteGlobal') as HTMLParagraphElement).textContent = \"$\"+(comisionTotalEmpleadosDB-comisionTotalPagadaBusinessDB).toLocaleString();\r\n                        }else{\r\n                            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                        }\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();\r\n            }\r\n        });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n        const f = event.target;\r\n        if (f=== miDialogoLiquidar || f === miDialogoDetalleComision || (f as HTMLInputElement).value === 'salir' || (f as HTMLInputElement).value === 'Cancelar' || (f as HTMLElement).id == 'btnXCerrarModalLiquidar' || (f as HTMLElement).id == 'btnXCerrarModalDetalleComision') {\r\n            miDialogoLiquidar.close();\r\n            miDialogoDetalleComision.close();\r\n        }\r\n    }\r\n\r\n\r\n    POS.callApiReporte = callApiReporte;\r\n    \r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas')&&!document.querySelector('.modorapido'))return;\r\n\r\n  const POS = (window as any).POS;\r\n\r\n  interface getAdquirienteDian {\r\n    ReceiverEmail:string, \r\n    ReceiverName:string, \r\n    StatusCode:string\r\n  }\r\n\r\n  interface adquirientes {\r\n    id?:string,\r\n    type_document_identification_id:string,\r\n    identification_number:string,\r\n    business_name:string,\r\n    email:string,\r\n    address:string,\r\n    municipality_id?:string,\r\n    department_id?:string,\r\n    ciudad_nombre:string\r\n    type_organization_id:string,\r\n    type_regime_id:string,\r\n    phone:string\r\n  }\r\n\r\n  type municipalities = {\r\n        id:string,\r\n        department_id:string,\r\n        name:string,\r\n        code:string,\r\n  };\r\n  let cities:municipalities[]=[];\r\n\r\n  const facturarA = document.querySelector('#facturarA') as HTMLButtonElement;\r\n  const miDialogoFacturarA = document.querySelector('#miDialogoFacturarA') as any;\r\n  const formFacturarA = document.querySelector('#formFacturarA') as HTMLFormElement;\r\n  const documentinput = document.querySelector('#identification_number') as HTMLInputElement;\r\n  const businessNameInput = document.querySelector('#business_name') as HTMLInputElement;\r\n  const btnBuscarAdquiriente = document.querySelector('#btnBuscarAdquiriente') as HTMLButtonElement;\r\n  const selectDepartments = document.querySelector('#department_id') as HTMLSelectElement;\r\n  const selectdCities = document.querySelector('#municipality_id') as HTMLSelectElement;\r\n  let customers:adquirientes[] = [];\r\n  let customersfiltrado:adquirientes|undefined, token:string|undefined;\r\n\r\n\r\n  (async ()=>{\r\n    const url = `/admin/api/filterAdquirientes`; \r\n    const respuesta = await fetch(url);\r\n    const resultado = await respuesta.json();\r\n    customers = resultado;\r\n    //formatearponentes(resultado);\r\n  })();\r\n\r\n  //consultar token\r\n  (async ()=>{\r\n    const url = `/admin/api/getCompaniesAll`; \r\n    const respuesta = await fetch(url);\r\n    const resultado:{id:string, identification_number:string, business_name:string, idsoftware:string, token:string, estado:string}[] = await respuesta.json();\r\n    token = resultado.find(x=>x.estado==='1')?.token;\r\n  })();\r\n\r\n  btnBuscarAdquiriente.addEventListener('click', (e:Event)=>{\r\n    if(documentinput.value.trim().length > 4 && token!=undefined){\r\n      console.log(documentinput.value.trim());\r\n      GetAcquirerDian(documentinput.value.trim());\r\n    }\r\n  });\r\n\r\n  const GetAcquirerDian = async (identificationnumber: string)=>{\r\n    try {\r\n          const url = \"https://apidianj2.com/api/ubl2.1/getAcquirer/13/\"+identificationnumber;  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {\r\n                                    method: 'GET',\r\n                                    headers: { \r\n                                      \"Accept\": \"application/json\", \r\n                                      \"Content-Type\": \"application/json\",\r\n                                      \"Authorization\": \"Bearer \"+token\r\n                                    },\r\n                                  }); \r\n          const resultado = await respuesta.json();\r\n          const {ReceiverEmail, ReceiverName, StatusCode}:getAdquirienteDian = resultado.data.GetAcquirerResult;\r\n          if(StatusCode === '200'){\r\n            (formFacturarA['business_name'] as HTMLInputElement).value = ReceiverName;\r\n            (formFacturarA['email'] as HTMLInputElement).value = ReceiverEmail;\r\n          }else{\r\n            msjAlert('error', 'No se encontro cliente en base de datos de la Dian', document.querySelector('#divmsjalertanoclienteDian') as HTMLElement);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n  }\r\n\r\n\r\n\r\n  //buscar adquiriente\r\n  documentinput.addEventListener('input', buscarAquiriente);\r\n  businessNameInput.addEventListener('input', buscarAquiriente);\r\n\r\n  function buscarAquiriente(e:Event){\r\n      const input = e.target as HTMLInputElement;\r\n      const busqueda:string = input.value.toLowerCase();\r\n\r\n      if(busqueda.length<3){\r\n        customersfiltrado = undefined;\r\n        //mostrarAdquiriente();\r\n        return;\r\n      }\r\n\r\n      customersfiltrado = customers.find(adq =>{\r\n        if(input.id==='identification_number'){\r\n          return adq.identification_number.trim() === busqueda.trim();\r\n        }else{\r\n          const nombre = adq.business_name.toLowerCase();\r\n          return nombre.trim() === busqueda.trim();\r\n        }\r\n      });\r\n      \r\n      mostrarAdquiriente();\r\n  }\r\n\r\n  function mostrarAdquiriente(){\r\n    if(customersfiltrado != undefined){\r\n      $('#type_document_identification_id').val(customersfiltrado.type_document_identification_id);\r\n      documentinput.value = customersfiltrado.identification_number;\r\n      (document.querySelector('#business_name') as HTMLInputElement).value = customersfiltrado.business_name;\r\n      (document.querySelector('#email') as HTMLInputElement).value = customersfiltrado.email;\r\n      (document.querySelector('#address') as HTMLInputElement).value = customersfiltrado.address;\r\n      if(customersfiltrado.department_id){\r\n        $('#department_id').val(customersfiltrado.department_id);\r\n        imprimirCiudades(customersfiltrado.department_id);\r\n      }\r\n      //$('#municipality_id').val(customersfiltrado.municipality_id);\r\n      $('#type_organization_id').val(customersfiltrado.type_organization_id);\r\n      $('#type_regime_id').val(customersfiltrado.type_regime_id);\r\n      (document.querySelector('#phone') as HTMLInputElement).value = customersfiltrado.phone;\r\n    }else{\r\n      $('#type_document_identification_id').val(\"\");\r\n      //(document.querySelector('#business_name') as HTMLInputElement).value = '';\r\n      (document.querySelector('#email') as HTMLInputElement).value = '';\r\n      (document.querySelector('#address') as HTMLInputElement).value = '';\r\n      $('#department_id').val(\"\");\r\n      $('#municipality_id').val(\"\");\r\n      $('#type_organization_id').val(\"\");\r\n      $('#type_regime_id').val(\"\");\r\n      (document.querySelector('#phone') as HTMLInputElement).value = \"\";\r\n    }\r\n  }\r\n\r\n\r\n\r\n  /////       Obtener municipio segun departamento        ///////\r\n  selectDepartments?.addEventListener('change', (e:Event)=>{\r\n    const x:HTMLOptionElement = (e.target as HTMLOptionElement);\r\n    imprimirCiudades(x.value);\r\n  });\r\n\r\n  function imprimirCiudades(x:string){\r\n    (async ()=>{\r\n      try {\r\n        const url = \"/admin/api/citiesXdepartments?id=\"+x; //llamado a la API REST y se trae las cities segun cliente elegido\r\n        const respuesta = await fetch(url); \r\n        const resultado = await respuesta.json(); \r\n        if(resultado.error){\r\n          Swal.fire(resultado.error[0], '', 'error')\r\n        }else{\r\n          cities = resultado;\r\n          addCitiesToSelect(cities);\r\n        }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n  }\r\n  \r\n  function addCitiesToSelect<T extends {id:string, department_id:string, name:string, code:string}>(addrs: T[]):void{\r\n    while(selectdCities?.firstChild)selectdCities.removeChild(selectdCities?.firstChild);\r\n    addrs.forEach(x =>{\r\n      const option = document.createElement('option');\r\n      option.textContent = x.name;\r\n      option.value = x.id;\r\n      option.dataset.code = x.code;\r\n      option.dataset.department_id = x.department_id;\r\n      selectdCities.appendChild(option);\r\n    });\r\n    if(customersfiltrado!=undefined&&customersfiltrado.municipality_id)$('#municipality_id').val(customersfiltrado.municipality_id);\r\n  }\r\n\r\n\r\n  ///////////////////// evento al btn facturar A /////////////////////\r\n  facturarA.addEventListener('click', (e:Event)=>{\r\n    miDialogoFacturarA.showModal();\r\n    document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n  });\r\n\r\n   \r\n  formFacturarA.addEventListener('submit', (e:Event)=>{\r\n    e.preventDefault();\r\n    const data = new FormData(formFacturarA);\r\n    const datosAdquiriente: Record<string, FormDataEntryValue> = Object.fromEntries(data.entries());\r\n    miDialogoFacturarA.close();\r\n    document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n\r\n    const identification = datosAdquiriente.identification_number as string;\r\n    const requiereEmail = identification && identification!='222222222222';\r\n    // Validar email solo si identification_number es distinto de 222222222222 y no vacío\r\n    if (requiereEmail && !validarEmail(datosAdquiriente.email as string)) {\r\n        Swal.fire(\"Correo incorrecto\", \"Debe ingresar un email válido o enviar a consumidor final o generico: 222222222222\", \"error\");\r\n        return; // detiene el proceso\r\n    }\r\n\r\n    if(identification && identification!='222222222222'){\r\n      const dv = getDgv(Number(identification));\r\n      datosAdquiriente.dv = dv.toString();\r\n    }\r\n\r\n    console.log(datosAdquiriente);\r\n\r\n    POS.gestionarAdquiriente.datosAdquiriente = datosAdquiriente; //guarda en el objeto global\r\n    //guardar adquiriente en DB.\r\n    guardarAdquiriente(datosAdquiriente);\r\n  });\r\n\r\n  function validarEmail(correo: string): boolean {\r\n      const regex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;\r\n      return regex.test(correo);\r\n  }\r\n\r\n\r\n  async function guardarAdquiriente(datosAdquiriente: Record<string, FormDataEntryValue>){\r\n    try {\r\n          const url = \"/admin/api/guardarAdquiriente\";  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {\r\n                                    method: 'POST',\r\n                                    headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                    body: JSON.stringify(datosAdquiriente)\r\n                                  }); \r\n          const resultado = await respuesta.json();\r\n          //añadir o actualizar al arreglo customers\r\n          if(resultado.tipo == \"crear\"){\r\n            customers = [...customers, resultado.obj];\r\n          }else{\r\n            /// actualizar el arregle del adquiriente o customers ///\r\n            customers.forEach(a=>{if(a.identification_number == resultado.obj.identification_number)a = Object.assign(a, resultado.obj);});\r\n          }\r\n          datosAdquiriente.id = resultado.obj.id;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n  }\r\n  \r\n\r\n  const gestionarAdquiriente = {  //objeto a exportar\r\n    miDialogoFacturarA,\r\n    datosAdquiriente: {} //inicializar \r\n  };\r\n\r\n  POS.gestionarAdquiriente = gestionarAdquiriente;\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas')&&!document.querySelector('.modorapido'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const btnAddCliente = document.querySelector('#addcliente') as HTMLElement;\r\n    const btnAddDir = document.querySelector('#adddir') as HTMLElement;\r\n    const miDialogoAddCliente = document.querySelector('#miDialogoAddCliente') as any;\r\n    //const miDialogoAddDir = document.querySelector('#miDialogoAddDir') as any;\r\n    const selectCliente = document.querySelector('#selectCliente') as HTMLSelectElement;\r\n    const tel = document.querySelector('#telefono')! as HTMLInputElement;\r\n    const dirEntrega = document.querySelector('#direccionEntrega')! as HTMLSelectElement;\r\n\r\n  const gestionClientes = {\r\n    selectCliente,\r\n    dirEntrega,\r\n    miDialogoAddCliente,\r\n    //miDialogoAddDir,\r\n\r\n    clientes(){\r\n        \r\n        //////////// evento al boton añadir cliente nuevo //////////////\r\n        btnAddCliente?.addEventListener('click', (e)=>{\r\n            miDialogoAddCliente.showModal();\r\n            ($('#selectCliente') as any).select2({\r\n                dropdownParent: $('#miDialogoAddCliente'),\r\n                placeholder: \"Seleccionar el cliente\",\r\n                maximumSelectionLength: 1\r\n            });\r\n            document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });\r\n        //////////// evento al boton añadir nueva direccion //////////////\r\n        /*btnAddDir?.addEventListener('click', (e)=>{\r\n            miDialogoAddDir.showModal();\r\n            document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });*/\r\n        //////////// evento al btn submit del formulario add nuevo cliente //////////////\r\n        document.querySelector('#formAddCliente')?.addEventListener('submit', e=>{\r\n            e.preventDefault();\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('idcliente', selectCliente?.value??null); //id del cliente\r\n                datos.append('nombre', (document.querySelector('#nombreclientenuevo') as HTMLInputElement).value);\r\n                datos.append('apellido', (document.querySelector('#clientenuevoapellido') as HTMLInputElement).value || '  ');\r\n                datos.append('tipodocumento', (document.querySelector('#tipodocumento') as HTMLInputElement).value);\r\n                datos.append('telefono', (document.querySelector('#telefono') as HTMLInputElement).value);\r\n                datos.append('iddireccion', (document.querySelector('#direccionEntrega') as HTMLSelectElement).value);\r\n                //datos.append('idtarifa', (document.querySelector('#clientenuevotarifa') as HTMLSelectElement).value);\r\n                datos.append('tipodocumento', (document.querySelector('#tipodocumento') as HTMLInputElement).value);\r\n                datos.append('identificacion', (document.querySelector('#identificacion') as HTMLInputElement).value);\r\n                datos.append('email', (document.querySelector('#clientenuevoemail') as HTMLInputElement).value);\r\n                datos.append('departamento', (document.querySelector('#departamento') as HTMLInputElement).value||'No definido');\r\n                datos.append('ciudad', (document.querySelector('#ciudad') as HTMLInputElement).value || 'No definido');\r\n                datos.append('direccion', (document.querySelector('#clientenuevodireccion') as HTMLInputElement).value);\r\n                try {\r\n                    let url = \"/admin/api/apiCrearCliente\";\r\n                    if(selectCliente.value!=='')url = \"/admin/api/actualizarCliente\";\r\n\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    if(selectCliente.value=='')addClienteSelect(resultado.nextID);\r\n                    if(selectCliente.value!=='')$('#selectCliente').val(resultado.nextID).trigger('change');\r\n                    //POS.limpiarformdialog();\r\n                    }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n            miDialogoAddCliente.close();\r\n            document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });\r\n        /////////////// añadir cliente al select despues de crearse ///////////////////\r\n        function addClienteSelect(clienteID:string): void{\r\n            const option = document.createElement('option');\r\n            option.textContent = (document.querySelector('#nombreclientenuevo') as HTMLInputElement).value + \" \" + (document.querySelector('#clientenuevoapellido') as HTMLInputElement).value;\r\n            option.value = clienteID;\r\n            option.dataset.tipodocumento = (document.querySelector('#tipodocumento') as HTMLInputElement).value;\r\n            option.dataset.identidad = (document.querySelector('#identificacion') as HTMLInputElement).value;\r\n            selectCliente?.appendChild(option);\r\n            $('#selectCliente').val(clienteID).trigger('change'); // seleccionar el cliente nuevo, en el select y dispara evento\r\n        }\r\n        \r\n        //evento 'cambio' al selecionar cliente, tambien se ejecuta cuando se crea cliente nuevo//\r\n        $(\"#selectCliente\").on('change', (e)=>{\r\n            const idcli = (e.target as HTMLInputElement).value;\r\n            if(idcli){\r\n                (async ()=>{\r\n                    try {\r\n                        const url = \"/admin/api/clientes/direccionesXcliente?id=\"+idcli; //llamado a la API REST y se trae el cliente y sus direcciones direccionescontrolador, tambien traer sus precios personalizados\r\n                        const respuesta = await fetch(url); \r\n                        const resultado = await respuesta.json();\r\n                        (document.querySelector('#nombreclientenuevo') as HTMLInputElement).value = resultado.nombre;\r\n                        (document.querySelector('#clientenuevoapellido') as HTMLInputElement).value = resultado.apellido;\r\n                        (document.querySelector('#telefono') as HTMLInputElement).value =  resultado.telefono;\r\n                        addDireccionSelect(resultado);\r\n                        (document.querySelector('#tipodocumento') as HTMLSelectElement).value = resultado.tipodocumento;\r\n                        (document.querySelector('#identificacion') as HTMLInputElement).value = resultado.identificacion;\r\n                        (document.querySelector('#clientenuevoemail') as HTMLInputElement).value = resultado.email;\r\n                        (document.querySelector('#resumenCliente') as HTMLParagraphElement).textContent = resultado.nombre+' '+resultado.apellido;\r\n                        (document.querySelector('#badgeEstado') as HTMLParagraphElement).textContent = 'SELECCIONADO';\r\n                        (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.remove('bg-gray-100', 'text-gray-700');\r\n                        (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.add('bg-green-100', 'text-green-600');\r\n                        //mapear los precios personalizados del cliente con arreglo de los productos\r\n                        actualizarPreciosCliente(resultado.preciospersonalizados);\r\n                    } catch (error) {\r\n                        console.log(error);\r\n                    }\r\n                })();   \r\n            }else{\r\n                (document.querySelector('#resumenCliente') as HTMLParagraphElement).textContent = 'Seleccionar cliente';\r\n                (document.querySelector('#badgeEstado') as HTMLParagraphElement).textContent = 'SIN CLIENTE';\r\n                (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.remove('bg-green-100', 'text-green-600');\r\n                (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.add('bg-gray-100', 'text-gray-700');\r\n                //actualizar array de products y DOM\r\n                for(const prod of POS.products){\r\n                    const item = POS.hackerList.get('id', prod.id)[0];\r\n                    prod.precio_venta = prod.precio_original;\r\n                    if(item)item.elm.querySelector('.precioVenta').textContent = '$'+Number(prod.precio_venta).toLocaleString();\r\n                }\r\n                //actualizar el carrito de ventas con los valores originales\r\n                if(POS.carrito)\r\n                    POS.carrito.forEach((cr:CarritoItem)=>{\r\n                        cr.valorunidad = POS.products.find((p:productsapi)=>p.id==cr.idproducto)?.precio_venta??cr.valorunidad;\r\n                        cr.subtotal = cr.valorunidad * cr.stock!;\r\n                        cr.total = cr.subtotal;\r\n                        cr.valorcomision = (cr.subtotal*cr.percentcomision)/100;\r\n                        cr.base = 1/(1+(Number(cr.impuesto)/100))*cr.subtotal;\r\n                        cr.valorimp = cr.subtotal - cr.base;\r\n                    });\r\n                POS.valorCarritoTotal();\r\n            }\r\n        });\r\n\r\n        ////// añade direccion al select de direcciones, cuando se selecciona o se agrega un cliente o si se agrega un nueva direccion/////\r\n        function addDireccionSelect<T extends {id:string, nombre:string, apellido:string, telefono:string, identificacion:string, email:string, direcciones:{id:string, idcliente:string, idtarifa:string, tarifa:{id:string, idcliente:string, nombre:string, valor:string}, direccion:string, departamento:string, ciudad:string}[]}>(addrs: T):void{\r\n            while(dirEntrega?.firstChild)dirEntrega.removeChild(dirEntrega?.firstChild);\r\n            const setTarifas = new Set();\r\n            POS.tarifas.length = 0;\r\n            addrs.direcciones.forEach(dir =>{\r\n                const option = document.createElement('option');\r\n                option.textContent = dir.direccion;\r\n                option.value = dir.id;\r\n                option.dataset.idcliente = dir.idcliente;\r\n                option.dataset.idtarifa = dir.idtarifa;\r\n                option.dataset.ciudad = dir.ciudad;\r\n                dirEntrega.appendChild(option);\r\n                dir.tarifa.idcliente = dir.idcliente;\r\n                if(!setTarifas.has(dir.tarifa.id)){\r\n                POS.tarifas = [...POS.tarifas, dir.tarifa];\r\n                setTarifas.add(dir.tarifa.id);\r\n                }\r\n            });\r\n            setTarifas.clear();\r\n            POS.printTarifaEnvio();\r\n            POS.valorCarritoTotal();\r\n            (document.querySelector('#departamento') as HTMLInputElement).value = addrs.direcciones[0]?.departamento??'No especificado';\r\n            (document.querySelector('#ciudad') as HTMLInputElement).value = addrs.direcciones[0]?.ciudad??'No especificado';\r\n        }\r\n\r\n\r\n        function actualizarPreciosCliente(preciosDelCliente:{id:string, idcliente:string, idproducto:string, precioxcliente:string}[]){\r\n            //resetar o eliminar precios personalizados de clientes anteriores\r\n            const mapaPrecios = new Map( preciosDelCliente.map(p => [p.idproducto, p.precioxcliente]) );\r\n            POS.products.forEach((prod:productsapi) => {\r\n                if(mapaPrecios.has(prod.id)){\r\n                    prod.precio_venta = mapaPrecios.get(prod.id)!;\r\n                }else{\r\n                    prod.precio_venta = prod.precio_original!;\r\n                }\r\n            });\r\n\r\n            for(const prod of mapaPrecios.entries()){\r\n                const item = POS.hackerList.get('id', prod[0])[0];\r\n                if(item)item.elm.querySelector('.precioVenta').textContent = '$'+Number(prod[1]).toLocaleString();\r\n            }\r\n        }\r\n\r\n\r\n        ///////// Evento al input de telefono para buscar cliente ////////////\r\n        tel?.addEventListener('input', (e:Event)=>{\r\n            const contact = (e.target as HTMLInputElement).value.trim();\r\n            if (contact.length < 6) return;\r\n            const cli = clientesDB.find(c => c.telefono === contact);\r\n            console.log(cli);\r\n            if(cli!=undefined)$('#selectCliente').val(cli.id).trigger('change'); \r\n        });\r\n        \r\n\r\n        ///////// Evento al select de direcciones ////////////\r\n        dirEntrega?.addEventListener('change', (e)=>{\r\n            const select = (e.target as HTMLSelectElement);\r\n            const x:string = select.options[select.selectedIndex].dataset.ciudad||'';\r\n            (document.querySelector('#ciudad') as HTMLInputElement).value = x;\r\n            POS.printTarifaEnvio();\r\n            POS.valorCarritoTotal();\r\n        });\r\n\r\n        ////////////////// evento al btn submit del formulario add direccion //////////////////////\r\n        /*document.querySelector('#formAddDir')?.addEventListener('submit', e=>{\r\n            e.preventDefault();\r\n            (async ()=>{\r\n                const datos = new FormData();\r\n                datos.append('idcliente', selectCliente.value);\r\n                datos.append('departamento', (document.querySelector('#adddepartamento') as HTMLInputElement).value);\r\n                datos.append('ciudad', (document.querySelector('#addciudad') as HTMLInputElement).value);\r\n                datos.append('direccion', (document.querySelector('#adddireccion') as HTMLInputElement).value);\r\n                datos.append('idtarifa', (document.querySelector('#tarifa') as HTMLSelectElement).value);\r\n                try {\r\n                    const url = \"/admin/api/addDireccionCliente\";  //direccionescontrolador\r\n                    const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                    const resultado = await respuesta.json();\r\n                    if(resultado.exito !== undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    addDireccionSelect(resultado.direcciones);\r\n                    }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                    }\r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n            //miDialogoAddDir.close();\r\n            //document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        });*/\r\n        \r\n    }\r\n    \r\n  };\r\n\r\n  (window as any).POS.gestionClientes = gestionClientes;\r\n\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas')&&!document.querySelector('.crearseparado')&&!document.querySelector('.modorapido'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    //obtener valor porcentual del interes por cuota\r\n    let tasaInteresDB:number = 0;\r\n    /*(async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getParamGlobal\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          tasaInteresDB = Number(resultado.tasa_de_interes_por_cuota.valor_final);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();*/\r\n    tasaInteresDB = Number(getParam.tasa_de_interes_por_cuota.valor_final);\r\n\r\n    const mediospago = document.querySelectorAll<HTMLInputElement>('.mediopago');\r\n    const interes = document.querySelector('#interes') as HTMLSelectElement;\r\n    const abonoinicial = (document.querySelector('#abonoinicial') as HTMLInputElement);\r\n    const cantidadcuotas = (document.querySelector('#cantidadcuotas') as HTMLInputElement);\r\n    //let tipoventa:string=\"Contado\";\r\n    let valoresCredito = {capital:0, abonoinicial:0, cantidadcuotas:1, montocuota:0, frecuenciapago:1, interes:0, interestotal:0, valorinterestotal:0, valorinteresxcuota:0, montototal:0};\r\n\r\n    //eventos a los inputs medios de pago\r\n    mediospago.forEach(m=>{m.addEventListener('input', (e)=>{ calcularmediospago(e);});});\r\n\r\n    /////////////////////  evento al input recibido  //////////////////////////\r\n    document.querySelector<HTMLInputElement>('#recibio')?.addEventListener('input', (e)=>{\r\n      calcularCambio((e.target as HTMLInputElement).value);\r\n    });\r\n    \r\n    const gestionSubirModalPagar = {\r\n        \r\n      subirModalPagar(){\r\n        //initvaloresCredito();\r\n        document.querySelector('#totalPagar')!.textContent = `${POS.valorTotal.total.toLocaleString()}`;\r\n        //como se puede cerrar el modal y aumentar los productos, hay calcular los inputs\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{\r\n            if(index>0)totalotrosmedios += parseInt(item.value.replace(/[,.]/g, ''));\r\n        });\r\n\r\n        if(POS.valorTotal.total<totalotrosmedios){\r\n            totalotrosmedios = 0;\r\n            POS.mapMediospago.clear();\r\n            $('.mediopago').val(0);\r\n        }\r\n        if(POS.tipoventa == \"Contado\"){\r\n            (document.querySelector('.Efectivo')! as HTMLInputElement).value =  `${(POS.valorTotal.total-totalotrosmedios).toLocaleString()}`;\r\n            POS.mapMediospago.set('1', POS.valorTotal.total-totalotrosmedios); //inicialmente el valor total se establece para efectivo\r\n        }\r\n        if(POS.valorTotal.total-totalotrosmedios == 0 && POS.mapMediospago.has('1'))POS.mapMediospago.delete('1');\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n        if(POS.tipoventa == \"Credito\")calculoTasaInteres();\r\n        if(POS.tipoventa == \"Contado\")initvaloresCredito();\r\n      },\r\n      calculoTasaInteres,\r\n      valoresCredito\r\n      \r\n    };\r\n\r\n\r\n    function initvaloresCredito(){\r\n      /*valoresCredito.capital = POS.valorTotal.total;  //inicializar el capital en el obj\r\n      valoresCredito.cantidadcuotas = Number(cantidadcuotas.value);\r\n      valoresCredito.montocuota = (valoresCredito.capital - valoresCredito.abonoinicial)/valoresCredito.cantidadcuotas;\r\n      valoresCredito.interes = 0;  //No aplicar interes\r\n      valoresCredito.interestotal = 0;  // 0% de interes\r\n      valoresCredito.valorinterestotal = 0; //0$ de interes total de la factura\r\n      valoresCredito.valorinteresxcuota = 0;  //0$ de interes de cada cuota\r\n      valoresCredito.montototal = valoresCredito.capital;\r\n      (document.querySelector('#montocuota') as HTMLInputElement).value = valoresCredito.montocuota+'';*/\r\n      valoresCredito.capital=0; \r\n      valoresCredito.abonoinicial=0;\r\n      valoresCredito.cantidadcuotas=1;\r\n      valoresCredito.montocuota=0;\r\n      valoresCredito.frecuenciapago=1,\r\n      valoresCredito.interes=0;  //No aplicar interes\r\n      valoresCredito.interestotal=0;  // 0% de interes\r\n      valoresCredito.valorinterestotal=0;  //0$ de interes total de la factura\r\n      valoresCredito.valorinteresxcuota=0;  //0$ de interes de cada cuota\r\n      valoresCredito.montototal=0;\r\n    }\r\n\r\n    \r\n    function calcularmediospago(e:Event){\r\n        let totalotrosmedios = 0;\r\n        mediospago.forEach((item, index)=>{ //sumar todos los medios de pago menos el efectivo\r\n          if(index>0&&POS.tipoventa==\"Contado\" || POS.tipoventa==\"Credito\")totalotrosmedios += parseInt(item.value.replace(/[,.]/g, ''));\r\n        });\r\n        if(totalotrosmedios<=POS.valorTotal.total&&POS.tipoventa == \"Contado\" || totalotrosmedios<=valoresCredito.abonoinicial&&POS.tipoventa == \"Credito\"){\r\n          if(POS.tipoventa == \"Contado\"){\r\n            POS.mapMediospago.set('1', POS.valorTotal.total-totalotrosmedios);\r\n            if(POS.valorTotal.total-totalotrosmedios == 0 && POS.mapMediospago.has('1'))POS.mapMediospago.delete('1'); //se elimina medio de pago efectivo\r\n          }\r\n          POS.mapMediospago.set((e.target as HTMLInputElement).id, parseInt((e.target as HTMLInputElement).value.replace(/[,.]/g, '')));\r\n          if((e.target as HTMLInputElement).value == '0' && POS.mapMediospago.has((e.target as HTMLInputElement).id))POS.mapMediospago.delete((e.target as HTMLInputElement).id);\r\n        }else{ //si la suma de los medios de pago superan el valor total, toma el ultimo input digitado y lo reestablece a su ultimo valor\r\n          if(POS.mapMediospago.has((e.target as HTMLInputElement).id)){\r\n            (e.target as HTMLInputElement).value = POS.mapMediospago.get((e.target as HTMLInputElement).id).toLocaleString();\r\n          }else{\r\n            (e.target as HTMLInputElement).value = '0';\r\n          }\r\n        }\r\n        if(POS.tipoventa == \"Contado\"){\r\n          mediospago[0].value = (POS.mapMediospago.get('1')??0).toLocaleString();  //medio de pago en efectivo\r\n        }\r\n        calcularCambio(document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n    }\r\n\r\n    function calcularCambio(recibido:string):void{\r\n      recibido = recibido.replace(/[,.]/g, '');\r\n      if(Number(recibido)>POS.mapMediospago.get('1')){\r\n        (document.querySelector('#cambio') as HTMLElement).textContent = (Number(recibido)-POS.mapMediospago.get('1')).toLocaleString()+'';\r\n        return;\r\n      }\r\n      (document.querySelector('#cambio') as HTMLElement).textContent = '0';\r\n    }\r\n\r\n\r\n    ////////////////////  CALCULO DE VALORES DEL CREDITO  //////////////////////\r\n\r\n    interes.addEventListener('change', e=>calculoTasaInteres());\r\n    cantidadcuotas.addEventListener('input', e=>calculoTasaInteres());\r\n    abonoinicial.addEventListener('input', e=>calculoTasaInteres());\r\n\r\n    function calculoTasaInteres(){\r\n      let creditofinal = recalcularCapitalXAbono(); //capital inicial - abono\r\n      initMediosPagos();\r\n      valoresCredito.cantidadcuotas = Number(cantidadcuotas.value);\r\n      if(cantidadcuotas.value == '1' || (interes.value == '0' || interes.value == '')){\r\n        (document.querySelector('#montocuota') as HTMLInputElement).value =  (Math.ceil((creditofinal/valoresCredito.cantidadcuotas)*100)/100)+'';\r\n        //(document.querySelector('#interestotal') as HTMLInputElement).value = '0';\r\n        //(document.querySelector('#valorinteresxcuota') as HTMLInputElement).value = '0';\r\n        //(document.querySelector('#valorinterestotal') as HTMLInputElement).value = '0';\r\n        //(document.querySelector('#montototal') as HTMLInputElement).value = creditofinal.toLocaleString();\r\n        valoresCredito.montocuota = (Math.ceil((creditofinal/valoresCredito.cantidadcuotas)*100)/100);\r\n        valoresCredito.interestotal = 0;\r\n        valoresCredito.valorinteresxcuota = 0;\r\n        valoresCredito.valorinterestotal = 0;\r\n        valoresCredito.montototal = creditofinal;\r\n      }\r\n      if(cantidadcuotas.value !== '1'&&interes.value === '1'){\r\n        const valorInteres = creditofinal*(tasaInteresDB/100)*valoresCredito.cantidadcuotas;\r\n        const total = creditofinal + valorInteres;\r\n        const valorxcuota = Math.ceil((total/valoresCredito.cantidadcuotas)*100)/100;\r\n        (document.querySelector('#montocuota') as HTMLInputElement).value = valorxcuota+'';\r\n        //(document.querySelector('#interestotal') as HTMLInputElement).value = 2*valoresCredito.cantidadcuotas+''; //porcentaje de interes total\r\n        //(document.querySelector('#valorinteresxcuota') as HTMLInputElement).value = valorInteres/valoresCredito.cantidadcuotas+'';\r\n        //(document.querySelector('#valorinterestotal') as HTMLInputElement).value = valorInteres.toLocaleString();  //valor del interes total del credito\r\n        //(document.querySelector('#montototal') as HTMLInputElement).value = total.toLocaleString();  //valor total del credito\r\n        valoresCredito.interes = 1;\r\n        valoresCredito.montocuota = valorxcuota;\r\n        valoresCredito.interestotal = tasaInteresDB*valoresCredito.cantidadcuotas;\r\n        valoresCredito.valorinteresxcuota = valorInteres/valoresCredito.cantidadcuotas;\r\n        valoresCredito.valorinterestotal = valorInteres;\r\n        valoresCredito.montototal = total;\r\n      }\r\n      //(document.querySelector('#capitalinicial') as HTMLInputElement).value = capital.value.toLocaleString();\r\n      //(document.querySelector('#abono') as HTMLInputElement).value = Number(abonoinicial.value).toLocaleString();\r\n      //(document.querySelector('#capitalFinanciado') as HTMLInputElement).value = creditofinal+'';\r\n      \r\n    }\r\n\r\n    function recalcularCapitalXAbono():number{\r\n      const capital = POS.valorTotal.total;\r\n      let abono = Number(abonoinicial.value??0);\r\n      const capitalinicial:number = capital;\r\n      let creditofinal:number = capitalinicial;\r\n      if(capital>0){\r\n        if(abono < capitalinicial){\r\n          creditofinal = capitalinicial-abono;\r\n        }else{\r\n          abonoinicial.value = '0';\r\n        }\r\n      }\r\n      valoresCredito.capital = capital;\r\n      valoresCredito.abonoinicial = abono;\r\n      document.querySelector('#valorAbono')!.textContent = abono.toLocaleString();\r\n      return creditofinal;\r\n    }\r\n\r\n\r\n    function initMediosPagos(){\r\n      mediospago.forEach(z=>z.value = '0');\r\n      POS.mapMediospago.clear();\r\n    }\r\n\r\n    POS.gestionSubirModalPagar = gestionSubirModalPagar;\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.ventas') || document.querySelector('.ordenresumen') || document.querySelector('.detalleinvoice') || document.querySelector('.modorapido')){\r\n\r\n    const sendInvoiceAPI = {\r\n\r\n      async sendInvoice(x:number){\r\n        console.log(x);\r\n        try {\r\n            const url = \"/admin/api/sendInvoice\"; //llamado a la API REST apidiancontrolador.php\r\n            const respuesta = await fetch(url, {\r\n              method: 'POST', \r\n              headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n              body: JSON.stringify({id: x}) \r\n            });\r\n            \r\n            const responseDian = await respuesta.json();\r\n            /*return new Promise(resolve => {\r\n              setTimeout(() => {\r\n                  resolve('ok');\r\n              }, 4000);\r\n            }); */\r\n            return responseDian;\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      }\r\n    };\r\n  \r\n\r\n    (window as any).POS.sendInvoiceAPI = sendInvoiceAPI;\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.modorapido')){\r\n\r\n        const POS = (window as any).POS;\r\n\r\n        interface Item {\r\n            id_impuesto: number,\r\n            facturaid: number,\r\n            basegravable: number,\r\n            valorimpuesto: number\r\n        }\r\n\r\n\r\n        const selectCliente = POS.gestionClientes.selectCliente;\r\n        const dirEntrega = POS.gestionClientes.dirEntrega;\r\n        const btnCaja = document.querySelector('#caja') as HTMLSelectElement; //select de la caja en el modal pagar\r\n        const btnTipoFacturador = document.querySelector('#facturador') as HTMLSelectElement; //select del consecutivo o facturador en el modal de pago\r\n        const btnfacturar = document.querySelector('#btnfacturar');\r\n        const btnguardar = document.querySelector('#btnguardar');\r\n        const btnPagar = document.getElementById('btnPagar') as HTMLInputElement;\r\n        const miDialogoAddCliente = POS.gestionClientes.miDialogoAddCliente;\r\n        const miDialogoGuardar = document.querySelector('#miDialogoGuardar') as any;\r\n        const miDialogoFacturarA = POS.gestionarAdquiriente.miDialogoFacturarA;\r\n        const miDialogoFacturar = document.querySelector('#miDialogoFacturar') as any;\r\n        const totalUnidades = document.querySelector('#totalUnidades') as HTMLSpanElement;\r\n        const tablaMR = document.getElementById('tablaVenta') as HTMLBodyElement;\r\n\r\n        let factimpuestos:Item[] = [];\r\n        let carrito:CarritoItem[]=[];\r\n        let allproducts:productsapi[] = [];\r\n        let filteredData: {id:string, text:string, tipo:string, tipoproducto:string, tipoproduccion:string, sku:string, unidadmedida:string}[];   //tipoproducto = 0 es producto simple,  1 = compuesto,  si no viene es subproducto, tipo=0 es producto(simple o compuesto), tipo=1 es subproducto\r\n        const valorTotal = {porcentgananciauser: 0, valorgananciauser: 0, subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, idtarifa: 0, valortarifa: 0, total: 0}; //datos global de la venta\r\n        let tarifas:{id:string, idcliente:string, nombre:string, valor:string}[] = [];\r\n        //const dataCredit = {capital:0, abonoinicial:0, saldopendiente:0, cantidadcuotas:0, interes:'0', interestotal:0, valorinterestotal:0, montototal:0, descuentocredito: 0};\r\n\r\n        const constImp: {[key:string]: number} = {};\r\n        constImp['excluido'] = 0;\r\n        constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n        constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n        constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n        constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n        constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n        let  tipoventa:string=\"Contado\";\r\n        const mapMediospago = new Map();\r\n\r\n        const mediosPagoDBMAP = new Map<string, string>(  //se usa para imprimir los medios de pago en el servidor de impresion\r\n            mediosPagoDB.map(m => [m.id, m.mediopago]) //mediosPagoDB se declara en app.ts el cual viene del <script> en index.php que convierte el array de medios de pago de php a js.\r\n        );\r\n\r\n        POS.gestionClientes.clientes();  //inicializa modulo de clientes\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/allproducts\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y compuestos\r\n                const respuesta = await fetch(url);\r\n                const resultado:productsapi[] = await respuesta.json();\r\n                filteredData = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1').map(item => ({ id: item.id, text: item.nombre, tipo:item.tipoproducto??'1', tipoproducto: item.tipoproducto, tipoproduccion: item.tipoproduccion, sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2();\r\n                allproducts = resultado.filter(x=>x.habilitarventa=='1'&&x.visible=='1');\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        activarselect2();\r\n        function activarselect2(){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Buscar producto...\",\r\n                maximumSelectionLength: 1,\r\n            });  \r\n        }\r\n\r\n\r\n        let barcode = \"\";\r\n        let lastKeyTime = Date.now();\r\n        window.addEventListener('keydown', (e: KeyboardEvent) => {\r\n            let estado = true;\r\n            const currentTime = Date.now();\r\n            const target = e.target as HTMLElement;\r\n            const cobrar:boolean = miDialogoFacturar?.open;\r\n\r\n            if (e.key === 'Control')(document.querySelector('#articulo') as HTMLSelectElement).focus();\r\n            if (e.key === 'F8')(document.querySelector('#facturarA') as HTMLButtonElement).click();\r\n\r\n            // 1. FILTRO DE ENTRADA mejorado\r\n            // Si el foco está en un input que NO sea el de búsqueda de Select2, ignoramos.\r\n            // El buscador de Select2 suele tener la clase 'select2-search__field'\r\n            const isSelect2Input = $(target).hasClass('select2-search__field');\r\n            const isBody = target.tagName === 'BODY';\r\n            const isButton = target.tagName === 'BUTTON' || $(target).hasClass('btn');\r\n\r\n            // Si está escribiendo en un input normal (ej: Notas) y NO es el de Select2, salimos\r\n            if (!isSelect2Input && !isBody && !isButton && (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA')) {\r\n                if (currentTime - lastKeyTime < 43 && e.key === 'Enter'){\r\n                    e.preventDefault();\r\n                    if(target.classList.contains('inputcantidad')){\r\n                        const inputcantidad = (target as HTMLInputElement);\r\n                        inputcantidad.value = '1';\r\n                        inputcantidad.dispatchEvent(new Event('input', { bubbles: true }));\r\n                    }\r\n                    return;\r\n                }\r\n                if(target.classList.contains('inputcantidad')&& e.key === 'Enter'){\r\n                    e.preventDefault();\r\n                    btnfacturar?.dispatchEvent( new Event('click'));\r\n                }\r\n            }\r\n\r\n            // 2. LÓGICA DE VELOCIDAD\r\n            if (currentTime - lastKeyTime > 43)barcode = \"\"; \r\n            lastKeyTime = currentTime;\r\n\r\n            // 3. CAPTURA DEL ENTER\r\n            if (e.key === 'Enter') {\r\n                if (barcode.length >= 3) {\r\n                    e.preventDefault();\r\n                    e.stopImmediatePropagation(); // <--- CRITICO: Detiene a Select2 y a cualquier botón\r\n                    searchBarCode(barcode);\r\n                    barcode = \"\";\r\n                    return false;\r\n                }\r\n                if(cobrar){\r\n                    e.preventDefault();\r\n                    btnPagar.click();\r\n                }\r\n                barcode = \"\";\r\n            } else {\r\n                // 4. ACUMULACIÓN\r\n                barcode += e.key;\r\n            }\r\n        }, true); // <--- El \"true\" activa el modo CAPTURA\r\n\r\n\r\n        function searchBarCode(barcode:string){\r\n            const itemselected = allproducts.find(x=>x.sku==barcode);\r\n            if(itemselected != undefined){\r\n                let cantidad = 1, productSelected = carrito.find(x=>x.idproducto==itemselected.id);\r\n                if(productSelected != undefined)cantidad += productSelected.cantidad;\r\n                agregarProducto(itemselected.id, cantidad);\r\n            }\r\n        }\r\n\r\n        ////// EVENTO AL SELECT ARTICULOS O ITEMS PARA SELECCIONAR EL ITEM Y AÑADIR AL CARRITO ////// \r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos){\r\n                let cantidad = 1, itemselected = carrito.find(x=>x.idproducto==datos.id);\r\n                if(itemselected != undefined)cantidad += itemselected.cantidad;\r\n                agregarProducto(datos.id, cantidad);\r\n                $(\"#articulo\").val('null').trigger('change');\r\n            }\r\n        });\r\n\r\n\r\n        function agregarProducto(id:string, cantidad:number) {\r\n            const index = carrito.findIndex(x=>x.idproducto==id);\r\n            if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                const cantidad = 1;\r\n                const itemselected = allproducts.find(x=>x.id==id)!;\r\n                const productototal = Number(itemselected.precio_venta)*cantidad;\r\n                const productovalorimp = productototal*constImp[itemselected.impuesto??'0']; //si producto.impuesto es null toma el valor de cero\r\n                \r\n                //varia segun la prioridad de la comision\r\n                if(itemselected.prioridadcomision === '0')  //si el porcentaje es por usuario\r\n                    itemselected.percentcomision = Number(percentComisionUser);\r\n                const valorcomision:number = (productototal*itemselected.percentcomision)/100;\r\n                \r\n                const item:CarritoItem = {\r\n                    id: '',\r\n                    idproducto: itemselected?.id!,\r\n                    tipoproducto: itemselected.tipoproducto,\r\n                    tipoproduccion: itemselected.tipoproduccion,\r\n                    idcategoria: itemselected.idcategoria,\r\n                    nombreproducto: itemselected.nombre,\r\n                    rendimientoestandar: itemselected.rendimientoestandar,\r\n                    foto: itemselected.foto,\r\n                    costo: itemselected.precio_compra,\r\n                    valorunidad: Number(itemselected.precio_venta),\r\n                    cantidad: cantidad,\r\n                    percentcomision: itemselected.percentcomision,\r\n                    valorcomision: valorcomision,\r\n                    subtotal: productototal, //este es el subtotal del producto\r\n                    base: productototal-productovalorimp,\r\n                    impuesto: itemselected.impuesto, //porcentaje de impuesto, es null si es excluido de iva\r\n                    valorimp: productovalorimp,\r\n                    descuento: 0,\r\n                    total: productototal //valorunidad x cantidad\r\n                }\r\n                carrito = [...carrito, item];\r\n            }else{ //sumar cantidad cuando el item ya existe \r\n                if(cantidad <= 0){\r\n                    cantidad = 0;\r\n                    carrito[index].total = 0;\r\n                    //carrito = carrito.filter(x=>x.iditem != id);\r\n                }\r\n                sumarcantidad(carrito[index], cantidad);\r\n            }\r\n            \r\n            while(tablaMR.firstChild)tablaMR.removeChild(tablaMR.firstChild);\r\n\r\n            carrito.forEach(item=>{\r\n                const tr = document.createElement('tr') as HTMLTableRowElement;\r\n                tr.classList.add('productselect');\r\n                tr.dataset.idproducto = `${item.idproducto}`;\r\n                tr.innerHTML = `<td class=\"py-2 pl-4\">${item.nombreproducto}</td>\r\n                                <td class=\"py-2 text-center cursor-pointer cantidad\"><input type=\"text\" class=\"inputcantidad w-20 p-2 text-center\" value=\"${item.cantidad}\"></td>\r\n                                <td class=\"py-2 text-right\">${item.valorunidad}</td>\r\n                                <td class=\"py-2 text-right totalFila\">${item.total}</td>\r\n                                <td class=\"text-center\"><div class=\"btn-xs btn-red eliminarProducto\"><i class=\"fa-solid fa-trash-can\"></i></div></td>`;\r\n                tablaMR.prepend(tr);\r\n            });\r\n            valorCarritoTotal();\r\n        }\r\n\r\n\r\n        tablaMR?.addEventListener('input', e=>{\r\n            const input = e.target as HTMLInputElement;\r\n            if (!input.classList.contains('inputcantidad')) return;\r\n            const fila = input?.closest('.productselect') as HTMLTableRowElement;\r\n            const idProduct = fila.dataset.idproducto!;\r\n            const productoCarrito = carrito.find(x=>x.idproducto==idProduct);\r\n            \r\n            if(productoCarrito==undefined)return;\r\n                \r\n            let val = input.value;\r\n            val = val.replace(/[^0-9.]/g, '');\r\n            const partes = val.split('.');\r\n            if(partes.length > 2)val = partes[0]+'.'+partes.slice(1).join('');\r\n            if (val.startsWith('.'))val = '1';\r\n            if (val === '' || isNaN(parseFloat(val))) val = '';\r\n\r\n            input.value = val;\r\n            let cantidad = Number(val);\r\n            \r\n            if(cantidad <= 0){\r\n                cantidad = 0;\r\n                productoCarrito.total = 0;\r\n                //carrito = carrito.filter(x=>x.iditem != id);\r\n            }\r\n                \r\n            sumarcantidad(productoCarrito, cantidad);\r\n            valorCarritoTotal();\r\n        });\r\n\r\n        function sumarcantidad(productoCarrito:CarritoItem, cantidad:number){\r\n            productoCarrito.cantidad = cantidad;\r\n            productoCarrito.subtotal = (productoCarrito.valorunidad)*productoCarrito.cantidad;\r\n            productoCarrito.total = productoCarrito.subtotal;\r\n            productoCarrito.valorcomision = (productoCarrito.subtotal*productoCarrito.percentcomision)/100;\r\n            //calculo del impuesto y base por producto en el carrito deventas\r\n            productoCarrito.valorimp = parseFloat((productoCarrito.total*constImp[productoCarrito.impuesto??0]).toFixed(3));\r\n            productoCarrito.base = parseFloat((productoCarrito.total-productoCarrito.valorimp).toFixed(3));\r\n        }\r\n\r\n\r\n        ////// EVENTO POR TECLADO DE LA TABLA MODO RAPIDO DE ITEMS SELECCIONADOS\r\n        tablaMR.addEventListener('keydown', (e: KeyboardEvent) => {\r\n            const target = e.target as HTMLElement;\r\n            if (target.classList.contains('inputcantidad')) { //Delegation al inputcantidad de la tabla\r\n                const input = target as HTMLInputElement;\r\n                if (e.key === 'ArrowUp') {\r\n                    e.preventDefault();\r\n                    input.value = String((Number(input.value) || 0) + 1);\r\n                    beep(900);\r\n                    flashCantidad(input, 'up');\r\n                    input.dispatchEvent(new Event('input', { bubbles: true })); // 🔥 reutiliza lógica\r\n                }\r\n\r\n                if (e.key === 'ArrowDown') {\r\n                    e.preventDefault();\r\n                    input.value = String(Math.max(0, (Number(input.value) || 0) - 1));\r\n                    beep(500);\r\n                    flashCantidad(input, 'down');\r\n                    input.dispatchEvent(new Event('input', { bubbles: true })); // 🔥 reutiliza lógica\r\n                }\r\n            }\r\n        });\r\n\r\n\r\n        document.querySelector('#btnScanner')?.addEventListener('click', ()=>\r\n            (document.querySelector('#articulo') as HTMLSelectElement).focus()\r\n        );\r\n\r\n\r\n        /////////////////////// evento a la tabla de productos de venta (carrito) //////////////////////////\r\n        tablaMR?.addEventListener('click', (e:Event)=>{\r\n            if((e.target as HTMLElement).classList.contains('eliminarProducto') || (e.target as HTMLElement).tagName == \"I\"){\r\n                const elementProduct = (e.target as HTMLElement)?.closest('.productselect');\r\n                const idProduct = (elementProduct as HTMLElement).dataset.idproducto!;\r\n                carrito = carrito.filter(x=>x.idproducto != idProduct);\r\n                valorCarritoTotal();\r\n                tablaMR?.querySelector(`TR[data-idproducto=\"${idProduct}\"]`)?.remove();\r\n            }\r\n        });\r\n\r\n\r\n        function printTarifaEnvio():void{\r\n            tarifas = POS.tarifas;\r\n            const selectDir = dirEntrega.options[dirEntrega.selectedIndex];\r\n        \r\n        }\r\n        \r\n        ////////////////////// valores finales subtotal y total ////////////////////////\r\n        function valorCarritoTotal(){\r\n            valorTotal.valorgananciauser = 0;\r\n            //calcular el impuesto discriminado por tarifa\r\n            const idimpuesto: Record<string, number> = {'0': 1, '5': 2, '16': 3, '19': 4, 'excluido': 5, '8': 6 };\r\n            const objbase:{'0':number, '5':number, '16':number, '19':number, 'excluido':number, '8':number} = {'0': 0, '5': 0, '16': 0, '19': 0, 'excluido':0, '8': 0};\r\n\r\n            const mapImpuesto = new Map();\r\n            carrito.forEach(x=>{\r\n                if(x.impuesto){\r\n                if(mapImpuesto.has(x.impuesto)){\r\n                    const valor = mapImpuesto.get(x.impuesto) + x.total*constImp[x.impuesto];\r\n                    mapImpuesto.set(x.impuesto, valor);\r\n                }else{\r\n                    mapImpuesto.set(x.impuesto, x.total*constImp[x.impuesto]);\r\n                }\r\n                }\r\n                if(x.impuesto == null)x.impuesto = \"excluido\";\r\n                objbase[x.impuesto as keyof typeof objbase] += x.base;\r\n                const impValor = mapImpuesto.get(x.impuesto)??0;\r\n                const index = factimpuestos.findIndex(Obj=>Obj.id_impuesto == idimpuesto[x.impuesto]);\r\n                if(index!=-1){ //si existe remplazar obj\r\n                    factimpuestos[index] = {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor};\r\n                }else{\r\n                    factimpuestos = [...factimpuestos, {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor}];\r\n                }\r\n\r\n                //calcular valor total de comision para el usuario\r\n                valorTotal.valorgananciauser += x.valorcomision;\r\n            });\r\n            \r\n            //Valor del impuesto total de todos los productos, es decir de la factura;\r\n            let valorTotalImp:number = 0;\r\n            for(let valorImp of mapImpuesto.values())valorTotalImp += valorImp;\r\n            valorTotal.valorimpuestototal = parseFloat(valorTotalImp.toFixed(3));  //valor del impuesto total factura de todos los productos\r\n            valorTotal.subtotal = carrito.reduce((total, x)=>x.total+total, 0);\r\n            valorTotal.porcentgananciauser =  (100*valorTotal.valorgananciauser)/valorTotal.subtotal;\r\n            valorTotal.base = valorTotal.subtotal - valorTotal.valorimpuestototal;  //valor de la base total factura de todos los productos\r\n            valorTotal.total = valorTotal.subtotal + valorTotal.valortarifa - valorTotal.descuento;\r\n            document.querySelector('#subTotal')!.textContent = '$'+valorTotal.subtotal.toLocaleString();\r\n            (document.querySelector('#impuesto') as HTMLElement).textContent = '$'+valorTotalImp.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n            //(document.querySelector('#valorTarifa') as HTMLElement).textContent = '$'+valorTotal.valortarifa.toLocaleString();\r\n            document.querySelector('#total')!.textContent = '$ '+valorTotal.total.toLocaleString();\r\n            // cantidad total de productos\r\n            totalUnidades.textContent = carrito.reduce((total, producto)=>producto.cantidad+total, 0)+'';\r\n\r\n            POS.carrito = carrito;\r\n        }\r\n\r\n\r\n        btnguardar?.addEventListener('click', ()=>{if(carrito.length)miDialogoGuardar.showModal();});\r\n        btnfacturar?.addEventListener('click', ()=>{\r\n            if(carrito.length){\r\n                document.querySelector('.Efectivo')?.setAttribute('readonly', 'true');\r\n                document.querySelector('#inputscreditos')?.classList.add('hidden');\r\n                document.querySelector('#inputscreditos')?.classList.remove('flex');\r\n                tipoventa = \"Contado\";\r\n                POS.tipoventa = tipoventa;\r\n                POS.gestionSubirModalPagar.subirModalPagar();\r\n                (document.querySelector('#formfacturar #first') as HTMLInputElement).checked = true;\r\n                miDialogoFacturar.showModal();\r\n            }\r\n        });\r\n\r\n\r\n        ////////////////// evento al bton pagar del modal facturar //////////////////////\r\n        document.querySelector('#formfacturar')?.addEventListener('submit', e=>{\r\n            e.preventDefault();\r\n            if(valorTotal.total <0 || valorTotal.subtotal <0){\r\n                msjAlert('error', 'No se puede procesar pago con $0', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n                return;\r\n            }\r\n\r\n            //calcular si el totoal de los medios de pago es menor al abono inicial, abortar pago...\r\n            let totalMediosPago:number = 0;\r\n            for(let value of mapMediospago.values())totalMediosPago+=value;\r\n            if(totalMediosPago<POS.gestionSubirModalPagar.valoresCredito.abonoinicial){\r\n                msjAlert('error', 'Medio de pago no indicado', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n                return;\r\n            }\r\n        \r\n            btnPagar.disabled = true;\r\n            btnPagar.value = 'Procesando...';\r\n            procesarpedido('Paga', '0');\r\n        });\r\n\r\n        async function procesarpedido(estado:string, ctz:string){\r\n            const imprimir = document.querySelector('input[name=\"imprimir\"]:checked') as HTMLInputElement;\r\n            const valoresCredito = POS.gestionSubirModalPagar.valoresCredito;\r\n            const datos = new FormData();\r\n            //datos.append('id', datosfactura?.id??'');\r\n            datos.append('idcliente', (document.querySelector('#selectCliente') as HTMLSelectElement).value || '1');\r\n            datos.append('idvendedor', (document.querySelector('#vendedor') as HTMLParagraphElement).dataset.idvendedor!);\r\n            datos.append('idcaja', btnCaja.value);\r\n            datos.append('idconsecutivo', btnTipoFacturador.value);\r\n            datos.append('iddireccion', dirEntrega.value);\r\n            datos.append('idtarifazona', valorTotal.idtarifa+'');\r\n            datos.append('idcanaldeventa', (document.querySelector('#canalVenta') as HTMLSelectElement)?.value??'1');\r\n            datos.append('cliente', selectCliente.value==''?'N/A':selectCliente.options[selectCliente.selectedIndex].textContent!);\r\n            datos.append('vendedor', (document.querySelector('#vendedor') as HTMLParagraphElement).textContent!);\r\n            datos.append('caja', (document.querySelector('#caja option:checked') as HTMLSelectElement).textContent!);\r\n            datos.append('tipofacturador', btnTipoFacturador.options[btnTipoFacturador.selectedIndex].textContent!);\r\n            datos.append('direccion', dirEntrega.options[dirEntrega.selectedIndex]?.text??'');\r\n            //datos.append('tarifazona', nombretarifa||'');\r\n            datos.append('carrito', JSON.stringify(carrito.filter(x=>x.cantidad>0)));  //envio de todos los productos con sus cantidades\r\n            datos.append('totalunidades', totalUnidades.textContent!);\r\n            datos.append('mediosPago', JSON.stringify(Array.from(mapMediospago, ([idmediopago, valor])=>({idmediopago, id_factura:0, valor}))));\r\n            datos.append('factimpuestos', JSON.stringify(factimpuestos));\r\n            datos.append('recibido', document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n            datos.append('transaccion', '');\r\n            datos.append('tipoventa', tipoventa);\r\n            datos.append('valoresCredito', JSON.stringify(valoresCredito));\r\n            datos.append('cotizacion', ctz);  //1= cotizacion, 0 = no cotizacion pagada.\r\n            datos.append('estado', estado);\r\n            datos.append('porcentgananciauser', valorTotal.porcentgananciauser.toFixed(2));\r\n            datos.append('valorgananciauser', valorTotal.valorgananciauser.toFixed(2));\r\n            datos.append('subtotal', valorTotal.subtotal+'');\r\n            datos.append('base', valorTotal.base.toFixed(3));\r\n            datos.append('valorimpuestototal', valorTotal.valorimpuestototal+''); //valor total del impuesto. \r\n            datos.append('dctox100',valorTotal.dctox100+'');\r\n            datos.append('descuento',valorTotal.descuento+'');\r\n            datos.append('total', valorTotal.total.toString());\r\n            datos.append('observacion', document.querySelector<HTMLTextAreaElement>('#observacion')!.value);\r\n            datos.append('departamento', '');\r\n            //datos.append('ciudad', (document.querySelector('#ciudad') as HTMLInputElement).value);\r\n            //datos.append('entrega', modalidadEntrega.textContent!.replace(': ', ''));\r\n            datos.append('valortarifa', valorTotal.valortarifa+'');\r\n            datos.append('datosAdquiriente', JSON.stringify(POS.gestionarAdquiriente.datosAdquiriente));\r\n            datos.append('opc1', '');\r\n            datos.append('opc2', '');\r\n            try {\r\n                const url = \"/admin/api/facturarModorapido\";  //va al controlador ventascontrolador\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json();\r\n\r\n                if(estado == \"Paga\"){\r\n                    resultado.dataInvoice.items = carrito.filter(x=>x.cantidad>0);\r\n                    resultado.dataInvoice.mediospago = Array.from(mapMediospago, ([idmediopago, valor])=>({\r\n                    idmediopago,\r\n                    mediopago: mediosPagoDBMAP.get(idmediopago),\r\n                    valor,\r\n                    }));\r\n                }\r\n\r\n                if(resultado.exito !== undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    btnPagar.disabled = false;\r\n                    btnPagar.value = 'Pagar';\r\n                    miDialogoFacturar.close();\r\n                \r\n                    //ENVIAR FACTURA A DIAN SI ES FACTURACION ELECTRONICA\r\n                    if(btnTipoFacturador.options[btnTipoFacturador.selectedIndex].dataset.idtipofacturador == '1'){\r\n                    const resDian = await POS.sendInvoiceAPI.sendInvoice(resultado.idfactura);\r\n                    POS.gestionarAdquiriente.datosAdquiriente = {}; //reiniciar datos de adquiriente cada vez que se facture electronicamente\r\n                    resultado.dataInvoice.cufe = resDian.cufe;\r\n                    resultado.dataInvoice.link = resDian.link;\r\n                    console.log(resDian);\r\n                    }\r\n                    //IMPRIMIR TICKET POS\r\n                    if(resultado.idfactura && imprimir.value === '1')printTicketPOS(resultado.idfactura, resultado.dataInvoice);\r\n                    vaciarventa();\r\n                }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        }\r\n\r\n\r\n        async function printTicketPOS(idfactura:string, datainvoice:DataInvoice){\r\n            try {\r\n                const url = \"http://localhost:3100/api/printPOS/ticket1/CAJA\"; //llamado a la API server print nodejs/ts\r\n                const respuesta = await fetch(url, {\r\n                method: 'POST',\r\n                headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                body: JSON.stringify(datainvoice)\r\n                });\r\n                const resultado = await respuesta.json();\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n\r\n            setTimeout(() => {\r\n                window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");\r\n            }, 1000);\r\n        }\r\n\r\n\r\n        function vaciarventa():void\r\n        {\r\n            //if(datosfactura?.id)datosfactura.id = '';\r\n            (document.querySelector('#formFacturarA') as HTMLFormElement)?.reset();\r\n            (document.querySelector('#formfacturar') as HTMLFormElement)?.reset();\r\n            (document.querySelector('#formAddCliente') as HTMLFormElement).reset();\r\n            (document.querySelector('#badgeEstado') as HTMLParagraphElement).textContent = 'SIN CLIENTE';\r\n            (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.remove('bg-green-100', 'text-green-600');\r\n            (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.add('bg-gray-100', 'text-gray-700');\r\n            (document.querySelector('#resumenCliente') as HTMLParagraphElement).textContent = \"Seleccionar cliente\";\r\n            mapMediospago.clear();\r\n            $('.mediopago').val(0);\r\n            carrito.length = 0;\r\n            factimpuestos.length = 0;\r\n\r\n            history.replaceState({}, \"\", \"/admin/ventas/modorapido\");  //modificar la URL sin recargar la página.\r\n            while(tablaMR?.firstChild)tablaMR.removeChild(tablaMR?.firstChild);\r\n            //(document.querySelector('#npedido') as HTMLInputElement).value = '';\r\n            document.querySelector('#subTotal')!.textContent = '$'+0;\r\n            document.querySelector('#impuesto')!.textContent = '$'+0;\r\n            //(document.querySelector('#descuento') as HTMLElement).textContent = '$'+0;\r\n            totalUnidades.textContent = '0';\r\n            document.querySelector('#total')!.textContent = '$'+0;\r\n            //$('#selectCliente').val('').trigger('change');   //aqui tambien se reinicia la elemento del valor de la tarifa\r\n            for(const key in valorTotal)valorTotal[key as keyof typeof valorTotal] = 0; //reiniciar objeto\r\n        }\r\n\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n            if (f=== miDialogoAddCliente || f=== miDialogoFacturarA || f === miDialogoGuardar || f === miDialogoFacturar || (f as HTMLInputElement).value === 'Cancelar' || (f as HTMLInputElement).closest('.salir') || (f as HTMLInputElement).closest('.noguardar') || (f as HTMLInputElement).closest('.siguardar')) {\r\n                miDialogoFacturarA.close();\r\n                miDialogoFacturar.close();\r\n                miDialogoAddCliente.close();\r\n                miDialogoGuardar.close();\r\n                if((f as HTMLInputElement).closest('.siguardar')){\r\n                    tipoventa = \"\";\r\n                    //procesarpedido('Guardado', '1');\r\n                }\r\n            }\r\n        }\r\n\r\n\r\n        POS.valorCarritoTotal = valorCarritoTotal;\r\n        POS.valorTotal = valorTotal;\r\n        POS.mapMediospago = mapMediospago;\r\n        POS.tarifas = tarifas;\r\n        POS.printTarifaEnvio = printTarifaEnvio;\r\n\r\n    }\r\n\r\n})();","(()=>{\r\n\r\n    if(\r\n        !document.querySelector('.ventasgenerales') &&\r\n        !document.querySelector('.remisiones') &&\r\n        !document.querySelector('.cuotasCreditos') &&\r\n        !document.querySelector('.movimientosinventarios') &&\r\n        !document.querySelector('.estadosfinancierosCreditos') &&\r\n        !document.querySelector('.comisiones'))return;\r\n\r\n     const POS = (window as any).POS;\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\";\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual?.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior?.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy?.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer?.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        POS.callApiReporte(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n    \r\n      POS.callApiReporte(fechainicio, fechafin);\r\n    });\r\n\r\n})();","(function(){\r\n  if(document.querySelector('.reportes')){\r\n    const graficaventa = document.querySelectorAll<HTMLButtonElement>('.graficaventa');\r\n    const chartventas = (document.getElementById('chartventas') as HTMLCanvasElement)?.getContext('2d');\r\n    const chartutilidad = (document.getElementById('chartutilidad') as HTMLCanvasElement)?.getContext('2d');\r\n\r\n    let chartVentasInstance: any | null = null;\r\n\r\n    /*(async ()=>{\r\n        try {\r\n          const url = \"https://apidianj2.com/api/getconfigcompanies\"; //llamado a la API REST Dianlaravel\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          console.log(resultado);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n\r\n    /*new Chart(ctx, {\r\n      type: 'line',\r\n      data: {\r\n          labels: [1,2,3,4,5,6,7,8,9],//resultado.map(programa=>programa.nombre),\r\n          datasets: [{\r\n          label: '# of Votes',\r\n          data: [1,2,3,4,10,3,11,4,17],//resultado.map(programa=>programa.total),\r\n          borderColor: '#00c8c2',\r\n          //backgroundColor: ['#ea580c', '#84cc16', '#22d3ee', '#a855f7'],\r\n          backgroundColor: '#ea580c',\r\n          //tension: 0.3,\r\n          //stepped: 'middle',\r\n          }]\r\n      },\r\n      options: {\r\n          scales: {\r\n              y: {\r\n                  beginAtZero: true\r\n              }\r\n          },\r\n          plugins: {legend: {display: false } } //elimina el label del dataset\r\n      }\r\n    });*/\r\n\r\n\r\n    //graficaVentaMensual.addEventListener('click', ()=>{\r\n      //console.log(777);\r\n      /*(async ()=>{\r\n        try {\r\n          const url = \"https://apidianj2.com/api/getconfigcompanies\"; //llamado a la API REST Dianlaravel\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          console.log(resultado);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n      /*const idcli = 1;\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/ventasGraficaMensual?id=\"+idcli; //llamado a la API REST en reportescontrolador.php\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          console.log(resultado);\r\n          graficaVentas(resultado);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();*/\r\n    //});\r\n\r\n    callapiventasgrafica(\"/admin/api/ventasGraficaMensual\");\r\n\r\n    graficaventa.forEach((btngrafica, index) =>{\r\n      btngrafica.addEventListener('click', (e:Event)=>{\r\n        let url:string = \"/admin/api/ventasGraficaMensual\"; //llamado a la API REST en reportescontrolador.php\r\n        if(index == 1){  //grafico diario\r\n          url = \"/admin/api/ventasGraficaDiario\"; //llamado a la API REST en reportescontrolador.php\r\n        }\r\n        callapiventasgrafica(url);\r\n      })\r\n    });\r\n\r\n    async function callapiventasgrafica(url:string){\r\n      try {\r\n        const respuesta = await fetch(url); \r\n        const resultado = await respuesta.json(); \r\n        graficaVentas(resultado);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n    function graficaVentas(resultado:{label:String[], datos:string[]}){\r\n      if (chartVentasInstance)chartVentasInstance.destroy();\r\n      chartVentasInstance = new Chart(chartventas, {\r\n        type: 'bar',\r\n        data: {\r\n          labels: resultado.label,\r\n          datasets: [{\r\n            label: 'Total Ventas',\r\n            data: resultado.datos,\r\n            borderWidth: 1\r\n          }]\r\n        },\r\n        options: {\r\n          scales: {\r\n            y: {\r\n              beginAtZero: true,\r\n              grid: {display: false} //ocultar regilla horizontal\r\n            },\r\n            x: {\r\n                grid: {display: false}, ////ocultar regilla vertical\r\n            }\r\n          },\r\n          responsive: true,\r\n        }\r\n      });\r\n    }\r\n\r\n\r\n\r\n    ////////////////////////////  chartutilidad - grafica costo/utlidad //////////////////////////////////\r\n    (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/graficaValorInventario\"; //llamado a la API REST en reportescontrolador.php\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          new Chart(chartutilidad, {\r\n            type: 'doughnut',\r\n            data: {\r\n              labels: ['Ventas total:', 'Costo:', 'Utilidad:'],\r\n              datasets: [{\r\n                label: 'Total Ventas',\r\n                data: [Number(resultado.valorventa), Number(resultado.costoinv), (Number(resultado.valorventa) - Number(resultado.costoinv))],\r\n                backgroundColor: ['rgb(54, 162, 235)','rgb(255, 99, 132)', 'rgb(255, 205, 86)'],\r\n                //borderWidth: 1\r\n                hoverOffset: 4\r\n              }]\r\n            },\r\n            options: {\r\n              responsive: true,\r\n              plugins: {\r\n                legend: {\r\n                    labels: {\r\n                        generateLabels: (chart:any) => {\r\n                            const data = chart.data.datasets[0].data;\r\n                            const labels = chart.data.labels;\r\n                            return labels.map((label:any, i:any) => ({\r\n                                text: `${label}: ${data[i]}`,\r\n                                fillStyle: chart.data.datasets[0].backgroundColor[i],\r\n                                index: i\r\n                            }));\r\n                        }\r\n                    }\r\n                }\r\n              }\r\n            }\r\n          });\r\n\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    })();\r\n\r\n\r\n\r\n\r\n    ////////////////////////////////////////////////////////////////////    \r\n    \r\n\r\n    /* cerrarDialogoExterno(event:Event) {\r\n      if (event.target === modalFecha || (event.target as HTMLInputElement).value === 'cancelar' || (event.target as HTMLElement).closest('.finCerrarcaja')) {\r\n          modalFecha.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          if((event.target as HTMLElement).closest('.finCerrarcaja'))console.log(45);//eliminarCita(event.target.closest('.terminarcita').id);\r\n      }\r\n    }*/\r\n\r\n  }\r\n})();","(function(){\r\n  if(document.querySelector('.empleados')){\r\n    const crearempleado = document.querySelector('#crearempleado') as HTMLElement;\r\n    const dialogoEmpleado:any = document.getElementById(\"miDialogoEmpleado\");\r\n    const dialogoContraseña = document.getElementById(\"miDialogoContraseña\");\r\n    const btnupImage = document.querySelector('#upImage') as HTMLInputElement;\r\n    const btncustomUpImage = document.querySelector('#customUpImage') as HTMLButtonElement;\r\n    const imginputfile = document.querySelector('#imginputfile') as HTMLImageElement;  //img\r\n\r\n    const inputNombre = document.querySelector('#nombreempleado') as HTMLInputElement;\r\n    const inputApellido = document.querySelector('#apellidoempleado') as HTMLInputElement;\r\n    const inputnickname = document.querySelector('#nicknameempleado') as HTMLInputElement;\r\n    //const inputcedula = document.querySelector('#cedulaempleado') as HTMLInputElement;\r\n    const inputpassword = document.querySelector('#passwordempleado') as HTMLInputElement;\r\n    const inputpassword2 = document.querySelector('#passwordempleado2 ') as HTMLInputElement;\r\n    const inputMovil = document.querySelector('#movilempleado ') as HTMLInputElement;\r\n    const porcentajeganancia = document.querySelector('#porcentajeganancia ') as HTMLInputElement;\r\n    //const inputEmail = document.querySelector('#emailempleado') as HTMLInputElement;\r\n    //const inputDepartamento = document.querySelector('#departamentoempleado') as HTMLInputElement;\r\n    //const inputCiudad = document.querySelector('#ciudadempleado') as HTMLInputElement;\r\n    //const inputDireccion = document.querySelector('#direccionempleado') as HTMLInputElement;\r\n    const inputPerfil = document.querySelector('#perfilempleado') as HTMLInputElement;\r\n\r\n    let indiceFila=0, control=0, tablaempleados:HTMLElement;\r\n      \r\n    interface empleadoApi {\r\n      id:string,\r\n      nombre: string,\r\n      apellido: string,\r\n      nickname: string,\r\n      cedula: string,\r\n      movil: string,\r\n      email: string,\r\n      departamento: string,\r\n      ciudad: string,\r\n      direccion: string,\r\n      perfil: string, \r\n      porcentajeganancia:string,\r\n      img:string,\r\n      idusuariospermisos:{id:string, usuarioid:string, permisoid:string}[]\r\n      permisos:{id:string, nombre:string}[]\r\n    };\r\n\r\n    let unempleado:empleadoApi|undefined, empleadosapi:empleadoApi[];\r\n\r\n    /////////////////  traer todos los empleados con sus skills  ///////////////////\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getAllemployee\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          empleadosapi = await respuesta.json(); \r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n    inputPerfil.addEventListener('change', (e)=>{\r\n      if((e.target as HTMLSelectElement).value == '2'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n      if((e.target as HTMLSelectElement).value == '3'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"block\";\r\n      }\r\n      if((e.target as HTMLSelectElement).value == '4'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"block\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n    });\r\n\r\n    //////////////////  TABLA //////////////////////\r\n    tablaempleados = ($('#tablaempleados') as any).DataTable(configdatatables);\r\n\r\n    //////////////////// ventana modal al crear empleado  //////////////////////\r\n    crearempleado.addEventListener('click', (e)=>{\r\n      control = 0;\r\n      limpiarformdialog();\r\n      \r\n      (document.querySelector('#campopass1') as HTMLElement).style.display = \"\";\r\n      (document.querySelector('#campopass2') as HTMLElement).style.display = \"\";\r\n      (document.querySelector('#passwordempleado') as HTMLInputElement).setAttribute('required', 'true');\r\n      (document.querySelector('#passwordempleado2') as HTMLInputElement).setAttribute('required', 'true');\r\n\r\n      document.querySelector('#modalEmpleado')!.textContent = \"Crear empleado\";\r\n      (document.querySelector('#btnEditarCrearEmpleado') as HTMLInputElement).value = \"Crear\";\r\n      dialogoEmpleado.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n     //////////////////// Cargar imagen como preview  //////////////////////\r\n    btncustomUpImage.addEventListener('click', ()=>btnupImage.click());\r\n    btnupImage.addEventListener('change', function(){\r\n      const file = this.files?.[0];\r\n      if(file){\r\n        const reader = new FileReader();\r\n        reader.onload = function(){\r\n          const resrult:(string | ArrayBuffer | null) = reader.result;\r\n          if(typeof resrult == \"string\")imginputfile.src = resrult;\r\n        } \r\n        reader.readAsDataURL(file);\r\n      }\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaempleados')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarEmpleado\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarEmpleado\"))editarEmpleado(e);\r\n      if((e.target as HTMLElement)?.classList.contains(\"updatePassword\")||(e.target as HTMLElement).parentElement?.classList.contains(\"updatePassword\"))updatePassword(e);\r\n      if(target?.classList.contains(\"eliminarEmpleado\")||target.parentElement?.classList.contains(\"eliminarEmpleado\"))eliminarEmpleado(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar empleado  //////////////////////\r\n    function editarEmpleado(e:Event){\r\n      let idempleado = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idempleado = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n\r\n      (document.querySelector('#campopass1') as HTMLElement).style.display = \"none\";\r\n      (document.querySelector('#campopass2') as HTMLElement).style.display = \"none\";\r\n      (document.querySelector('#passwordempleado') as HTMLInputElement).removeAttribute('required');\r\n      (document.querySelector('#passwordempleado2') as HTMLInputElement).removeAttribute('required');\r\n\r\n      document.querySelector('#modalEmpleado')!.textContent = \"Actualizar Empleado\";\r\n      (document.querySelector('#btnEditarCrearEmpleado') as HTMLInputElement)!.value = \"Actualizar\";\r\n      unempleado = empleadosapi.find(x => x.id==idempleado); //me trae al empleado seleccionado\r\n      imginputfile.src = \"/build/img/\"+unempleado?.img;\r\n      inputNombre.value = unempleado?.nombre??'';\r\n      inputApellido.value = unempleado?.apellido??'';\r\n      inputnickname.value = unempleado?.nickname??'';\r\n      //inputcedula.value = unempleado?.cedula??'';\r\n      inputMovil.value = unempleado?.movil??'';\r\n      porcentajeganancia.value = unempleado?.porcentajeganancia??'0';\r\n      //inputEmail.value = unempleado?.email??'';\r\n      //inputDepartamento.value = unempleado?.departamento??'';\r\n      //inputCiudad.value = unempleado?.ciudad??'';\r\n      //inputDireccion.value = unempleado?.direccion??'';\r\n      $('#perfilempleado').val(unempleado?.perfil??'');\r\n      if(unempleado?.perfil == '2'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n      if(unempleado?.perfil == '3'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"none\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"block\";\r\n      }\r\n      if(unempleado?.perfil == '4'){\r\n        (document.querySelector('#contentpermisos') as HTMLElement).style.display = \"block\";\r\n        (document.querySelector('#contentpermisosadmin') as HTMLElement).style.display = \"none\";\r\n      }\r\n      printpermisos(unempleado?.permisos??[]);\r\n      indiceFila = (tablaempleados as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      dialogoEmpleado.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    function printpermisos(leave:{id:string, nombre:string}[]){\r\n      document.querySelectorAll<HTMLInputElement>('#contentpermisos input[type=\"checkbox\"]').forEach(checkbox=>{checkbox.checked=false}); //limpia los checkbox\r\n      leave.forEach(s =>{\r\n        const inputpermiso = document.querySelector(`input[value=\"${s.id}\"]`) as HTMLInputElement;\r\n        inputpermiso.checked = true;\r\n      });\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar empleado  //////////////////////\r\n    document.querySelector('#formCrearUpdateEmpleado')?.addEventListener('submit', e=>{\r\n      if(control){\r\n        e.preventDefault();\r\n        var imgFile:(string|File), info = (tablaempleados as any).page.info();\r\n        imgFile=unempleado!.img;\r\n        if(!imginputfile.src.includes(unempleado!.img)){ //cambio de imagen\r\n          imgFile = ((e.target as HTMLFormElement).elements.namedItem(\"upImage\") as HTMLInputElement).files?.[0]!; //obtengo el archivo\r\n          if(imgFile){\r\n            if(imgFile.type!==\"image/png\"&&imgFile.type!==\"image/jpeg\"){\r\n              msjAlert('error', 'No es un formato valido para la foto', (document.querySelector('#divmsjalertaempleado1') as HTMLElement));\r\n              return;\r\n            }\r\n            if(imgFile.size>550000){ //si es mayor a 550KB\r\n              msjAlert('error', 'La imagen no debe superar los 500KB', document.querySelector('#divmsjalertaempleado1')!);\r\n              return;\r\n            }\r\n          }\r\n        }\r\n\r\n        var arraypermisos:{id:string, nombre:string}[] = [];\r\n        document.querySelectorAll<HTMLInputElement>('#contentpermisos input[type=\"checkbox\"]').forEach(x=>{\r\n          if(x.checked)arraypermisos = [...arraypermisos, {id:x.value, nombre: x.nextElementSibling?.textContent??'permiso'}];\r\n        });\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unempleado!.id);\r\n          datos.append('img', imgFile); //en el backend no se lee con $_POST, se lee con $_FILES\r\n          datos.append('nombre', inputNombre.value);\r\n          datos.append('apellido', inputApellido.value);\r\n          datos.append('nickname', inputnickname.value);\r\n          //datos.append('cedula', inputcedula.value);\r\n          datos.append('password', inputpassword.value);\r\n          datos.append('password2', inputpassword2.value);\r\n          datos.append('movil', inputMovil.value);\r\n          datos.append('porcentajeganancia', porcentajeganancia.value);\r\n          //datos.append('email', inputEmail.value);\r\n          //datos.append('departamento', inputDepartamento.value);\r\n          //datos.append('ciudad', inputCiudad.value);\r\n          //datos.append('direccion', inputDireccion.value);\r\n          datos.append('perfil', inputPerfil.value);\r\n          datos.append('idpermisos', JSON.stringify(arraypermisos.map(v=>v.id)));\r\n          try {\r\n              const url = \"/admin/api/actualizarEmpleado\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                ///////// cambiar la fila completa, su contenido //////////\r\n                const datosActuales = (tablaempleados as any).row(indiceFila+=info.start).data();\r\n                /*NOMBRE*/datosActuales[1] = inputNombre.value +' '+inputApellido.value;\r\n                /*img*/datosActuales[2] = `<div class=\"text-center\"><img style=\"width: 40px;\" src=\"/build/img/${resultado.rutaimg}\" alt=\"\"></div>`;\r\n                /*USER*/datosActuales[3] = inputnickname.value;\r\n                /*PERFIL*/datosActuales[6] = inputPerfil.value==='1'?'root':inputPerfil.value=='2'?'Superior':inputPerfil.value == '3'?'Admin':'Asesor';\r\n                //actualizar el empleado y arreglo de permisos\r\n                empleadosapi.forEach(a=>{\r\n                  if(a.id == unempleado?.id){\r\n                    a.nombre = inputNombre.value;\r\n                    a.apellido = inputApellido.value;\r\n                    a.nickname = inputnickname.value;\r\n                    a.movil = inputMovil.value;\r\n                    a.porcentajeganancia = porcentajeganancia.value;\r\n                    a.perfil = inputPerfil.value;\r\n                    a.permisos = arraypermisos; //arreglo de permisos\r\n                    a.img = resultado.rutaimg;\r\n                  }\r\n                });\r\n\r\n                (tablaempleados as any).row(indiceFila).data(datosActuales).draw();\r\n                (tablaempleados as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n              dialogoEmpleado.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n      } //fin if(control)\r\n    });\r\n\r\n\r\n    ////////////////////  Actualizar contraseña del empleado  //////////////////////\r\n    function updatePassword(e:Event){\r\n      let idempleado = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement).tagName === 'I')idempleado = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      unempleado = empleadosapi.find(x => x.id==idempleado);\r\n      (document.querySelector('#nombreEmpleadoPass') as HTMLElement).textContent = unempleado?.nombre+\" \"+(unempleado?.apellido??'');\r\n      (dialogoContraseña as any)?.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    document.querySelector('#formContraseña')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      (async ()=>{\r\n        const datos = new FormData();\r\n        datos.append('id', unempleado!.id);\r\n        datos.append('password', (document.querySelector('#changePassword') as HTMLInputElement).value);\r\n        try {\r\n            const url = \"/admin/api/updatepassword\";\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.exito[0]);\r\n            }\r\n            (dialogoContraseña as any)?.close();\r\n            document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar el empleado  //////////////////////\r\n    function eliminarEmpleado(e:Event){\r\n      let idempleado = (e.target as HTMLElement).parentElement!.id, info = (tablaempleados as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idempleado = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaempleados as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el empleado?',\r\n          text: \"El empleado sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idempleado);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarEmpleado\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaempleados as any).row(indiceFila).remove().draw(); \r\n                        (tablaempleados as any).page(info.page).draw('page');\r\n                        empleadosapi = empleadosapi.filter(x=>x.id!=idempleado);\r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === dialogoEmpleado || event.target === dialogoContraseña || (event.target as HTMLInputElement).value === 'Cancelar') {\r\n          dialogoEmpleado.close();\r\n          (dialogoContraseña as any)?.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      imginputfile.src = ' ';\r\n      (document.querySelector('#formCrearUpdateEmpleado') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.gestionbancos')){\r\n    const crearBanco = document.querySelector('#crearBanco') as HTMLButtonElement;\r\n    const miDialogoBanco = document.querySelector('#miDialogoBanco') as any;\r\n\r\n    let indiceFila=0, control=0, tablaBancos:HTMLElement;\r\n\r\n    type bancosapi = {\r\n        id:string,\r\n        nombre: string,\r\n        numerocuenta: string,\r\n        saldo: string,\r\n        estado: string,\r\n        created_at: string\r\n      };\r\n  \r\n      let bancos:bancosapi[]=[], unbanco:bancosapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allbancos\"; //llamado a la API REST y se trae todos los bancos\r\n            const respuesta = await fetch(url); \r\n            bancos = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaBancos = ($('#tablaBancos') as any).DataTable(configdatatables);\r\n\r\n    crearBanco.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalBanco')!.textContent = \"Crear banco\";\r\n        (document.querySelector('#btnEditarCrearBanco') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoBanco.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaBancos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarBanco\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarBanco\"))editarBanco(e);\r\n      if(target?.classList.contains(\"eliminarBanco\")||target.parentElement?.classList.contains(\"eliminarBanco\"))eliminarBanco(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar banco  //////////////////////\r\n    function editarBanco(e:Event){\r\n      let idbanco = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idbanco = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalBanco')!.textContent = \"Actualizar banco\";\r\n      (document.querySelector('#btnEditarCrearBanco') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unbanco = bancos.find(x => x.id==idbanco); //me trae a la banco seleccionada\r\n      (document.querySelector('#nombreBanco')as HTMLInputElement).value = unbanco?.nombre!;\r\n      (document.querySelector('#numeroCuenta')as HTMLInputElement).value = unbanco?.numerocuenta!;\r\n      \r\n      indiceFila = (tablaBancos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoBanco.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar banco  //////////////////////\r\n    document.querySelector('#formCrearUpdateBanco')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearBanco\";\r\n      if(control)urlApi = \"actualizarBanco\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaBancos as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unbanco?.id?unbanco?.id:'');\r\n          datos.append('nombre', $('#nombreBanco').val()as string);\r\n          datos.append('numerocuenta', $('#numeroCuenta').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoBanco.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de la banco ///\r\n                  bancos = [...bancos, resultado.banco];\r\n                  (tablaBancos as any).row.add([\r\n                      (tablaBancos as any).rows().count() + 1,\r\n                      resultado.banco.nombre,\r\n                      resultado.banco.numerocuenta,\r\n                      resultado.banco.created_at,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.banco.id}\" data-banco=\"${resultado.banco.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarBanco\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarBanco\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de bancos ///\r\n                  bancos.forEach(a=>{if(a.id == unbanco?.id)a = Object.assign(a, resultado.banco[0]);});\r\n                  const datosActuales = (tablaBancos as any).row(indiceFila+=info.start).data();\r\n                  /*BANCO*/      datosActuales[1] = resultado.banco[0].nombre;\r\n                  /*NUM CUENTA*/ datosActuales[2] = resultado.banco[0].numerocuenta;\r\n                  (tablaBancos as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaBancos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar banco  //////////////////////\r\n    function eliminarBanco(e:Event){\r\n      let idbanco = (e.target as HTMLElement).parentElement!.id, info = (tablaBancos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idbanco = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaBancos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el banco?',\r\n          text: \"El banco sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idbanco);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarBanco\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaBancos as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaBancos as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoBanco || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoBanco.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrarbanco')){  //Cuando se hace el cierre de banco\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateBanco') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.gestioncajas')){\r\n    const crearCaja = document.querySelector('#crearCaja') as HTMLButtonElement;\r\n    const miDialogoCaja = document.querySelector('#miDialogoCaja') as any;\r\n\r\n    let indiceFila=0, control=0, tablaCajas:HTMLElement;\r\n\r\n    type cajasapi = {\r\n        id:string,\r\n        idtipoconsecutivo: string,\r\n        nombre: string,\r\n        negocio: string\r\n      };\r\n  \r\n      let cajas:cajasapi[]=[], unacaja:cajasapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allcajas\"; //llamado a la API REST y se trae todos las cajas\r\n            const respuesta = await fetch(url); \r\n            cajas = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaCajas = ($('#tablaCajas') as any).DataTable(configdatatables);\r\n\r\n    crearCaja.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalCaja')!.textContent = \"Crear caja\";\r\n        (document.querySelector('#btnEditarCrearCaja') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoCaja.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaCajas')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarCaja\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarCaja\"))editarCaja(e);\r\n      if(target?.classList.contains(\"eliminarCaja\")||target.parentElement?.classList.contains(\"eliminarCaja\"))eliminarCaja(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar caja  //////////////////////\r\n    function editarCaja(e:Event){\r\n      let idcaja = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idcaja = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalCaja')!.textContent = \"Actualizar caja\";\r\n      (document.querySelector('#btnEditarCrearCaja') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unacaja = cajas.find(x => x.id==idcaja); //me trae a la caja seleccionada\r\n      (document.querySelector('#nombrecaja')as HTMLInputElement).value = unacaja?.nombre!;\r\n      $('#idtipoconsecutivo').val(unacaja?.idtipoconsecutivo??'');\r\n      $('#negociogestioncaja').val(1);\r\n      \r\n      indiceFila = (tablaCajas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoCaja.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar caja  //////////////////////\r\n    document.querySelector('#formCrearUpdateCaja')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearCaja\";\r\n      if(control)urlApi = \"actualizarCaja\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaCajas as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unacaja?.id?unacaja?.id:'');\r\n          datos.append('idtipoconsecutivo', $('#idtipoconsecutivo').val()as string);\r\n          datos.append('nombre', $('#nombrecaja').val()as string);\r\n          datos.append('negocio', $('#negociogestioncaja').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoCaja.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de la caja ///\r\n                  cajas = [...cajas, resultado.caja];\r\n                  (tablaCajas as any).row.add([\r\n                      (tablaCajas as any).rows().count() + 1,\r\n                      resultado.caja.nombre,\r\n                      resultado.caja.nombreconsecutivo.nombre,\r\n                      resultado.caja.negocio,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.caja.id}\" data-caja=\"${resultado.caja.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarCaja\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarCaja\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de cajas ///\r\n                  cajas.forEach(a=>{if(a.id == unacaja?.id)a = Object.assign(a, resultado.caja[0]);});\r\n                  const datosActuales = (tablaCajas as any).row(indiceFila+=info.start).data();\r\n                  /*CAJA*/      datosActuales[1] = resultado.caja[0].nombre;\r\n                  /*FACT AUTO*/ datosActuales[2] = $('#idtipoconsecutivo option:selected').text();\r\n                  /*NEGOCIO*/   datosActuales[3] = $('#negociogestioncaja option:selected').text();\r\n                  (tablaCajas as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaCajas as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar caja  //////////////////////\r\n    function eliminarCaja(e:Event){\r\n      let idcaja = (e.target as HTMLElement).parentElement!.id, info = (tablaCajas as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idcaja = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaCajas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar la caja?',\r\n          text: \"La caja sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idcaja);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarCaja\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaCajas as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaCajas as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoCaja || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoCaja.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrarcaja')){  //Cuando se hace el cierre de caja\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCaja') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.gestionfacturadores')){\r\n    const POS = (window as any).POS;\r\n    const crearFacturador = document.querySelector('#crearFacturador') as HTMLButtonElement;\r\n    const miDialogoFacturador = document.querySelector('#miDialogoFacturador') as any;\r\n\r\n    let indiceFila=0, control=0, tablaFacturadores:HTMLElement;\r\n\r\n    type facturadoresapi = {\r\n        id:string,\r\n        id_sucursalid: string,\r\n        idtipofacturador: string,\r\n        idnegocio: string,\r\n        nombre: string\r\n        rangoinicial:string,\r\n        rangofinal: string,\r\n        siguientevalor: string,\r\n        fechainicio: string\r\n        fechafin:string,\r\n        resolucion: string,\r\n        consecutivoremplazo: string,\r\n        prefijo: string,\r\n        mostrarresolucion:string,\r\n        mostrarimpuestodiscriminado: string,\r\n        tokenfacturaelectronica: string,\r\n        electronica: string,\r\n        estado: string\r\n      };\r\n  \r\n      let facturadores:facturadoresapi[]=[], unfacturador:facturadoresapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allfacturadores\"; //llamado a la API REST y se trae todos los consecutivos\r\n            const respuesta = await fetch(url); \r\n            facturadores = await respuesta.json();\r\n            POS.facturadores = facturadores;  //se expone globalmente para procesar en gestiondian.ts\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaFacturadores = ($('#tablaFacturadores') as any).DataTable(configdatatables);\r\n\r\n    crearFacturador.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalFacturador')!.textContent = \"Crear facturador\";\r\n        (document.querySelector('#btnEditarCrearFacturador') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoFacturador.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaFacturadores')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarFacturador\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarFacturador\"))editarFacturador(e);\r\n      if(target?.classList.contains(\"eliminarFacturador\")||target.parentElement?.classList.contains(\"eliminarFacturador\"))eliminarFacturador(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar facturador  //////////////////////\r\n    function editarFacturador(e:Event){\r\n      let idfacturador = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idfacturador = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalFacturador')!.textContent = \"Actualizar facturador\";\r\n      (document.querySelector('#btnEditarCrearFacturador') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unfacturador = facturadores.find(x => x.id==idfacturador); //me trae el facturador seleccionado\r\n      (document.querySelector('#nombrefacturador')as HTMLInputElement).value = unfacturador?.nombre!;\r\n      $('#idtipofacturador').val(unfacturador?.idtipofacturador??'');\r\n      $('#rangoinicial').val(unfacturador?.rangoinicial??'');\r\n      $('#rangofinal').val(unfacturador?.rangofinal??'');\r\n      $('#siguientevalor').val(unfacturador?.siguientevalor??'');\r\n      $('#fechainicio').val(unfacturador?.fechainicio??'');\r\n      $('#fechafin').val(unfacturador?.fechafin??'');\r\n      $('#resolucion').val(unfacturador?.resolucion??'');\r\n      $('#prefijo').val(unfacturador?.prefijo??'');\r\n      $('#negociofacturador').val(1);\r\n      \r\n      indiceFila = (tablaFacturadores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoFacturador.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar facturador  //////////////////////\r\n    document.querySelector('#formCrearUpdateFacturador')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearFacturador\";\r\n      if(control)urlApi = \"actualizarFacturador\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaFacturadores as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unfacturador?.id?unfacturador?.id:'');\r\n          datos.append('idtipofacturador', $('#idtipofacturador').val()as string);\r\n          datos.append('idnegocio', $('#negociofacturador').val()as string);\r\n          datos.append('nombre', $('#nombrefacturador').val()as string);\r\n          datos.append('rangoinicial', $('#rangoinicial').val()as string);\r\n          datos.append('rangofinal', $('#rangofinal').val()as string);\r\n          datos.append('siguientevalor', $('#siguientevalor').val()as string);\r\n          datos.append('fechainicio', $('#fechainicio').val()as string);\r\n          datos.append('fechafin', $('#fechafin').val()as string);\r\n          datos.append('resolucion', $('#resolucion').val()as string);\r\n          //datos.append('consecutivoremplazo', $('#negociofacturador').val()as string);\r\n          datos.append('prefijo', $('#prefijo').val()as string);\r\n          /*datos.append('mostrarresolucion', $('#negociofacturador').val()as string);\r\n          datos.append('mostrarimpuestodiscriminado', $('#nombrefacturador').val()as string);\r\n          datos.append('tokenfacturaelectronica', $('#negociofacturador').val()as string);\r\n          datos.append('electronica', $('#negociofacturador').val()as string);\r\n          datos.append('estado', $('#nombrefacturador').val()as string);*/\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoFacturador.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle del facturador///\r\n                  facturadores = [...facturadores, resultado.facturador];\r\n                  (tablaFacturadores as any).row.add([\r\n                      (tablaFacturadores as any).rows().count() + 1,\r\n                      resultado.facturador.nombre,\r\n                      resultado.facturador.nombretipofacturador.nombre,\r\n                      resultado.facturador.rangoinicial,\r\n                      resultado.facturador.siguientevalor,\r\n                      resultado.facturador.fechafin,\r\n                      resultado.facturador.estado==1?'Activo':'Inactivo',\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.facturador.id}\" data-facturador=\"${resultado.facturador.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarFacturador\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarFacturador\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                  crearConsecutivoGestionCaja(resultado.facturador.id, resultado.facturador.nombre);\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de facturadores ///\r\n                  facturadores.forEach(a=>{if(a.id == unfacturador?.id)a = Object.assign(a, resultado.facturador[0]);});\r\n                  const datosActuales = (tablaFacturadores as any).row(indiceFila+=info.start).data();\r\n                  /*xx*/datosActuales[1] = resultado.facturador[0].nombre;\r\n                  /*x*/ datosActuales[2] = resultado.facturador[0].nombretipofacturador;\r\n                  /*x*/ datosActuales[3] = resultado.facturador[0].rangoinicial;\r\n                        datosActuales[4] = resultado.facturador[0].siguientevalor;\r\n                        datosActuales[5] = resultado.facturador[0].fechafin;\r\n                        datosActuales[6] = resultado.facturador[0].estado==1?'Activo':'Inactivo';\r\n                  (tablaFacturadores as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaFacturadores as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                  actualizarConsecutivoGestionCaja(unfacturador!.id, resultado.facturador[0].nombre);\r\n                }\r\n              }else{\r\n                miDialogoFacturador.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar facturador  //////////////////////\r\n    function eliminarFacturador(e:Event){\r\n      let idfacturador = (e.target as HTMLElement).parentElement!.id, info = (tablaFacturadores as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idfacturador = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaFacturadores as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el facturador?',\r\n          text: \"El facturador sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idfacturador);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarFacturador\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaFacturadores as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaFacturadores as any).page(info.page).draw('page');\r\n                        eliminardegestioncaja(idfacturador);\r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function crearConsecutivoGestionCaja(idfacturador:string, nombre:string){\r\n      const selectConsecutivoCaja = document.querySelector('#idtipoconsecutivo') as HTMLSelectElement;\r\n      const option = document.createElement('option');\r\n      option.value = idfacturador;\r\n      option.textContent = nombre;\r\n      selectConsecutivoCaja.appendChild(option);\r\n    }\r\n\r\n    function actualizarConsecutivoGestionCaja(idfacturador:string, nombre:string){\r\n      const selectConsecutivoCaja = document.querySelector('#idtipoconsecutivo') as HTMLSelectElement;\r\n      const opcionconsecutivo = selectConsecutivoCaja.querySelector(`option[value=\"${idfacturador}\"]`) as HTMLOptionElement;\r\n      opcionconsecutivo.textContent = nombre;\r\n    }\r\n\r\n    function eliminardegestioncaja(idfacturador:string){\r\n      const selectConsecutivoCaja = document.querySelector('#idtipoconsecutivo') as HTMLSelectElement;\r\n      const opcionconsecutivo = selectConsecutivoCaja.querySelector(`option[value=\"${idfacturador}\"]`);\r\n      opcionconsecutivo?.remove();\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoFacturador || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoFacturador.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateFacturador') as HTMLFormElement)?.reset();\r\n    }\r\n  }\r\n  \r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.gestionimpresoras')){\r\n    const crearImpresora = document.querySelector('#crearImpresora') as HTMLButtonElement;\r\n    const miDialogoIMpresora = document.querySelector('#miDialogoIMpresora') as any;\r\n\r\n    let indiceFila=0, control=0, tablaImpresoras:HTMLElement;\r\n\r\n    type printersApi = {\r\n      id:string,\r\n      nombre: string,\r\n      nombrecompartido: string,\r\n      estacion: string,\r\n      estado: string,\r\n      created_at: string\r\n    };\r\n\r\n    let impresoras:printersApi[]=[], unPrinter:printersApi|undefined;\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/allPrinters\"; //llamado a la API REST y se trae todos las impresoras\r\n          const respuesta = await fetch(url); \r\n          impresoras = await respuesta.json(); \r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaImpresoras = ($('#tablaImpresoras') as any).DataTable(configdatatables);\r\n\r\n    crearImpresora.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalIMpresora')!.textContent = \"Crear punto de impresora\";\r\n        (document.querySelector('#btnEditarCrearImpresora') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoIMpresora.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaImpresoras')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarImpresora\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarImpresora\"))editarImpresora(e);\r\n      if(target?.classList.contains(\"eliminarImpresora\")||target.parentElement?.classList.contains(\"eliminarImpresora\"))eliminarImpresora(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar impresora  //////////////////////\r\n    function editarImpresora(e:Event){\r\n      let idimpresora = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idimpresora = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalIMpresora')!.textContent = \"Actualizar punto de impresora\";\r\n      (document.querySelector('#btnEditarCrearImpresora') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unPrinter = impresoras.find(x => x.id==idimpresora); //me trae a lA impresora seleccionada\r\n      (document.querySelector('#nombreImpresora')as HTMLInputElement).value = unPrinter?.nombre!;\r\n      (document.querySelector('#nombreCompartido')as HTMLInputElement).value = unPrinter?.nombrecompartido!;\r\n      (document.querySelector('#estacion')as HTMLInputElement).value = unPrinter?.estacion!;\r\n      \r\n      indiceFila = (tablaImpresoras as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoIMpresora.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar impresora  //////////////////////\r\n    document.querySelector('#formCrearUpdateIMpresora')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearImpresora\";\r\n      if(control)urlApi = \"actualizarIMpresora\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaImpresoras as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unPrinter?.id?unPrinter?.id:'');\r\n          datos.append('nombre', $('#nombreIMpresora').val()as string);\r\n          datos.append('nombrecompartido', $('#nombrecompartido').val()as string);\r\n          datos.append('estacion', $('#estacion').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoIMpresora.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de las impresoras ///\r\n                  impresoras = [...impresoras, resultado.printer];\r\n                  (tablaImpresoras as any).row.add([\r\n                      (tablaImpresoras as any).rows().count() + 1,\r\n                      resultado.printer.nombre,\r\n                      resultado.printer.nombrecompartido,\r\n                      resultado.printer.estacion,\r\n                      resultado.printer.created_at,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.printer.id}\">\r\n                          <button class=\"btn-md btn-turquoise editarImpresora\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarImpresora\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de impresoras ///\r\n                  impresoras.forEach(a=>{if(a.id == unPrinter?.id)a = Object.assign(a, resultado.printer[0]);});\r\n                  const datosActuales = (tablaImpresoras as any).row(indiceFila+=info.start).data();\r\n                  /*NOMBRE*/      datosActuales[1] = resultado.printer[0].nombre;\r\n                  /*NOMBRECOMPARTIDO*/ datosActuales[2] = resultado.printer[0].nombrecompartido;\r\n                  /*ESTACION*/ datosActuales[3] = resultado.printer[0].estacion;\r\n                  (tablaImpresoras as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaImpresoras as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar impresora  //////////////////////\r\n    function eliminarImpresora(e:Event){\r\n      let idimpresora = (e.target as HTMLElement).parentElement!.id, info = (tablaImpresoras as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idimpresora = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaImpresoras as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el impresora?',\r\n          text: \"El impresora sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idimpresora);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarImpresora\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaImpresoras as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaImpresoras as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoIMpresora || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoIMpresora.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateIMpresora') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.mediosPagos')){\r\n    const crearMedioPago = document.querySelector('#crearMedioPago') as HTMLButtonElement;\r\n    const miDialogoMedioPago = document.querySelector('#miDialogoMedioPago') as any;\r\n\r\n    let indiceFila=0, control=0, tablamediosPagos:HTMLElement;\r\n\r\n    type mediospagoapi = {\r\n        id:string,\r\n        mediopago: string,\r\n        estado: string,\r\n        nick: string\r\n      };\r\n  \r\n      let mediospagos:mediospagoapi[]=[], unmediopago:mediospagoapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/allmediospago\"; //llamado a la API REST y se trae todos las medios de pago\r\n            const respuesta = await fetch(url); \r\n            mediospagos = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablamediosPagos = ($('#tablamediosPagos') as any).DataTable(configdatatables);\r\n\r\n    crearMedioPago.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalMedioPago')!.textContent = \"Crear medio de pago\";\r\n        (document.querySelector('#btnEditarCrearMedioPago') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoMedioPago.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablamediosPagos')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"statemediopago\"))changeState(e);\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarMedioPago\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarMedioPago\"))editarMedioPago(e);\r\n      if(target?.classList.contains(\"eliminarMedioPago\")||target.parentElement?.classList.contains(\"eliminarMedioPago\"))eliminarMedioPago(e);\r\n    });\r\n\r\n\r\n    ///////////////  Cambiar estado del medio de pago  ////////////////\r\n    function changeState(e:Event){\r\n      const button=(e.target as HTMLButtonElement), info = (tablamediosPagos as any).page.info();\r\n      indiceFila =  (tablamediosPagos as any).row(button.closest('tr')).index();\r\n      (async ()=>{ \r\n        const datos = new FormData();\r\n        datos.append('id', button.id);\r\n        datos.append('estado', button.dataset.state=='0'?'1':'0');\r\n        try {\r\n            const url = \"/admin/api/updateStateMedioPago\";\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();  \r\n            if(resultado.exito !== undefined){\r\n              const s1 = `<button id=\"${button.id}\" data-state=\"${button.dataset.state=='0'?'1':'0'}\" class=\"statemediopago btn-xs ${button.dataset.state=='0'?'btn-lima':'btn-red'}\">${button.dataset.state=='0'?'Activo':'Inactivo'}</button>`;\r\n              (tablamediosPagos as any).cell((tablamediosPagos as any).row(indiceFila+=info.start), 2).data(s1).draw(); //se modifica solo la columna con la fila correspondiente, y destruye la que habai antes\r\n              (tablamediosPagos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n            }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();//cierre de async()\r\n    }\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar medio de pago  //////////////////////\r\n    function editarMedioPago(e:Event){\r\n      let idmediopago = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idmediopago = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalMedioPago')!.textContent = \"Actualizar medio de pago\";\r\n      (document.querySelector('#btnEditarCrearMedioPago') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unmediopago = mediospagos.find(x => x.id==idmediopago); //me trae el emdio de pago seleccionado\r\n      (document.querySelector('#nombreMedioPago')as HTMLInputElement).value = unmediopago?.mediopago!;\r\n      \r\n      indiceFila = (tablamediosPagos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoMedioPago.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar medio de pago  //////////////////////\r\n    document.querySelector('#formCrearUpdateMedioPago')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearMedioPago\";\r\n      if(control)urlApi = \"actualizarMedioPago\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablamediosPagos as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unmediopago?.id?unmediopago?.id:'');\r\n          datos.append('mediopago', $('#nombreMedioPago').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoMedioPago.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de los medios de pagos ///\r\n                  mediospagos = [...mediospagos, resultado.mediopago];\r\n                  (tablamediosPagos as any).row.add([\r\n                      (tablamediosPagos as any).rows().count() + 1,\r\n                      resultado.mediopago.mediopago,\r\n                      resultado.mediopago.estado == '1'?'Activo':'Inactivo',\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.mediopago.id}\" data-mediopago=\"${resultado.mediopago.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarMedioPago\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarMedioPago\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de medios de pagos ///\r\n                  mediospagos.forEach(a=>{if(a.id == unmediopago?.id)a = Object.assign(a, resultado.mediopago[0]);});\r\n                  const datosActuales = (tablamediosPagos as any).row(indiceFila+=info.start).data();\r\n                  /*MEDIO DE PAGO*/ datosActuales[1] = resultado.mediopago.mediopago;\r\n                  /*ESTADO*/        datosActuales[2] = resultado.mediopago.estado == '1'?'Activo':'Inactivo';\r\n                  (tablamediosPagos as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablamediosPagos as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar medio de pago  //////////////////////\r\n    function eliminarMedioPago(e:Event){\r\n      let idmediopago = (e.target as HTMLElement).parentElement!.id, info = (tablamediosPagos as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idmediopago = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablamediosPagos as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar el medio de pago?',\r\n          text: \"El medio de pago sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idmediopago);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarMedioPago\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablamediosPagos as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablamediosPagos as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoMedioPago || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoMedioPago.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrarcaja')){  //Cuando se hace el cierre de caja\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCaja') as HTMLFormElement)?.reset();\r\n    }\r\n  }\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.tarifas')){\r\n    const crearTarifa = document.querySelector('#crearTarifa') as HTMLButtonElement;\r\n    const miDialogoTarifa = document.querySelector('#miDialogoTarifa') as any;\r\n\r\n    let indiceFila=0, control=0, tablaTarifas:HTMLElement;\r\n\r\n    type tarifasapi = {\r\n        id:string,\r\n        nombre: string,\r\n        valor: string,\r\n      };\r\n  \r\n      let tarifas:tarifasapi[]=[], unatarifa:tarifasapi|undefined;\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/alltarifas\"; //llamado a la API REST y se trae todos las tarifas\r\n            const respuesta = await fetch(url); \r\n            tarifas = await respuesta.json(); \r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n     //////////////////  TABLA //////////////////////\r\n    tablaTarifas = ($('#tablaTarifas') as any).DataTable(configdatatables);\r\n\r\n    crearTarifa.addEventListener('click', ()=>{\r\n        control = 0;\r\n        limpiarformdialog();\r\n        document.querySelector('#modalTarifa')!.textContent = \"Crear tarifa\";\r\n        (document.querySelector('#btnEditarCrearTarifa') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoTarifa.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    document.querySelector('#tablaTarifas')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if((e.target as HTMLElement)?.classList.contains(\"editarTarifa\")||(e.target as HTMLElement).parentElement?.classList.contains(\"editarTarifa\"))editarTarifa(e);\r\n      if(target?.classList.contains(\"eliminarTarifa\")||target.parentElement?.classList.contains(\"eliminarTarifa\"))eliminarTarifa(e);\r\n    });\r\n\r\n    //////////////////// ventana modal al Actualizar/Editar tarifa  //////////////////////\r\n    function editarTarifa(e:Event){\r\n      let idtarifa = (e.target as HTMLElement).parentElement?.id;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idtarifa = (e.target as HTMLElement).parentElement?.parentElement?.id;\r\n      control = 1;\r\n      document.querySelector('#modalTarifa')!.textContent = \"Actualizar tarifa\";\r\n      (document.querySelector('#btnEditarCrearTarifa') as HTMLInputElement)!.value = \"Actualizar\";\r\n      \r\n      unatarifa = tarifas.find(x => x.id==idtarifa); //me trae a la tarifa seleccionada\r\n      (document.querySelector('#nombreTarifa')as HTMLInputElement).value = unatarifa?.nombre!;\r\n      (document.querySelector('#valorTarifa')as HTMLInputElement).value = unatarifa?.valor!;\r\n      \r\n      indiceFila = (tablaTarifas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      miDialogoTarifa.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n    ////////////////////  Actualizar/Editar tarifa  //////////////////////\r\n    document.querySelector('#formCrearUpdateTarifa')?.addEventListener('submit', e=>{\r\n      let urlApi = \"crearTarifa\";\r\n      if(control)urlApi = \"actualizarTarifa\";\r\n\r\n        e.preventDefault();\r\n        var info = (tablaTarifas as any).page.info();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          datos.append('id', unatarifa?.id?unatarifa?.id:'');\r\n          datos.append('nombre', $('#nombreTarifa').val()as string);\r\n          datos.append('valor', $('#valorTarifa').val()as string);\r\n          try {\r\n              const url = \"/admin/api/\"+urlApi;\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                miDialogoTarifa.close();\r\n                document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                if(!control){ //si es crear registro\r\n                  /// actualizar el arregle de la tarifa ///\r\n                  tarifas = [...tarifas, resultado.tarifa];\r\n                  (tablaTarifas as any).row.add([\r\n                      (tablaTarifas as any).rows().count() + 1,\r\n                      resultado.tarifa.nombre,\r\n                      resultado.tarifa.valor,\r\n                      `<div class=\"acciones-btns\" id=\"${resultado.tarifa.id}\" data-tarifa=\"${resultado.tarifa.nombre}\">\r\n                          <button class=\"btn-md btn-turquoise editarTarifa\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                          <button class=\"btn-md btn-red eliminarTarifa\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                      </div>`\r\n                  ]).draw(false); // draw(false) evita recargar toda la tabla\r\n                }else{ //si es actualizar\r\n                  /// actualizar el arregle de tarifas ///\r\n                  tarifas.forEach(a=>{if(a.id == unatarifa?.id)a = Object.assign(a, resultado.tarifa[0]);});\r\n                  const datosActuales = (tablaTarifas as any).row(indiceFila+=info.start).data();\r\n                  /*TARIFA*/ datosActuales[1] = resultado.tarifa[0].nombre;\r\n                  /*VALOR*/  datosActuales[2] = '$'+Number(resultado.tarifa[0].valor).toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n                  (tablaTarifas as any).row(indiceFila).data(datosActuales).draw();\r\n                  (tablaTarifas as any).page(info.page).draw('page'); //me mantiene la pagina actual\r\n                }\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n    ////////////////////  Eliminar tarifa  //////////////////////\r\n    function eliminarTarifa(e:Event){\r\n      let idtarifa = (e.target as HTMLElement).parentElement!.id, info = (tablaTarifas as any).page.info();\r\n      if((e.target as HTMLElement).tagName === 'I')idtarifa = (e.target as HTMLElement).parentElement!.parentElement!.id;\r\n      indiceFila = (tablaTarifas as any).row((e.target as HTMLElement).closest('tr')).index();\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar la tarifa?',\r\n          text: \"La tarifa sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idtarifa);\r\n                  try {\r\n                      const url = \"/admin/api/eliminarTarifa\";\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        (tablaTarifas as any).row(indiceFila+info.start).remove().draw(); \r\n                        (tablaTarifas as any).page(info.page).draw('page'); \r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if (event.target === miDialogoTarifa || (event.target as HTMLInputElement).value === 'Salir') {\r\n          miDialogoTarifa.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n          /*if((event.target as HTMLElement).closest('.finCerrartarifa')){  //Cuando se hace el cierre de tarifa\r\n            confirmarcierre();\r\n          }*/\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateTarifa') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n  if(document.querySelector('.configNotificationWS')){\r\n\r\n    const nombreWS = document.querySelector('#nombreWS') as HTMLInputElement;\r\n    const movilWS = document.querySelector('#movilWS') as HTMLInputElement;\r\n    const tipoWS = document.querySelector('#tipoWS') as HTMLInputElement;\r\n    const tablaNumbersWS = document.querySelector('#tablaNumbersWS tbody') as HTMLTableElement;\r\n    let indiceFila=0, control=0;\r\n\r\n    tablaNumbersWS?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"test\"))sendTest(target.closest('tr')?.id);//console.log(target.closest('tr'));\r\n      if(target?.classList.contains(\"eliminarContacto\")||target.parentElement?.classList.contains(\"eliminarContacto\"))deleteContactNotificationWS(e);\r\n    });\r\n    \r\n\r\n    async function sendTest(id:string|undefined){\r\n      try {\r\n          const url = \"/admin/api/ws/notificacionWS/sendTest?id=\"+id;\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          if(resultado && resultado.code === 200 && !resultado.error){\r\n            msjalertToast('success', '¡Éxito!', 'Mensaje de prueba enviado');\r\n          }else{\r\n              msjalertToast('error', '¡Error!', 'Error al enviar el test');\r\n          }\r\n      } catch (error) {\r\n          console.log(error)\r\n      }\r\n    }\r\n\r\n\r\n    ////////////////////  Eliminar contacto de notificacion de whatsapp  //////////////////////\r\n    function deleteContactNotificationWS(e:Event){\r\n      const fila = (e.target as HTMLTableRowElement).closest('tr');\r\n      if(!fila)return;\r\n\r\n      indiceFila = Number(fila.id);\r\n      if(!Number.isInteger(indiceFila))return;\r\n\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar contacto?',\r\n          text: \"El contacto de notificacion de whatsapp sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', indiceFila+'');\r\n                  try {\r\n                      const url = \"/admin/api/ws/notificacionWS/eliminarContacto?id=\"+indiceFila;\r\n                      const respuesta = await fetch(url); \r\n                      const resultado = await respuesta.json(); \r\n                      if(resultado.exito !== undefined){\r\n                        fila.remove();\r\n                        Swal.fire(resultado.exito[0], '', 'success')\r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    ////////////////////  Crear contacto para notificacion de whatsapp  //////////////////////\r\n    document.querySelector('#formCreateContactNotifcationWs')?.addEventListener('submit', e=>{\r\n        e.preventDefault();\r\n        \r\n        (async ()=>{ \r\n          const datos = new FormData();\r\n          //datos.append('id', unacaja?.id?unacaja?.id:'');\r\n          datos.append('nombre', nombreWS.value);\r\n          datos.append('movil', movilWS.value);\r\n          datos.append('tipo', tipoWS.value);\r\n          try {\r\n              const url = \"/admin/api/ws/notificacionWS/crearContacto\";\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();  \r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                const tr = document.createElement('tr');\r\n                tr.id = resultado.data[1];\r\n                tr.insertAdjacentHTML('afterbegin', `\r\n                  <td class=\"\">${nombreWS.value}</td>\r\n                  <td>${movilWS.value}</td>\r\n                  <td>${ tipoWS.value}</td>\r\n                  <td class=\"\"><button class=\"test btn-xs btn-blueintense\">Test</button></td>\r\n                  <td><button id=\"\" data-state=\"\" class=\"btn-xs btn-lima\">Activo</button></td>\r\n                  <td class=\"\"><button class=\"btn-md btn-red eliminarContacto\" title=\"Eliminar contacto\"><i class=\"fa-solid fa-trash-can\"></i></button></td>`);\r\n                tablaNumbersWS?.appendChild(tr);\r\n                (document.querySelector('#formCreateContactNotifcationWs') as HTMLFormElement)?.reset();\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();//cierre de async()\r\n    });\r\n\r\n\r\n\r\n  }\r\n\r\n})();","\r\n(()=>{\r\n    if(document.querySelector('.ventas')){\r\n\r\n      const POS = (window as any).POS;\r\n\r\n      const inputBuscar = document.querySelector<HTMLInputElement>('#buscarproducto');\r\n      const filtrocategorias = document.querySelectorAll('.filtrocategorias');  //los btns de las categorias\r\n      const btnCategorias = document.querySelector<HTMLButtonElement>('#btnCategorias');\r\n      const menuCategorias = document.querySelector<HTMLDivElement>('#menuCategorias');\r\n\r\n      var options = {\r\n        valueNames: [ 'card-producto', { data: ['id', 'categoria', 'code'] }],\r\n        page: 18,\r\n        pagination: true,\r\n      };\r\n      const productos = document.querySelectorAll<HTMLElement>('.producto');\r\n      if(productos.length)\r\n      var hackerList = new List('hacker-list', options);\r\n      POS.hackerList = hackerList;  //exportar\r\n\r\n      filtrocategorias.forEach(element => {\r\n        element.addEventListener('click', (e)=>{\r\n          const categoria:string = (e.target as HTMLElement).dataset.categoria!;\r\n          document.querySelector('#categorySelect')!.textContent = categoria;\r\n          if(hackerList)\r\n            hackerList.filter((item: any)=>{\r\n              hackerList.search('');\r\n              if(categoria === 'Todos')return true;\r\n              return item.values().categoria === categoria\r\n            });\r\n        });\r\n      });\r\n\r\n\r\n      inputBuscar?.addEventListener('keydown', (e) => {\r\n        if (e.key !== 'Enter') return;\r\n\r\n        e.preventDefault();\r\n\r\n        if (!hackerList) return;\r\n\r\n        const items = hackerList.visibleItems;\r\n\r\n        console.log(items);\r\n        if (!items.length) {\r\n          inputBuscar.value = '';\r\n          hackerList.search('');\r\n          return;\r\n        }\r\n\r\n        const productosku = items[0].elm as HTMLElement;\r\n        const products = POS.products as productsapi[];\r\n        const precio = products.find(x=>x.id == productosku.dataset.id)?.precio_venta;\r\n        POS.actualizarCarrito(productosku.dataset.id, 1, true, true, precio);\r\n\r\n        inputBuscar.value = '';\r\n        hackerList.search('');\r\n      });\r\n\r\n\r\n      //////--------  Apertura y cierre del btn Categorias\r\n\r\n      btnCategorias?.addEventListener('click', (e) => {\r\n        e.stopPropagation(); // evita cierre inmediato\r\n        menuCategorias?.classList.toggle('hidden');\r\n        if(!menuCategorias?.classList.contains('hidden'))document.addEventListener('click', cerrarMenuCategorias);\r\n      });\r\n      // cerrar al hacer click en una categoría\r\n      document.querySelectorAll('.filtrocategorias').forEach(el => {\r\n        el.addEventListener('click', () => {\r\n          menuCategorias?.classList.add('hidden');\r\n          document.removeEventListener('click', cerrarMenuCategorias);\r\n        });\r\n      });\r\n      // cerrar al hacer click fuera del menú\r\n      function cerrarMenuCategorias() {\r\n        menuCategorias?.classList.add('hidden');\r\n        document.removeEventListener('click', cerrarMenuCategorias);\r\n      }\r\n\r\n\r\n\r\n      //////---------------------------------------------------------------------------\r\n\r\n\r\n      const btnCarritoMovil = document.querySelector('#btnCarritoMovil') as HTMLButtonElement; //btn para abrir el modal del carrito de ventas en movil\r\n      const contenidocarrito = document.getElementById('contenidocarrito') as HTMLElement;\r\n      const contenedorDesktop = document.getElementById('contenedorDesktop') as HTMLDivElement;\r\n      //const miDialogoCarritoMovil = document.getElementById('miDialogoCarritoMovil') as HTMLDialogElement;\r\n      const btnCerrarCarritoMovil = document.querySelector('#btnCerrarCarritoMovil') as HTMLButtonElement;\r\n      const overlayCarrito = document.getElementById('overlayCarrito') as HTMLDivElement;\r\n      const screenWidth:number = window.innerWidth;\r\n\r\n      /*if(screenWidth<992)miDialogoCarritoMovil.appendChild(contenidocarrito);\r\n\r\n      window.addEventListener('resize', ()=>{\r\n        if (window.innerWidth >= 992) {\r\n          contenedorDesktop.appendChild(contenidocarrito);\r\n          miDialogoCarritoMovil.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        } else {\r\n          miDialogoCarritoMovil.appendChild(contenidocarrito);\r\n        }\r\n      });*/\r\n\r\n      // btn para abrir el carrito de ventas en movil\r\n      btnCarritoMovil?.addEventListener('click', (e)=>{\r\n        //miDialogoCarritoMovil.showModal();\r\n        //document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        contenedorDesktop.classList.remove('translate-x-full');\r\n        overlayCarrito.classList.remove('hidden');\r\n      });\r\n\r\n      btnCerrarCarritoMovil.addEventListener('click', ()=>{\r\n        //miDialogoCarritoMovil.close();\r\n        //document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        contenedorDesktop.classList.add('translate-x-full');\r\n        overlayCarrito.classList.add('hidden');\r\n      });\r\n\r\n      /*function cerrarDialogoExterno(event:Event) {\r\n        const f = event.target;\r\n        if (f === miDialogoCarritoMovil ) {\r\n          miDialogoCarritoMovil.close();\r\n          document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }*/\r\n\r\n\r\n      /*const paginador ={\r\n\r\n      }\r\n      POS.paginador = paginador;*/\r\n\r\n    }\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n  const productosAPI = {\r\n\r\n    async getProductosAPI(){\r\n      try {\r\n          const url = \"/admin/api/allproducts\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const products = await respuesta.json();\r\n          return products;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n    \r\n  };\r\n\r\n  (window as any).POS.productosAPI = productosAPI;\r\n\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas')&&!document.querySelector('.crearseparado'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const btndescuento = document.querySelector('#btndescuento') as HTMLButtonElement;\r\n    const miDialogoDescuento = document.querySelector('#miDialogoDescuento') as any;\r\n    const tipoDescts = document.querySelectorAll<HTMLInputElement>('input[name=\"tipodescuento\"]'); //radio buttom\r\n    const inputDescuento = document.querySelector('#inputDescuento') as HTMLInputElement;\r\n    const inputDescuentoClave = document.querySelector('#inputDescuentoClave') as HTMLInputElement;\r\n    let valorMax = 0;\r\n    \r\n    interface clavesApi {\r\n      clave:string,\r\n      valor_default:string|null,\r\n      valor_final:string|null,\r\n      valor_local:string|null\r\n    };\r\n\r\n    let clavedcto:clavesApi[];\r\n\r\n    (async ()=>{\r\n      try {\r\n          const url = \"/admin/api/getPasswords\"; //llamado a la API REST\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          clavedcto = resultado;\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();\r\n    \r\n    btndescuento?.addEventListener('click', ()=>{\r\n      if(POS.carrito.length){\r\n        valorMax = POS.valorTotal.subtotal;\r\n        //validar que si al reducir los productos o aumentar recalcular el porcentaje\r\n        miDialogoDescuento.showModal();\r\n        document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n    /////////////////////  logica del descuento  //////////////////////////\r\n    tipoDescts.forEach(desc=>{ //evento a los radiobutton\r\n      desc.addEventListener('change', (e:Event)=>{\r\n        if((e.target as HTMLInputElement).value === \"porcentaje\"){\r\n          valorMax = 100;\r\n          inputDescuento.value = '';\r\n        }\r\n        if((e.target as HTMLInputElement).value === \"valor\"){\r\n          inputDescuento.value = '';\r\n          valorMax = POS.valorTotal.subtotal;\r\n        }\r\n      });\r\n    });\r\n\r\n    inputDescuento?.addEventListener('input', (e)=>{\r\n      var valorInput:number = Number((e.target as HTMLInputElement).value);\r\n      if(valorInput > valorMax){\r\n        inputDescuento.value = valorMax+'';\r\n        valorInput = valorMax; \r\n      }\r\n    });\r\n\r\n    document.querySelector('#formDescuento')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      const valorInput:number = Number(inputDescuento.value);\r\n      if(tipoDescts[0].checked){  //tipo valor\r\n        POS.valorTotal.dctox100 = Math.round((valorInput*100)/POS.valorTotal.subtotal);  // valor en porcentaje\r\n        POS.valorTotal.descuento = valorInput;  //valor del dcto\r\n      }\r\n      if(tipoDescts[1].checked){ //tipo porcentaje\r\n        POS.valorTotal.descuento = (POS.valorTotal.subtotal*valorInput)/100;  //valor descontado\r\n        POS.valorTotal.dctox100 = valorInput;  //valor en porcentaje\r\n      }\r\n      //validar en backend password\r\n      const v:number = validarPasswordDcto();\r\n      if(!v)return;\r\n      \r\n      POS.valorTotal.total = POS.valorTotal.subtotal - POS.valorTotal.descuento + POS.valorTotal.valortarifa;\r\n      document.querySelector('#total')!.textContent = '$ '+POS.valorTotal.total.toLocaleString();\r\n      (document.querySelector('#descuento') as HTMLElement).textContent = '$'+POS.valorTotal.descuento.toLocaleString();\r\n      miDialogoDescuento.close();\r\n      document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    });\r\n    \r\n    function validarPasswordDcto():number{\r\n      const clave = clavedcto.find(c => c.clave=='clave_para_agregar_descuento');\r\n      if(clave?.valor_final!==null && inputDescuentoClave.value !== clave?.valor_final){\r\n        msjAlert('error', 'El password es invalido', (document.querySelector('#divmsjalertaClaveDcto') as HTMLElement));\r\n        return 0;\r\n      }\r\n      return 1;\r\n    }\r\n    \r\n    const gestionarDescuentos = { miDialogoDescuento }\r\n\r\n    POS.gestionarDescuentos = gestionarDescuentos;\r\n    \r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const btnotros = document.querySelector('#btnotros') as HTMLButtonElement;  //btn de otros\r\n    const miDialogoOtrosProductos = document.querySelector('#miDialogoOtrosProductos') as any;\r\n    let otrosproductos:{id:number, nombre:string, cantidad:number, valorunidad:number, total:number}={\r\n      id: 0,\r\n      nombre: '',\r\n      cantidad: 0,\r\n      valorunidad: 0,\r\n      total: 0\r\n    }\r\n\r\n    ///////////////////// Evento al btn Otros /////////////////////////\r\n    btnotros.addEventListener('click', (e:Event)=>{\r\n      miDialogoOtrosProductos.showModal();\r\n      document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    });\r\n\r\n    const gestionOtrosProductos = {\r\n      miDialogoOtrosProductos,  \r\n      otrosproductos(){\r\n\r\n        /////////////////////Evento al formulario de agregar otros productos //////////////////////\r\n        document.querySelector('#formOtrosProductos')?.addEventListener('submit', (e:Event)=>{\r\n            e.preventDefault();\r\n            const formelements = (e.target as HTMLFormElement).elements;\r\n            const impuesto = (formelements.namedItem('porcentaje_de_impuesto') as HTMLSelectElement).value;\r\n            const cantidadotros = Number((formelements.namedItem('cantidadotros') as HTMLInputElement).value);\r\n            const preciootros = Number((formelements.namedItem('preciootros') as HTMLInputElement).value);\r\n            \r\n            otrosproductos!.id += -1 ;\r\n            otrosproductos!.nombre = (formelements.namedItem('nombreotros') as HTMLInputElement).value;\r\n            otrosproductos!.cantidad = cantidadotros;\r\n            otrosproductos!.valorunidad = preciootros/cantidadotros;\r\n            otrosproductos!.total = preciootros;\r\n            \r\n            POS.products.push({\r\n                ID: otrosproductos!.id+'',\r\n                id: otrosproductos!.id+'', \r\n                idcategoria: '-1',\r\n                idunidadmedida: '1',\r\n                nombre: otrosproductos!.nombre,\r\n                foto: 'na',\r\n                impuesto: impuesto==''?null:impuesto, //impuesto en %\r\n                marca: 'na',\r\n                tipoproducto: '-1', // 0 = simple,  1 = compuesto\r\n                tipoproduccion: '-1', //0 = inmediato, 1 = construccion\r\n                codigo: '-1',\r\n                unidadmedida: 'Unidad',\r\n                descripcion: 'na',\r\n                peso: 'na',\r\n                medidas: 'na',\r\n                color: 'na',\r\n                funcion: 'na',\r\n                uso: 'na',\r\n                fabricante: 'na',\r\n                garantia: 'na',\r\n                stock: '0',\r\n                promediostock: '0',\r\n                stockminimo: '1',\r\n                categoria: 'na',\r\n                rendimientoestandar: '1',\r\n                precio_compra: '0',\r\n                precio_venta: otrosproductos!.valorunidad+'',\r\n                percentcomision: 0,\r\n                fecha_ingreso: '',\r\n                estado: '1',\r\n                visible: '1'\r\n            });\r\n\r\n            POS.actualizarCarrito(otrosproductos.id+'', cantidadotros, false, false, otrosproductos!.valorunidad+'');\r\n            miDialogoOtrosProductos.close();\r\n            document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n            (e.target as HTMLFormElement).reset();\r\n        });\r\n\r\n      }\r\n    };\r\n\r\n    (window as any).POS.gestionOtrosProductos = gestionOtrosProductos;\r\n\r\n})();","(()=>{\r\n  if(!document.querySelector('.ventas'))return;\r\n\r\n  const POS = (window as any).POS;\r\n\r\n  const miDialogoPreciosAdicionales = document.querySelector('#miDialogoPreciosAdicionales') as HTMLDialogElement;\r\n  const aplicarprecioadicional = document.querySelector('#aplicarprecioadicional') as HTMLButtonElement;\r\n  const inputComisionProducto = document.querySelector('#comisionproducto') as HTMLInputElement;\r\n  const inputCantidadCalculada = document.querySelector('#inputCantidadCalculada') as HTMLInputElement;\r\n  const operationSum = document.querySelector('#operationSum') as HTMLInputElement;\r\n  const operationLess = document.querySelector('#operationLess') as HTMLInputElement;\r\n  const reset = document.querySelector('#reset') as HTMLInputElement;\r\n  const textCantidadCalculada = document.querySelector('#textCantidadCalculada') as HTMLParagraphElement;\r\n  const lastOperation = document.querySelector('#lastOperation') as HTMLParagraphElement;\r\n  let cantidadTotal:number = 0;\r\n  let historialCalculadora: string[] = [];\r\n\r\n  let producto:  Partial<productsapi>|undefined = {};\r\n\r\n  function cargarPreciosAdicionales() {\r\n    const listaPrecios = document.querySelector('#listaPrecios') as HTMLElement;\r\n\r\n    while(listaPrecios.firstChild)listaPrecios.removeChild(listaPrecios.firstChild);\r\n\r\n    producto?.preciosadicionales?.forEach(precio=>{\r\n      const preciohtml = `<label class=\"flex justify-between items-center p-4 rounded-xl bg-indigo-50 dark:bg-indigo-950/30 border border-indigo-200 dark:border-indigo-800 cursor-pointer hover:bg-indigo-100 dark:hover:bg-indigo-900/40 transition\">\r\n                            <div class=\"flex items-center gap-3\">\r\n                                <input type=\"radio\" class=\"w-5 h-5 text-indigo-600 focus:ring-indigo-500 inputprecioadicional\" data-idproducto=\"${producto?.id}\"  name=\"precioSeleccionado\" value=\"${precio.precio}\">\r\n                                <span class=\"text-gray-900 dark:text-gray-100 text-lg font-medium\">Precio adicional</span>\r\n                            </div>\r\n                            <span class=\"text-gray-800 dark:text-gray-200 text-lg font-semibold\">$${Number(precio.precio).toLocaleString()}</span>\r\n                          </label>`;\r\n      listaPrecios.insertAdjacentHTML('beforeend', preciohtml);\r\n    });\r\n  }\r\n\r\n  aplicarprecioadicional.addEventListener('click', ()=>{\r\n    const comision = inputComisionProducto.value.trim();\r\n    const seleccionado = document.querySelector('.inputprecioadicional:checked') as HTMLInputElement;\r\n\r\n    if(producto != undefined && comision!=='' && !Number.isNaN(Number(comision))){  //ajustar porcentaje de comision a producto\r\n      producto.percentcomision = Number(comision);\r\n      //actualizar el carrito con el nuevo valor de comision\r\n      const unitem:CarritoItem|undefined = (POS.carrito as CarritoItem[])?.find(x=>x.idproducto == producto?.id);\r\n      if(unitem!=undefined)unitem.percentcomision = Number(comision);\r\n    }\r\n\r\n    miDialogoPreciosAdicionales.close();\r\n    document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    if(producto != undefined)POS.actualizarCarrito(producto.id, cantidadTotal==0?1:cantidadTotal, true, true, seleccionado?.checked?seleccionado.value:producto.precio_venta);\r\n  });\r\n\r\n\r\n  //****CALCULADORA\r\n  inputCantidadCalculada.addEventListener('keydown', (e: KeyboardEvent)=>{\r\n    if(e.key === '+') {\r\n      e.preventDefault();\r\n      calcular('sumar');\r\n    }\r\n    if(e.key === '-') {\r\n      e.preventDefault();\r\n      calcular('restar');\r\n    }\r\n  });\r\n\r\n  function calcular(operacion: 'sumar' | 'restar'):void{\r\n    const cantidad = Number(inputCantidadCalculada.value);\r\n    /*if(isNaN(cantidad) || inputCantidadCalculada.value === ''){\r\n      inputCantidadCalculada.focus();\r\n      return;\r\n    }*/\r\n    if(operacion === 'sumar'){\r\n      cantidadTotal += cantidad;\r\n      //lastOperation.textContent = `+${cantidad}`;\r\n      historialCalculadora.push(`+${cantidad}`);\r\n      lastOperation.textContent = historialCalculadora.join('');\r\n\r\n    }else{\r\n      cantidadTotal -= cantidad;\r\n      //lastOperation.textContent = `-${cantidad}`;\r\n      historialCalculadora.push(`-${cantidad}`);\r\n      lastOperation.textContent = historialCalculadora.join('');\r\n    }\r\n    textCantidadCalculada.textContent = cantidadTotal.toFixed(2);\r\n    inputCantidadCalculada.value = '';\r\n    inputCantidadCalculada.focus();\r\n  }\r\n\r\n  operationSum.addEventListener('click', ()=>calcular('sumar'));\r\n  operationLess.addEventListener('click', ()=>calcular('restar'));\r\n\r\n  reset.addEventListener('click', ()=>{\r\n    cantidadTotal = 0;\r\n    inputCantidadCalculada.value = '';\r\n    textCantidadCalculada.textContent = '0';\r\n    lastOperation.textContent = '0';\r\n    historialCalculadora.length = 0;\r\n  });\r\n  //****FIN CALCULADORA\r\n\r\n  \r\n\r\n  const gestionarPreciosAdicionales = {\r\n    miDialogoPreciosAdicionales,\r\n    abrirDialogo(elementProduct: HTMLElement) {\r\n      (document.querySelector('#textCardProduct') as HTMLParagraphElement).textContent = elementProduct.querySelector('.card-producto')?.textContent??'';\r\n      miDialogoPreciosAdicionales.showModal();\r\n      cantidadTotal = 0;\r\n      textCantidadCalculada.textContent = '0';\r\n      lastOperation.textContent = '0';\r\n      historialCalculadora.length = 0;\r\n      const products = POS.products as productsapi[];\r\n      producto = products.find(x=>x.id==elementProduct.dataset.id!);\r\n      cargarPreciosAdicionales();\r\n      document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    },\r\n  };\r\n\r\n  POS.gestionarPreciosAdicionales = gestionarPreciosAdicionales;\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.ventas')){\r\n\r\n    const POS = (window as any).POS;\r\n     \r\n    const selectCliente = POS.gestionClientes.selectCliente;\r\n    const dirEntrega = POS.gestionClientes.dirEntrega;\r\n    const productos = document.querySelectorAll<HTMLElement>('#producto')!;\r\n    const selectVendedor = (document.querySelector('#vendedor') as HTMLSelectElement);\r\n    const valorDomicilio = document.querySelector('#valorDomicilio') as HTMLInputElement;\r\n    const contentproducts = document.querySelector('#productos');\r\n    const btnEntrega = document.querySelector('#btnEntrega');\r\n    const modalidadEntrega = document.querySelector('#modalidadEntrega') as HTMLElement;\r\n    const totalunidades = document.querySelector('#totalunidades') as HTMLElement;\r\n    const tablaventa = document.querySelector('#tablaventa tbody');\r\n    const btnguardar = document.querySelector('#btnguardar');\r\n    const btnfacturar = document.querySelector('#btnfacturar');\r\n    const btnaplicarcredito = document.querySelector('#btnaplicarcredito');\r\n    const miDialogoAddCliente = POS.gestionClientes.miDialogoAddCliente;\r\n    //const miDialogoAddDir = POS.gestionClientes.miDialogoAddDir;\r\n    const miDialogoOtrosProductos = POS.gestionOtrosProductos.miDialogoOtrosProductos;\r\n    const miDialogoPreciosAdicionales = POS.gestionarPreciosAdicionales.miDialogoPreciosAdicionales;\r\n    const miDialogoFacturarA = POS.gestionarAdquiriente.miDialogoFacturarA;\r\n    const miDialogoDescuento = POS.gestionarDescuentos.miDialogoDescuento;\r\n    const miDialogoCredito = document.querySelector('#miDialogoCredito') as any;\r\n    const miDialogoGuardar = document.querySelector('#miDialogoGuardar') as any;\r\n    const miDialogoFacturar = document.querySelector('#miDialogoFacturar') as any;\r\n    const miDialogoCalculadora = document.querySelector('#miDialogoCalculadora') as HTMLDialogElement;\r\n    const btnCaja = document.querySelector('#caja') as HTMLSelectElement; //select de la caja en el modal pagar\r\n    const btnTipoFacturador = document.querySelector('#facturador') as HTMLSelectElement; //select del consecutivo o facturador en el modal de pago\r\n    const btnPagar = document.getElementById('btnPagar') as HTMLInputElement;\r\n    \r\n    let carrito:{id:string, idproducto:string, tipoproducto:string, tipoproduccion:string, idcategoria: string, foto:string, nombreproducto: string, rendimientoestandar:string, costo:string, valorunidad: string, stock: number, promediostock: number, prioridadcomision: string, percentcomision: number, valorcomision: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total: number}[]=[];\r\n    const valorTotal = {porcentgananciauser: 0, valorgananciauser: 0, subtotal: 0, base: 0, valorimpuestototal: 0, dctox100: 0, descuento: 0, idtarifa: 0, valortarifa: 0, total: 0}; //datos global de la venta\r\n    let tarifas:{id:string, idcliente:string, nombre:string, valor:string}[] = [];\r\n    let indiceCarrito = 0, nombretarifa:string|undefined='', tipoventa:string=\"Contado\";\r\n    const promesas: Promise<any>[] = [];\r\n    let printerBT:string = getParam.impresora_principal_de_CAJA_para_Android_por_BT.valor_final;\r\n    \r\n    const constImp: {[key:string]: number} = {};\r\n    constImp['excluido'] = 0;\r\n    constImp['0'] = 0;  //exento de iva, tarifa 0%\r\n    constImp['5'] = 0.0476190476190476; //iva, tarifa al 5%,  Bienes/servicios al 5\r\n    constImp['8'] = 0.0740740740740741; //inc, tarifa al 8%,  impuesto nacional al consumo\r\n    constImp['16'] = 0.1379310344827586; //iva, tarifa al 16%,  contratos firmados con el estado antes de ley 1819\r\n    constImp['19'] = 0.1596638655462185; //iva, tarifa al 19%,  tarifa general\r\n\r\n    interface Item {\r\n      id_impuesto: number,\r\n      facturaid: number,\r\n      basegravable: number,\r\n      valorimpuesto: number\r\n    }\r\n    let factimpuestos:Item[] = [];\r\n\r\n    let products:productsapi[]=[], unproducto:productsapi;\r\n    const mapMediospago = new Map();\r\n\r\n    const mediosPagoDBMAP = new Map<string, string>(  //se usa para imprimir los medios de pago en el servidor de impresion\r\n      mediosPagoDB.map(m => [m.id, m.mediopago]) //mediosPagoDB se declara en app.ts el cual viene del <script> en index.php que convierte el array de medios de pago de php a js.\r\n    );\r\n\r\n    (async ()=>{\r\n      products = await POS.productosAPI.getProductosAPI();\r\n      POS.products = products;  //Se expone globalmente\r\n      POS.gestionOtrosProductos.otrosproductos();\r\n    })();\r\n\r\n    /*productos.forEach(producto=>{\r\n      producto.addEventListener('click', (e)=>{\r\n        console.log(producto.dataset.id);\r\n      });\r\n    });*/\r\n    \r\n\r\n\r\n                       /******** *********/\r\n\r\n    selectFacturadorSegunCaja(btnCaja);\r\n    btnCaja.addEventListener('change', (e:Event)=>selectFacturadorSegunCaja(e.target as HTMLSelectElement));\r\n    function selectFacturadorSegunCaja(z:HTMLSelectElement){\r\n      $('#facturador').val(z.options[z.selectedIndex].dataset.idfacturador??'1');\r\n    }\r\n\r\n    POS.gestionClientes.clientes();  //inicializa modulo de clientes\r\n\r\n    //////////// evento al boton modalidad de entrega //////////////\r\n    btnEntrega?.addEventListener('click', (e:Event)=>{\r\n      modalidadEntrega.textContent == \": Presencial\"?modalidadEntrega.textContent = \": Domicilio\":modalidadEntrega.textContent=\": Presencial\";\r\n      printTarifaEnvio();\r\n      valorCarritoTotal();\r\n    });\r\n\r\n    ///////// funcion que imprime el valor de la tarifa segun direccion ///////////\r\n    function printTarifaEnvio():void{\r\n      tarifas = POS.tarifas; //viene de ahelper.clientes.ts\r\n      const selectDir = dirEntrega.options[dirEntrega.selectedIndex];\r\n      document.querySelector('#confirmarDespacho')?.classList.remove('hidden');\r\n      if(modalidadEntrega.textContent == \": Presencial\" || dirEntrega.selectedIndex == -1){\r\n        document.querySelector('#confirmarDespacho')?.classList.add('hidden');\r\n        valorTotal.valortarifa = 0;\r\n        nombretarifa = '';\r\n        return;\r\n      }\r\n      if(selectDir?.dataset.idtarifa && modalidadEntrega.textContent == \": Domicilio\"){\r\n        const objtarifa = tarifas.find(tarifa =>{\r\n          if(tarifa.idcliente == selectDir.dataset.idcliente && tarifa.id == selectDir.dataset.idtarifa)return true;\r\n        });\r\n        if(valorDomicilio.value == '' || isNaN(Number(valorDomicilio.value))){\r\n          valorTotal.valortarifa = Number(objtarifa?.valor);\r\n        }else{\r\n          valorTotal.valortarifa = Number(valorDomicilio.value);\r\n        }\r\n        valorTotal.idtarifa = Number(objtarifa?.id);\r\n        nombretarifa = objtarifa?.nombre;\r\n      }\r\n    }\r\n\r\n\r\n    //////////// evento a toda el area de los productos a seleccionar //////////////\r\n    contentproducts?.addEventListener('click', (e:Event)=>{\r\n      const elementProduct = (e.target as HTMLElement)?.closest('.producto');\r\n      const count = carrito.find(x=>x.idproducto == (elementProduct as HTMLElement).dataset.id);\r\n\r\n      if((e.target as HTMLElement).parentElement?.id === 'precioadicional'){\r\n        POS.gestionarPreciosAdicionales.abrirDialogo(elementProduct);  //ejecuta los precios adicionales\r\n        return;\r\n      }\r\n\r\n      if(window.innerWidth < 992){\r\n        // Crear popup\r\n        const popup = document.createElement('div');\r\n        popup.className = `popup absolute z-40 right-8 top-1/3 opacity-0 translate-x-0 translate-y-0 transition-all duration-500 w-10 h-10 rounded-full text-center grid place-items-center bg-teal-400 text-white font-semibold text-lg`;\r\n        popup.innerHTML = `${(count?.stock??0)+1}`;\r\n        elementProduct!.appendChild(popup);\r\n        // Forzar reflow para activar transición\r\n        requestAnimationFrame(() => {\r\n          popup.classList.remove(\"opacity-0\", \"translate-y-0\", \"translate-x-0\");\r\n          popup.classList.add(\"opacity-100\", \"-translate-y-14\", \"translate-x-10\");\r\n        });\r\n        const popupx = document.querySelectorAll('.popup');\r\n        setTimeout(() => {popupx.forEach(t=>{t.remove();});}, 2500);\r\n      }\r\n\r\n      const precio = products.find(x=>x.id == (elementProduct as HTMLElement).dataset.id)?.precio_venta;\r\n      if(elementProduct)actualizarCarrito((elementProduct as HTMLElement).dataset.id!, 1, true, true, precio);\r\n    });\r\n\r\n    function printProduct(id:string, precio:string){ //recibe el id del producto\r\n      const uncarrito = carrito.find(x=>x.idproducto==id&&x.valorunidad==precio)!;\r\n      const tr = document.createElement('TR');\r\n      tr.classList.add('productselect');\r\n      tr.dataset.id = `${id}`;\r\n      tr.dataset.precio = precio;\r\n      tr.insertAdjacentHTML('afterbegin', \r\n        `<td class=\"!px-0 !py-2 text-xl text-gray-500 leading-5 nombreproducto\">${uncarrito?.nombreproducto}</td>\r\n        <td class=\"!px-0 !py-2\">\r\n          <div class=\"flex items-center gap-2 px-4\">\r\n            <button type=\"button\" class=\"w-8 h-8 bg-indigo-700 text-white rounded-full flex items-center justify-center\">\r\n              <span class=\"menos material-symbols-outlined text-base\">remove</span>\r\n            </button>\r\n\r\n            <input type=\"text\" class=\"inputcantidad w-20 px-2 text-center\" value=\"${uncarrito.stock}\">\r\n\r\n            <button type=\"button\" class=\"w-8 h-8 bg-indigo-700 text-white rounded-full flex items-center justify-center\">\r\n              <span class=\"mas material-symbols-outlined text-base\">add</span>\r\n            </button>\r\n          </div>\r\n        </td>\r\n        <td class=\"!p-2 text-xl text-gray-500 leading-5\">$${Number(uncarrito?.valorunidad).toLocaleString()}</td>\r\n        <td class=\"!p-2 text-xl text-gray-500 leading-5\">$${Number(uncarrito?.total).toLocaleString()}</td>\r\n        <td class=\"accionestd\"><div class=\"acciones-btns\"><button class=\"btn-md btn-red eliminarProducto\"><i class=\"fa-solid fa-trash-can\"></i></button></div></td>`);\r\n      tablaventa?.appendChild(tr);\r\n    } //oninput=\"this.value = parseInt(this.value.replace(/[,.]/g, '')||1)\"\r\n\r\n\r\n    function actualizarCarrito(id:string, cantidad:number, control:boolean, stateinput:boolean, precio:string = '0'){\r\n      ///limpiar el campo de buscar producto\r\n      (document.querySelector('#buscarproducto') as HTMLInputElement).value = '';\r\n      //const hackerList = POS.hackerList;\r\n      //hackerList.search('');\r\n      const index = carrito.findIndex(x=>x.idproducto==id && x.valorunidad == precio); //devuelve el index si el producto existe\r\n      \r\n      if(index>-1){\r\n        if(cantidad < 0 && (carrito[index].stock + cantidad)<0){\r\n          cantidad = 0;\r\n          carrito[index].stock = 0;\r\n          carrito[index].total = 0;\r\n        }\r\n        if(control){ //cuando el producto se agrega desde la lista de productos\r\n          carrito[index].stock += cantidad;\r\n        }else{ //cuando el producto se agrega por el input cantidad\r\n          carrito[index].stock = cantidad;\r\n        }\r\n       \r\n        \r\n        carrito[index].subtotal = parseInt(carrito[index].valorunidad)*carrito[index].stock;\r\n        carrito[index].total = carrito[index].subtotal;\r\n        carrito[index].valorcomision = (carrito[index].subtotal*carrito[index].percentcomision)/100;\r\n        //calculo del impuesto y base por producto en el carrito deventas\r\n        carrito[index].valorimp = parseFloat((carrito[index].total*constImp[carrito[index].impuesto??0]).toFixed(3));\r\n        carrito[index].base = parseFloat((carrito[index].total-carrito[index].valorimp).toFixed(3));\r\n\r\n        valorCarritoTotal();\r\n        if(stateinput)\r\n        (tablaventa?.querySelector(`TR[data-id=\"${id}\"][data-precio=\"${precio}\"] .inputcantidad`) as HTMLInputElement).value = carrito[index].stock+'';\r\n        (tablaventa?.querySelector(`TR[data-id=\"${id}\"][data-precio=\"${precio}\"]`)?.children?.[3] as HTMLElement).textContent = \"$\"+carrito[index].total.toLocaleString();\r\n      }else{  //agregar a carrito si el producto no esta agregado en carrito, se agrega por primera vez\r\n        const producto = products.find(x=>x.id==id)!; //products es el arreglo de todos los productos traido por api\r\n        if(cantidad < 0)cantidad = 0;\r\n        const productovalorimp = (Number(precio)*cantidad)*constImp[producto.impuesto??'0']; //si producto.impuesto es null toma el valor de cero\r\n        const productototal = Number(precio)*cantidad;\r\n\r\n        //varia segun la prioridad de la comision\r\n        if(producto.prioridadcomision === '0'){  //si el porcentaje es por usuario\r\n          //producto.percentcomision = Number(percentComisionUser);  ////porcentaje de comision del usuario logueado\r\n          producto.percentcomision = Number(selectVendedor.options[selectVendedor.selectedIndex].dataset.comision);\r\n        }\r\n        const valorcomision:number = (productototal*producto.percentcomision)/100;\r\n        \r\n        var a:{id:string, idproducto:string, tipoproducto:string, tipoproduccion:string, idcategoria: string, nombreproducto: string, rendimientoestandar:string, foto:string, costo:string, valorunidad: string, stock: number, promediostock: number, prioridadcomision:string, percentcomision: number, valorcomision: number, subtotal: number, base:number, impuesto:string, valorimp:number, descuento:number, total:number} = {\r\n          id: '',\r\n          idproducto: producto?.id!,\r\n          tipoproducto: producto.tipoproducto,\r\n          tipoproduccion: producto.tipoproduccion,\r\n          idcategoria: producto.idcategoria,\r\n          nombreproducto: producto.nombre,\r\n          rendimientoestandar: producto.rendimientoestandar,\r\n          foto: producto.foto,\r\n          costo: producto.precio_compra,\r\n          valorunidad: precio,\r\n          stock: cantidad,\r\n          promediostock: Number(producto.promediostock),\r\n          prioridadcomision: producto.prioridadcomision,\r\n          percentcomision: Number(producto.percentcomision),\r\n          valorcomision: valorcomision,\r\n          subtotal: productototal, //este es el subtotal del producto\r\n          base: productototal-productovalorimp,\r\n          impuesto: producto.impuesto, //porcentaje de impuesto, es null si es excluido de iva\r\n          valorimp: productovalorimp,\r\n          descuento: 0,\r\n          total: productototal //valorunidad x cantidad\r\n        }\r\n        \r\n        carrito = [...carrito, a];\r\n        valorCarritoTotal();\r\n        printProduct(id, precio);\r\n        POS.carrito = carrito;\r\n      }\r\n    }\r\n\r\n    //evento al select del vendedor\r\n    selectVendedor.addEventListener('change', (e:Event)=>{\r\n      const target = e.target as HTMLSelectElement;\r\n      const comisionUser:number = Number(target.selectedOptions[0].dataset.comision);\r\n      carrito.forEach(x=>{ \r\n        if(x.prioridadcomision === '0'){\r\n          x.percentcomision = comisionUser;\r\n          x.valorcomision = (x.total*comisionUser)/100;\r\n        }\r\n      });\r\n      valorCarritoTotal();\r\n    });\r\n\r\n    ////////////////////// valores finales subtotal y total ////////////////////////\r\n    function valorCarritoTotal(){\r\n      valorTotal.valorgananciauser = 0;\r\n      //calcular el impuesto discriminado por tarifa\r\n      const idimpuesto: Record<string, number> = {'0': 1, '5': 2, '16': 3, '19': 4, 'excluido': 5, '8': 6 };\r\n      const objbase:{'0':number, '5':number, '16':number, '19':number, 'excluido':number, '8':number} = {'0': 0, '5': 0, '16': 0, '19': 0, 'excluido':0, '8': 0};\r\n\r\n      const mapImpuesto = new Map();\r\n      carrito.forEach(x=>{\r\n        if(x.impuesto){\r\n          if(mapImpuesto.has(x.impuesto)){\r\n            const valor = mapImpuesto.get(x.impuesto) + x.total*constImp[x.impuesto];\r\n            mapImpuesto.set(x.impuesto, valor);\r\n          }else{\r\n            mapImpuesto.set(x.impuesto, x.total*constImp[x.impuesto]);\r\n          }\r\n        }\r\n        if(x.impuesto == null)x.impuesto = \"excluido\";\r\n        objbase[x.impuesto as keyof typeof objbase] += x.base;\r\n        const impValor = mapImpuesto.get(x.impuesto)??0;\r\n        const index = factimpuestos.findIndex(Obj=>Obj.id_impuesto == idimpuesto[x.impuesto]);\r\n        if(index!=-1){ //si existe remplazar obj\r\n          factimpuestos[index] = {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor};\r\n        }else{\r\n          factimpuestos = [...factimpuestos, {id_impuesto:idimpuesto[x.impuesto], facturaid:0, basegravable:objbase[x.impuesto as keyof typeof objbase], valorimpuesto: impValor}];\r\n        }\r\n        \r\n        //calcular valor total de comision para el usuario\r\n        valorTotal.valorgananciauser += Number(x.valorcomision);\r\n      });\r\n     \r\n      //Valor del impuesto total de todos los productos, es decir de la factura;\r\n      let valorTotalImp:number = 0;\r\n      for(let valorImp of mapImpuesto.values())valorTotalImp += valorImp;\r\n      \r\n      valorTotal.valorimpuestototal = parseFloat(valorTotalImp.toFixed(3));  //valor del impuesto total factura de todos los productos\r\n\r\n      valorTotal.subtotal = carrito.reduce((total, x)=>x.total+total, 0);\r\n      valorTotal.porcentgananciauser =  (100*valorTotal.valorgananciauser)/valorTotal.subtotal;\r\n      valorTotal.base = valorTotal.subtotal - valorTotal.valorimpuestototal;  //valor de la base total factura de todos los productos\r\n      valorTotal.total = valorTotal.subtotal + valorTotal.valortarifa - valorTotal.descuento;\r\n      document.querySelector('#subTotal')!.textContent = '$'+valorTotal.subtotal.toLocaleString();\r\n      (document.querySelector('#impuesto') as HTMLElement).textContent = '$'+valorTotalImp.toLocaleString('es-CO', {minimumFractionDigits: 2, maximumFractionDigits: 2});\r\n      (document.querySelector('#valorTarifa') as HTMLElement).textContent = '$'+valorTotal.valortarifa.toLocaleString();\r\n      document.querySelector('#total')!.textContent = '$ '+valorTotal.total.toLocaleString();\r\n      // cantidad total de productos\r\n      totalunidades.textContent = carrito.reduce((total, producto)=>producto.stock+total, 0)+'';\r\n    }\r\n\r\n\r\n    /////////////////////// evento a la tabla de productos de venta (carrito) //////////////////////////\r\n    tablaventa?.addEventListener('click', (e:Event)=>{\r\n      const elementProduct = (e.target as HTMLElement)?.closest('.productselect');\r\n      const idProduct = (elementProduct as HTMLElement).dataset.id!;\r\n      const precio = (elementProduct as HTMLElement).dataset.precio!;\r\n      //const productoCarrito = carrito.find(x=>x.idproducto==idProduct && x.valorunidad==precio);\r\n      let productoCarrito;\r\n\r\n      for (let i = 0; i < carrito.length; i++) {\r\n        const item = carrito[i];\r\n        if (item.idproducto == idProduct && item.valorunidad == precio) {\r\n            indiceCarrito = i;\r\n            productoCarrito = item;\r\n            break;\r\n        }\r\n      }\r\n\r\n      if((e.target as HTMLElement).classList.contains('nombreproducto')){\r\n        (document.querySelector('#inputMerma') as HTMLInputElement).value = '';\r\n        if(getParam.activar_calculadira_de_merma_en_modulo_de_ventas.valor_final == '1'){\r\n          miDialogoCalculadora.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n      }\r\n      \r\n      if((e.target as HTMLElement).classList.contains('menos')){\r\n        actualizarCarrito(idProduct, productoCarrito!.stock-1, false, true, productoCarrito?.valorunidad);\r\n      }\r\n      if((e.target as HTMLElement).classList.contains('mas')){\r\n        actualizarCarrito(idProduct, productoCarrito!.stock+1, false, true, productoCarrito?.valorunidad);\r\n      }\r\n      if((e.target as HTMLElement).classList.contains('eliminarProducto') || (e.target as HTMLElement).tagName == \"I\"){\r\n        carrito = carrito.filter(x=>x.idproducto != idProduct || x.valorunidad != precio);\r\n        valorCarritoTotal();\r\n        tablaventa?.querySelector(`TR[data-id=\"${idProduct}\"][data-precio=\"${precio}\"]`)?.remove();\r\n      }\r\n    });\r\n\r\n\r\n    tablaventa?.addEventListener('input', e=>{\r\n      const input = e.target as HTMLInputElement;\r\n      if (!input.classList.contains('inputcantidad')) return;\r\n      const fila = input?.closest('.productselect') as HTMLTableRowElement;\r\n      const idProduct = fila.dataset.id!;\r\n      const precio = fila.dataset.precio!;\r\n      const productoCarrito = carrito.find(x=>x.idproducto==idProduct && x.valorunidad==precio);\r\n\r\n      let val = input.value;\r\n      val = val.replace(/[^0-9.]/g, '');\r\n      const partes = val.split('.');\r\n      if(partes.length > 2)val = partes[0]+'.'+partes.slice(1).join('');\r\n      if (val.startsWith('.'))val = '1';\r\n      if (val === '' || isNaN(parseFloat(val))) val = '';\r\n\r\n      input.value = val;\r\n      actualizarCarrito(idProduct, Number(input.value), false, false,  productoCarrito?.valorunidad);\r\n    });\r\n\r\n\r\n    document.querySelector('#btnMermaCantidad')?.addEventListener('click', (e:Event)=>{\r\n      const inputMerma = (document.querySelector('#inputMerma') as HTMLInputElement).value;\r\n      const {idproducto, stock, valorunidad} = carrito[indiceCarrito];\r\n      let nuevaCantidad = stock - Number(inputMerma);\r\n      if(nuevaCantidad<0)nuevaCantidad=0;\r\n      (tablaventa?.querySelector(`TR[data-id=\"${idproducto}\"][data-precio=\"${valorunidad}\"] .inputcantidad`) as HTMLInputElement).value = nuevaCantidad+'';\r\n      actualizarCarrito(idproducto, nuevaCantidad, false, false, valorunidad);\r\n      miDialogoCalculadora.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    /*btnvaciar?.addEventListener('click', ()=>{\r\n      if(carrito.length){\r\n        miDialogoVaciar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });*/\r\n\r\n    btnguardar?.addEventListener('click', ()=>{\r\n      if(carrito.length && valorTotal.total>0){\r\n        miDialogoGuardar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n    btnaplicarcredito?.addEventListener('click', ()=>{\r\n      if(modalidadEntrega.textContent === \": Domicilio\" && (selectCliente.value =='' || !dirEntrega.value) || selectCliente.value ==''){\r\n        msjAlert('error', 'Cliente o direccion no seleccionado', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n        return;\r\n      }\r\n      if(carrito.length && valorTotal.total>0){\r\n        document.querySelector('.Efectivo')?.removeAttribute('readonly');\r\n        document.querySelector('#inputscreditos')?.classList.add('flex');\r\n        document.querySelector('#inputscreditos')?.classList.remove('hidden');\r\n        if(tipoventa == \"Contado\"){\r\n          mapMediospago.clear();\r\n          $('.mediopago').val(0);\r\n        }\r\n        tipoventa = \"Credito\";\r\n        POS.tipoventa = tipoventa;\r\n        POS.gestionSubirModalPagar.subirModalPagar();\r\n        //miDialogoCredito.showModal();\r\n        miDialogoFacturar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n    btnfacturar?.addEventListener('click', ()=>{\r\n      if(modalidadEntrega.textContent === \": Domicilio\" && (selectCliente.value =='' || !dirEntrega.value)){\r\n        msjAlert('error', 'Cliente o direccion no seleccionado', (document.querySelector('#divmsjalerta1') as HTMLElement));\r\n        return;\r\n      }\r\n      \r\n      if(modalidadEntrega.textContent == \": Domicilio\")document.querySelector('#confirmarDespacho')?.classList.remove('hidden');\r\n\r\n      if(carrito.length && valorTotal.total>0){\r\n        document.querySelector('.Efectivo')?.setAttribute('readonly', 'true');\r\n        document.querySelector('#inputscreditos')?.classList.add('hidden');\r\n        document.querySelector('#inputscreditos')?.classList.remove('flex');\r\n        tipoventa = \"Contado\";\r\n        POS.tipoventa = tipoventa;\r\n        POS.gestionSubirModalPagar.subirModalPagar();\r\n        miDialogoFacturar.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    });\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if (f === miDialogoDescuento || f === miDialogoCredito || f === miDialogoGuardar || f === miDialogoFacturar || f === miDialogoAddCliente || f === miDialogoOtrosProductos || f === miDialogoFacturarA || /*f === miDialogoAddDir ||*/ f=== miDialogoPreciosAdicionales || f === miDialogoCalculadora || (f as HTMLInputElement).closest('.salir') || (f as HTMLInputElement).closest('.novaciar') || (f as HTMLInputElement).closest('.cotizacion') || (f as HTMLInputElement).closest('.remision') || (f as HTMLInputElement).closest('.siguardar') || (f as HTMLButtonElement).value == \"Cancelar\" || /*(f as HTMLButtonElement).value == \"Seleccionar\" ||*/ (f as HTMLButtonElement).classList.contains('btnCerrarPreciosAdicionales') ) {\r\n        miDialogoDescuento.close();\r\n        //miDialogoCredito.close();\r\n        miDialogoGuardar.close();\r\n        miDialogoFacturar.close();\r\n        miDialogoAddCliente.close();\r\n        //miDialogoAddDir.close();\r\n        miDialogoFacturarA.close();\r\n        miDialogoOtrosProductos.close();\r\n        miDialogoPreciosAdicionales.close();\r\n        miDialogoCalculadora.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        if((f as HTMLInputElement).closest('.cotizacion')){\r\n          tipoventa = \"\";\r\n          procesarpedido('Guardado', '1');\r\n        }\r\n        if((f as HTMLInputElement).closest('.remision')){\r\n          tipoventa = \"\";\r\n          procesarpedido('Remision', '0');\r\n        }\r\n        //if((f as HTMLInputElement).closest('.sivaciar'))vaciarventa();\r\n      }\r\n    }\r\n\r\n    function vaciarventa():void\r\n    {\r\n      if(datosfactura?.id)datosfactura.id = '';\r\n      (document.querySelector('#formFacturarA') as HTMLFormElement)?.reset();\r\n      (document.querySelector('#formfacturar') as HTMLFormElement)?.reset();\r\n      (document.querySelector('#formAddCliente') as HTMLFormElement).reset();\r\n      (document.querySelector('#badgeEstado') as HTMLParagraphElement).textContent = 'SIN CLIENTE';\r\n      (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.remove('bg-green-100', 'text-green-600');\r\n      (document.querySelector('#badgeEstado') as HTMLParagraphElement).classList.add('bg-gray-100', 'text-gray-700');\r\n      (document.querySelector('#resumenCliente') as HTMLParagraphElement).textContent = \"Seleccionar cliente\";\r\n      mapMediospago.clear();\r\n      $('.mediopago').val(0);\r\n      carrito.length = 0;\r\n      factimpuestos.length = 0;\r\n\r\n      history.replaceState({}, \"\", \"/admin/ventas\");\r\n      while(tablaventa?.firstChild)tablaventa.removeChild(tablaventa?.firstChild);\r\n      (document.querySelector('#npedido') as HTMLInputElement).value = '';\r\n      document.querySelector('#subTotal')!.textContent = '$'+0;\r\n      document.querySelector('#impuesto')!.textContent = '$'+0;\r\n      (document.querySelector('#descuento') as HTMLElement).textContent = '$'+0;\r\n      document.querySelector('#total')!.textContent = '$'+0;\r\n      $('#selectCliente').val('').trigger('change');   //aqui tambien se reinicia la elemento del valor de la tarifa\r\n      for(const key in valorTotal)valorTotal[key as keyof typeof valorTotal] = 0; //reiniciar objeto\r\n      //volver a mapear los productos con los valores originales de inventario\r\n\r\n      //actualizar DOM\r\n      for(const prod of products){\r\n          const item = POS.hackerList.get('id', prod.id)[0];\r\n          prod.precio_venta = prod.precio_original!;\r\n          if(item)item.elm.querySelector('.precioVenta').textContent = '$'+Number(prod.precio_venta).toLocaleString();\r\n      }\r\n    }\r\n\r\n\r\n    ////////////////// evento al bton pagar del modal facturar //////////////////////\r\n    document.querySelector('#formfacturar')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      if(valorTotal.total <0 || valorTotal.subtotal <0){\r\n        msjAlert('error', 'No se puede procesar pago con $0', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n\r\n      //calcular si el totoal de los medios de pago es menor al abono inicial, abortar pago...\r\n      let totalMediosPago:number = 0;\r\n      for(let value of mapMediospago.values())totalMediosPago+=value;\r\n      if(totalMediosPago<POS.gestionSubirModalPagar.valoresCredito.abonoinicial){\r\n        msjAlert('error', 'Medio de pago no indicado', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n\r\n      if(tipoventa == \"Credito\" && (isNaN(POS.gestionSubirModalPagar.valoresCredito.cantidadcuotas)||POS.gestionSubirModalPagar.valoresCredito.cantidadcuotas<=0)){\r\n        msjAlert('error', 'Plazo de cuotas no especificado', (document.querySelector('#divmsjalertaprocesarpago') as HTMLElement));\r\n        return;\r\n      }\r\n  \r\n      btnPagar.disabled = true;\r\n      btnPagar.value = 'Procesando...';\r\n      procesarpedido('Paga', '0');\r\n    });\r\n\r\n    async function procesarpedido(estado:string, ctz:string){\r\n      const imprimir = document.querySelector('input[name=\"imprimir\"]:checked') as HTMLInputElement;\r\n      const despachar = document.querySelector('#despachar') as HTMLInputElement;\r\n      const valoresCredito = POS.gestionSubirModalPagar.valoresCredito;\r\n      const tipoEntrega = modalidadEntrega.textContent!.replace(': ', '');\r\n      const datos = new FormData();\r\n      datos.append('id', datosfactura?.id??'');\r\n      datos.append('idcliente', (document.querySelector('#selectCliente') as HTMLSelectElement).value || '1');\r\n      datos.append('idvendedor', selectVendedor.value);\r\n      datos.append('idcaja', btnCaja.value);\r\n      datos.append('idconsecutivo', btnTipoFacturador.value);\r\n      datos.append('iddireccion', dirEntrega.value);\r\n      datos.append('idtarifazona', valorTotal.idtarifa+'');\r\n      datos.append('idcanaldeventa', (document.querySelector('#canalVenta') as HTMLSelectElement)?.value??'1');\r\n      datos.append('cliente', selectCliente.value==''?'N/A':selectCliente.options[selectCliente.selectedIndex].textContent!);\r\n      datos.append('vendedor', $('#vendedor option:selected').text());\r\n      datos.append('caja', (document.querySelector('#caja option:checked') as HTMLSelectElement).textContent!);\r\n      datos.append('tipofacturador', btnTipoFacturador.options[btnTipoFacturador.selectedIndex].textContent!);\r\n      datos.append('direccion', dirEntrega.options[dirEntrega.selectedIndex]?.text??'');\r\n      datos.append('tarifazona', nombretarifa||'');\r\n      datos.append('carrito', JSON.stringify(carrito.filter(x=>x.stock>0)));  //envio de todos los productos con sus cantidades\r\n      datos.append('totalunidades', totalunidades.textContent!);\r\n      //datos.append('mediosPago', JSON.stringify(Object.fromEntries(mapMediospago)));\r\n      datos.append('mediosPago', JSON.stringify(Array.from(mapMediospago, ([idmediopago, valor])=>({idmediopago, id_factura:0, valor}))));\r\n      datos.append('factimpuestos', JSON.stringify(factimpuestos));\r\n      datos.append('recibido', document.querySelector<HTMLInputElement>('#recibio')!.value);\r\n      datos.append('transaccion', '');\r\n      datos.append('tipoventa', tipoventa);\r\n      datos.append('valoresCredito', JSON.stringify(valoresCredito));\r\n      datos.append('cotizacion', ctz);  //1= cotizacion, 0 = no cotizacion pagada.\r\n      datos.append('remision', estado=='Remision'?'1':'0');  //1= cotizacion, 0 = no cotizacion pagada.\r\n      datos.append('estado', estado);\r\n      datos.append('porcentgananciauser', valorTotal.porcentgananciauser.toFixed(2));\r\n      datos.append('valorgananciauser', valorTotal.valorgananciauser.toFixed(2));\r\n      datos.append('subtotal', valorTotal.subtotal+'');\r\n      datos.append('base', valorTotal.base.toFixed(3));\r\n      datos.append('valorimpuestototal', valorTotal.valorimpuestototal+''); //valor total del impuesto. \r\n      datos.append('dctox100',valorTotal.dctox100+'');\r\n      datos.append('descuento',valorTotal.descuento+'');\r\n      datos.append('total', valorTotal.total.toString());\r\n      datos.append('observacion', document.querySelector<HTMLTextAreaElement>('#observacion')!.value);\r\n      datos.append('departamento', '');\r\n      datos.append('ciudad', (document.querySelector('#ciudad') as HTMLInputElement).value);\r\n      datos.append('entrega', tipoEntrega);\r\n      datos.append('entregado', estado=='Paga'&&tipoEntrega=='Domicilio'?(despachar.checked?'1':'0'):estado=='Paga'&&tipoEntrega=='Presencial'?'1':'0'); //si es remision no se ha entregado, si es pago y entrega a domicilio se define segun el checkbox de despachar, si es pago y entrega presencial se marca como entregado\r\n      datos.append('valortarifa', valorTotal.valortarifa+'');\r\n      datos.append('datosAdquiriente', JSON.stringify(POS.gestionarAdquiriente.datosAdquiriente));\r\n      datos.append('opc1', '');\r\n      datos.append('opc2', '');\r\n  \r\n      try {\r\n          const url = \"/admin/api/facturar\";  //va al controlador ventascontrolador\r\n          const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n          const resultado = await respuesta.json();\r\n\r\n          if(resultado.exito !== undefined){\r\n            if(estado == \"Paga\"){\r\n              resultado.dataInvoice.items = carrito.filter(x=>x.stock>0);\r\n              resultado.dataInvoice.mediospago = Array.from(mapMediospago, ([idmediopago, valor])=>({\r\n                idmediopago,\r\n                mediopago: mediosPagoDBMAP.get(idmediopago),\r\n                valor,\r\n              }));\r\n            }\r\n\r\n            limpiarFormFacturar();\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            //ENVIAR FACTURA A DIAN SI ES FACTURACION ELECTRONICA\r\n            if(btnTipoFacturador.options[btnTipoFacturador.selectedIndex].dataset.idtipofacturador == '1'){\r\n              const resDian = await POS.sendInvoiceAPI.sendInvoice(resultado.idfactura);\r\n              POS.gestionarAdquiriente.datosAdquiriente = {}; //reiniciar datos de adquiriente cada vez que se facture electronicamente\r\n              resultado.dataInvoice.cufe = resDian.cufe;\r\n              resultado.dataInvoice.link = resDian.link;\r\n              console.log(resDian);\r\n            }\r\n            //IMPRIMIR TICKET POS\r\n            if(resultado.idfactura && imprimir.value === '1')printTicketPOS(resultado.idfactura, resultado.dataInvoice);\r\n            vaciarventa();\r\n          }else{\r\n            limpiarFormFacturar();\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n\r\n    function limpiarFormFacturar(){\r\n      btnPagar.disabled = false;\r\n      btnPagar.value = 'Pagar';\r\n      miDialogoFacturar.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      (document.getElementById('contenedorDesktop') as HTMLDivElement).classList.add('translate-x-full');\r\n      (document.getElementById('overlayCarrito') as HTMLDivElement).classList.add('hidden');\r\n    }\r\n\r\n\r\n    async function printTicketPOS(idfactura:string, datainvoice:DataInvoice){\r\n      console.log(datainvoice);\r\n      ////// cuando no es impresora CAJA por BT\r\n      const isAndroid = /Android/i.test(navigator.userAgent);\r\n\r\n      if(printerBT === '1'){  //solo aplica para impresora principal si es android\r\n        const builder = new InvoiceTicketBuilder2(datainvoice);\r\n        const ticket = await builder.generate(true); //true para version buffer bytes\r\n        \r\n        const base64 = bytesToBase64(ticket);\r\n        //const url = `intent://base64,${base64}#Intent;scheme=rawbt;package=ru.a4024.rawbtprinter;end;`;\r\n        //const url = `intent://base64,${base64}#Intent;scheme=rawbt;package=ru.a4024.rawbtprinter;end;`;\r\n        //window.location.href = url;\r\n        if (isAndroid)window.location.href = `rawbt:base64,${base64}`;\r\n\r\n        //version string\r\n          //const encoder = new TextEncoder();\r\n          //const bytes = encoder.encode(ticket);\r\n        //descargar .bin a equipo\r\n          /*const blob = new Blob([ticket], { type: 'application/octet-stream' });\r\n          const url = URL.createObjectURL(blob);\r\n          const a = document.createElement('a');\r\n          a.href = url;\r\n          a.download = 'ticket.bin';\r\n          a.click();\r\n          URL.revokeObjectURL(url);*/\r\n      }\r\n\r\n\r\n      setTimeout(() => {\r\n        window.open(\"/admin/printPDFPOS?id=\" + idfactura, \"_blank\");\r\n      }, 1000);\r\n\r\n      /*\r\n      try {\r\n        const url = \"http://localhost:3100/api/printPOS/ticket1/CAJA\"; //llamado a la API server print nodejs/ts\r\n        const respuesta = await fetch(url, {\r\n          method: 'POST',\r\n          headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n          body: JSON.stringify(datainvoice)\r\n        });\r\n        const resultado = await respuesta.json();\r\n        console.log(resultado);\r\n      } catch (error) {\r\n        console.log(error);\r\n      }*/\r\n\r\n    }\r\n\r\n    \r\n    /////////////////////////obtener datos de cotizacion /////////////////////\r\n    const parametrosURL = new URLSearchParams(window.location.search);\r\n    const id = parametrosURL.get('id');\r\n    let datosfactura:{id:string, idcliente: string, idvendedor:string, idcaja:string, idconsecutivo:string, iddireccion:string, idtarifazona:string, idcierrecaja:string, num_orden:string, cliente:string, vendedor:string, caja:string, tipofacturador:string, direccion:string, tarifazona:string, totalunidades:string, recibido:string, transaccion:string, tipoventa:string,\r\n                      cotizacion:string, estado:string, cambioaventa:string, referencia:string, subtotal:string, base:string, valorimpuestototal:string, dctox100:string, descuento:string, total:string, observacion:string, departamento:string, ciudad:string, entrega:string, valortarifa:string, fechacreacion:string, fechapago:string, opc1:string, opc2:string};\r\n    if(id){\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/getcotizacion_venta?id=\"+id; //llamado a la API REST\r\n            const respuesta = await fetch(url); \r\n            const resultado = await respuesta.json();\r\n            datosfactura = resultado.factura;\r\n            carrito = resultado.productos;\r\n            carrito.forEach(item =>printProduct(item.idproducto, item.valorunidad));\r\n            //valorCarritoTotal(); //recalcula impuestos de la cotizacion y valores totales\r\n            (document.querySelector('#npedido') as HTMLInputElement).value = datosfactura.num_orden;\r\n            $('#selectCliente').val(datosfactura.idcliente).trigger('change');\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formAddCliente') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n\r\n    //exponer variables y funciones globalmente\r\n    POS.limpiarformdialog = limpiarformdialog;\r\n    POS.printTarifaEnvio = printTarifaEnvio;\r\n    POS.valorCarritoTotal = valorCarritoTotal;\r\n    POS.actualizarCarrito = actualizarCarrito;\r\n    //POS.calcularCambio = calcularCambio;\r\n    POS.cerrarDialogoExterno = cerrarDialogoExterno;\r\n    POS.tarifas = tarifas;\r\n    POS.valorTotal = valorTotal;\r\n    POS.mapMediospago = mapMediospago;\r\n    POS.tipoventa = tipoventa;\r\n    //POS.carrito = carrito;\r\n    //POS.products = products;\r\n  }\r\n\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.editartrasladoinv')){\r\n        // EDITAR LOS PRODUCTOS A TRASLADOR A OTRA SEDE\r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const btnUpdateTrasladoInv = document.querySelector('#btnUpdateTrasladoInv') as HTMLButtonElement;\r\n        let carrito:{id: string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, iditem:string, nombreitem:string, tipo:string, unidadmedida:string, cantidad: number, factor: number}[]=[];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json(); \r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n        \r\n        const parametrosURL = new URLSearchParams(window.location.search);\r\n        const id = parametrosURL.get('id');\r\n        if(id!=null && /^\\d+$/.test(id) && Number(id) >= 1){\r\n            (async ()=>{\r\n                try {\r\n                    const url = \"/admin/api/idOrdenTrasladoSolicitudInv?id=\"+id; //llamado a la API REST y trae el detalle de la orden trasladar/solicitud desde trasladarinvcontrolador.php\r\n                    const respuesta = await fetch(url); \r\n                    const resultado = await respuesta.json();\r\n                    const detalleOrden = resultado.orden[0];\r\n                    const itemsorden:{id:string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, nombre:string, cantidad:number}[] = detalleOrden.detalletrasladoinv;\r\n                    carrito = itemsorden.map(item =>{\r\n                        const esProducto = item.fkproducto && !item.idsubproducto_id;\r\n                        return {\r\n                            id: item.id,\r\n                            id_trasladoinv: item.id_trasladoinv,\r\n                            fkproducto: item.fkproducto,\r\n                            idsubproducto_id: item.idsubproducto_id,\r\n                            iditem: esProducto?item.fkproducto:item.idsubproducto_id, \r\n                            nombreitem: item.nombre, \r\n                            tipo: esProducto?'0':'1', \r\n                            unidadmedida:'', \r\n                            cantidad: item.cantidad, \r\n                            factor: 1\r\n                        }\r\n                    });\r\n                    //printDetalleOrden(detalleOrden);\r\n                    carrito.forEach(c =>printItemTable(c.iditem, c.tipo, c.unidadmedida, c.cantidad, c.nombreitem));   \r\n                } catch (error) {\r\n                    console.log(error);\r\n                }\r\n            })();\r\n        }\r\n        \r\n        \r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });  \r\n        }\r\n\r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos)(document.querySelector('#unidadmedida') as HTMLInputElement).value = datos.unidadmedida;\r\n        });\r\n\r\n        btnAddItem.addEventListener('click', (e)=>{\r\n            let cantidad = parseFloat((document.querySelector('#cantidad') as HTMLInputElement).value);\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            console.log(datos);\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.iditem==datos.id&&x.tipo==datos.tipo);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!; \r\n                    const item:{id:string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, iditem: string, nombreitem: string, tipo: string, unidadmedida: string, cantidad: number, factor: number} = {\r\n                        id: '',\r\n                        id_trasladoinv: id!,\r\n                        fkproducto: itemselected.tipo=='0'?itemselected.id:'NULL', \r\n                        idsubproducto_id: itemselected.tipo=='1'?itemselected.id:'NULL',\r\n                        iditem: itemselected?.id!,\r\n                        nombreitem: itemselected.text,\r\n                        tipo: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n                        unidadmedida: itemselected.unidadmedida,\r\n                        cantidad: cantidad,\r\n                        factor: 1,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(itemselected.id, itemselected.tipo, itemselected.unidadmedida, cantidad, itemselected.text);\r\n                }else{\r\n                    carrito[index].cantidad = cantidad;\r\n                    const tr = document.querySelector(`[data-id=\"${carrito[index].iditem}\"][data-tipo=\"${carrito[index].tipo}\"]`)!;\r\n                    tr.children[1].textContent = carrito[index].cantidad+'';\r\n                }\r\n            }\r\n        });\r\n\r\n        function printItemTable(id:string, tipo:string, unidadmedida:string, cantidad:number, nombre:string){\r\n            let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            /*if(tipo=='1'){   //si es un subproducto\r\n                options = \"\";\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == id); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            if(tipo=='0'){\r\n                options = \"\";\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }*/\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.dataset.tipo = `${tipo}`;\r\n            tr.insertAdjacentHTML('afterbegin', \r\n                `<td class=\"p-4\">${nombre}</td>\r\n                <td class=\"p-4\">${cantidad}</td>\r\n                <td class=\"p-4 flex items-center justify-center gap-2\">\r\n                    <button class=\"flex items-center gap-1 px-3 py-1 text-base text-indigo-600 border border-indigo-200 rounded-lg hover:bg-indigo-50\">\r\n                        👁 Ver\r\n                    </button>\r\n                    <button class=\"w-11 h-11 flex items-center justify-center text-green-600 border border-green-200 rounded-full hover:bg-green-50 text-xl\">✅</button>\r\n                    <button class=\"eliminarItem w-11 h-11 flex items-center justify-center text-rose-600 border border-rose-200 rounded-full hover:bg-rose-50 text-xl\">❌</button>\r\n                </td>`);\r\n            tablaItems?.appendChild(tr);\r\n        }\r\n\r\n\r\n        /*function printDetalleOrden(detalleOrden:{id:string, sucursal_origen:string, sucursal_destino:string, tipo:string, fkusuario:string, nombreusuario:string, estado:string}){\r\n            console.log(detalleOrden);\r\n\r\n        }*/\r\n\r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaItems?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n        \r\n            if((e.target as HTMLElement).classList.contains('eliminarItem')){ //se trae todoscon true menos el que coincida con iditem y tipoitem\r\n                carrito = carrito.filter(x=> {\r\n                    if(x.iditem==iditem){\r\n                        if(x.tipo==tipoitem){\r\n                            return false;\r\n                        }else{\r\n                            return true;\r\n                        }\r\n                    }else{\r\n                        return true;\r\n                    }\r\n                });\r\n                tablaItems?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"]`)?.remove();\r\n            }\r\n            //itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n\r\n        btnUpdateTrasladoInv.addEventListener('click', ()=>{\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Esta seguro de actualizar la orden de transferencia?',\r\n                text: \"Se procesara la orden con todos los productos para la sede destino\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('id_trasladoinv', id!);\r\n                        datos.append('ids', JSON.stringify(carrito.map(x=>x.id)));\r\n                        datos.append('nuevosproductos', JSON.stringify(carrito));\r\n                        try {\r\n                            const url = \"/admin/api/editarOrdenTransferencia\";  //api llamada a trasladosinvcontrolador\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                                setTimeout(() => {\r\n                                    window.location.href = `/admin/almacen/trasladarinventario`;\r\n                                }, 1600);\r\n                                Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()\r\n                }\r\n            });\r\n        });\r\n\r\n    }\r\n})();","(()=>{\r\n\r\n    if(document.querySelector('.nuevotrasladoinv')){\r\n        // PROCESO SOLICITUD DE INVENTARIO A OTRAS SEDES\r\n        const btnAnterior = document.getElementById(\"btnAnteriorTrasladoInv\") as HTMLButtonElement;\r\n        const btnSiguiente = document.getElementById(\"btnSiguienteTrasladoInv\") as HTMLButtonElement;\r\n        const steps = document.querySelectorAll<HTMLDivElement>(\".step-circle\");\r\n        const stepSections = document.querySelectorAll<HTMLElement>(\".step-section\");\r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const resumenSedeDestino = document.querySelector('#resumenSedeDestino') as HTMLParagraphElement;\r\n        const resumenFecha = document.querySelector('#resumenFecha') as HTMLParagraphElement;\r\n        const resumenObservaciones = document.querySelector('#resumenObservaciones') as HTMLParagraphElement;\r\n        let carrito:{iditem:string, idpx:string, idsx:string, tipo: string, nombreitem:string, unidad:string, cantidad: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra: number, valorcompra: number}[]=[];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n        let currentStep = 1;\r\n        const totalSteps = 3;\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json(); \r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n\r\n        //establecer fecha por defecto\r\n        const inputFecha = document.getElementById('fecha') as HTMLInputElement;\r\n            const hoy = new Date();\r\n            const yyyy = hoy.getFullYear();\r\n            const mm = String(hoy.getMonth() + 1).padStart(2, '0'); // Mes con 2 dígitos\r\n            const dd = String(hoy.getDate()).padStart(2, '0');      // Día con 2 dígitos\r\n            inputFecha.value = `${yyyy}-${mm}-${dd}`;\r\n\r\n        function actualizarProgreso() {\r\n            // Actualizar barra de progreso\r\n            steps.forEach((step, index) => {\r\n                const stepNumber = index + 1;\r\n                if (stepNumber < currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-green-500 text-white font-semibold flex items-center justify-center\";\r\n                } else if (stepNumber === currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-indigo-600 text-white font-semibold flex items-center justify-center\";\r\n                } else {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full border-2 border-gray-300 text-gray-400 font-semibold flex items-center justify-center\";\r\n                }\r\n            });\r\n\r\n            // Mostrar solo la sección actual\r\n            stepSections.forEach((section, index) => {\r\n                if (index + 1 === currentStep) {\r\n                section.style.display = \"block\";\r\n                } else {\r\n                section.style.display = \"none\";\r\n                }\r\n            });\r\n\r\n            // Deshabilitar/activar botones si es necesario\r\n            btnAnterior.disabled = currentStep === 1;\r\n            //btnSiguiente.disabled = currentStep === totalSteps;\r\n        }\r\n\r\n        // Inicializar vista\r\n        actualizarProgreso();\r\n\r\n        // Eventos de navegación\r\n        btnSiguiente.addEventListener(\"click\", () => {\r\n            if (currentStep < totalSteps) {\r\n                currentStep++;\r\n                if(currentStep===3 && carrito.length===0){\r\n                    currentStep--;\r\n                    return;\r\n                }\r\n                if(currentStep===3 && carrito.length>0)resumen();\r\n                actualizarProgreso();\r\n            }else{\r\n                generarorden();\r\n            }\r\n            \r\n        });\r\n\r\n        btnAnterior.addEventListener(\"click\", () => {\r\n            if (currentStep > 1) {\r\n                currentStep--;\r\n                actualizarProgreso();\r\n            }\r\n        });\r\n\r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });\r\n           \r\n        }\r\n\r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos)(document.querySelector('#unidadmedida') as HTMLInputElement).value = datos.unidadmedida;\r\n        });\r\n\r\n        btnAddItem.addEventListener('click', (e)=>{\r\n            let cantidad = parseFloat((document.querySelector('#cantidad') as HTMLInputElement).value);\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            console.log(datos);\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.iditem==datos.id&&x.tipo==datos.tipo);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!; //products es el arreglo de todos los productos traido por api\r\n                    const item:{iditem: string, idpx: string, idsx: string, tipo: string, nombreitem: string, unidad: string, cantidad: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra:number, valorcompra: number} = {\r\n                        iditem: itemselected?.id!,\r\n                        idpx: itemselected.tipo=='0'?itemselected.id:'NULL',\r\n                        idsx: itemselected.tipo=='1'?itemselected.id:'NULL',\r\n                        tipo: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n                        nombreitem: itemselected.text,\r\n                        unidad: itemselected.unidadmedida,\r\n                        cantidad: cantidad,\r\n                        factor: 1,\r\n                        impuesto: 0,\r\n                        valorunidad: 0,\r\n                        subtotal: 0,\r\n                        precio_compra: 0,\r\n                        valorcompra: 0,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(datos.id, datos.tipo, datos.unidadmedida, cantidad);\r\n                }else{\r\n                    carrito[index].cantidad = cantidad;\r\n                    const tr = document.querySelector(`[data-id=\"${carrito[index].iditem}\"][data-tipo=\"${carrito[index].tipo}\"]`)!;\r\n                    tr.children[1].textContent = carrito[index].cantidad+'';\r\n                }\r\n            }\r\n        });\r\n\r\n        function printItemTable(id:string, tipo:string, unidadmedida:string, cantidad:number){\r\n            let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            const unItem = filteredData.find(x=>x.id==id&&x.tipo==tipo)!;\r\n            /*if(tipo=='1'){   //si es un subproducto\r\n                options = \"\";\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == id); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            if(tipo=='0'){\r\n                options = \"\";\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }*/\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.dataset.tipo = `${tipo}`;\r\n            tr.insertAdjacentHTML('afterbegin', \r\n                `<td class=\"p-4\">${unItem?.text}</td>\r\n                <td class=\"p-4\">${cantidad}</td>\r\n                <td class=\"p-4 flex items-center justify-center gap-2\">\r\n                    <button class=\"flex items-center gap-1 px-3 py-1 text-base text-indigo-600 border border-indigo-200 rounded-lg hover:bg-indigo-50\">\r\n                        👁 Ver\r\n                    </button>\r\n                    <button class=\"w-11 h-11 flex items-center justify-center text-green-600 border border-green-200 rounded-full hover:bg-green-50 text-xl\">✅</button>\r\n                    <button class=\"eliminarItem w-11 h-11 flex items-center justify-center text-rose-600 border border-rose-200 rounded-full hover:bg-rose-50 text-xl\">❌</button>\r\n                </td>`);\r\n            tablaItems?.appendChild(tr);\r\n        }\r\n\r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaItems?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n\r\n            const itemCarrito = carrito.find(x=>x.iditem==iditem&&x.tipo==tipoitem)!;\r\n            \r\n        \r\n            if((e.target as HTMLElement).classList.contains('eliminarItem')){\r\n                carrito = carrito.filter(x=> {\r\n                    if(x.iditem==iditem){\r\n                        if(x.tipo==tipoitem){\r\n                            return false;\r\n                        }else{\r\n                            return true;\r\n                        }\r\n                    }else{\r\n                        return true;\r\n                    }\r\n                });\r\n                tablaItems?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"]`)?.remove();\r\n                //resumen();\r\n            }\r\n\r\n            //itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n        function resumen(){\r\n            const tablaproductosresumen = document.querySelector('#tablaproductosresumen tbody');\r\n            while(tablaproductosresumen?.firstChild)tablaproductosresumen.removeChild(tablaproductosresumen.firstChild);\r\n            resumenSedeDestino.textContent = (document.querySelector('#sucursaldestino') as HTMLSelectElement).selectedOptions[0].text;\r\n            resumenFecha.textContent = inputFecha.value;\r\n            resumenObservaciones.textContent = (document.querySelector('#observaciones') as HTMLTextAreaElement).value;\r\n\r\n            carrito.forEach(z=>{\r\n                const tr = document.createElement('tr');\r\n                const tdnombre = document.createElement('td');\r\n                tdnombre.textContent = z.nombreitem;\r\n                tr?.appendChild(tdnombre);\r\n                const tdcantidad = document.createElement('td');\r\n                tdcantidad.textContent = z.cantidad+'';\r\n                tr?.appendChild(tdcantidad);\r\n                const tdund = document.createElement('td');\r\n                tdund.textContent = z.unidad;\r\n                tr?.appendChild(tdund);\r\n                tablaproductosresumen?.appendChild(tr);\r\n            });\r\n        }\r\n\r\n        function generarorden(){\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Esta seguro de generar orden de transferencia?',\r\n                text: \"Se procesara la orden con todos los productos en la sede destino\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    const idsucursalorigen = document.querySelector('#sucursalorigen') as HTMLSelectElement;\r\n                    const sucursaldestino = document.querySelector('#sucursaldestino') as HTMLSelectElement;\r\n                    (async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('idsucursalorigen', idsucursalorigen.value);\r\n                        datos.append('idsucursaldestino', sucursaldestino.value);\r\n                        datos.append('productos', JSON.stringify(carrito));\r\n                        try {\r\n                            const url = \"/admin/api/apinuevotrasladoinv\";  //api llamada a trasladosinvcontrolador\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                                setTimeout(() => {\r\n                                    window.location.href = `/admin/almacen/trasladarinventario`;\r\n                                }, 1100);\r\n                                Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()\r\n                }\r\n            });\r\n        }\r\n\r\n    }\r\n})();","(()=>{\r\n\r\n    if(document.querySelector('.solicitarinvnetario')){\r\n        // PROCESO SOLICITUD DE INVENTARIO A OTRAS SEDES\r\n        const btnAnterior = document.getElementById(\"btnAnteriorSolicitudInv\") as HTMLButtonElement;\r\n        const btnSiguiente = document.getElementById(\"btnSiguienteSolicitudInv\") as HTMLButtonElement;\r\n        const steps = document.querySelectorAll<HTMLDivElement>(\".step-circle\");\r\n        const stepSections = document.querySelectorAll<HTMLElement>(\".step-section\");\r\n        const btnAddItem = document.querySelector('#btnAddItem') as HTMLButtonElement;\r\n        const tablaItems = document.querySelector('#tablaItems tbody');\r\n        const resumenSedeDestino = document.querySelector('#resumenSedeDestino') as HTMLParagraphElement;\r\n        const resumenFecha = document.querySelector('#resumenFecha') as HTMLParagraphElement;\r\n        const resumenObservaciones = document.querySelector('#resumenObservaciones') as HTMLParagraphElement;\r\n        let carrito:{iditem:string, idpx:string, idsx:string, tipo: string, nombreitem:string, unidad:string, cantidad: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra: number, valorcompra: number}[]=[];\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n        let currentStep = 1;\r\n        const totalSteps = 3;\r\n\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json(); \r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.tipoproducto??'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n\r\n        //establecer fecha por defecto\r\n        const inputFecha = document.getElementById('fecha') as HTMLInputElement;\r\n            const hoy = new Date();\r\n            const yyyy = hoy.getFullYear();\r\n            const mm = String(hoy.getMonth() + 1).padStart(2, '0'); // Mes con 2 dígitos\r\n            const dd = String(hoy.getDate()).padStart(2, '0');      // Día con 2 dígitos\r\n            inputFecha.value = `${yyyy}-${mm}-${dd}`;\r\n\r\n        function actualizarProgreso() {\r\n            // Actualizar barra de progreso\r\n            steps.forEach((step, index) => {\r\n                const stepNumber = index + 1;\r\n                if (stepNumber < currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-green-500 text-white font-semibold flex items-center justify-center\";\r\n                } else if (stepNumber === currentStep) {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full bg-indigo-600 text-white font-semibold flex items-center justify-center\";\r\n                } else {\r\n                step.className =\r\n                    \"step-circle w-10 h-10 rounded-full border-2 border-gray-300 text-gray-400 font-semibold flex items-center justify-center\";\r\n                }\r\n            });\r\n\r\n            // Mostrar solo la sección actual\r\n            stepSections.forEach((section, index) => {\r\n                if (index + 1 === currentStep) {\r\n                section.style.display = \"block\";\r\n                } else {\r\n                section.style.display = \"none\";\r\n                }\r\n            });\r\n\r\n            // Deshabilitar/activar botones si es necesario\r\n            btnAnterior.disabled = currentStep === 1;\r\n            //btnSiguiente.disabled = currentStep === totalSteps;\r\n        }\r\n\r\n        // Inicializar vista\r\n        actualizarProgreso();\r\n\r\n        // Eventos de navegación\r\n        btnSiguiente.addEventListener(\"click\", () => {\r\n            if (currentStep < totalSteps) {\r\n                currentStep++;\r\n                if(currentStep===3 && carrito.length===0){\r\n                    currentStep--;\r\n                    return;\r\n                }\r\n                if(currentStep===3 && carrito.length>0)resumen();\r\n                actualizarProgreso();\r\n            }else{\r\n                generarorden();\r\n            }\r\n            \r\n        });\r\n\r\n        btnAnterior.addEventListener(\"click\", () => {\r\n            if (currentStep > 1) {\r\n                currentStep--;\r\n                actualizarProgreso();\r\n            }\r\n        });\r\n\r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#articulo') as any).select2({ \r\n                width: '100%',\r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n            });\r\n           \r\n        }\r\n\r\n        $(\"#articulo\").on('change', (e)=>{\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            if(datos)(document.querySelector('#unidadmedida') as HTMLInputElement).value = datos.unidadmedida;\r\n        });\r\n\r\n        btnAddItem.addEventListener('click', (e)=>{\r\n            let cantidad = parseFloat((document.querySelector('#cantidad') as HTMLInputElement).value);\r\n            let datos = ($('#articulo') as any).select2('data')[0];\r\n            console.log(datos);\r\n            if(datos){\r\n                const index = carrito.findIndex(x=>x.iditem==datos.id&&x.tipo==datos.tipo);\r\n                if(index == -1){  //si el item seleccionado no existe en el carrito, agregarlo.\r\n                    const itemselected = filteredData.find(x=>x.id==datos.id&&x.tipo==datos.tipo)!; //products es el arreglo de todos los productos traido por api\r\n                    const item:{iditem: string, idpx: string, idsx: string, tipo: string, nombreitem: string, unidad: string, cantidad: number, factor: number, impuesto: number, valorunidad: number, subtotal: number, precio_compra:number, valorcompra: number} = {\r\n                        iditem: itemselected?.id!,\r\n                        idpx: itemselected.tipo=='0'?itemselected.id:'NULL',\r\n                        idsx: itemselected.tipo=='1'?itemselected.id:'NULL',\r\n                        tipo: itemselected.tipo,  ////tipo = 0 es producto simple,  1 = subproducto\r\n                        nombreitem: itemselected.text,\r\n                        unidad: itemselected.unidadmedida,\r\n                        cantidad: cantidad,\r\n                        factor: 1,\r\n                        impuesto: 0,\r\n                        valorunidad: 0,\r\n                        subtotal: 0,\r\n                        precio_compra: 0,\r\n                        valorcompra: 0,\r\n                    }\r\n                    carrito = [...carrito, item];\r\n                    printItemTable(datos.id, datos.tipo, datos.unidadmedida, cantidad);\r\n                }else{\r\n                    carrito[index].cantidad = cantidad;\r\n                    const tr = document.querySelector(`[data-id=\"${carrito[index].iditem}\"][data-tipo=\"${carrito[index].tipo}\"]`)!;\r\n                    tr.children[1].textContent = carrito[index].cantidad+'';\r\n                }\r\n            }\r\n        });\r\n\r\n        function printItemTable(id:string, tipo:string, unidadmedida:string, cantidad:number){\r\n            let options = `<option data-factor=\"1\" value=\"\" >${unidadmedida}</option>`;\r\n            const unItem = filteredData.find(x=>x.id==id&&x.tipo==tipo)!;\r\n            /*if(tipo=='1'){   //si es un subproducto\r\n                options = \"\";\r\n                const subproductounidades = allConversionUnidades.filter(x => x.idsubproducto == id); \r\n                subproductounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idsubproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }\r\n            if(tipo=='0'){\r\n                options = \"\";\r\n                const productounidades = allConversionUnidades.filter(x => x.idproducto == id); \r\n                productounidades.forEach(u=>options+=`<option data-factor=\"${u.factorconversion}\" value=\"${u.idproducto}\" >${u.nombreunidaddestino}</option>`);\r\n            }*/\r\n            const tr = document.createElement('TR');\r\n            tr.classList.add('itemselect');\r\n            tr.dataset.id = `${id}`;\r\n            tr.dataset.tipo = `${tipo}`;\r\n            tr.insertAdjacentHTML('afterbegin', \r\n                `<td class=\"p-4\">${unItem?.text}</td>\r\n                <td class=\"p-4\">${cantidad}</td>\r\n                <td class=\"p-4 flex items-center justify-center gap-2\">\r\n                    <button class=\"flex items-center gap-1 px-3 py-1 text-base text-indigo-600 border border-indigo-200 rounded-lg hover:bg-indigo-50\">\r\n                        👁 Ver\r\n                    </button>\r\n                    <button class=\"w-11 h-11 flex items-center justify-center text-green-600 border border-green-200 rounded-full hover:bg-green-50 text-xl\">✅</button>\r\n                    <button class=\"eliminarItem w-11 h-11 flex items-center justify-center text-rose-600 border border-rose-200 rounded-full hover:bg-rose-50 text-xl\">❌</button>\r\n                </td>`);\r\n            tablaItems?.appendChild(tr);\r\n        }\r\n\r\n\r\n        //////////////////////////////////// evento a la tabla de los productos seleccionados  ///////////////////////////////////\r\n        tablaItems?.addEventListener('click', (e:Event)=>{\r\n            const elementItem = (e.target as HTMLElement)?.closest('.itemselect'); //seleccionamos el tr de la tabla\r\n            const iditem = (elementItem as HTMLElement).dataset.id!;\r\n            const tipoitem = (elementItem as HTMLElement).dataset.tipo!;\r\n\r\n            const itemCarrito = carrito.find(x=>x.iditem==iditem&&x.tipo==tipoitem)!;\r\n            \r\n        \r\n            if((e.target as HTMLElement).classList.contains('eliminarItem')){\r\n                carrito = carrito.filter(x=> {\r\n                    if(x.iditem==iditem){\r\n                        if(x.tipo==tipoitem){\r\n                            return false;\r\n                        }else{\r\n                            return true;\r\n                        }\r\n                    }else{\r\n                        return true;\r\n                    }\r\n                });\r\n                tablaItems?.querySelector(`TR[data-id=\"${iditem}\"][data-tipo=\"${tipoitem}\"]`)?.remove();\r\n                //resumen();\r\n            }\r\n\r\n            //itemCarrito.cantidad = itemCarrito.cantidadcomprado*itemCarrito.factor;\r\n        });\r\n\r\n        function resumen(){\r\n            const tablaproductosresumen = document.querySelector('#tablaproductosresumen tbody');\r\n            while(tablaproductosresumen?.firstChild)tablaproductosresumen.removeChild(tablaproductosresumen.firstChild);\r\n            resumenSedeDestino.textContent = (document.querySelector('#sucursaldestino') as HTMLSelectElement).textContent;\r\n            resumenFecha.textContent = inputFecha.value;\r\n            resumenObservaciones.textContent = (document.querySelector('#observaciones') as HTMLTextAreaElement).value;\r\n\r\n            carrito.forEach(z=>{\r\n                const tr = document.createElement('tr');\r\n                const tdnombre = document.createElement('td');\r\n                tdnombre.textContent = z.nombreitem;\r\n                tr?.appendChild(tdnombre);\r\n                const tdcantidad = document.createElement('td');\r\n                tdcantidad.textContent = z.cantidad+'';\r\n                tr?.appendChild(tdcantidad);\r\n                const tdund = document.createElement('td');\r\n                tdund.textContent = z.unidad;\r\n                tr?.appendChild(tdund);\r\n                tablaproductosresumen?.appendChild(tr);\r\n            });\r\n        }\r\n\r\n        function generarorden(){\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Esta seguro de generar orden de solicitud?',\r\n                text: \"Se procesara la orden con todos los productos en la sede destino\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    const idsucursalorigen = document.querySelector('#sucursalorigen') as HTMLSelectElement;\r\n                    const sucursaldestino = document.querySelector('#sucursaldestino') as HTMLSelectElement;\r\n                    (async ()=>{ \r\n                        const datos = new FormData();\r\n                        datos.append('idsucursalorigen', idsucursalorigen.value);\r\n                        datos.append('idsucursaldestino', sucursaldestino.value);\r\n                        datos.append('productos', JSON.stringify(carrito));\r\n                        try {\r\n                            const url = \"/admin/api/apisolicitarinventario\";  //api llamada a trasladosinvcontrolador.php\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                            const resultado = await respuesta.json();  \r\n                            if(resultado.exito !== undefined){\r\n                                setTimeout(() => {\r\n                                    window.location.href = `/admin/almacen/solicitudesrecibidas`;\r\n                                }, 600);\r\n                                Swal.fire(resultado.exito[0], '', 'success') \r\n                            }else{\r\n                                Swal.fire(resultado.error[0], '', 'error')\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();//cierre de async()\r\n                }\r\n            });\r\n        }\r\n\r\n    }\r\n})();","(()=>{\r\n  if(document.querySelector('.solicitudesrecibidas')){\r\n    const miDialogoDetalleTrasladoSolicitud = document.querySelector('#miDialogoDetalleTrasladoSolicitud') as any;\r\n    const btnXCerrarDetalleTrasladoSolicitud = document.querySelector('#btnXCerrarDetalleTrasladoSolicitud') as HTMLButtonElement;\r\n    const numOrden = document.querySelector('#numOrden') as HTMLSpanElement;\r\n    const parrafoSedeorigen = document.querySelector('#sedeorigen') as HTMLParagraphElement;\r\n    const parrafoSededestino = document.querySelector('#sededestino') as HTMLParagraphElement;\r\n    const parrafotipo = document.querySelector('#tipo') as HTMLParagraphElement;\r\n    const textareaobservacion = document.querySelector('#observaciones') as HTMLTextAreaElement;\r\n    const tbodydetalleorden = document.querySelector('#tabladetalleorden tbody') as HTMLTableElement;\r\n    const filtroSucursal = document.getElementById('filtroSucursal') as HTMLSelectElement;\r\n    const filtroEstado = document.getElementById('filtroEstados') as HTMLSelectElement;\r\n    const filas = document.querySelectorAll<HTMLTableRowElement>('#tablaTraslados tbody tr');\r\n    \r\n    type ordenestrasladosinv = {\r\n      id:string,\r\n      id_sucursalorigen: string,\r\n      id_sucursaldestino: string,\r\n      fkusuario: string,\r\n      sucursal_origen:string,\r\n      sucursal_destino:string,\r\n      nombreusuario:string,\r\n      tipo: string,\r\n      observacion: string,\r\n      estado: string,\r\n      created_at: string,\r\n      detalletrasladoinv: {id:string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, nombre:string, cantidad:string, unidadmedida:string, cantidadrecibida:string, cantidadrechazada:string}[]\r\n    };\r\n\r\n    let ordenes:ordenestrasladosinv[]=[], unaorden:ordenestrasladosinv;\r\n\r\n    /*(async ()=>{\r\n      try {\r\n          const url = \"/admin/api/allordenestrasladoinv\"; //llamado a la API REST y se trae todos los productos\r\n          const respuesta = await fetch(url); \r\n          ordenes = await respuesta.json(); \r\n          console.log(ordenes);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();*/\r\n\r\n    const divAlert = document.querySelector('.divmsjalerta0') as HTMLElement;\r\n    if(divAlert)borrarMsjAlert(divAlert);\r\n\r\n\r\n    //evento a la tabla\r\n    document.querySelector('#tablaTraslados')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"enviar\")||target.parentElement?.classList.contains(\"enviar\"))enviar(e);\r\n      if(target?.classList.contains(\"detalle\")||target.parentElement?.classList.contains(\"detalle\"))detalle(e);\r\n      if(target?.classList.contains(\"cancelar\")||target.parentElement?.classList.contains(\"cancelar\"))cancelar(e);\r\n    });\r\n\r\n\r\n    ////// cuando se envia o recibir mercancia, pasa a estado en transito o entregada\r\n    function enviar(e:Event){\r\n      let idorden = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idorden = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      \r\n      let title:String = '', text:string = '', urlapi:string = '', estado:string = '';\r\n      const tr = (e.target as HTMLElement).closest('tr') as HTMLTableRowElement;\r\n      if(tr.children[4].textContent === 'Ingreso'){\r\n        title = 'Desea confirmar la recepcion de mercancia?';\r\n        text = \"La marcancia ingresara al inventario de la sucursal y no se podra modificar.\";\r\n        urlapi = 'confirmaringresoinv';\r\n        estado = 'entregada';\r\n      }\r\n      if(tr.children[4].textContent === 'Solicitud'){\r\n        title = 'Desea confirmar el envio de mercancia?';\r\n        text = \"La orden entrara en estado: 'EN TRANSITO' y sera aceptada o rechazda por la sede de destino.\";\r\n        urlapi = 'confirmarnuevotrasladoinv';\r\n        estado = 'entransito';\r\n      }\r\n      \r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: title,\r\n          text: text,\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idorden);\r\n                  try {\r\n                      const url = \"/admin/api/\"+urlapi;  //api llamada a trasladosinvcontrolador para confirmar envio, pasa a estado en transito\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        tr.children[5].innerHTML = `<span class=\"px-3 py-1 text-base font-semibold rounded-full ${estado=='entregada'?'bg-sky-50 text-sky-600':estado=='entransito'?'bg-yellow-100 text-yellow-700':'bg-rose-50 text-rose-600'}\">${estado}</span>`;\r\n                        Swal.fire(resultado.exito[0], '', 'success') \r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function detalle(e:Event){\r\n      let idorden = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idorden = (e.target as HTMLElement).parentElement?.parentElement?.id!;  \r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/idOrdenTrasladoSolicitudInv?id=\"+idorden; //llamado a la API REST y trae el detalle de la orden trasladar/solicitud desde trasladarinvcontrolador.php\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          imprimirdatos(resultado.orden[0]);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n      //unaorden = ordenes.find(x=>x.id === idorden)!; //obtengo el producto.\r\n      miDialogoDetalleTrasladoSolicitud.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n\r\n    function cancelar(e:Event){\r\n      let idorden = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idorden = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      const tr = (e.target as HTMLElement).closest('tr') as HTMLTableRowElement;\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea anular la orden de envio de mercancia?',\r\n          text: \"La orden y sus productos seran cancelados por completo y no se enviara.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idorden);\r\n                  try {\r\n                      const url = \"/admin/api/anularnuevotrasladoinv\";  //api llamada a trasladosinvcontrolador para anular envio, pasa a estado en transito\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                          tr.remove();\r\n                          Swal.fire(resultado.exito[0], '', 'success') \r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n\r\n    }\r\n\r\n    function imprimirdatos(detalleorden:ordenestrasladosinv){\r\n      numOrden.textContent = detalleorden.id;\r\n      parrafoSedeorigen.textContent = detalleorden.sucursal_origen;\r\n      parrafoSededestino.textContent = detalleorden.sucursal_destino;\r\n      parrafotipo.textContent = detalleorden.tipo;\r\n      textareaobservacion.textContent = detalleorden.observacion;\r\n      while(tbodydetalleorden.firstChild)tbodydetalleorden.removeChild(tbodydetalleorden.firstChild);\r\n      detalleorden.detalletrasladoinv.forEach(x=>{\r\n        const tr = document.createElement('tr');\r\n        const tdproducto = document.createElement('td');\r\n        tdproducto.classList.add('px-4', 'py-2', 'border');\r\n        tdproducto.textContent = x.nombre;\r\n        const tdcantidad = document.createElement('td');\r\n        tdcantidad.classList.add('px-4', 'py-2', 'border');\r\n        tdcantidad.textContent = x.cantidad;\r\n        const tdunidadmedida = document.createElement('td');\r\n        tdunidadmedida.classList.add('px-4', 'py-2', 'border');\r\n        tdunidadmedida.textContent = x.unidadmedida;\r\n        tr.appendChild(tdproducto);\r\n        tr.appendChild(tdcantidad);\r\n        tr.appendChild(tdunidadmedida);\r\n        tbodydetalleorden.appendChild(tr);\r\n      });\r\n    }\r\n\r\n\r\n    filtroSucursal.addEventListener('change', filtrarTabla);\r\n    filtroEstado.addEventListener('change', filtrarTabla);\r\n\r\n    function filtrarTabla() {\r\n      const sucursal:string = filtroSucursal.value.trim().toLowerCase();\r\n      const estado:string = filtroEstado.value.trim().toLowerCase();\r\n      \r\n      filas.forEach(fila => {\r\n        const textoSucursal:string = fila.cells[1].textContent!.trim().toLowerCase();\r\n        const textoEstado:string = fila.cells[5].textContent!.trim().toLowerCase();\r\n        const coincideSucursal = !sucursal || textoSucursal === sucursal;\r\n        const coincideEstado = !estado || textoEstado === estado;\r\n        fila.style.display = (coincideSucursal && coincideEstado) ? '' : 'none';\r\n      });\r\n    }\r\n\r\n    \r\n    function cerrarDialogoExterno(event:Event) {\r\n      const target = event.target;\r\n       const btnxcerrardetalleorden = (target as HTMLElement).parentElement?.id;\r\n      if (target === miDialogoDetalleTrasladoSolicitud || (target as HTMLInputElement).value === 'salir' || btnxcerrardetalleorden == 'btnXCerrarDetalleTrasladoSolicitud' || target == btnXCerrarDetalleTrasladoSolicitud) {\r\n        miDialogoDetalleTrasladoSolicitud.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n  }\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.trasladoinventario')){\r\n    const miDialogoDetalleTrasladoSolicitud = document.querySelector('#miDialogoDetalleTrasladoSolicitud') as any;\r\n    const btnXCerrarDetalleTrasladoSolicitud = document.querySelector('#btnXCerrarDetalleTrasladoSolicitud') as HTMLButtonElement;\r\n    const numOrden = document.querySelector('#numOrden') as HTMLSpanElement;\r\n    const parrafoSedeorigen = document.querySelector('#sedeorigen') as HTMLParagraphElement;\r\n    const parrafoSededestino = document.querySelector('#sededestino') as HTMLParagraphElement;\r\n    const parrafotipo = document.querySelector('#tipo') as HTMLParagraphElement;\r\n    const textareaobservacion = document.querySelector('#observaciones') as HTMLTextAreaElement;\r\n    const tbodydetalleorden = document.querySelector('#tabladetalleorden tbody') as HTMLTableElement;\r\n    const filtroSucursal = document.getElementById('filtroSucursal') as HTMLSelectElement;\r\n    const filtroEstado = document.getElementById('filtroEstados') as HTMLSelectElement;\r\n    const filas = document.querySelectorAll<HTMLTableRowElement>('#tablaTraslados tbody tr');\r\n\r\n    type ordenestrasladosinv = {\r\n      id:string,\r\n      id_sucursalorigen: string,\r\n      id_sucursaldestino: string,\r\n      fkusuario: string,\r\n      sucursal_origen:string,\r\n      sucursal_destino:string,\r\n      nombreusuario:string,\r\n      tipo: string,\r\n      observacion: string,\r\n      estado: string,\r\n      created_at: string,\r\n      detalletrasladoinv: {id:string, id_trasladoinv:string, fkproducto:string, idsubproducto_id:string, nombre:string, cantidad:string, unidadmedida:string, cantidadrecibida:string, cantidadrechazada:string}[]\r\n    };\r\n\r\n    let ordenes:ordenestrasladosinv[]=[], unaorden:ordenestrasladosinv;\r\n\r\n    /*(async ()=>{\r\n      try {\r\n          const url = \"/admin/api/allordenestrasladoinv\"; //llamado a la API REST y se trae todos los productos\r\n          const respuesta = await fetch(url); \r\n          ordenes = await respuesta.json(); \r\n          console.log(ordenes);\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    })();*/\r\n\r\n    const divAlert = document.querySelector('.divmsjalerta0') as HTMLElement;\r\n    if(divAlert)borrarMsjAlert(divAlert);\r\n\r\n\r\n    //evento a la tabla\r\n    document.querySelector('#tablaTraslados')?.addEventListener(\"click\", (e)=>{ //evento click sobre toda la tabla\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"enviar\")||target.parentElement?.classList.contains(\"enviar\"))enviar(e);\r\n      if(target?.classList.contains(\"detalle\")||target.parentElement?.classList.contains(\"detalle\"))detalle(e);\r\n      if(target?.classList.contains(\"cancelar\")||target.parentElement?.classList.contains(\"cancelar\"))cancelar(e);\r\n    });\r\n\r\n\r\n    ////// cuando se envia mercancia, pasa a estado en transito, tambien aplica cuando se solicitar mercancia y en la sede destino despachan, con este btn se recepciona.\r\n    function enviar(e:Event){\r\n      let idorden = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idorden = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      \r\n      let title:String = '', text:string = '', urlapi:string = '', estado:string = '';\r\n      const tr = (e.target as HTMLElement).closest('tr') as HTMLTableRowElement;\r\n      console.log(tr.children[4].textContent);\r\n      if(tr.children[4].textContent === 'Solicitud'){\r\n        title = 'Desea confirmar la recepcion de la mercancia solicitada?';\r\n        text = \"La marcancia ingresara al inventario de la sucursal y no se podra modificar.\";\r\n        urlapi = 'confirmaringresoinv';\r\n        estado = 'entregada';\r\n      }\r\n      if(tr.children[4].textContent === 'Salida'){\r\n        title = 'Desea confirmar el envio de mercancia?';\r\n        text = \"La orden entrara en estado: 'EN TRANSITO' y sera aceptada o rechazda por la sede de destino.\";\r\n        urlapi = 'confirmarnuevotrasladoinv';\r\n        estado = 'entransito';\r\n      }\r\n      \r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: title,\r\n          text: text,\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              //Swal.fire('orden procesada', '', 'success') \r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idorden);\r\n                  try {\r\n                      const url = \"/admin/api/\"+urlapi;  //api llamada a trasladosinvcontrolador para confirmar envio, pasa a estado en transito\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                        tr.children[5].innerHTML = `<span class=\"px-3 py-1 text-base font-semibold rounded-full ${estado=='entregada'?'bg-sky-50 text-sky-600':estado=='entransito'?'bg-yellow-100 text-yellow-700':'bg-rose-50 text-rose-600'}\">${estado}</span>`;\r\n                        Swal.fire(resultado.exito[0], '', 'success') \r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n    }\r\n\r\n    function detalle(e:Event){\r\n      let idorden = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idorden = (e.target as HTMLElement).parentElement?.parentElement?.id!;  \r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/idOrdenTrasladoSolicitudInv?id=\"+idorden; //llamado a la API REST y trae el detalle de la orden trasladar/solicitud desde trasladarinvcontrolador.php\r\n          const respuesta = await fetch(url);\r\n          const resultado = await respuesta.json();\r\n          imprimirdatos(resultado.orden[0]);\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n\r\n      //unaorden = ordenes.find(x=>x.id === idorden)!; //obtengo el producto.\r\n      miDialogoDetalleTrasladoSolicitud.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    }\r\n\r\n\r\n    function cancelar(e:Event){\r\n      let idorden = (e.target as HTMLElement).parentElement?.id!;\r\n      if((e.target as HTMLElement)?.tagName === 'I')idorden = (e.target as HTMLElement).parentElement?.parentElement?.id!;\r\n      const tr = (e.target as HTMLElement).closest('tr') as HTMLTableRowElement;\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea anular la orden de envio de mercancia?',\r\n          text: \"La orden y sus productos seran cancelados por completo y no se enviara.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n              (async ()=>{ \r\n                  const datos = new FormData();\r\n                  datos.append('id', idorden);\r\n                  try {\r\n                      const url = \"/admin/api/anularnuevotrasladoinv\";  //api llamada a trasladosinvcontrolador para anular envio, pasa a estado en transito\r\n                      const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                      const resultado = await respuesta.json();  \r\n                      if(resultado.exito !== undefined){\r\n                          tr.remove();\r\n                          Swal.fire(resultado.exito[0], '', 'success') \r\n                      }else{\r\n                          Swal.fire(resultado.error[0], '', 'error')\r\n                      }\r\n                  } catch (error) {\r\n                      console.log(error);\r\n                  }\r\n              })();//cierre de async()\r\n          }\r\n      });\r\n\r\n    }\r\n\r\n    function imprimirdatos(detalleorden:ordenestrasladosinv){\r\n      numOrden.textContent = detalleorden.id;\r\n      parrafoSedeorigen.textContent = detalleorden.sucursal_origen;\r\n      parrafoSededestino.textContent = detalleorden.sucursal_destino;\r\n      parrafotipo.textContent = detalleorden.tipo;\r\n      textareaobservacion.textContent = detalleorden.observacion;\r\n      while(tbodydetalleorden.firstChild)tbodydetalleorden.removeChild(tbodydetalleorden.firstChild);\r\n      detalleorden.detalletrasladoinv.forEach(x=>{\r\n        const tr = document.createElement('tr');\r\n        const tdproducto = document.createElement('td');\r\n        tdproducto.classList.add('px-4', 'py-2', 'border');\r\n        tdproducto.textContent = x.nombre;\r\n        const tdcantidad = document.createElement('td');\r\n        tdcantidad.classList.add('px-4', 'py-2', 'border');\r\n        tdcantidad.textContent = x.cantidad;\r\n        const tdunidadmedida = document.createElement('td');\r\n        tdunidadmedida.classList.add('px-4', 'py-2', 'border');\r\n        tdunidadmedida.textContent = x.unidadmedida;\r\n        tr.appendChild(tdproducto);\r\n        tr.appendChild(tdcantidad);\r\n        tr.appendChild(tdunidadmedida);\r\n        tbodydetalleorden.appendChild(tr);\r\n      });\r\n    }\r\n\r\n    filtroSucursal.addEventListener('change', filtrarTabla);\r\n    filtroEstado.addEventListener('change', filtrarTabla);\r\n\r\n    function filtrarTabla() {\r\n      const sucursal:string = filtroSucursal.value.trim().toLowerCase();\r\n      const estado:string = filtroEstado.value.trim().toLowerCase();\r\n      \r\n      filas.forEach(fila => {\r\n        const textoSucursal:string = fila.cells[1].textContent!.trim().toLowerCase();\r\n        const textoEstado:string = fila.cells[5].textContent!.trim().toLowerCase();\r\n        const coincideSucursal = !sucursal || textoSucursal === sucursal;\r\n        const coincideEstado = !estado || textoEstado === estado;\r\n        fila.style.display = (coincideSucursal && coincideEstado) ? '' : 'none';\r\n      });\r\n    }\r\n\r\n    \r\n    function cerrarDialogoExterno(event:Event) {\r\n      const target = event.target;\r\n       const btnxcerrardetalleorden = (target as HTMLElement).parentElement?.id;\r\n      if (target === miDialogoDetalleTrasladoSolicitud || (target as HTMLInputElement).value === 'salir' || btnxcerrardetalleorden == 'btnXCerrarDetalleTrasladoSolicitud' || target == btnXCerrarDetalleTrasladoSolicitud) {\r\n        miDialogoDetalleTrasladoSolicitud.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.creditosAnulados')){\r\n        let tablaCreditosAnulados:HTMLElement;\r\n        tablaCreditosAnulados = ($('#tablaCreditosAnulados') as any).DataTable(configdatatablesgenerico);\r\n    }\r\n    if(document.querySelector('.creditosFinalizados')){\r\n        let tablaCreditosFinalizados:HTMLElement;\r\n        tablaCreditosFinalizados = ($('#tablaCreditosFinalizados') as any).DataTable(configdatatablesgenerico);\r\n    }\r\n\r\n})();","(()=>{\r\n\r\n    if(!document.querySelector('.cuotasCreditos'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const tablaCuotasCreditos = ($('#tablaCuotasCreditos') as any);\r\n\r\n    interface i_cuotasCreditos {\r\n        fechapagado:string,\r\n        idtipofinanciacion:string,\r\n        cliente:string,\r\n        credito:string,\r\n        numerocuota:string,\r\n        valorpormedio:string,\r\n        mediopago:string,\r\n        idestadocreditos:string,\r\n    }\r\n\r\n    let cuotasCreditos:i_cuotasCreditos[] = [];\r\n\r\n    //tablaProductosVendidos.DataTable(configdatatables25reg);\r\n\r\n\r\n    async function callApiReporte(dateinicio:string, datefin:string){\r\n        console.log(dateinicio, datefin);\r\n        \r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/reportes/creditos/cuotasCreditos\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            cuotasCreditos = resultado;\r\n            console.log(cuotasCreditos);\r\n            printCuotasCreditos();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n    \r\n\r\n    printCuotasCreditos();\r\n    function printCuotasCreditos(){\r\n        tablaCuotasCreditos.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: cuotasCreditos,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Fecha', data: 'fechapagado'},\r\n                        {title: 'Tipo', data: 'idtipofinanciacion', render: (data:number) => `${data==1?'Credito':'Separado'}`},\r\n                        {title: 'Cliente', data: 'cliente'},\r\n                        {title: 'Credito', data: 'credito'},\r\n                        {title: 'N° Cuota', data: 'numerocuota'},\r\n                        {title: 'Valor', data: 'valorpormedio', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Medio de pago', data: 'mediopago'},\r\n                        {\r\n                            title: 'Estado', \r\n                            data: 'idestadocreditos', \r\n                            render: (data: any, type: any, row: any) => { \r\n                                                                            return `<button class=\"btn-xs ${row.idestadocreditos=='1'?'btn-lima':row.idestadocreditos=='2'?'btn-blue':'btn-red'}\">\r\n                                                                                        ${row.idestadocreditos=='1'?'Finalizado':row.idestadocreditos=='2'?'Abierto':'Anulado'}\r\n                                                                                    </button>`\r\n                                                                        }\r\n                        }\r\n            ],\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                        {extend: 'excelHtml5', title: 'facturas procesadas'},  \r\n                        {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                        {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                        'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n        });\r\n    }\r\n\r\n\r\n    POS.callApiReporte = callApiReporte;\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.detalleinvoice')){\r\n    const POS = (window as any).POS;\r\n    const btnEnvarDian = document.querySelector('#btnEnvarDian') as HTMLButtonElement;\r\n    const btnModalNotaCredito = document.querySelector('#btnModalNotaCredito') as HTMLButtonElement;\r\n    const btnNuevaFactura = document.querySelector('#btnNuevaFactura') as HTMLButtonElement;\r\n    const tipoConsecutivo = document.querySelectorAll<HTMLButtonElement>('input[name=\"tipoConsecutivo\"]');\r\n    const selectSetConsecutivo = document.querySelector('#selectSetConsecutivo') as HTMLSelectElement;\r\n    const miDialogoNC = document.querySelector('#miDialogoNC') as any;\r\n\r\n    const facturarA = document.querySelector('#facturarA') as HTMLButtonElement;  //btn para asignar adquiriente\r\n    const miDialogoFacturarA = document.querySelector('#miDialogoFacturarA') as any;\r\n    const modalNuevaFactura = document.querySelector('#modalNuevaFactura') as HTMLDialogElement;\r\n    const modalEditarResolution = document.querySelector('#modalEditarResolution') as HTMLDialogElement;\r\n    const formFacturarA = document.querySelector('#formFacturarA') as HTMLFormElement;\r\n    const documentinput = document.querySelector('#identification_number') as HTMLInputElement;\r\n    const selectDepartments = document.querySelector('#department_id') as HTMLSelectElement;\r\n    const selectdCities = document.querySelector('#municipality_id') as HTMLSelectElement;\r\n    let isElectronica = false, idfeEditarResolution:string;\r\n    let customers:adquirientes[] = [];\r\n    let customersfiltrados:adquirientes[] = [];\r\n\r\n\r\n    interface document {\r\n      id:string,\r\n      id_estadoelectronica:string,\r\n      consecutivo_id:string,\r\n      id_facturaid:string,\r\n      id_adquiriente:string,\r\n      id_estadonota:string,\r\n      numero:string,\r\n      num_factura:string,\r\n      prefijo:string\r\n      filename:string,\r\n      identificacion:string\r\n      nombre?:string,\r\n      email?:string,\r\n      link:string,\r\n      nota_credito:string,\r\n      prefixnc:string,\r\n      num_nota:string,\r\n      linknc:string,\r\n      filenamenc:string,\r\n      fecha_factura:string,\r\n      fecha_nota:string\r\n    }\r\n\r\n    interface adquirientes {\r\n      id?:string,\r\n      type_document_identification_id:string,\r\n      identification_number:string,\r\n      business_name:string,\r\n      email:string,\r\n      address:string,\r\n      municipality_id?:string,\r\n      department_id?:string,\r\n      ciudad_nombre:string\r\n      type_organization_id:string,\r\n      type_regime_id:string,\r\n      phone:string\r\n    }\r\n\r\n    type municipalities = { id:string, department_id:string, name:string, code:string };\r\n    let cities:municipalities[]=[];\r\n\r\n\r\n    (async ()=>{\r\n      const url = `/admin/api/filterAdquirientes`; \r\n      const respuesta = await fetch(url);\r\n      const resultado = await respuesta.json();\r\n      customers = resultado;\r\n    })();\r\n\r\n\r\n    //buscar adquiriente con el numero de indentificacion que esta en el modal de adquiriente\r\n    documentinput.addEventListener('input', buscarAquiriente);\r\n\r\n    function buscarAquiriente(e:Event){\r\n        const busqueda:string = (e.target as HTMLInputElement).value;\r\n        if(busqueda.length > 3 && /^\\d+$/.test(busqueda)){\r\n            //const expresionregular = new RegExp(busqueda, \"i\");\r\n            customersfiltrados = customers.filter(document => { \r\n                if(document.identification_number.trim() === busqueda.trim()){\r\n                    return document;\r\n                }\r\n            });   \r\n        }else{\r\n            customersfiltrados = [];\r\n        }\r\n        mostrarAdquiriente();\r\n    }\r\n\r\n    function mostrarAdquiriente(){\r\n      if(customersfiltrados.length>0){\r\n        $('#type_document_identification_id').val(customersfiltrados[0].type_document_identification_id);\r\n        (document.querySelector('#identification_number') as HTMLInputElement).value = customersfiltrados[0].identification_number;\r\n        (document.querySelector('#business_name') as HTMLInputElement).value = customersfiltrados[0].business_name;\r\n        (document.querySelector('#email') as HTMLInputElement).value = customersfiltrados[0].email;\r\n        (document.querySelector('#address') as HTMLInputElement).value = customersfiltrados[0].address;\r\n        if(customersfiltrados[0].department_id){\r\n          $('#department_id').val(customersfiltrados[0].department_id);\r\n          imprimirCiudades(customersfiltrados[0].department_id);\r\n        }\r\n        //$('#municipality_id').val(customersfiltrados[0].municipality_id);\r\n        $('#type_organization_id').val(customersfiltrados[0].type_organization_id);\r\n        $('#type_regime_id').val(customersfiltrados[0].type_regime_id);\r\n        (document.querySelector('#phone') as HTMLInputElement).value = customersfiltrados[0].phone;\r\n      }else{\r\n        $('#type_document_identification_id').val(\"\");\r\n        (document.querySelector('#business_name') as HTMLInputElement).value = '';\r\n        (document.querySelector('#email') as HTMLInputElement).value = '';\r\n        (document.querySelector('#address') as HTMLInputElement).value = '';\r\n        $('#department_id').val(\"\");\r\n        $('#municipality_id').val(\"\");\r\n        $('#type_organization_id').val(\"\");\r\n        $('#type_regime_id').val(\"\");\r\n        (document.querySelector('#phone') as HTMLInputElement).value = \"\";\r\n      }\r\n    }\r\n\r\n\r\n\r\n    /////       Obtener municipio segun departamento        ///////\r\n    selectDepartments?.addEventListener('change', (e:Event)=>{\r\n      const x:HTMLOptionElement = (e.target as HTMLOptionElement);\r\n      imprimirCiudades(x.value);\r\n    });\r\n\r\n    function imprimirCiudades(x:string){\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/citiesXdepartments?id=\"+x; //llamado a la API REST y se trae las cities segun cliente elegido\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          if(resultado.error){\r\n            Swal.fire(resultado.error[0], '', 'error')\r\n          }else{\r\n            cities = resultado;\r\n            addCitiesToSelect(cities);\r\n          }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n    \r\n    function addCitiesToSelect<T extends {id:string, department_id:string, name:string, code:string}>(addrs: T[]):void{\r\n      while(selectdCities?.firstChild)selectdCities.removeChild(selectdCities?.firstChild);\r\n      addrs.forEach(x =>{\r\n        const option = document.createElement('option');\r\n        option.textContent = x.name;\r\n        option.value = x.id;\r\n        option.dataset.code = x.code;\r\n        option.dataset.department_id = x.department_id;\r\n        selectdCities.appendChild(option);\r\n      });\r\n      if(customersfiltrados.length>0&&customersfiltrados[0].municipality_id)$('#municipality_id').val(customersfiltrados[0].municipality_id);\r\n    }\r\n\r\n    ///////////////////// Enviar a DIAN //////////////////////\r\n    btnEnvarDian.addEventListener('click', async ()=>{\r\n      const idfactura:string = (document.querySelector('#idfactura') as HTMLInputElement).value;\r\n      const idfe:string = (document.querySelector('#idfe') as HTMLInputElement).value;\r\n      const idfeState:string = (document.querySelector('#idfeState') as HTMLInputElement).value;\r\n      (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n      if(idfeState != '2'){\r\n        const resDian = await POS.sendInvoiceAPI.sendInvoice(idfactura);\r\n        const filaDoc = document.querySelector(`#detalleDocumentos tr[data-idfe=\"${idfe}\"]`);\r\n        if(resDian.exito !== undefined){\r\n          document.querySelector('#estadoFactura')!.textContent = 'Aceptada DIAN';\r\n          document.querySelector('#estadoFactura')?.classList.remove('bg-slate-100', 'text-gray-700', 'bg-yellow-100', 'text-yellow-700');\r\n          document.querySelector('#estadoFactura')?.classList.add('bg-green-500', 'text-white');\r\n          msjalertToast('success', '¡Éxito!', resDian.exito[0]);\r\n          if(filaDoc)filaDoc.children[3].children[1].innerHTML = `<a class=\"btn-xs btn-lima\" href=\"${resDian.link}\" target=\"_blank\"> Aceptada </a>`;\r\n        }else{\r\n          document.querySelector('#estadoFactura')!.textContent = 'Error';\r\n          document.querySelector('#estadoFactura')?.classList.remove('bg-slate-100', 'g-green-500', 'text-gray-700', 'bg-yellow-100', 'text-yellow-700');\r\n          document.querySelector('#estadoFactura')?.classList.add('bg-red-500', 'text-white');\r\n          msjalertToast('error', '¡Error!', resDian.error[0]);\r\n          if(filaDoc)filaDoc.children[3].children[1].innerHTML = `<a class=\"btn-xs btn-red\" href=\"/\" target=\"_blank\"> Error </a>`;\r\n        }\r\n      }else{\r\n        msjalertToast('error', '¡Error!', 'Factura electronica aceptada por la Dian, no se puede volver a enviar');\r\n      }\r\n      (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n    });\r\n\r\n\r\n    ///////////////////// btn nueva factura //////////////////////\r\n    btnNuevaFactura.addEventListener('click', ()=>{\r\n      modalNuevaFactura.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    ///////////////////// evento al btn facturar A - adquiriente /////////////////////\r\n    facturarA.addEventListener('click', (e:Event)=>{\r\n      miDialogoFacturarA.showModal();\r\n      document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    //tipoConsecutivo es para generar nueva factura electronica\r\n    tipoConsecutivo.forEach(radio=>{\r\n      radio.addEventListener('change', (e:Event)=>{\r\n        const targetDom = e.target as HTMLInputElement;\r\n        if(targetDom.value == 'manual'){\r\n          document.querySelector('#consecutivoManual')?.classList.remove('hidden');\r\n          document.querySelector('#consecutivoManual')?.setAttribute(\"required\", \"\");\r\n        }else{\r\n          document.querySelector('#consecutivoManual')?.classList.add('hidden');\r\n          document.querySelector('#consecutivoManual')?.removeAttribute(\"required\");\r\n          (document.querySelector('#consecutivoManual') as HTMLInputElement).value = '';\r\n        }\r\n      })\r\n    });\r\n\r\n    /////////// Generar nueva facutura /////////\r\n    document.querySelector('#formNuevaFactura')?.addEventListener('submit', async e=>{\r\n      e.preventDefault();\r\n      const idResolution = (document.querySelector('#selectResolucion') as HTMLInputElement).value;\r\n      const datos = new FormData();\r\n      datos.append('idfactura', (document.querySelector('#idfactura') as HTMLInputElement).value);\r\n      datos.append('idResolution', idResolution);\r\n      datos.append('numConsecutivoManual', (document.querySelector('#consecutivoManual') as HTMLButtonElement)?.value || '');\r\n      modalNuevaFactura.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/crearFacturaPOSaElectronica\";  //api llamada en parametroscontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              (document.querySelector('#idfe') as HTMLInputElement).value = resultado.facturaelectronica.id;\r\n              (document.querySelector('#idfeState') as HTMLInputElement).value = resultado.facturaelectronica.id_estadoelectronica;\r\n              document.querySelector('#prefixNumber')!.textContent = `Factura #${resultado.facturaelectronica.num_factura}`;\r\n              document.querySelector('#estadoFactura')!.textContent = 'Pendiente DIAN';\r\n              document.querySelector('#estadoFactura')?.classList.remove('bg-slate-100', 'text-gray-700', 'bg-green-500', 'text-white');\r\n              document.querySelector('#estadoFactura')?.classList.add('bg-yellow-100', 'text-yellow-700');\r\n              isElectronica = true;  //condicion para que el adquiriente se aguarde y se asocie al documento\r\n              printDocumentInTable(resultado.facturaelectronica);\r\n              insertInModalNC(resultado.facturaelectronica);\r\n              customersfiltrados = customers.filter(x=>x.id == resultado.facturaelectronica.id_adquiriente);\r\n              mostrarAdquiriente();\r\n              document.querySelector('#nombreAdquiriente')!.textContent = customersfiltrados[0].business_name;\r\n              document.querySelector('#identificacionAdquiriente')!.textContent = customersfiltrados[0].identification_number;\r\n              document.querySelector('#emailAdquiriente')!.textContent = customersfiltrados[0].email;\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    });\r\n\r\n    function printDocumentInTable(facturaelectronica:document){\r\n      document.querySelector('#detalleDocumentos')?.insertAdjacentHTML('beforeend', `\r\n        <tr data-idfe=\"${facturaelectronica.id}\">\r\n          <td class=\"py-3 px-4\">${facturaelectronica.id}</td>\r\n          <td class=\"text-center\">N° ${facturaelectronica.id_facturaid}</td> \r\n          <td class=\"text-center\">${facturaelectronica.num_factura}${facturaelectronica.id_estadonota == '2' ? ` / ${facturaelectronica.prefixnc} - ${facturaelectronica.num_nota}` : ''}</td>\r\n          <td class=\"text-center\">\r\n            <div class=\"btn-xs ${facturaelectronica.id_estadoelectronica == '2' ?'btn-lima':(facturaelectronica.id_estadoelectronica == '1'?'btn-blue':'btn-red')}\"> ${facturaelectronica.id_estadoelectronica == '2'?'Aceptada':(facturaelectronica.id_estadoelectronica == '1'?'Pendiente':'Error')} </div>\r\n            <div class=\"btn-xs ${facturaelectronica.id_estadonota == '2' ?'btn-orange':(facturaelectronica.id_estadonota == '1'?'btn-blue':'btn-red')}\"> ${facturaelectronica.id_estadonota == '2' && facturaelectronica.nota_credito == '1' ?'Aceptada NC':(facturaelectronica.id_estadonota == '1' && facturaelectronica.nota_credito == '1'?'Pendiente NC':facturaelectronica.id_estadonota == '3' && facturaelectronica.nota_credito == '1'?'Error NC':'')} </div>\r\n          </td>\r\n          <td class=\"text-center\">${facturaelectronica.id_estadoelectronica != '2' ?'<span class=\"cursor-pointer material-symbols-outlined eliminarFactura\">delete</span>':''}</td>\r\n        </tr>`\r\n      );\r\n    }\r\n\r\n    function insertInModalNC(facturaelectronica:document){\r\n      const selectInvoice = document.querySelector('#selectInvoice') as HTMLSelectElement;\r\n      const option = document.createElement('option');\r\n      option.value = facturaelectronica.id;\r\n      option.textContent = facturaelectronica.num_factura;\r\n      selectInvoice.appendChild(option);\r\n    }\r\n    \r\n    /////////// Guardar adquiriente /////////\r\n    formFacturarA.addEventListener('submit', (e:Event)=>{\r\n      e.preventDefault();\r\n      const data = new FormData(formFacturarA);\r\n      const datosAdquiriente: Record<string, FormDataEntryValue> = Object.fromEntries(data.entries());\r\n      \r\n      miDialogoFacturarA.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      \r\n      const identification = datosAdquiriente.identification_number as string;\r\n      const requiereEmail = identification && identification!='222222222222';\r\n      // Validar email solo si identification_number es distinto de 222222222222 y no vacío\r\n      if (requiereEmail && !validarEmail(datosAdquiriente.email as string)) {\r\n          Swal.fire(\"Correo incorrecto\", \"Debe ingresar un email válido o enviar a consumidor final o generico: 222222222222\", \"error\");\r\n          return; // detiene el proceso\r\n      }\r\n      if(isElectronica){\r\n        document.querySelector('#nombreAdquiriente')!.textContent = datosAdquiriente.business_name as string;\r\n        document.querySelector('#identificacionAdquiriente')!.textContent = datosAdquiriente.identification_number as string;\r\n        document.querySelector('#emailAdquiriente')!.textContent = datosAdquiriente.email as string;\r\n        //guarda y asigna adquiriente en DB.\r\n        asignarAdquirienteAFactura(datosAdquiriente);\r\n      }else{\r\n        msjalertToast('error', '¡Error!', 'Se debe generar nueva factura electronica para asignarle un adquiriente.');\r\n      }\r\n    });\r\n\r\n    function validarEmail(correo: string): boolean {\r\n        const regex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;\r\n        return regex.test(correo);\r\n    }\r\n\r\n\r\n    //asigna adquiriente a la ultima factura electronica.\r\n    async function asignarAdquirienteAFactura(datosAdquiriente: Record<string, FormDataEntryValue>){\r\n      datosAdquiriente.idfactura = (document.querySelector('#idfactura') as HTMLInputElement).value;  ////id de la factura general\r\n      datosAdquiriente.idfe = (document.querySelector('#idfe') as HTMLInputElement).value;\r\n      try {\r\n            const url = \"/admin/api/asignarAdquirienteAFactura\";\r\n            const respuesta = await fetch(url, {\r\n                                      method: 'POST',\r\n                                      headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                      body: JSON.stringify(datosAdquiriente)\r\n                                    }); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              document.querySelector('#nombreAdquiriente')!.textContent = datosAdquiriente.business_name as string;\r\n              document.querySelector('#identificacionAdquiriente')!.textContent = datosAdquiriente.identification_number as string;\r\n              document.querySelector('#emailAdquiriente')!.textContent = datosAdquiriente.email as string;\r\n              if(resultado.tipo == \"crear\"){\r\n                customers = [...customers, resultado.obj];\r\n              }else{\r\n                /// actualizar el arregle del adquiriente o customers ///\r\n                customers.forEach(a=>{if(a.identification_number == resultado.obj.identification_number)a = Object.assign(a, resultado.obj);});\r\n              }\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n\r\n    ///////////////////-------    Btn NC     --------///////////////////\r\n    btnModalNotaCredito.addEventListener('click', ()=>{\r\n        limpiarformdialog();\r\n        miDialogoNC.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    ///////// Habilita el campo de consecutivo personalizado\r\n    selectSetConsecutivo?.addEventListener('change', (e:Event)=>{\r\n      const targetDom = e.target as HTMLSelectElement;\r\n      const habilitaconsecutivo = document.querySelector('.habilitaconsecutivo') as HTMLElement;\r\n      if(targetDom.value == '0'){  //  Siguiente consecutivo automatico\r\n        habilitaconsecutivo.style.display = \"none\";\r\n        document.querySelector('#consecutivoPersonalizado')?.removeAttribute(\"required\");\r\n        (document.querySelector('#consecutivoPersonalizado') as HTMLInputElement).value = '';\r\n      }\r\n      else{  //consecutivo personalizado\r\n        habilitaconsecutivo.style.display = \"flex\";\r\n        document.querySelector('#consecutivoPersonalizado')?.setAttribute(\"required\", \"\");\r\n      }\r\n    });\r\n\r\n    document.querySelector('#formNC')?.addEventListener('submit', async e=>{\r\n        e.preventDefault();\r\n        const idfactura:string = (document.querySelector('#idfactura') as HTMLInputElement).value;  //id de la factura general\r\n        const idInvoice:string = (document.querySelector('#selectInvoice') as HTMLSelectElement).value;\r\n        const idfeState:string = (document.querySelector('#idfeState') as HTMLInputElement).value;\r\n        const consecutivo = (document.querySelector('#consecutivoPersonalizado') as HTMLInputElement).value;\r\n        miDialogoNC.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n        if(idfeState == '2'){\r\n          try {\r\n              const url = \"/admin/api/sendNc\"; //llamado a la API REST apidiancontrolador.php\r\n              const respuesta = await fetch(url, {\r\n                  method: 'POST', \r\n                  headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                  body: JSON.stringify({id: idInvoice, idfactura, consecutivo})  //si consecutivo es vacio '', es siguiente consecutivo\r\n              });\r\n              const responseDian = await respuesta.json(); \r\n              console.log(responseDian);\r\n              const filaDoc = document.querySelector(`#detalleDocumentos tr[data-idfe=\"${idInvoice}\"]`);\r\n              if(filaDoc)filaDoc.children[2].textContent = filaDoc.children[2].textContent+' / '+responseDian.notacredito.prefixnc+' - '+responseDian.notacredito.num_nota;\r\n              if(responseDian.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', responseDian.exito[0]);\r\n                //actualizar tabla de detalle de documentos electronicos\r\n                if(filaDoc){\r\n                  const enlace = filaDoc.children[3].children[1] as HTMLAnchorElement;\r\n                  enlace.innerHTML = `Aceptada NC`;\r\n                  enlace.classList.remove('btn-blue', 'btn-red');\r\n                  enlace.classList.add('btn-orange');\r\n                  enlace.href = responseDian.notacredito.linknc;\r\n                }\r\n                //quitar el documento del select de la modal NC\r\n                eliminarOptionSelectNC(idInvoice);\r\n              }else{\r\n                msjalertToast('error', '¡Error!', responseDian.error[0]);\r\n                //actualizar tabla de detalle de documentos electronicos\r\n                if(filaDoc){\r\n                  const enlace = filaDoc.children[3].children[1] as HTMLAnchorElement;\r\n                  enlace.innerHTML = `Error NC`;\r\n                  enlace.classList.remove('btn-blue', 'btn-orange');\r\n                  enlace.classList.add('btn-red');\r\n                  enlace.href = responseDian.notacredito.linknc;\r\n                }\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        }else{\r\n          msjalertToast('error', '¡Error!', 'Error, la factura electronica no esta aceptada por la Dian o ya se genero nota credito.');\r\n        }\r\n    });\r\n\r\n    //eliminar option 'documento electronico' del select de la modal NC\r\n    function eliminarOptionSelectNC(idInvoice:string){\r\n      const selectInvoice = document.querySelector('#selectInvoice') as HTMLSelectElement;\r\n      const optionsToRemove = selectInvoice.querySelector(`option[value=\"${idInvoice}\"]`);\r\n      if(optionsToRemove)optionsToRemove.remove();\r\n    }\r\n\r\n\r\n    /////////  ENVENTO A LA TABLA DE DETALLE DE DOCUMENTOS  ///////////\r\n    document.querySelector('#detalleDocumentos')?.addEventListener('click', e=>{\r\n      const evento = e.target;\r\n      const tr:string|undefined = (evento as HTMLSpanElement).closest('tr')?.dataset.idfe;\r\n      if((evento as HTMLSpanElement).classList.contains('eliminarFactura'))\r\n        if(tr != undefined)eliminarFacturaElectronica(tr);\r\n      if((evento as HTMLSpanElement).classList.contains('editarResolution'))\r\n        if(tr != undefined){\r\n          idfeEditarResolution = tr;\r\n          modalEditarResolution.showModal();\r\n          document.addEventListener(\"click\", cerrarDialogoExterno);\r\n        }\r\n    });\r\n\r\n    document.querySelector('#formEditarResolution')?.addEventListener('submit', async e=>{\r\n        e.preventDefault();\r\n        try {\r\n        const url = \"/admin/api/editarResolutionFE\"; //llamado a la API REST apidiancontrolador.php\r\n        const respuesta = await fetch(url, {\r\n            method: 'POST', \r\n            headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n            body: JSON.stringify({\r\n                                    idfe: idfeEditarResolution,\r\n                                    idresolution: (document.querySelector('#selectEditarResolucion') as HTMLInputElement).value,\r\n                                    consecutivo: (document.querySelector('#consecutivoEditarResolution') as HTMLInputElement).value\r\n                                  })\r\n        });\r\n        const resultado = await respuesta.json();\r\n        if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            const filaDoc = document.querySelector(`#detalleDocumentos tr[data-idfe=\"${idfeEditarResolution}\"]`) as HTMLTableRowElement;\r\n            filaDoc.children[2].textContent = resultado.prefijoNum;\r\n             document.querySelector('#prefixNumber')!.textContent = `Factura #${resultado.prefijoNum}`;\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n        console.log(error);\r\n      }\r\n    });\r\n\r\n    async function eliminarFacturaElectronica(idfe:string){\r\n      try {\r\n          const url = \"/admin/api/eliminarFacturaElectronica\"; //llamado a la API REST apidiancontrolador.php\r\n          const respuesta = await fetch(url, {\r\n              method: 'POST', \r\n              headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n              body: JSON.stringify({id: idfe})\r\n          });\r\n          const resultado = await respuesta.json(); \r\n          console.log(resultado);\r\n          const filaDoc = document.querySelector(`#detalleDocumentos tr[data-idfe=\"${idfe}\"]`);\r\n          if(resultado.exito !== undefined){\r\n            msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            if(filaDoc)filaDoc.remove();\r\n            eliminarOptionSelectNC(idfe);\r\n          }else{\r\n            msjalertToast('error', '¡Error!', resultado.error[0]);\r\n          }\r\n      } catch (error) {\r\n          console.log(error);\r\n      }\r\n    }\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if( f === miDialogoNC || f === modalNuevaFactura || f === miDialogoFacturarA || f === modalEditarResolution || (f as HTMLInputElement).value === 'Salir' || (f as HTMLInputElement).value === 'Cancelar') {\r\n        miDialogoNC.close();\r\n        modalNuevaFactura.close();\r\n        miDialogoFacturarA.close();\r\n        modalEditarResolution.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCompañia') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.facturaselectronicas')){\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\", tablaFacturasElectronicas:HTMLElement;\r\n\r\n    interface invoice {\r\n        id:string,     //id de la factura_electronica\r\n        orden:string,  //id de la factura\r\n        prefijo:string,\r\n        numero:string, //numero del consecutivo de la factura electronica\r\n        resolucion:string,\r\n        cufe:string,\r\n        identificacion:string,\r\n        nombre:string,\r\n        tipoventa:string,\r\n        base:string,\r\n        valorimpuestototal:string,\r\n        total:string,\r\n        created_at: string\r\n    }\r\n\r\n    let facturaselectronicas:invoice[] = [];\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      callApiInvoice(fechainicio, fechafin);\r\n    });\r\n\r\n    async function callApiInvoice(dateinicio:string, datefin:string){\r\n        document.querySelector('#fecha1')!.textContent = dateinicio;\r\n        document.querySelector('#fecha2')!.textContent = datefin;\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/facturaselectronicas\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            facturaselectronicas = resultado;\r\n            printTableFacturasPagas();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    printTableFacturasPagas();\r\n    function printTableFacturasPagas(){\r\n        tablaFacturasElectronicas = ($('#tablaFacturasElectronicas') as any).DataTable({\r\n            \"responsive\": true,\r\n            destroy: true, // importante si recargas la tabla\r\n            data: facturaselectronicas,\r\n            columns: [\r\n                        {title: 'Orden', data: 'orden'}, \r\n                        {title: 'Prefijo', data: 'prefijo'}, \r\n                        {title: 'Num', data: 'numero'},\r\n                        { \r\n                            title: 'Abrir', \r\n                            data: null, \r\n                            orderable: false, \r\n                            searchable: false, \r\n                            render: (data: any, type: any, row: any) => {return `<a class=\"btn-ver btn-xs btn-light\" target=\"_blank\" href=\"/admin/reportes/detalleInvoice?id=${row.orden}\" data-id=\"${row.orden}\">Abrir</a>`}\r\n                        },\r\n                        {\r\n                            title: 'Abrir Dian', \r\n                            data: null, \r\n                            orderable: false, \r\n                            searchable: false, \r\n                            render: (data: any, type: any, row: any) => {return `<a class=\"btn-ver btn-xs btn-lima\" data-id=\"${row.id}\" target=\"_blank\" href=\"${row.link}\">Abrir Dian</a>`}\r\n                        }, \r\n                        {title: 'Identificacion', data: 'identificacion'}, \r\n                        {title: 'Nombre', data: 'nombre'}, \r\n                        {title: 'Tipo venta', data: 'tipoventa'},\r\n                        {title: 'Prefijo NC', data: 'prefixnc'},\r\n                        {title: 'Nun NC', data: 'num_nota'},\r\n                        {title: 'Abrir NC',\r\n                                data: null, \r\n                                orderable: false, \r\n                                searchable: false, \r\n                                render: (data: any, type: any, row: any) => {return row.id_estadonota==2&&row.nota_credito == 1?`<a class=\"btn-ver btn-xs btn-orange\" target=\"_blank\" href=\"${row.linknc}\">Abrir NC</a>`:row.id_estadonota==1&&row.nota_credito == 1?'<button class=\"btn-xs btn-blue\">pendiente NC</button>':row.id_estadonota==3&&row.nota_credito == 1?'<button class=\"btn-xs btn-red\">Error NC</button>':''}\r\n                        },\r\n                        {title: 'Base', data: 'base', render: (data:number) => `$${Number(data).toLocaleString()}`}, \r\n                        {title: 'Valor imp', data: 'valorimpuestototal', render: (data:number) => `$${Number(data).toLocaleString()}`}, \r\n                        {title: 'Total', data: 'total', render: (data:number) => `$${Number(data).toLocaleString()}`}, \r\n                        {title: 'Fecha', data: 'created_at'},\r\n                        {\r\n                            title: 'Archivos', \r\n                            data: null, \r\n                            orderable: false, \r\n                            searchable: false, \r\n                            render: (data: any, type: any, row: any) => {return `\r\n                                                                                <a class=\"mr-4 text-3xl\" target=\"_blank\" href=\"https://apidianj2.com/j2softwarepos/download/${row.filename}\"><i class=\"fa-solid fa-file-pdf text-red-600\"></i></a>` \r\n                                                                                +(row.nota_credito == 1?` <a class=\" text-3xl\" target=\"_blank\" href=\"https://apidianj2.com/j2softwarepos/download/${row.filenamenc}\"><i class=\"fa-solid fa-file-pdf text-blue-400\"></i></a>`:'')\r\n                                                                        }\r\n                        }, \r\n                    ],\r\n            pageLength: 25,\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                        {extend: 'excelHtml5', title: 'facturas procesadas'},  \r\n                        {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                        {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                        'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n        });\r\n    }\r\n\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.electronicaspendientes')){\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\", tablaelectronicasPendientes:HTMLElement;\r\n\r\n    interface invoice {\r\n        id:string,     //id de la factura_electronica\r\n        orden:string,  //id de la factura\r\n        prefijo:string,\r\n        numero:string, //numero del consecutivo de la factura electronica\r\n        resolucion:string,\r\n        cufe:string,\r\n        identificacion:string,\r\n        nombre:string,\r\n        tipoventa:string,\r\n        base:string,\r\n        valorimpuestototal:string,\r\n        total:string,\r\n        created_at: string\r\n    }\r\n\r\n    let facturaselectronicaspendientes:invoice[] = [];\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        callApiInvoice(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      callApiInvoice(fechainicio, fechafin);\r\n    });\r\n\r\n    async function callApiInvoice(dateinicio:string, datefin:string){\r\n        document.querySelector('#fecha1')!.textContent = dateinicio;\r\n        document.querySelector('#fecha2')!.textContent = datefin;\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin);\r\n        try {\r\n            const url = \"/admin/api/electronicaspendientes\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            facturaselectronicaspendientes = resultado;\r\n            printTableFacturasPagas();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    printTableFacturasPagas();\r\n    function printTableFacturasPagas(){\r\n        tablaelectronicasPendientes = ($('#tablaelectronicasPendientes') as any).DataTable({\r\n            \"responsive\": true,\r\n            destroy: true, // importante si recargas la tabla\r\n            data: facturaselectronicaspendientes,\r\n            columns: [\r\n                        {title: 'Orden', data: 'orden'}, \r\n                        {title: 'Prefijo', data: 'prefijo'}, \r\n                        {title: 'Numero', data: 'numero'},\r\n                        { \r\n                            title: 'Abrir', \r\n                            data: null, \r\n                            orderable: false, \r\n                            searchable: false, \r\n                            render: (data: any, type: any, row: any) => {return `<a class=\"btn-ver btn-xs btn-light\" target=\"_blank\" href=\"/admin/reportes/detalleInvoice?id=${row.orden}\" data-id=\"${row.orden}\">Abrir</a>`}\r\n                        },\r\n                        {title: 'Identificacion', data: 'identificacion'}, \r\n                        {title: 'Nombre', data: 'nombre'}, \r\n                        {title: 'Tipo venta', data: 'tipoventa'}, \r\n                        {title: 'Base', data: 'base', render: (data:number) => `$${Number(data).toLocaleString()}`}, \r\n                        {title: 'Valor imp', data: 'valorimpuestototal', render: (data:number) => `$${Number(data).toLocaleString()}`}, \r\n                        {title: 'Total', data: 'total', render: (data:number) => `$${Number(data).toLocaleString()}`}, \r\n                        {title: 'Fecha', data: 'created_at'}\r\n                    ],\r\n            pageLength: 25,\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                    {extend: 'copyHtml5', text: 'Copia'}, \r\n                    {extend: 'excelHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'csvHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                    'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n        });\r\n    }\r\n\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n    if(!document.querySelector('.estadosfinancierosCreditos'))return;\r\n        const POS = (window as any).POS;\r\n\r\n        let tablaEstdosFinancierosCreditos:HTMLElement;\r\n        let estadosFinancierosCreditos:[] = [];\r\n\r\n\r\n        async function callApiReporte(dateinicio:string, datefin:string){\r\n            document.querySelector('#fecha1')!.textContent = dateinicio;\r\n            document.querySelector('#fecha2')!.textContent = datefin;\r\n            (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n            const datos = new FormData();\r\n            datos.append('fechainicio', dateinicio);\r\n            datos.append('fechafin', datefin);\r\n            try {\r\n                const url = \"/admin/api/reportes/creditos/estadosFinancieros\"; //llama a la api que esta en reportescontrolador.php\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                estadosFinancierosCreditos = await respuesta.json();\r\n                printTableEstadosFinancierosCreditos();\r\n            (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        }\r\n\r\n\r\n        printTableEstadosFinancierosCreditos();\r\n        function printTableEstadosFinancierosCreditos(){\r\n            tablaEstdosFinancierosCreditos = ($('#tablaEstdosFinancierosCreditos') as any).DataTable({\r\n                \"responsive\": true,\r\n                pageLength: 25,\r\n                destroy: true, // importante si recargas la tabla\r\n                data: estadosFinancierosCreditos,\r\n                columns: [\r\n                    {title: 'N°', data: 'num_orden'},\r\n                    {title: 'Fecha', data: 'fechainicio'},\r\n                    {title: 'Credito', data: 'capitalTotal', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    {title: 'Costo', data: 'costo_total', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    {title: 'Utilidad Comercial', data: 'utilidad_comercial', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    {title: 'Utilidad Proyectada', data: 'utilidad_proyectada', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    {title: 'Pagado', data: 'valor_pagado', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    {title: 'Utilidad Realizada', data: 'utilidad_realizada', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    {\r\n                        title: 'Estado',\r\n                        data: 'estado',\r\n                        render: (data: any, type: any, row: any) => {return `<a class=\"btn-xs ${row.estado=='2'?'btn-blue':row.estado=='1'?'btn-lima':'btn-light'}\" target=\"_blank\" href=\"/admin/creditos/detallecredito?id=${row.id}\">${row.estado=='1'?'Finalizado':'Abierto'}</a>`}\r\n                    },\r\n                ],\r\n                \r\n                \r\n                language: {\r\n                    search: 'Busqueda',\r\n                    emptyTable: 'No Hay datos disponibles',\r\n                    zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                    lengthMenu: '_MENU_ Entradas por pagina',\r\n                    info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                    infoEmpty: 'No hay entradas a mostrar',\r\n                    infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                    paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n                },\r\n                layout: {\r\n                    topStart: {\r\n                        buttons: [\r\n                        {extend: 'excelHtml5', title: 'facturas procesadas'}, \r\n                        {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                        {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                        'colvis'\r\n                        ],\r\n                        pageLength: 'pageLength'\r\n                    }\r\n                }\r\n            });\r\n        }\r\n\r\n        POS.callApiReporte = callApiReporte;\r\n    \r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.facturasprocesadas')){\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\", tablaFacturasProcesadas:HTMLElement;\r\n\r\n    interface facturaspagas {\r\n        id:string,\r\n        idvendedir:string,\r\n        idcaja:string,\r\n        idconsecutivo:string,\r\n        num_orden:string,\r\n        num_consecutivo:string,\r\n        vendedor:string,\r\n        valorgananciauser:string,\r\n        caja:string,\r\n        tipofacturador:string,\r\n        totalunidades:string,\r\n        recibido:string,\r\n        cambio:string,\r\n        tipoventa:string,\r\n        estado:string,\r\n        cambioaventa:string,\r\n        subtotal:string,\r\n        base:string,\r\n        valorimpuesto:string,\r\n        descuento:string,\r\n        total:string,\r\n        fechapago:string\r\n    } \r\n\r\n    let datosFacturasPagas:facturaspagas[] = [];\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      callApiFacturasPagas(fechainicio, fechafin);\r\n    });\r\n\r\n    async function callApiFacturasPagas(dateinicio:string, datefin:string){\r\n        document.querySelector('#fecha1')!.textContent = dateinicio;\r\n        document.querySelector('#fecha2')!.textContent = datefin;\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/facturaspagas\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            datosFacturasPagas = resultado;\r\n            printTableFacturasPagas();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    printTableFacturasPagas();\r\n    function printTableFacturasPagas(){\r\n        tablaFacturasProcesadas = ($('#tablaFacturasProcesadas') as any).DataTable({\r\n            \"responsive\": true,\r\n            destroy: true, // importante si recargas la tabla\r\n            data: datosFacturasPagas,\r\n            columns: [\r\n                {title: 'Orden', data: 'num_orden'},\r\n                {title: 'N° Factura', data: 'num_consecutivo'},\r\n                {title: 'Tipo', data: 'tipofacturador'},\r\n                {title: 'Tipo Venta', data: 'tipoventa'},\r\n                { \r\n                    title: 'Abrir', \r\n                    data: null, \r\n                    orderable: false, \r\n                    searchable: false, \r\n                    render: (data: any, type: any, row: any) => {return `<a class=\"btn-ver btn-xs btn-light\" target=\"_blank\" href=\"/admin/caja/ordenresumen?id=${row.id}\" data-id=\"${row.id}\">Abrir</a>`}\r\n                },\r\n                {title: 'Cant vendida', data: 'totalunidades'},\r\n                {title: 'B. gravable', data: 'base', render: (data:number) => `$${Number(data).toLocaleString()}`}, \r\n                {title: 'Imp', data: 'valorimpuestototal'}, \r\n                {title: 'Descuento', data: 'descuento'}, \r\n                {title: 'Total', data: 'total', render: (data: number, type: string) => {\r\n                                                                                            if (type === 'display') {\r\n                                                                                            return `$${data.toLocaleString('es-CO')}`;\r\n                                                                                            }\r\n                                                                                            return data; // para export, sort, filter\r\n                                                                                        }}, \r\n                {title: 'Vendedor', data: 'vendedor'},\r\n                {title: 'Comision', data: 'valorgananciauser', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                {title: 'Caja', data: 'caja'}],\r\n            pageLength: 25,\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                    {extend: 'copyHtml5', text: 'Copia'}, \r\n                    {extend: 'excelHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'csvHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                    'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n        });\r\n    }\r\n\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.facturasanuladas')){\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\", tablaFacturasAnuladas:HTMLElement;\r\n\r\n    interface factuarasanuladas {\r\n        id:string,\r\n        idvendedir:string,\r\n        idcaja:string,\r\n        idconsecutivo:string,\r\n        num_orden:string,\r\n        num_consecutivo:string,\r\n        vendedor:string,\r\n        caja:string,\r\n        tipofacturador:string,\r\n        totalunidades:string,\r\n        recibido:string,\r\n        cambio:string,\r\n        tipoventa:string,\r\n        estado:string,\r\n        cambioaventa:string,\r\n        subtotal:string,\r\n        base:string,\r\n        valorimpuesto:string,\r\n        descuento:string,\r\n        total:string,\r\n        fechapago:string\r\n    } \r\n\r\n    let datosFacturasAnuladas:factuarasanuladas[] = [];\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        callApiFacturasPagas(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      callApiFacturasPagas(fechainicio, fechafin);\r\n    });\r\n\r\n    async function callApiFacturasPagas(dateinicio:string, datefin:string){\r\n        document.querySelector('#fecha1')!.textContent = dateinicio;\r\n        document.querySelector('#fecha2')!.textContent = datefin;\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin);\r\n        try {\r\n            const url = \"/admin/api/facturasanuladas\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            datosFacturasAnuladas = resultado;\r\n            printTableFacturasPagas();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    printTableFacturasPagas();\r\n    function printTableFacturasPagas(){\r\n        tablaFacturasAnuladas = ($('#tablaFacturasAnuladas') as any).DataTable({\r\n            \"responsive\": true,\r\n            destroy: true, // importante si recargas la tabla\r\n            data: datosFacturasAnuladas,\r\n            columns: [{title: 'Orden', data: 'num_orden'}, {title: 'N° Factura', data: 'num_consecutivo'}, {title: 'Tipo', data: 'tipofacturador'}, {title: 'Cant vendida', data: 'totalunidades'}, {title: 'B. gravable', data: 'base', render: (data:number) => `$${Number(data).toLocaleString()}`}, {title: 'Imp', data: 'valorimpuestototal'}, {title: 'Descuento', data: 'descuento'}, {title: 'Total', data: 'total', render: (data:number) => `$${Number(data).toLocaleString()}`}, {title: 'Vendedor', data: 'vendedor'}, {title: 'Caja', data: 'caja'}],\r\n            pageLength: 25,\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                    {extend: 'copyHtml5', text: 'Copia'}, \r\n                    {extend: 'excelHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'csvHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                    'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n        });\r\n    }\r\n\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n    if(!document.querySelector('.remisiones'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const tablaRemisiones = ($('#tablaRemisiones') as any);\r\n\r\n    interface i_remisiones {\r\n        id:string,\r\n        fechacreacion:string,\r\n        vendedor:string,\r\n        cliente:string,\r\n        num_orden:string,\r\n        entrega:string,\r\n        entregado:string,\r\n    }\r\n\r\n    let remisiones:i_remisiones[] = [];\r\n\r\n\r\n    async function callApiReporte(dateinicio:string, datefin:string){\r\n        console.log(dateinicio, datefin);\r\n        \r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/reportes/remisiones\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            remisiones = resultado;\r\n            printRemisiones();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n    \r\n    printRemisiones();\r\n    function printRemisiones(){\r\n        tablaRemisiones.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: remisiones,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Id', data: 'id'},\r\n                        {title: 'Fecha', data: 'fechacreacion', render: (data:string) => `<div class=\"w-36 whitespace-normal\">${data}</div>`},\r\n                        {title: 'Fecha Entrega', data: 'fechaentrega',  render: (data:string) => `<div class=\"\">${data}</div>`},\r\n                        {title: 'Usuario', data: 'vendedor',  render: (data:string) => `<div class=\"w-48 whitespace-normal\">${data}</div>`},\r\n                        {title: 'Cliente', data: 'cliente',  render: (data:string) => `<div class=\"w-48 whitespace-normal\">${data}</div>`},\r\n                        {title: 'Orden', data: 'num_orden'},\r\n                        {title: 'Entrega', data: 'entrega'},\r\n                        {title: 'Estado', data: 'entregado', render: (data:string) => `${data=='1'?'<label class=\"text-green-500 font-medium\">Despachado</label>':'<label class=\"text-red-500 font-medium\">Pendiente</label>'}`},\r\n                        { \r\n                            title: 'Acciones', \r\n                            data: null, \r\n                            orderable: false, \r\n                            searchable: false, \r\n                            render: (data: any, type: any, row: any) => {return `<a class=\"btn-xs btn-indigo\" target=\"_blank\" href=\"/admin/caja/ordenresumen?id=${row.id}\" data-id=\"${row.id}\">Abrir</a>`}\r\n                        },        \r\n            ],\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                        {extend: 'excelHtml5', title: 'facturas procesadas'},  \r\n                        {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                        {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                        'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },\r\n        });\r\n    }\r\n\r\n\r\n    POS.callApiReporte = callApiReporte;\r\n\r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.detallecompra')){\r\n\r\n    const btnPrintCompra = document.querySelector('#btnPrintCompra') as HTMLButtonElement;\r\n\r\n    //capturar el id de la compra por la url\r\n    const parametrosURL = new URLSearchParams(window.location.search);\r\n    const id:string = parametrosURL.get('id')??'';\r\n    ///////// imprimir detalle de compra\r\n    btnPrintCompra.addEventListener('click', ()=>{\r\n      if(id!='' || !isNaN(Number(id))){\r\n        //const ventana = window.open('/printDetalleCompra?id='+id, '_blank');\r\n        const ventana = window.open('/admin/printComprobanteCompraPDF?id='+id, '_blank');\r\n        if(ventana){\r\n            ventana.onload = ()=>{\r\n                ventana?.focus();\r\n                ventana?.print();\r\n            };\r\n        }\r\n      }else{\r\n        msjalertToast('error', '¡Error!', 'Error al generar impresion.');\r\n      }\r\n    });\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.inventarioxproducto')){\r\n        let  tablaStockRapido:HTMLElement;\r\n        tablaStockRapido = ($('#tablaStockRapido') as any).DataTable(configdatatablesstockrapido);\r\n    }\r\n\r\n})();","(()=>{\r\n    if(!document.querySelector('.movimientosinventarios'))return;\r\n\r\n        const POS = (window as any).POS;\r\n\r\n        let tablaMovimientosInventarios:HTMLElement;\r\n        let datosMovimientosInventarios:[] = [];\r\n        //const mesyaño:[string, number] = mesyañoactual();\r\n\r\n\r\n        ///////   productos y subproductos en el select\r\n        let filteredData: {id:string, text:string, tipo:string, sku:string, unidadmedida:string}[];   //tipo = 0 es producto simple,  1 = subproducto\r\n        (async ()=>{\r\n            try {\r\n                const url = \"/admin/api/totalitems\"; //llamado a la API REST en el controlador almacencontrolador para treaer todas los productos simples y subproductos\r\n                const respuesta = await fetch(url); \r\n                const resultado:{id:string, nombre:string, preciopersonalizado:string, tipoproducto:string, sku:string, unidadmedida:string}[] = await respuesta.json();\r\n                filteredData = resultado.map(item => ({ id: item.id, text: item.nombre, tipo: item.preciopersonalizado?'0':'1', sku: item.sku, unidadmedida: item.unidadmedida }));\r\n                activarselect2(filteredData);\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        })();\r\n\r\n        function activarselect2(filteredData:{id:string, text:string, tipo:string, sku:string, unidadmedida:string}[]){\r\n            ($('#item') as any).select2({ \r\n                data: filteredData,\r\n                placeholder: \"Selecciona un item\",\r\n                maximumSelectionLength: 1,\r\n                /*\r\n                templateResult: function (data:{id:string, text:string, tipo:string}) {\r\n                    // Personalizar cómo se muestra cada opción en el dropdown\r\n                    if (!data.id) { return data.text; }  // Si no hay id, solo mostrar el texto\r\n                    const html = `\r\n                        <div class=\"custom-option\">\r\n                            <span class=\"item-name\">${data.text}</span> \r\n                            <span class=\"item-type\">${data.tipo}</span>  <!-- Mostrar tipo adicional -->\r\n                        </div>`;\r\n                    return $(html);  // Devolver el HTML personalizado\r\n                }*/\r\n            });\r\n        }\r\n\r\n\r\n        async function callApiReporte(dateinicio:string, datefin:string){\r\n            document.querySelector('#fecha1')!.textContent = dateinicio;\r\n            document.querySelector('#fecha2')!.textContent = datefin;\r\n            let datosItem = ($('#item') as any).select2('data')[0];\r\n            if(datosItem === undefined){\r\n                msjalertToast('error', '¡Error!', \"Seleccionar un item de la lista\");\r\n                return;\r\n            }\r\n\r\n            (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n            const datos = new FormData();\r\n            datos.append('fechainicio', dateinicio);\r\n            datos.append('fechafin', datefin+' 23:59:59');\r\n            datos.append('tipo', datosItem.tipo);\r\n            datos.append('iditem', datosItem.id);\r\n            try {\r\n                const url = \"/admin/api/movimientoInventario\"; //llama a la api que esta en reportescontrolador.php\r\n                const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n                const resultado = await respuesta.json();\r\n                datosMovimientosInventarios = resultado;\r\n                console.log(datosMovimientosInventarios);\r\n                printTableMovimientoInventario();\r\n            (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n        }\r\n\r\n\r\n        printTableMovimientoInventario();\r\n        function printTableMovimientoInventario(){\r\n            tablaMovimientosInventarios = ($('#tablaMovimientosInventarios') as any).DataTable({\r\n                \"responsive\": true,\r\n                pageLength: 25,\r\n                destroy: true, // importante si recargas la tabla\r\n                data: datosMovimientosInventarios,\r\n                order: [[8, \"desc\"]],\r\n                columns: [\r\n                    {title: 'id', data: 'id'}, \r\n                    {title: 'Usuario', data: 'usuario'},\r\n                    {title: 'Producto', data: 'nombre'},\r\n                    {title: 'Unidad', data: 'unidadmedida'},\r\n                    {\r\n                        title: 'tipo', \r\n                        data: null, \r\n                        orderable: false, \r\n                        searchable: false, \r\n                        render: (data: any, type: any, row: any) => {return `<button class=\"btn-xs ${row.tipo=='venta'?'btn-lima':row.tipo=='compra'?'btn-blue':row.tipo=='ajuste'?'btn-turquoise':(row.tipo=='descuento de unidades' || row.tipo=='descuento por produccion')?'btn-bluelight':row.tipo=='salida por traslado'?'btn-yellow':row.tipo=='devolucion'?'btn-red':'btn-blueintense'}\">${row.tipo}</button>`}\r\n                    },\r\n                    {title: 'Cantidad', data: 'cantidad'},\r\n                    {title: 'Stock anterior', data: 'stockanterior'},\r\n                    {title: 'Stock', data: 'stocknuevo'},\r\n                    {title: 'Fecha', data: 'created_at'},\r\n                    {title: 'Referencia', data: 'referencia'},\r\n                ],\r\n                \r\n                \r\n                language: {\r\n                    search: 'Busqueda',\r\n                    emptyTable: 'No Hay datos disponibles',\r\n                    zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                    lengthMenu: '_MENU_ Entradas por pagina',\r\n                    info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                    infoEmpty: 'No hay entradas a mostrar',\r\n                    infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                    paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n                },\r\n                layout: {\r\n                    topStart: {\r\n                        buttons: [\r\n                        {extend: 'excelHtml5', title: 'facturas procesadas'}, \r\n                        {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                        {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                        'colvis'\r\n                        ],\r\n                        pageLength: 'pageLength'\r\n                    }\r\n                }\r\n            });\r\n        }\r\n\r\n        POS.callApiReporte = callApiReporte;\r\n    \r\n})();","(():void=>{\r\n\r\n  if(document.querySelector('.reportescompras')){\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\", tablaReportesCompras:HTMLElement;\r\n\r\n    interface compras {\r\n        id:string,\r\n        formapago:string,\r\n        nfactura:string,\r\n        impuesto:string,\r\n        cantidaditems:string,\r\n        observacion:string,\r\n        estado:string,\r\n        subtotal:string,\r\n        valortotal:string,\r\n        fechacompra:string,\r\n        nombreusuario:string,\r\n        nombreproveedor:string,\r\n        nombrecaja:string\r\n        estadocierrecaja:string\r\n    } \r\n\r\n    let datosCompras:compras[] = [];\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        callApiCompras(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        callApiCompras(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        callApiCompras(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        callApiCompras(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      callApiCompras(fechainicio, fechafin);\r\n    });\r\n\r\n    async function callApiCompras(dateinicio:string, datefin:string){\r\n        document.querySelector('#fecha1')!.textContent = dateinicio;\r\n        document.querySelector('#fecha2')!.textContent = datefin;\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/reportecompras\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            datosCompras = resultado;\r\n            console.log(datosCompras);\r\n            printTableCompras();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    printTableCompras();\r\n    function printTableCompras(){\r\n        tablaReportesCompras = ($('#tablaReportesCompras') as any).DataTable({\r\n            \"responsive\": true,\r\n            destroy: true, // importante si recargas la tabla\r\n            data: datosCompras,\r\n            columns: [\r\n                {title: 'id', data: 'id'}, \r\n                {title: 'usuario', data: 'nombreusuario'},\r\n                {title: 'proveedor', data: 'nombreproveedor'},\r\n                {title: 'caja', data: null, render: (data:compras)=>{ const x = data.estadocierrecaja == '0'?'Abierta':'Cerrada'; return `${data.nombrecaja} - ${x}`; }},\r\n                {title: 'formapago', data: 'formapago'}, \r\n                {title: 'nfactura', data: 'nfactura'},\r\n                {title: 'cantidaditems', data: 'cantidaditems'},\r\n                {title: 'valortotal', data: 'valortotal', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                {title: 'fechacompra', data: 'fechacompra'},\r\n                { \r\n                    title: 'Acciones', \r\n                    data: null, \r\n                    orderable: false, \r\n                    searchable: false, \r\n                    render: (data: any, type: any, row: any) => {return `<button class=\"btn-ver mr-4\" data-id=\"${row.id}\">✳️​</button> <button class=\"btn-eliminar\" data-id=\"${row.id}\">⛔​</button>`}\r\n                }\r\n            ],\r\n            \r\n            /*pageLength: 25,\r\n            language: {\r\n                search: 'Busqueda',\r\n                emptyTable: 'No Hay datos disponibles',\r\n                zeroRecords:    \"No se encontraron registros coincidentes\",\r\n                lengthMenu: '_MENU_ Entradas por pagina',\r\n                info: 'Mostrando pagina _PAGE_ de _PAGES_',\r\n                infoEmpty: 'No hay entradas a mostrar',\r\n                infoFiltered: ' (filtrado desde _MAX_ registros)',\r\n                paginate: {\"first\": \"<<\", \"last\": \">>\", \"next\": \">\", \"previous\": \"<\"}\r\n            },\r\n            layout: {\r\n                topStart: {\r\n                    buttons: [\r\n                    {extend: 'copyHtml5', text: 'Copia'}, \r\n                    {extend: 'excelHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'csvHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'pdfHtml5', title: 'facturas procesadas'}, \r\n                    {extend: 'print', title: 'facturas procesadas', text: 'Imprimir'},\r\n                    'colvis'\r\n                    ],\r\n                    pageLength: 'pageLength'\r\n                }\r\n            },*/\r\n        });\r\n    }\r\n\r\n\r\n    //evento click sobre toda la tabla compras\r\n    document.querySelector('#tablaReportesCompras')?.addEventListener(\"click\", (e)=>{\r\n      const target = e.target as HTMLButtonElement;\r\n      let idcompra = target?.dataset.id;\r\n      if((e.target as HTMLButtonElement)?.classList.contains(\"btn-ver\"))verCompra(idcompra);\r\n      if(target?.classList.contains(\"btn-eliminar\"))eliminarCompra(idcompra, target);\r\n    });\r\n\r\n    function verCompra(idcompra:string|undefined){\r\n        const compra = datosCompras.find(x=>x.id==idcompra);\r\n        if(compra?.id != null)window.location.href = '/admin/reportes/detallecompra?id='+compra.id;\r\n    }\r\n\r\n    function eliminarCompra(idcompra:string|undefined, target:HTMLButtonElement){\r\n        const compra = datosCompras.find(x=>x.id==idcompra);\r\n        const fila = (tablaReportesCompras as any).row(target.closest('tr'));\r\n        if(compra?.estadocierrecaja === '0'){\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar la compra del sistema?',\r\n                text: \"La compra sera eliminado por completo de la aplicacion.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (async ()=>{\r\n                        const datos = new FormData();\r\n                        datos.append('id', compra.id);\r\n                        try {\r\n                            const url = \"/admin/api/eliminarcompra\"; //llamado a la API REST en reportescontrolador para eliminar la compra\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos});\r\n                            const resultado = await respuesta.json();\r\n                            if(resultado.exito !== undefined){ \r\n                                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                                fila.remove().draw(false);\r\n                            }else{\r\n                                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();\r\n                }\r\n            });\r\n        }else{\r\n             msjalertToast('error', '¡Error!', 'No se puede eliminar la compra, porque la caja esta cerrada');\r\n        }\r\n    }\r\n\r\n\r\n  }\r\n\r\n})();","(():void=>{\r\n  if(document.querySelector('.gastoseingresos')){\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\", tablaGastos:HTMLTableElement, tablaIngresos:HTMLTableElement;\r\n\r\n    interface apigastos {\r\n        Id:string,\r\n        id_compra:string,\r\n        idg_cierrecaja:string,\r\n        nombrecaja:string,\r\n        nombrebanco:string,\r\n        nombre:string,\r\n        operacion:string,\r\n        categoriagasto:string,\r\n        estado:string,\r\n        valor:string,\r\n        descripcion:string,\r\n        imgcomprobante:string,\r\n        fecha:string\r\n    }\r\n\r\n    interface apiingresos {\r\n        id:string,\r\n        operacion:string,\r\n        valor:string,\r\n        fecha:string,\r\n        nombrecaja:string,\r\n        estado:string,\r\n        nombreusuario:string\r\n    }\r\n\r\n    let datosGastos:apigastos[] = [], datosIngresos:apiingresos[] = [];\r\n\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        callApiGastosIngresos(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        callApiGastosIngresos(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        callApiGastosIngresos(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        callApiGastosIngresos(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      callApiGastosIngresos(fechainicio, fechafin);\r\n    });\r\n\r\n    async function callApiGastosIngresos(dateinicio:string, datefin:string){\r\n        document.querySelector('#fecha1')!.textContent = dateinicio;\r\n        document.querySelector('#fecha2')!.textContent = datefin;\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/gastoseingresos\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            datosGastos = resultado.gastos;\r\n            datosIngresos = resultado.ingresos;\r\n            console.log(resultado);\r\n            printTableGastos();\r\n            printTableIngresos();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n    \r\n\r\n\r\n    printTableGastos();\r\n    function printTableGastos(){\r\n        tablaGastos = ($('#tablaGastos') as any).DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: datosGastos,\r\n            columns: [\r\n                        {title: 'id', data: 'Id'}, \r\n                        {   \r\n                            title: 'Caja', \r\n                            data: null, render: (data: apigastos) => { \r\n                                            const x = data.estado == '0'?'Abierta':'Cerrada';\r\n                                            return `${data.nombrecaja} - ${x}`;\r\n                                        } \r\n                        },\r\n                        {title: 'Banco', data: 'nombrebanco'},\r\n                        {title: 'Usuario', data: 'nombre'},\r\n                        {title: 'Operacion', data: 'operacion'},\r\n                        {title: 'Tipo Gasto', data: 'categoriagasto'},\r\n                        {title: 'Valor', data: 'valor', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Fecha', data: 'fecha'},\r\n                        { \r\n                            title: 'Acciones', \r\n                            data: null, \r\n                            orderable: false, \r\n                            searchable: false, \r\n                            render: (data: any, type: any, row: any) => { \r\n                                    return `<button class=\"btn-ver\" data-id=\"${row.Id}\">✳️​</button>\r\n                                            <button class=\"btn-imgcomprobante\" data-id=\"${row.Id}\">🧾​</button>\r\n                                            <button class=\"btn-eliminar\" data-id=\"${row.Id}\">⛔​</button>`}\r\n                        },\r\n                        {title: 'Descripcion', data: 'descripcion'},\r\n                    ],\r\n        });\r\n    }\r\n\r\n\r\n    printTableIngresos();\r\n    function printTableIngresos(){\r\n        tablaIngresos = ($('#tablaIngresos') as any).DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: datosIngresos,\r\n            columns: [\r\n                        {title: 'id', data: 'id'}, \r\n                        {   \r\n                            title: 'Caja', \r\n                            data: null, render: (data: apiingresos) => { \r\n                                            const x = data.estado == '0'?'Abierta':'Cerrada';\r\n                                            return `${data.nombrecaja} - ${x}`;\r\n                                        } \r\n                        },\r\n                        {title: 'Usuario', data: 'nombreusuario'},\r\n                        {title: 'Operacion', data: 'operacion'},\r\n                        {title: 'Valor', data: 'valor', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Fecha', data: 'fecha'},\r\n                        { \r\n                            title: 'Acciones', \r\n                            data: null, \r\n                            orderable: false, \r\n                            searchable: false, \r\n                            render: (data: any, type: any, row: any) => {return `<button class=\"btn-eliminar\" data-id=\"${row.id}\">⛔​</button>`}\r\n                        }\r\n                    ],\r\n        });\r\n    }\r\n    \r\n\r\n    //evento click sobre toda la tabla gastos\r\n    document.querySelector('#tablaGastos')?.addEventListener(\"click\", (e)=>{\r\n      const target = e.target as HTMLButtonElement;\r\n      let idgasto = target?.dataset.id;\r\n      if((e.target as HTMLButtonElement)?.classList.contains(\"btn-ver\"))verGasto(idgasto);\r\n      if(target?.classList.contains(\"btn-imgcomprobante\"))imgcomprobante(idgasto);\r\n      if(target?.classList.contains(\"btn-eliminar\"))eliminarGasto(idgasto, target);\r\n    });\r\n\r\n    //solo aplica para gastos de tipo compra\r\n    function verGasto(idgasto:string|undefined){\r\n        const gasto = datosGastos.find(x=>x.Id==idgasto);\r\n        if(gasto?.id_compra != null)window.location.href = '/admin/reportes/detallecompra?id='+gasto.id_compra;\r\n    }\r\n\r\n    function imgcomprobante(idgasto:string|undefined){\r\n        const gasto = datosGastos.find(x=>x.Id==idgasto);\r\n        if(gasto?.imgcomprobante)window.open(\"/build/img/\"+gasto?.imgcomprobante, \"_blank\");\r\n    }\r\n\r\n    function eliminarGasto(idgasto:string|undefined, target:HTMLButtonElement){\r\n        const gasto = datosGastos.find(x=>x.Id==idgasto);\r\n        const fila = (tablaGastos as any).row(target.closest('tr'));\r\n        if(gasto?.estado === '0'){\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar el gasto de la caja?',\r\n                text: \"El gasto sera eliminado por completo de la caja.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (async ()=>{\r\n                        const datos = new FormData();\r\n                        datos.append('id', gasto.Id);\r\n                        try {\r\n                            const url = \"/admin/api/eliminargasto\"; //llamado a la API REST en reportescontrolador para eliminar el gasto\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos});\r\n                            const resultado = await respuesta.json();\r\n                            if(resultado.exito !== undefined){ \r\n                                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                                fila.remove().draw(false);\r\n                            }else{\r\n                                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();\r\n                }\r\n            });\r\n        }else{\r\n             msjalertToast('error', '¡Error!', 'No se puede eliminar el gasto, porque la caja esta cerrada');\r\n        }\r\n    }\r\n\r\n\r\n    //evento click sobre toda la tabla ingresos\r\n    document.querySelector('#tablaIngresos')?.addEventListener(\"click\", (e)=>{\r\n      const target = e.target as HTMLButtonElement;\r\n      let idingreso = target?.dataset.id;\r\n      if(target?.classList.contains(\"btn-eliminar\"))eliminarIngreso(idingreso, target);\r\n    });\r\n\r\n    function eliminarIngreso(idingreso:string|undefined, target:HTMLButtonElement){\r\n        const ingreso = datosIngresos.find(x=>x.id==idingreso);\r\n        const fila = (tablaIngresos as any).row(target.closest('tr'));\r\n        if(ingreso?.estado === '0'){\r\n            Swal.fire({\r\n                customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n                icon: 'question',\r\n                title: 'Desea eliminar el ingreso de la caja?',\r\n                text: \"El ingreso sera eliminado por completo de la caja.\",\r\n                showCancelButton: true,\r\n                confirmButtonText: 'Si',\r\n                cancelButtonText: 'No',\r\n            }).then((result:any) => {\r\n                if (result.isConfirmed) {\r\n                    (async ()=>{\r\n                        const datos = new FormData();\r\n                        datos.append('id', ingreso.id);\r\n                        try {\r\n                            const url = \"/admin/api/eliminaringreso\"; //llamado a la API REST en reportescontrolador para eliminar un ingreso\r\n                            const respuesta = await fetch(url, {method: 'POST', body: datos});\r\n                            const resultado = await respuesta.json();\r\n                            if(resultado.exito !== undefined){ \r\n                                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                                fila.remove().draw(false);\r\n                            }else{\r\n                                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                            }\r\n                        } catch (error) {\r\n                            console.log(error);\r\n                        }\r\n                    })();\r\n                }\r\n            });\r\n        }else{\r\n             msjalertToast('error', '¡Error!', 'No se puede eliminar el ingreso, porque la caja esta cerrada');\r\n        }\r\n    }\r\n\r\n  }\r\n\r\n})();","(()=>{\r\n    if(document.querySelector('.utilidadxproducto')){\r\n        let tablaUtilidadXProducto:HTMLElement;\r\n        tablaUtilidadXProducto = ($('#tablaUtilidadXProducto') as any).DataTable(configdatatablesgenerico);\r\n    }\r\n\r\n})();","\r\n(()=>{\r\n\r\n    if(!document.querySelector('.ventasgenerales'))return;\r\n\r\n    const POS = (window as any).POS;\r\n\r\n    const tablaProductosVendidos = ($('#tablaProductosVendidos') as any);\r\n    const tablaMediosPagos = ($('#tablaMediosPagos') as any);\r\n    const tablacreditosSeparados = ($('#tablacreditosSeparados') as any);\r\n    const tablaGastos = ($('#tablaGastos') as any);\r\n    const tablaIngresoCanalventa = ($('#tablaIngresoCanalventa') as any);\r\n    const tablaVentasXUsuario = ($('#tablaVentasXUsuario') as any);\r\n    const tablaResumenVentas = ($('#tablaResumenVentas') as any);\r\n    const tablaResumenCreditos = document.querySelector('#tablaResumenCreditos tbody');\r\n    const printBalance = document.querySelector('#printBalance') as HTMLButtonElement;\r\n    \r\n    interface i_productosVendidos {\r\n        idproducto:string,\r\n        cantidadrefencia:string,\r\n        nombreproducto:string,\r\n        totalProductosVendidos:string,\r\n        valorunidad:string,\r\n        valorTotal:string\r\n    }\r\n\r\n    interface i_mediosPagos {\r\n        idmediopago:string,\r\n        cantidadMP:string,\r\n        mediopago:string,\r\n        valor:string\r\n    }\r\n\r\n    interface i_creditosSeparados {\r\n        idestadocreditos:string,\r\n        estado:string\r\n        carteraTotal:string,\r\n        carteraXCobrar:string,\r\n        totalAbonado:string,\r\n        total:string,\r\n    }\r\n\r\n    interface i_canaldeVenta {\r\n        canaldeventa:string,\r\n        transacciones:string,\r\n        valor:string,\r\n    }\r\n\r\n\r\n    interface i_ventasEmpleados {\r\n        empleado:string,\r\n        ventasRealizadas:string,\r\n        totalVentas:string,\r\n        porcentaje:string,\r\n        valorComision:string,\r\n    }\r\n\r\n    interface i_gastos {\r\n        descripcion:string,\r\n        tipogasto:string,\r\n        valor:string,\r\n    }\r\n    \r\n    interface i_resumenVentas {\r\n        ventas:string,\r\n        total_ventas:string,\r\n        total_costo:string,\r\n        ganancia:string,\r\n        margenutilidad:string,\r\n    }\r\n\r\n    interface i_resumenCreditos {\r\n        creditos:string,\r\n        capitalTotal:string,\r\n        costo_total:string,\r\n        utilidad_comercial:string,\r\n        utilidad_proyectada:string,\r\n        valor_pagado:string,\r\n        utilidad_realizada:string\r\n    }\r\n\r\n    let productosVendidos:i_productosVendidos[] = [], mediosPagos:i_mediosPagos[] = [], creditosSeparados:i_creditosSeparados[] = [], ventasEmpleados:i_ventasEmpleados[]=[], gastos:i_gastos[]=[], canalVenta:i_canaldeVenta[]=[], resumenVentas:i_resumenVentas[]=[], resumenCreditos:i_resumenCreditos[]=[];\r\n    let totalabonos:number = 0, dateStart = '', dateEnd = '';\r\n    //tablaProductosVendidos.DataTable(configdatatables25reg);\r\n\r\n\r\n    async function callApiReporte(dateinicio:string, datefin:string){\r\n        dateStart = dateinicio;\r\n        dateEnd = datefin;\r\n        document.querySelector('#fecha1')!.textContent = dateinicio;\r\n        document.querySelector('#fecha2')!.textContent = datefin;\r\n        \r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/reportes/reportesGenerales\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            productosVendidos = resultado.productosVendidos;\r\n            mediosPagos = resultado.mediosPagos;\r\n            creditosSeparados = resultado.separados;\r\n            ventasEmpleados = resultado.ventasXusuario;\r\n            gastos = resultado.gastos;\r\n            canalVenta = resultado.canalVenta;\r\n            resumenCreditos = resultado.resumenCreditos;\r\n            resumenVentas = resultado.resumenVentas;\r\n            printProductosVendidos();\r\n            printMediosPagos();\r\n            printCreditosSeparados();\r\n            printVentasUsuarios();\r\n            printGastos();\r\n            printCanalVenta();\r\n            totalabonos = Number(resultado.totalabonos);\r\n            printResumen(Number(resultado.totalDescuentos[0].total_descuentos));\r\n            document.querySelector('#totalDescto')!.textContent = '$'+Number(resultado.totalDescuentos[0].total_descuentos).toLocaleString();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    printProductosVendidos();\r\n    function printProductosVendidos(){\r\n        tablaProductosVendidos.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: productosVendidos,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Producto', data: 'nombreproducto'},\r\n                        {title: 'Cantidad Vendida', data: 'totalProductosVendidos'},\r\n                        {title: 'V. Unidad', data: 'valorunidad', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Total Ventas', data: 'valorTotal', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Costo Total', data: 'costoTotal', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Utilidad', data: 'utilidad', render: (data:number) => `$${Number(data).toLocaleString()}`}\r\n                    ],\r\n        });\r\n    }\r\n\r\n    printMediosPagos();\r\n    function printMediosPagos(){\r\n        tablaMediosPagos.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: mediosPagos,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Medio de Pago', data: 'mediopago'},\r\n                        {title: 'Transacciones', data: 'cantidadMP'},\r\n                        {title: 'Total Ventas', data: 'valor', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    ],\r\n        });\r\n    }\r\n\r\n    printCreditosSeparados();\r\n    function printCreditosSeparados(){\r\n        tablacreditosSeparados.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: creditosSeparados,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {\r\n                            title: 'Estado', \r\n                            data: 'estado', \r\n                            render: (data: any, type: any, row: any) => {return `<button class=\"btn-xs ${row.estado=='Abierto'?'btn-blue':row.estado=='Finalizado'?'btn-lima':'btn-light'}\">${row.estado}</button>`}\r\n                        },\r\n                        {title: 'Cartera Total', data: 'carteraTotal', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Cartera Por Cobrar', data: 'carteraXCobrar', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Total Abonado', data: 'totalAbonado', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Total', data: 'total'}\r\n                    ],\r\n        });\r\n    }\r\n\r\n\r\n    printCanalVenta();\r\n    function printCanalVenta(){\r\n        tablaIngresoCanalventa.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: canalVenta,\r\n            pageLength: 25,\r\n            order: [[ 1, 'asc' ]],\r\n            columns: [\r\n                        {title: 'Canal De Venta', data: 'canalVenta'},\r\n                        {title: 'Transacciones', data: 'transacciones'},\r\n                        {title: 'Valor', data: 'valor', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    ],\r\n        });\r\n    }\r\n\r\n\r\n    printVentasUsuarios();\r\n    function printVentasUsuarios(){\r\n        tablaVentasXUsuario.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: ventasEmpleados,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Empleado', data: 'empleado'},\r\n                        {title: 'Ventas Realizadas', data: 'ventasRealizadas'},\r\n                        {title: 'Total Ventas', data: 'totalVentas', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Porcentaje', data: 'porcentaje'},\r\n                        {title: 'Valor comision', data: 'valorComision', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    ],\r\n        });\r\n    }\r\n\r\n\r\n    printGastos();\r\n    function printGastos(){\r\n        tablaGastos.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: gastos,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Descripcion', data: 'descripcion'},\r\n                        {title: 'Tipo Gasto', data: 'tipogasto'},\r\n                        {title: 'Valor', data: 'valor', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    ],\r\n        });\r\n    }\r\n\r\n\r\n    printResumen(0);\r\n    function printResumen(dscto:number){\r\n\r\n        const contentUtilidadRF = document.querySelector('#contentUtilidadRF') as HTMLSpanElement;\r\n        const textUtilidadRF = document.querySelector('#textUtilidadRF') as HTMLSpanElement;\r\n        const utilidadRF = document.querySelector('#utilidadRF') as HTMLSpanElement;\r\n\r\n        const ventaBruta = Number(resumenVentas[0]?.total_ventas??0);\r\n        const ventaNeta = ventaBruta - dscto;\r\n        const totalIngreso = ventaNeta+totalabonos;\r\n        const totalEgreso = Number(gastos.at(-1)?.valor ?? 0);\r\n        const utilidadTotal = totalIngreso - totalEgreso;\r\n        const margenUtilidadTotal = totalIngreso > 0 ? (utilidadTotal / totalIngreso) * 100 : 0;\r\n        const rentabilidadTotal = totalEgreso > 0 ? (utilidadTotal / totalEgreso) * 100 : 0;\r\n\r\n        //cards\r\n        (document.querySelector('#IngresoTotalCard') as HTMLElement).textContent = '$'+totalIngreso.toLocaleString();\r\n        (document.querySelector('#utilidadCard') as HTMLElement).textContent = '$'+utilidadTotal.toLocaleString();\r\n        (document.querySelector('#totalAbonosCard') as HTMLElement).textContent = '$'+totalabonos.toLocaleString();\r\n        (document.querySelector('#carteraPendienteCard') as HTMLElement).textContent = '$'+Number(creditosSeparados[1]?.carteraXCobrar??0).toLocaleString();\r\n\r\n        //tabla de resumen financiero\r\n        (document.querySelector('#ventaBrutaRF') as HTMLSpanElement).textContent = '$'+ventaBruta.toLocaleString();\r\n        (document.querySelector('#descuentosRF') as HTMLSpanElement).textContent = '-$'+dscto.toLocaleString();\r\n        (document.querySelector('#ventaNetaRF') as HTMLSpanElement).textContent =  '$'+ventaNeta.toLocaleString();\r\n        (document.querySelector('#totalAbonosRF') as HTMLSpanElement).textContent = '$'+totalabonos.toLocaleString();\r\n        (document.querySelector('#ingresoTotalRF') as HTMLSpanElement).textContent = '$'+totalIngreso.toLocaleString();\r\n        (document.querySelector('#egresosRF') as HTMLSpanElement).textContent = '-$'+totalEgreso.toLocaleString();\r\n        (document.querySelector('#margenUtilidadRF') as HTMLSpanElement).textContent = margenUtilidadTotal.toLocaleString()+'%';\r\n        utilidadRF.textContent = '$'+utilidadTotal.toLocaleString();\r\n        if(utilidadTotal>=0){\r\n            contentUtilidadRF.classList.add('bg-emerald-500/10', 'border-emerald-500/20');\r\n            textUtilidadRF.classList.add('text-emerald-700');\r\n            utilidadRF.classList.add('text-emerald-600');\r\n            contentUtilidadRF.classList.remove('bg-red-500/10', 'border-red-500/20');\r\n            textUtilidadRF.classList.remove('text-red-700');\r\n            utilidadRF.classList.remove('text-red-600');\r\n        }else{\r\n            contentUtilidadRF.classList.remove('bg-emerald-500/10', 'border-emerald-500/20');\r\n            textUtilidadRF.classList.remove('text-emerald-700');\r\n            utilidadRF.classList.remove('text-emerald-600');\r\n            contentUtilidadRF.classList.add('bg-red-500/10', 'border-red-500/20');\r\n            textUtilidadRF.classList.add('text-red-700');\r\n            utilidadRF.classList.add('text-red-600');\r\n        }\r\n\r\n\r\n\r\n        //resumen financiero total de ventas\r\n        tablaResumenVentas.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: resumenVentas,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Ventas', data: 'ventas'},\r\n                        {title: 'Total Ventas Productos', data: 'total_ventas', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Total Costo Productos', data: 'total_costo', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Ganancia', data: 'ganancia', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Margen Utilidad', data: 'margenutilidad', render: (data:number) => `${Number(data).toLocaleString()}%`},\r\n                    ],\r\n        });\r\n\r\n        //resumen financiero total creditos\r\n        /*tablaResumenCreditos.DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: resumenCreditos,\r\n            pageLength: 25,\r\n            order: [[ 1, 'desc' ]],\r\n            columns: [\r\n                        {title: 'Creditos', data: 'creditos'},\r\n                        {title: 'Credito Total', data: 'capitalTotal', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Costo Total', data: 'costo_total', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Utilidad Comercial', data: 'utilidad_comercial', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Utilidad Proyectada', data: 'utilidad_proyectada', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Pago total', data: 'valor_pagado', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                        {title: 'Utilidad Realizada', data: 'utilidad_realizada', render: (data:number) => `$${Number(data).toLocaleString()}`},\r\n                    ],\r\n        });*/\r\n\r\n\r\n        //tabla resumen financiero de creditos\r\n        const tr = document.createElement('tr') as HTMLTableRowElement;\r\n        while(tablaResumenCreditos?.firstChild)tablaResumenCreditos.removeChild(tablaResumenCreditos.firstChild);\r\n        tr.insertAdjacentHTML('afterbegin', `\r\n          <td class=\"\">${resumenCreditos[0]?.creditos??0}</td> \r\n          <td class=\"\">$${Number(resumenCreditos[0]?.capitalTotal??0).toLocaleString()}</td>\r\n          <td class=\"\">$${Number(resumenCreditos[0]?.costo_total??0).toLocaleString()}</td>\r\n          <td class=\"\">$${Number(resumenCreditos[0]?.utilidad_comercial??0).toLocaleString()}</td>\r\n          <td class=\"\">$${Number(resumenCreditos[0]?.utilidad_proyectada??0).toLocaleString()}</td>\r\n          <td class=\"\">$${Number(resumenCreditos[0]?.valor_pagado??0).toLocaleString()}</td>\r\n          <td class=\"\">$${Number(resumenCreditos[0]?.utilidad_realizada??0).toLocaleString()}</td>`);\r\n        tablaResumenCreditos?.appendChild(tr);\r\n\r\n        //tabla rentabilidad\r\n        (document.querySelector('#ingresoTotal') as HTMLElement).textContent = '$'+totalIngreso.toLocaleString();\r\n        (document.querySelector('#egreso') as HTMLElement).textContent = '$'+totalEgreso.toLocaleString();\r\n        (document.querySelector('#utilidadTotal') as HTMLElement).textContent = '$'+utilidadTotal.toLocaleString();\r\n        (document.querySelector('#margenUtilidadTotal') as HTMLElement).textContent = margenUtilidadTotal.toFixed(2) + '%';\r\n        (document.querySelector('#rentabilidadTotal') as HTMLElement).textContent = rentabilidadTotal.toFixed(2) + '%';\r\n    }\r\n\r\n\r\n    printBalance.addEventListener('click', ()=>{\r\n      const contentBalanceGeneral = document.querySelector('#contentBalanceGeneral') as HTMLElement;\r\n\r\n      const ventana = window.open('', '_blank', 'width=900,height=700');\r\n      if(ventana){\r\n        ventana?.document.write(`\r\n            <html>\r\n                <head>\r\n                    <title>Balance</title>\r\n                    <link rel=\"stylesheet\" href=\"/build/css/tailwindapp.css\">\r\n                    <link rel=\"stylesheet\" href=\"/build/css/app.css\">\r\n                </head>\r\n                <body class=\"p-6\">\r\n                    <div class=\"my-8 p-6\">\r\n                        <h2 class=\"text-gray-600 text-3xl font-semibold my-12 pb-4 text-center\">📊 Balance financiero General</h2>\r\n                        <p class=\"text-2xl text-gray-600 mb-0\">PERIODO, <span class=\"text-gray-900 font-semibold ml-8\">Inicio: ${dateStart} - Fin: ${dateEnd}</span></p>    \r\n                    </div>\r\n                    ${contentBalanceGeneral.innerHTML}\r\n                </body>\r\n            </html>\r\n        `);\r\n\r\n        ventana.document.close();\r\n        ventana.onload = ()=>{\r\n            ventana?.focus();\r\n            ventana?.print();\r\n            setTimeout(() => { ventana?.close(); }, 200); // Cerrar la ventana después de unos segundos\r\n        };\r\n      }\r\n    });\r\n\r\n\r\n    POS.callApiReporte = callApiReporte;\r\n\r\n})();","(()=>{\r\n  if(document.querySelector('.ventasxtransaccion')){\r\n\r\n    const btnmensual = document.querySelector('#btnmensual') as HTMLButtonElement;\r\n    const btndiario = document.querySelector('#btndiario') as HTMLButtonElement;\r\n    const miDialogoMes = document.querySelector('#miDialogoMes') as any;\r\n    const miDialogoDiario = document.querySelector('#miDialogoDiario') as any;\r\n    let tablaTransaccioneXVenta:HTMLTableElement;\r\n\r\n    interface transacciones {\r\n      fecha:string,\r\n      total_venta:string,\r\n      num_transacciones:string,\r\n      promedio_transaccion:string,\r\n      transaccion_mas_alta:string,\r\n      transaccion_mas_baja:string\r\n    }\r\n    let datatransacciones:transacciones[] = [];\r\n\r\n    btnmensual?.addEventListener('click', ()=>{\r\n        miDialogoMes.showModal(); //seleccionar año\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    btndiario?.addEventListener('click', ()=>{\r\n        miDialogoDiario.showModal();  //seleccionar mes\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    //seleccionar año, transacciones mes acumulado de un año\r\n    document.querySelector('#formMes')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      const inputselectaño = document.querySelector('#inputselectaño') as HTMLInputElement;\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/ventasxtransaccionanual?x=\"+inputselectaño.value; //llamado a la API REST en reportescontrolador.php\r\n          const respuesta = await fetch(url);\r\n          const resultado = await respuesta.json();\r\n          datatransacciones = resultado;\r\n          console.log(resultado);\r\n          printTableTranscciones()\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n      miDialogoMes.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    //seleccionar mes, transacciones acumuladas por dia durante un mes y año elejido\r\n    document.querySelector('#formDiario')?.addEventListener('submit', e=>{\r\n      e.preventDefault();\r\n      const inputselectmesyaño = document.querySelector('#inputselectmesyaño') as HTMLInputElement;\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/ventasxtransaccionmes?x=\"+inputselectmesyaño.value; //llamado a la API REST en reportescontrolador.php\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json();\r\n          datatransacciones = resultado;\r\n          printTableTranscciones()\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n      miDialogoDiario.close();\r\n      document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    printTableTranscciones();\r\n    function printTableTranscciones(){\r\n\r\n        tablaTransaccioneXVenta = ($('#tablaTransaccioneXVenta') as any).DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: datatransacciones,\r\n            columns: [{title: 'Fecha', data: 'fecha'}, {title: 'Toal venta', data: 'total_venta', render: (data: number) => `$${Number(data).toLocaleString()}`}, {title: 'Numero de transacciones', data: 'num_transacciones'}, {title: 'Promedio por transacción', data: 'promedio_transaccion'}, {title: 'Transacción mas alta', data: 'transaccion_mas_alta'}, {title: 'Transacción mas baja', data: 'transaccion_mas_baja'}],\r\n        });\r\n    }\r\n\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      const f = event.target;\r\n      if (f === miDialogoMes || f === miDialogoDiario || (f as HTMLInputElement).closest('.salir')) {\r\n        miDialogoMes.close();\r\n        miDialogoDiario.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n  }\r\n\r\n\r\n})();\r\n   ","(():void=>{\r\n\r\n  if(document.querySelector('.ventasxcliente')){\r\n\r\n    const consultarFechaPersonalizada = document.querySelector('#consultarFechaPersonalizada') as HTMLButtonElement;\r\n    const btnmesactual = document.querySelector('#btnmesactual') as HTMLButtonElement;\r\n    const btnmesanterior = document.querySelector('#btnmesanterior') as HTMLButtonElement;\r\n    const btnhoy = document.querySelector('#btnhoy') as HTMLButtonElement;\r\n    const btnayer = document.querySelector('#btnayer') as HTMLButtonElement;\r\n    let fechainicio:string = \"\", fechafin:string = \"\", tablaVentasXCliente:HTMLElement;\r\n\r\n    interface ventaxcliente {\r\n        id:string,\r\n        nombre:string,\r\n        cantidad_facturas:string,\r\n        total_ventas:string\r\n    } \r\n\r\n    let datosVentaXCliente:ventaxcliente[] = [];\r\n\r\n\r\n    // SELECTOR DE FECHAS DEL CALENDARIO\r\n    ($('input[name=\"datetimes\"]')as any).daterangepicker({\r\n      timePicker: true,\r\n      //startDate: moment().startOf('hour'),\r\n      //endDate: moment().startOf('hour').add(32, 'hour'),\r\n      startDate: moment().set({ hour: 0, minute: 0, second: 1 }),\r\n      endDate: moment().set({ hour: 23, minute: 59, second: 59 }),\r\n      locale: {\r\n        format: 'M/DD hh:mm A'\r\n      }\r\n    });\r\n\r\n    $('input[name=\"datetimes\"]').on('apply.daterangepicker', function(ev, picker) {\r\n        var startDate = picker.startDate.format('YYYY-MM-DD HH:mm:ss');\r\n        var endDate = picker.endDate.format('YYYY-MM-DD HH:mm:ss');\r\n        fechainicio = startDate;\r\n        fechafin = endDate;\r\n        //(document.querySelector('#fechainicio') as HTMLParagraphElement).textContent = fechainicio;\r\n        //(document.querySelector('#fechafin') as HTMLParagraphElement).textContent = fechafin;\r\n    });\r\n\r\n    btnmesactual.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        // Primer día del mes actual\r\n        const primerDia = new Date(hoy.getFullYear(), hoy.getMonth(), 1);\r\n        // Último día del mes actual\r\n        const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);\r\n        const fechainiciobtn:string = primerDia.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDia.toISOString().split('T')[0];\r\n        callApiVentasXCliente(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n\r\n    btnmesanterior.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Primer día del mes anterior\r\n        const primerDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth() - 1, 1);\r\n        // Último día del mes anterior\r\n        const ultimoDiaMesAnterior = new Date(hoy.getFullYear(), hoy.getMonth(), 0);\r\n        const fechainiciobtn:string = primerDiaMesAnterior.toISOString().split('T')[0];\r\n        const fechafinbtn:string = ultimoDiaMesAnterior.toISOString().split('T')[0];\r\n        callApiVentasXCliente(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnhoy.addEventListener('click', (e:Event)=>{\r\n        const hoy = new Date();\r\n        const inicioDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 0, 0, 0);\r\n        const finDia = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioDia);\r\n        const fechafinbtn:string = formatoFecha(finDia);\r\n        callApiVentasXCliente(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    btnayer.addEventListener('click', (e:Event)=>{\r\n        // Fecha actual\r\n        const hoy = new Date();\r\n        // Día anterior\r\n        const ayer = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() - 1);\r\n        // Inicio y fin del día anterior\r\n        const inicioAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 0, 0, 0);\r\n        const finAyer = new Date(ayer.getFullYear(), ayer.getMonth(), ayer.getDate(), 23, 59, 59);\r\n        const fechainiciobtn:string = formatoFecha(inicioAyer);\r\n        const fechafinbtn:string = formatoFecha(finAyer);\r\n        callApiVentasXCliente(fechainiciobtn, fechafinbtn);\r\n    });\r\n\r\n    function formatoFecha(fecha: Date): string {\r\n        const año = fecha.getFullYear();\r\n        const mes = String(fecha.getMonth() + 1).padStart(2, \"0\");\r\n        const dia = String(fecha.getDate()).padStart(2, \"0\");\r\n        const hora = String(fecha.getHours()).padStart(2, \"0\");\r\n        const minuto = String(fecha.getMinutes()).padStart(2, \"0\");\r\n        const segundo = String(fecha.getSeconds()).padStart(2, \"0\");\r\n        return `${año}-${mes}-${dia} ${hora}:${minuto}:${segundo}`;\r\n    }\r\n\r\n\r\n    ////// consulta por fecha personalizada\r\n    consultarFechaPersonalizada.addEventListener('click', ()=>{\r\n      if(fechainicio == '' || fechafin == ''){\r\n         msjalertToast('error', '¡Error!', \"Elegir fechas a consultar\");\r\n         return;\r\n      }\r\n      callApiVentasXCliente(fechainicio, fechafin);\r\n    });\r\n\r\n    async function callApiVentasXCliente(dateinicio:string, datefin:string){\r\n        console.log(dateinicio, datefin);\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        const datos = new FormData();\r\n        datos.append('fechainicio', dateinicio);\r\n        datos.append('fechafin', datefin+' 23:59:59');\r\n        try {\r\n            const url = \"/admin/api/ventasxcliente\"; //llama a la api que esta en reportescontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            datosVentaXCliente = resultado;\r\n            printTableVentasXCliente();\r\n           (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n    }\r\n\r\n\r\n    printTableVentasXCliente();\r\n    function printTableVentasXCliente(){\r\n        tablaVentasXCliente = ($('#tablaVentasXCliente') as any).DataTable({\r\n            destroy: true, // importante si recargas la tabla\r\n            data: datosVentaXCliente,\r\n            columns: [{title: 'Nombre', data: 'nombre'}, {title: 'Cantidad_facturas', data: 'cantidad_facturas'}, {title: 'Total ventas', data: 'total_ventas', render: (data:number) => `$${Number(data).toLocaleString()}`}],\r\n        });\r\n    }\r\n\r\n  }\r\n\r\n})();","(function(){\r\n  if(document.querySelector('.contenedorsetup')){\r\n\r\n    const radios = document.querySelectorAll<HTMLInputElement>('.contenedorsetup input[type=\"radio\"]');\r\n    const claves = document.querySelectorAll<HTMLInputElement>('.keyinput');\r\n    const porcentaje_de_impuesto = document.querySelector('#porcentaje_de_impuesto') as HTMLSelectElement;\r\n    const indicador_caja = document.querySelector('#indicador_caja') as HTMLSelectElement;\r\n\r\n    radios.forEach(radio => {\r\n      radio.addEventListener('change', () => {\r\n        // Obtenemos el grupo (name) del radio\r\n        const grupo:string = radio.name;\r\n        // Obtenemos la opción seleccionada de ese grupo\r\n        const seleccionado = document.querySelector(`input[name=\"${grupo}\"]:checked`) as HTMLInputElement;\r\n\r\n        //console.log(`${grupo}, Opción seleccionada: ${seleccionado.value}`);\r\n        cambiarparametro(grupo, seleccionado.value);\r\n      });\r\n    });\r\n\r\n    ////////////// inputs tipo radio  ////////////////\r\n    function cambiarparametro(clave:string, valor:string){\r\n      const datos = new FormData();\r\n      datos.append(clave, valor);\r\n      (async ()=>{\r\n        try {\r\n            const url = \"/admin/api/parametrosSistema\";  //api llamada en parametroscontrolador.php\r\n            const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n\r\n    //////////  CLAVES  ////////////\r\n    ///////////  eventos a los inputs de las claves, limite de descuento, cantidad de zeta diarios etc 'Campos de entrada' /////////////\r\n    claves.forEach(c=>{\r\n      c.addEventListener('input', (e)=>{  \r\n        const inputClave = (e.target as HTMLInputElement);\r\n        const valorClave = (e.target as HTMLInputElement).value;\r\n        \r\n        (async ()=>{\r\n          const datos = new FormData();\r\n          datos.append(inputClave.name, valorClave);\r\n          try {\r\n              const url = \"/admin/api/parametrosSistemaClaves\";  //api llamada en parametroscontrolador.php\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito !== undefined){\r\n                inputClave.style.color = \"#02db02\";\r\n                inputClave.style.fontWeight = \"500\";\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n        })();\r\n      });\r\n    });\r\n\r\n\r\n\r\n    //////////////////   campo tipo de impuesto (%)   /////////////////////\r\n    porcentaje_de_impuesto?.addEventListener('input', parametrosSistemaTipoSelect);\r\n    //////////////////   Indicadores de caja   /////////////////////\r\n    indicador_caja?.addEventListener('input', parametrosSistemaTipoSelect);\r\n\r\n\r\n    function parametrosSistemaTipoSelect(e:Event){\r\n      const select = (e.target as HTMLSelectElement);\r\n      (async ()=>{\r\n          const datos = new FormData();\r\n          datos.append(select.name, select.value);\r\n          try {\r\n              const url = \"/admin/api/parametrosSistemaTipoSelect\";  //api llamada en parametroscontrolador.php\r\n              const respuesta = await fetch(url, {method: 'POST', body: datos}); \r\n              const resultado = await respuesta.json();\r\n              if(resultado.exito !== undefined){\r\n                msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              }else{\r\n                msjalertToast('error', '¡Error!', resultado.error[0]);\r\n              }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n      })();\r\n    }\r\n\r\n    \r\n  }\r\n\r\n})();","(()=>{\r\n\r\n    if(document.querySelector('.configsuscripcion')){\r\n        const btnDetalleSuscriptor = document.getElementById('btnDetalleSuscriptor') as HTMLButtonElement;\r\n        const btnRegistrarPago = document.getElementById('btnRegistrarPago') as HTMLButtonElement;\r\n        const miDialogoRegistrarPago:any = document.querySelector(\"#miDialogoRegistrarPago\");\r\n        const miDialogoDetalleSuscripcion:any = document.querySelector(\"#miDialogoDetalleSuscripcion\");\r\n        const estadoText = document.querySelector('#estadoText') as HTMLParagraphElement;\r\n\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n\r\n        btnDetalleSuscriptor?.addEventListener('click',()=>{\r\n            miDialogoDetalleSuscripcion.showModal();\r\n        });\r\n        btnRegistrarPago?.addEventListener('click',()=>{\r\n            miDialogoRegistrarPago.showModal();\r\n        });\r\n\r\n\r\n        document.querySelector('#formDetalleSuscripcion')?.addEventListener('submit', async(e:Event)=>{\r\n            e.preventDefault();\r\n            const form = e.target as HTMLFormElement;\r\n            const formData = new FormData(form);\r\n            const data = Object.fromEntries(formData.entries());\r\n            const detalleSuscrip = {\r\n                idplan: data.idplan,\r\n                valorplan: Number(data.valorplan)||0,\r\n                fecha_corte: data.fecha_corte,\r\n                estado: data.estado,\r\n                descuento: Number(data.descuento)||0,\r\n                detalledescuento: data.detalle_descuento,\r\n                cargo: Number(data.cargo)||0,\r\n                detallecargo: data.detalle_cargo,\r\n            }\r\n            try {\r\n                const url = \"/admin/api/suscripcion/detalleSuscripcion\"; //llamado a la API REST suscripcioncontrolador.php actualiza la sucursal\r\n                const respuesta = await fetch(url, {\r\n                                            method: 'POST', \r\n                                            headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                            body: JSON.stringify(detalleSuscrip) \r\n                                        });\r\n                const resultado = await respuesta.json();\r\n                console.log(resultado);\r\n                if(resultado.exito != undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    actualizarDetalleSuscripcion(detalleSuscrip);\r\n                }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n           miDialogoDetalleSuscripcion.close();\r\n        });\r\n\r\n\r\n        document.querySelector('#formRegistrarPago')?.addEventListener('submit', async(e:Event)=>{\r\n            e.preventDefault();\r\n            const form = e.target as HTMLFormElement;\r\n            const formData = new FormData(form);\r\n            const data = Object.fromEntries(formData.entries());\r\n            const pago = {\r\n                cantidad_plan: data.cantidad_plan,\r\n                valor_pagado: Number(data.valor_pagado)||0,\r\n                mediopago: data.medio_pago,\r\n                descripcion: data.descripcion,\r\n            }\r\n            try {\r\n                const url = \"/admin/api/suscripcion/registrarPago\"; //llamado a la API REST suscripcioncontrolador.php\r\n                const respuesta = await fetch(url, {\r\n                                            method: 'POST', \r\n                                            headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                            body: JSON.stringify(pago) \r\n                                        });\r\n                const resultado = await respuesta.json();\r\n                console.log(resultado);\r\n                if(resultado.exito != undefined){\r\n                    msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n                    actualizarDetalleSuscripcion(resultado.sucursal);\r\n                }else{\r\n                    msjalertToast('error', '¡Error!', resultado.error[0]);\r\n                }\r\n                miDialogoRegistrarPago.close();\r\n            } catch (error) {\r\n                console.log(error);\r\n            }\r\n    \r\n        });\r\n\r\n\r\n        function actualizarDetalleSuscripcion(detalleSuscrip:{valorplan: number, fecha_corte: FormDataEntryValue, estado: FormDataEntryValue, descuento: number, detalledescuento: FormDataEntryValue, cargo: number, detallecargo: FormDataEntryValue}){\r\n            (document.querySelector('#fecha_corteText') as HTMLParagraphElement).textContent = detalleSuscrip.fecha_corte as string;\r\n            (document.querySelector('#valorplanText') as HTMLParagraphElement).textContent = detalleSuscrip.valorplan.toLocaleString();\r\n            (document.querySelector('#valorplanResumen') as HTMLParagraphElement).textContent = '$'+detalleSuscrip.valorplan.toLocaleString();\r\n            estadoText.textContent = detalleSuscrip.estado == '1'?\"Activo\":\"Suspendido\";\r\n            if (detalleSuscrip.estado === '1') {\r\n                estadoText.classList.replace('bg-red-100', 'bg-green-100');\r\n                estadoText.classList.replace('text-red-700', 'text-green-700');\r\n            } else {\r\n                estadoText.classList.replace('bg-green-100', 'bg-red-100');\r\n                estadoText.classList.replace('text-green-700', 'text-red-700');\r\n            }\r\n        }\r\n\r\n\r\n        function cerrarDialogoExterno(event:Event) {\r\n            const f = event.target;\r\n            if (f=== miDialogoRegistrarPago || f === miDialogoDetalleSuscripcion || (f as HTMLInputElement).value === 'Cancelar' || (f as HTMLButtonElement).closest('.btnXCerrarRegistroPago') ) {\r\n                miDialogoRegistrarPago.close();\r\n                miDialogoDetalleSuscripcion.close();\r\n            }\r\n        }\r\n        \r\n    }\r\n\r\n\r\n})();","(()=>{\r\n    if(!document.querySelector('.gestionDian'))return;\r\n    const POS = (window as any).POS;\r\n\r\n    const btnAdquirirCompañia = document.querySelector('#btnAdquirirCompañia') as HTMLButtonElement;\r\n    const miDialogoAdquirirCompañia = document.querySelector('#miDialogoAdquirirCompañia') as any;\r\n\r\n    btnAdquirirCompañia.addEventListener('click', ()=>{\r\n        miDialogoAdquirirCompañia.showModal();\r\n        document.addEventListener(\"click\", POS.cerrarDialogoExterno);\r\n    });\r\n\r\n    ///////    CONSULTAR COMPAÑIA POR NIT   ///////\r\n    document.querySelector('#formAdquirirCompañia')?.addEventListener('submit', async (e:Event)=>{\r\n      e.preventDefault();\r\n      const nit = (document.querySelector('#nitcompany') as HTMLInputElement).value;\r\n      const adquirirCompañiaPassword = (document.querySelector('#adquirirCompañiaPassword') as HTMLInputElement).value;\r\n      miDialogoAdquirirCompañia.close();\r\n      document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n      try {\r\n        const url = `https://apidianj2.com/api/getCompany/${nit}`; //llamado a la API REST Dian-laravel para consultar la compañia por nit\r\n        const respuesta = await fetch(url);\r\n        const resultado = await respuesta.json();\r\n        const idcompany = await POS.crearCompanyJ2({ business_name:resultado.compañia.user.name, identification_number: resultado.compañia.identification_number, idsoftware: resultado.compañia.software.identifier, pinsoftware:12345, estado:1 }, resultado.compañia.user.api_token);\r\n        \r\n        /////    crear resolucion para NC    ///////\r\n        const extprefix = (resultado.compañia.user.name).match(/[a-zA-Z]/g)!;\r\n        const a:string = extprefix[0];\r\n        const b:string = extprefix[extprefix.length-1];\r\n        POS.crearResolucionNCJ2({ type_document_id: '4', prefix: 'NC'+a+b, from: '1', to: '99999999' }, resultado.compañia.identification_number, idcompany);\r\n      } catch (error) {\r\n        console.log(error);\r\n      }\r\n    });\r\n\r\n\r\n    const gestionAdquirirCompany = {  //objeto a exportar\r\n        miDialogoAdquirirCompañia,\r\n    };\r\n\r\n    POS.gestionAdquirirCompany = gestionAdquirirCompany;\r\n\r\n})();","(()=>{\r\n    if(!document.querySelector('.gestionDian'))return;\r\n    const POS = (window as any).POS;\r\n\r\n    const selectDepartments = document.querySelector('#department_id') as HTMLSelectElement;\r\n    const selectdCities = document.querySelector('#municipality_id') as HTMLSelectElement;\r\n\r\n    type municipalities = {\r\n        id:string,\r\n        department_id:string,\r\n        name:string,\r\n        code:string,\r\n      };\r\n      let cities:municipalities[]=[];\r\n\r\n    /////       Obtener municipio segun departamento        ///////\r\n    selectDepartments?.addEventListener('change', (e:Event)=>{\r\n      const x:HTMLOptionElement = (e.target as HTMLOptionElement);\r\n      imprimirCiudades(x.value);\r\n    });\r\n\r\n    function imprimirCiudades(x:string){\r\n      (async ()=>{\r\n        try {\r\n          const url = \"/admin/api/citiesXdepartments?id=\"+x; //llamado a la API REST y se trae las cities segun cliente elegido\r\n          const respuesta = await fetch(url); \r\n          const resultado = await respuesta.json(); \r\n          if(resultado.error){\r\n            Swal.fire(resultado.error[0], '', 'error')\r\n          }else{\r\n            cities = resultado;\r\n            addCitiesToSelect(cities);\r\n          }\r\n        } catch (error) {\r\n            console.log(error);\r\n        }\r\n      })();\r\n    }\r\n       \r\n    function addCitiesToSelect<T extends {id:string, department_id:string, name:string, code:string}>(addrs: T[]):void{\r\n      while(selectdCities?.firstChild)selectdCities.removeChild(selectdCities?.firstChild);\r\n      addrs.forEach(x =>{\r\n        const option = document.createElement('option');\r\n        option.textContent = x.name;\r\n        option.value = x.id;\r\n        option.dataset.code = x.code;\r\n        option.dataset.department_id = x.department_id;\r\n        selectdCities.appendChild(option);\r\n      });\r\n      \r\n    }\r\n\r\n})();","(()=>{\r\n    if(!document.querySelector('.gestionDian'))return;\r\n    const POS = (window as any).POS;\r\n\r\n    const selectResolucioncompañia = document.querySelector('#selectResolucioncompañia') as HTMLSelectElement;\r\n    const miDialogoGetResolucion = document.querySelector('#miDialogoGetResolucion') as any;\r\n\r\n    ///////    CONSULTAR RESOLUCIONES   ///////\r\n    document.querySelector('#formGetResolucion')?.addEventListener('submit', (e:Event)=>{\r\n      e.preventDefault();\r\n      const id:string = selectResolucioncompañia.options[selectResolucioncompañia.selectedIndex].value;\r\n      const companiesAll = POS.companiesAll as companiesDian[];\r\n      const oneC = companiesAll.find(x=>x.id == id)!;\r\n      getResolutions(oneC.id, oneC.idsoftware, oneC.token);\r\n    });\r\n\r\n    async function getResolutions(idcompany:string, idsoftware:string, token:string){\r\n      try {\r\n        const url = \"https://apidianj2.com/api/ubl2.1/numbering-range\"; //llamado a la API REST Dian-laravel para consultar las resoluciones\r\n        const respuesta = await fetch(url, {\r\n                                              method: 'POST',\r\n                                              headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\", \"Authorization\": \"Bearer \"+token },\r\n                                              body: JSON.stringify({\"IDSoftware\": idsoftware})\r\n                                            });\r\n        const resultado = await respuesta.json();\r\n        let arrayResolutions = resultado.ResponseDian.Envelope.Body.GetNumberingRangeResponse.GetNumberingRangeResult.ResponseList.NumberRangeResponse;\r\n        if(typeof arrayResolutions == 'object')arrayResolutions = [arrayResolutions];\r\n        if(arrayResolutions&&arrayResolutions.length>0)printResolutions(idcompany, arrayResolutions, token);\r\n      } catch (error) {\r\n        console.log(error);  \r\n      }\r\n    }\r\n\r\n    function printResolutions(idcompany:string, arrayResolutions:NumberRangeItem[], token:string){\r\n      const tablaListResolutions = document.querySelector('#tablaListResolutions tbody') as HTMLTableElement;\r\n      while(tablaListResolutions.firstChild)tablaListResolutions.removeChild(tablaListResolutions.firstChild);\r\n      arrayResolutions.forEach(r =>{\r\n        tablaListResolutions.insertAdjacentHTML('beforeend', \r\n          `<tr>\r\n              <td class=\"px-4 py-2 border\">${r.Prefix}</td>\r\n              <td class=\"px-3 py-2 border\">${r.ResolutionNumber}</td>\r\n              <td class=\"px-3 py-2 border\">${r.FromNumber} - ${r.ToNumber}</td>\r\n              <td class=\"px-3 py-2 border\">${r.ValidDateTo}</td>\r\n              <td class=\"px-4 py-2 border text-2xl\"><button class=\"downResolution\" type=\"button\" id=\"${r.ResolutionNumber}\" data-company=\"${idcompany}\">⏬</button></td>\r\n          </tr>`\r\n        )\r\n      });\r\n      tablaListResolutions.addEventListener('click', e=> descargarResolucion(e, arrayResolutions, token) );\r\n    }\r\n\r\n\r\n    async function descargarResolucion(e:Event, arrayResolutions:NumberRangeItem[], token:string){\r\n      const target = e.target as HTMLButtonElement;\r\n      if(target.classList.contains('downResolution')){\r\n        const idcompany:string = target.dataset.company!;\r\n        const numberResolution = target.id;\r\n        const resolutionSelected = arrayResolutions.find(x=>x.ResolutionNumber === numberResolution)!;\r\n        resolutionSelected.idcompany = idcompany;\r\n        (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"grid\";\r\n        try {\r\n          const url = `/admin/api/guardarResolutionJ2`; //llamado a la API para guardar la resolucion DIAN\r\n          const respuesta = await fetch(url,  { method: 'POST',\r\n                                                headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                                body: JSON.stringify(resolutionSelected)\r\n                                              });\r\n          const resultado = await respuesta.json();\r\n\r\n          //almacenar la resolucion obtenido de la dian en la API \r\n          const resolucion = {\r\n                  type_document_id:'1', \r\n                  prefix: resolutionSelected.Prefix, \r\n                  resolution: resolutionSelected.ResolutionNumber, \r\n                  resolution_date: resolutionSelected.ResolutionDate, \r\n                  technical_key: typeof resolutionSelected.TechnicalKey === 'string'?resolutionSelected.TechnicalKey:'', \r\n                  from: resolutionSelected.FromNumber, \r\n                  to: resolutionSelected.ToNumber, \r\n                  generated_to_date:'0', \r\n                  date_from: resolutionSelected.ValidDateFrom, \r\n                  date_to: resolutionSelected.ValidDateTo\r\n              };\r\n          const sendresolToAPI = await POS.crearResolucion(resolucion, token);\r\n\r\n          (document.querySelector('.content-spinner1') as HTMLElement).style.display = \"none\";\r\n\r\n          if(sendresolToAPI)msjalertToast('success', '¡Éxito!', 'Resoluccion asociada exitosamnete.');\r\n\r\n\r\n          if(resultado.exito != undefined){\r\n            const existeResol:number = POS.facturadores.findIndex((x:any)=>x.id==resultado.facturador.id&&x.resolucion == resolutionSelected?.ResolutionNumber);\r\n            if(existeResol === -1){ //si no existe consecutibo imprmir\r\n              // actualizar el arreglo de facturador\r\n              POS.facturadores.push(resultado.facturador); //= [...facturadores, resultado.facturador];\r\n              //insertar en vista facturador\r\n              const tablaFacturadores = ($('#tablaFacturadores') as any).DataTable(configdatatables);\r\n              (tablaFacturadores as any).row.add([\r\n                        (tablaFacturadores as any).rows().count() + 1,\r\n                        resultado.facturador.nombre,\r\n                        'ELECTRONICA',\r\n                        resolutionSelected?.FromNumber+' - '+resolutionSelected?.ToNumber,\r\n                        1,\r\n                        resolutionSelected?.ValidDateTo,\r\n                        'Activo',\r\n                        `<div class=\"acciones-btns\" id=\"${resultado.facturador.id}\" data-facturador=\"${resultado.facturador.nombre}\">\r\n                            <button class=\"btn-md btn-turquoise editarFacturador\"><i class=\"fa-solid fa-pen-to-square\"></i></button>\r\n                            <button class=\"btn-md btn-red eliminarFacturador\"><i class=\"fa-solid fa-trash-can\"></i></button>\r\n                        </div>`\r\n                    ]).draw(false);\r\n              //insertar facturador en caja para seleccionar\r\n              crearConsecutivoGestionCaja(resultado.facturador.id, resultado.facturador.nombre);\r\n            }\r\n          }\r\n        } catch (error) {\r\n          console.log(error);\r\n        }\r\n        miDialogoGetResolucion.close();\r\n        document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n      }//fin button\r\n    }//fin funcion descargarResolucion\r\n\r\n    \r\n    function crearConsecutivoGestionCaja(idfacturador:string, nombre:string){\r\n      const selectConsecutivoCaja = document.querySelector('#idtipoconsecutivo') as HTMLSelectElement;\r\n      const option = document.createElement('option');\r\n      option.value = idfacturador;\r\n      option.textContent = nombre;\r\n      selectConsecutivoCaja.appendChild(option);\r\n    }\r\n\r\n    const gestionarGetResolutions = {  //objeto a exportar\r\n        miDialogoGetResolucion,\r\n        selectResolucioncompañia,\r\n    };\r\n\r\n    POS.gestionarGetResolutions = gestionarGetResolutions;\r\n\r\n})();","(()=>{\r\n    if(!document.querySelector('.gestionDian'))return;\r\n    const POS = (window as any).POS;\r\n\r\n    const miDialogosetpruebas = document.querySelector('#miDialogosetpruebas') as any;\r\n    const selectSetCompañia = document.querySelector('#selectSetCompañia') as HTMLSelectElement;\r\n\r\n    ///////   ENVIAR SET DE PRUEBAS    ///////\r\n    document.querySelector('#formSetPruebas')?.addEventListener('submit', async(e:Event)=>{\r\n      e.preventDefault();\r\n      const id = selectSetCompañia.options[selectSetCompañia.selectedIndex]?.value;\r\n      const test = document.querySelector('#idsetpruebas') as HTMLInputElement;\r\n\r\n      const companiesAll = POS.companiesAll as companiesDian[];\r\n\r\n      const oneC = companiesAll.find(x=>x.id == id)!;\r\n      const token = oneC.token;\r\n\r\n      const date = new Date().toLocaleDateString('sv-SE');\r\n      const number = 992500000 + (Math.floor(Math.random()*500000)+1);  //rango de 1 a 500000\r\n\r\n      const factura = {\r\n        prefix: \"SETP\",\r\n        number, // dinámico\r\n        type_document_id: \"1\",\r\n        date,   // dinámico\r\n        time: \"00:00:01\",\r\n        resolution_number: \"18760000001\",\r\n        sendmail: false,\r\n        notes: \"Factura Electrónica de pruebas Auto\",\r\n        payment_form: {\r\n          payment_form_id: \"1\",\r\n          payment_method_id: \"10\",\r\n          payment_due_date: date,\r\n          duration_measure: \"0\"\r\n        },\r\n        customer: {\r\n          identification_number: \"222222222222\",\r\n          name: \"Consumidor Final\",\r\n          phone: null,\r\n          address: null,\r\n          type_document_identification_id: 3,\r\n          type_organization_id: 1,\r\n          municipality_id: null\r\n        },\r\n        invoice_lines: [\r\n          {\r\n            unit_measure_id: \"70\",\r\n            invoiced_quantity: \"1.00\",\r\n            line_extension_amount: \"2000.00\",\r\n            free_of_charge_indicator: false,\r\n            tax_totals: [\r\n              {\r\n                tax_id: 1,\r\n                tax_amount: \"0.00\",\r\n                taxable_amount: \"2000.00\",\r\n                percent: \"0\"\r\n              }\r\n            ],\r\n            description: \"Producto Prueba\",\r\n            code: \"155\",\r\n            type_item_identification_id: \"4\",\r\n            price_amount: \"2000.00\",\r\n            base_quantity: \"1\"\r\n          }\r\n        ],\r\n        legal_monetary_totals: {\r\n          line_extension_amount: \"2000\",\r\n          tax_exclusive_amount: \"2000\",\r\n          tax_inclusive_amount: \"2000\",\r\n          allowance_total_amount: \"0\",\r\n          charge_total_amount: \"0\",\r\n          payable_amount: \"2000\"\r\n        },\r\n        tax_totals: [\r\n          {\r\n            tax_id: 1,\r\n            tax_amount: \"0.00\",\r\n            percent: \"0\",\r\n            taxable_amount: \"2000.00\"\r\n          }\r\n        ]\r\n      };\r\n\r\n      try {\r\n        const url = \"https://apidianj2.com/api/ubl2.1/invoice/\"+test.value; //llamado a la API REST Dianlaravel\r\n        const respuesta = await fetch(url, {\r\n                                              method: 'POST',\r\n                                              headers: {\r\n                                                \"Accept\": \"application/json\",\r\n                                                \"Content-Type\": \"application/json\",\r\n                                                \"Authorization\": \"Bearer \"+token\r\n                                              },\r\n                                              body: JSON.stringify(factura)\r\n                                            });\r\n        const resultado = await respuesta.json();\r\n        modoproduccion(token);\r\n        miDialogosetpruebas.close();\r\n        document.removeEventListener(\"click\", POS.cerrarDialogoExterno);\r\n        return resultado.success;\r\n      } catch (error) {\r\n        console.log(error);\r\n        return false;\r\n      }\r\n    });\r\n\r\n    ///////    ENVIOREMNET MODO PRUEBAS - PRODUCCION    ///////\r\n    async function modoproduccion(token?:string){\r\n      try {\r\n        const url = \"https://apidianj2.com/api/ubl2.1/config/environment\"; //llamado a la API REST Dian-laravel\r\n        const respuesta = await fetch(url, {\r\n                                              method: 'PUT',\r\n                                              headers: {\r\n                                                \"Accept\": \"application/json\",\r\n                                                \"Content-Type\": \"application/json\",\r\n                                                \"Authorization\": \"Bearer \"+token\r\n                                              },\r\n                                              body: JSON.stringify({\"type_environment_id\": 1, \"payroll_type_environment_id\": 2})\r\n                                            });\r\n        const resultado = await respuesta.json();\r\n        msjalertToast('success', '¡Éxito!', 'Modo de producción activado correctamente.');\r\n        return resultado.success;\r\n      } catch (error) {\r\n        console.log(error);\r\n        return false;\r\n      }\r\n\r\n    }\r\n\r\n    const gestionarSetPruebas = {  //objeto a exportar\r\n        miDialogosetpruebas,\r\n        selectSetCompañia,\r\n    };\r\n\r\n  POS.gestionarSetPruebas = gestionarSetPruebas;\r\n\r\n})();","(():void=>{\r\n  if(document.querySelector('.gestionDian')){\r\n    const POS = (window as any).POS;\r\n    const btnCrearCompañia = document.querySelector('#btnCrearCompañia') as HTMLButtonElement;\r\n    const btnObtenerresolucion = document.querySelector('#btnObtenerresolucion') as HTMLButtonElement;\r\n    const BtnSetpruebas = document.querySelector('#BtnSetpruebas') as HTMLButtonElement;\r\n    const formCrearUpdateCompañia = document.querySelector('#formCrearUpdateCompañia') as HTMLFormElement;\r\n    const miDialogoAdquirirCompañia = POS.gestionAdquirirCompany.miDialogoAdquirirCompañia\r\n    const miDialogoCompañia = document.querySelector('#miDialogoCompañia') as any;\r\n    const miDialogoGetResolucion = POS.gestionarGetResolutions.miDialogoGetResolucion\r\n    const miDialogosetpruebas = POS.gestionarSetPruebas.miDialogosetpruebas;\r\n    const selectResolucioncompañia = POS.gestionarGetResolutions.selectResolucioncompañia;\r\n    const selectSetCompañia = POS.gestionarSetPruebas.selectSetCompañia;\r\n\r\n    interface configCompany {\r\n      success:boolean,\r\n      message:string,\r\n      password:string,\r\n      token:string,\r\n      company: {\r\n        address: string,\r\n        country_id: number,\r\n        created_at: string,\r\n        dv: string,\r\n        eqdocs_type_environment_id: number,\r\n        id: number,\r\n        identification_number: string,\r\n        language_id: number,\r\n        merchant_registration: string,\r\n        municipality_id: number,\r\n        payroll_type_environment_id: 2,\r\n        phone: string,\r\n        state: number,\r\n        tax_id: number,\r\n        type_currency_id: number,\r\n        type_document_identification_id: number,\r\n        type_environment_id: number,\r\n        type_liability_id: number,\r\n        type_operation_id: number,\r\n        type_organization_id: number,\r\n        type_regime_id: number,\r\n        updated_at: string,\r\n        user: {\r\n          email: string,\r\n          name: string,\r\n          updated_at: string,\r\n          created_at: string\r\n        }\r\n      }\r\n    }\r\n\r\n\r\n    //Resolucion a almacenar en API\r\n    interface resolconfig {\r\n      idcompany?:string,\r\n      type_document_id:string, \r\n      prefix:string, \r\n      resolution?:string, \r\n      resolution_date?:string, \r\n      technical_key?:string,   //para la nota credito invoice se usa como identification_number de la compañia\r\n      from:string,\r\n      to:string, \r\n      generated_to_date?:string, \r\n      date_from?:string, \r\n      date_to?:string\r\n    }\r\n\r\n\r\n    //  Obtener compañias\r\n    async function getCompañiasLocal<T>():Promise<T[]> {\r\n      try {\r\n          const url = \"/admin/api/getCompaniesAll\"; //llamado a la API REST y se trae las cities segun cliente elegido\r\n          const respuesta = await fetch(url); \r\n          const resultado:T[]= await respuesta.json(); \r\n          return resultado;\r\n        } catch (error) {\r\n            console.log(error);\r\n            return [];\r\n        }\r\n    }\r\n    \r\n    let companiesAll:companiesDian[];\r\n    (async()=>{\r\n      companiesAll = await getCompañiasLocal<{id:string, identification_number:string, business_name:string, idsoftware:string, token:string}>();\r\n      POS.companiesAll = companiesAll; //exponer globalmente\r\n    })();\r\n\r\n\r\n\r\n    ///////////////////-------    crear compañia     --------///////////////////\r\n    btnCrearCompañia.addEventListener('click', ()=>{\r\n        limpiarformdialog();\r\n        document.querySelector('#modalCompañia')!.textContent = \"Crear compañia\";\r\n        (document.querySelector('#btnEditarCrearCompañia') as HTMLInputElement).value = \"Crear\";\r\n        miDialogoCompañia.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    btnObtenerresolucion.addEventListener('click', ()=>{\r\n        limpiarformdialog();\r\n        miDialogoGetResolucion.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n    BtnSetpruebas.addEventListener('click', async ()=>{\r\n        limpiarformdialog();\r\n        //const r = await getCompañiasLocal();\r\n\r\n        miDialogosetpruebas.showModal();\r\n        document.addEventListener(\"click\", cerrarDialogoExterno);\r\n    });\r\n\r\n\r\n    formCrearUpdateCompañia.addEventListener('submit', async(e:Event)=>{\r\n      e.preventDefault();\r\n      const datos = new FormData(formCrearUpdateCompañia);\r\n      const archivoP12 = datos.get('certificate') as File;\r\n      const datoscompañia = Object.fromEntries(datos.entries());\r\n      datoscompañia.merchant_registration = \"0000000-00\";\r\n\r\n      const nit = datoscompañia.identification_number as string;\r\n      if(!/^\\d+$/.test(nit)){\r\n        alert('Numero del Nit no es valido');\r\n        return;\r\n      }\r\n      \r\n      if(archivoP12 && archivoP12.size>0){\r\n        if(!archivoP12.name.toLocaleLowerCase().endsWith('.p12')){\r\n          alert('Por favor seleccione un archivo formato .p12 valido');\r\n          return;\r\n        }\r\n        try {\r\n          const base64String = await base64(archivoP12);\r\n          datoscompañia.certificadop12base64 = base64String;\r\n          crearCompanyAPI(datoscompañia);\r\n        } catch (error) {\r\n          alert('Error durante el procesamiento del certificado .p12');\r\n          return;\r\n        }\r\n      }\r\n    });\r\n\r\n\r\n    async function crearCompanyAPI(datoscompañia: Record<string, FormDataEntryValue>){\r\n      const { identification_number, certificadop12base64, password, idsoftware, pinsoftware } = datoscompañia;\r\n        const dv = getDgv(Number(identification_number));\r\n        try{\r\n            const url = `https://apidianj2.com/api/ubl2.1/config/${identification_number}/${dv}`; //llamado a la API REST Dianlaravel\r\n            const respuesta = await fetch(url,  {\r\n                                                  method: 'POST',\r\n                                                  headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                                  body: JSON.stringify(datoscompañia)\r\n                                                });\r\n            const resultado = await respuesta.json();\r\n            if(resultado.success){\r\n              miDialogoCompañia.close();\r\n              document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n              \r\n              const cert = await configCertificado(resultado.token, certificadop12base64+'', password+'');\r\n              if(cert == undefined){\r\n                //eliminar usuario de la api\r\n                sendDeleteCompany('', identification_number+'', resultado.token);\r\n                msjalertToast('error', '¡Error!', 'Error en la obtencion del certificado digital.');\r\n                return;\r\n              }\r\n              const soft = await configSoftware(resultado.token, idsoftware+'', pinsoftware+'');\r\n              if(soft == undefined){\r\n                //eliminar usuario de la api\r\n                sendDeleteCompany('', identification_number+'', resultado.token);\r\n                msjalertToast('error', '¡Error!', 'Error en la configuracion del software.');\r\n                return;\r\n              }\r\n              const resolprueba:resolconfig = {\r\n                type_document_id:'1', \r\n                prefix:'SETP', \r\n                resolution:'18760000001', \r\n                resolution_date:'2019-01-19', \r\n                technical_key: 'fc8eac422eba16e22ffd8c6f94b3f40a6e38162c', \r\n                from: '990000000', \r\n                to: '995000000', \r\n                generated_to_date:'0', \r\n                date_from:'2019-01-19', \r\n                date_to: '2030-01-19'\r\n              };\r\n              const resol = await crearResolucion(resolprueba, resultado.token);\r\n              if(resol == undefined){\r\n                //eliminar usuario de la api\r\n                sendDeleteCompany('', identification_number+'', resultado.token);\r\n                msjalertToast('error', '¡Error!', 'Error en la configuracion de la resolucion.');\r\n                return;\r\n              }\r\n              /////    crear resolucion para NC    ///////\r\n              const extprefix = (datoscompañia.business_name as string).match(/[a-zA-Z]/g)!;\r\n              const a:string = extprefix[0];\r\n              const b:string = extprefix[extprefix.length-1];\r\n              const resolNC:resolconfig = {\r\n                type_document_id:'4', \r\n                prefix:'NC'+a+b, \r\n                from: '1', \r\n                to: '99999999', \r\n              };\r\n              \r\n              const resResolNC = await crearResolucion(resolNC, resultado.token); //crear resolucion nota credito invoice en la api\r\n              if(resResolNC == undefined){\r\n                //eliminar usuario de la api\r\n                sendDeleteCompany('', identification_number+'', resultado.token);\r\n                msjalertToast('error', '¡Error!', 'Error en la configuracion de la resolucion de NC.');\r\n                return;\r\n              }\r\n\r\n              const idcompany = await crearCompanyJ2(datoscompañia, resultado.token);\r\n              //crear resolucion nota credito invoice de forma local\r\n              if(idcompany!=undefined){\r\n                const resResolNCJ2 = crearResolucionNCJ2(resolNC, datoscompañia.identification_number+'', idcompany);\r\n              }\r\n      \r\n            }else{\r\n              msjalertToast('error', '¡Error!', 'No se pudo crear la compañia de facturacion.');\r\n            }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n    }\r\n\r\n\r\n    ///////    CREAR CERTIFICADO EN LA API DIAN    ///////\r\n    async function configCertificado(token:string, certificado:string, password:string):Promise<boolean|undefined> {\r\n      try{\r\n          const url = \"https://apidianj2.com/api/ubl2.1/config/certificate\"; //llamado a la API REST Dianlaravel\r\n          const respuesta = await fetch(url, {\r\n                                                method: 'PUT',\r\n                                                headers: {\r\n                                                  \"Accept\": \"application/json\",\r\n                                                  \"Content-Type\": \"application/json\",\r\n                                                  \"Authorization\": \"Bearer \"+token\r\n                                                },\r\n                                                body: JSON.stringify({\"certificate\": certificado, \"password\":password})\r\n                                              });\r\n          const resultado = await respuesta.json();\r\n          return resultado.success;\r\n        } catch (error) {\r\n            console.log(error);\r\n            return false;\r\n        }\r\n    }\r\n\r\n    \r\n    ///////    CREAR SOFTWARE EN LA API DIAN    ////////\r\n    async function configSoftware(token:string, idsoftware:string, pinsoftware:string):Promise<boolean|undefined>\r\n    {\r\n      try {\r\n        const url = \"https://apidianj2.com/api/ubl2.1/config/software\"; //llamado a la API REST Dianlaravel\r\n        const respuesta = await fetch(url, {\r\n                                              method: 'PUT',\r\n                                              headers: {\r\n                                                \"Accept\": \"application/json\",\r\n                                                \"Content-Type\": \"application/json\",\r\n                                                \"Authorization\": \"Bearer \"+token\r\n                                              },\r\n                                              body: JSON.stringify({\"id\": idsoftware, \"pin\":pinsoftware})\r\n                                            });\r\n        const resultado = await respuesta.json();\r\n        return resultado.success;\r\n      } catch (error) {\r\n        console.log(error);\r\n        return false;\r\n      }\r\n    }\r\n\r\n\r\n    ///////    CREAR RESOLUCIONES EN LA API    ////////\r\n    async function crearResolucion(resolition:resolconfig, token:string)\r\n    {\r\n      try {\r\n        const url = \"https://apidianj2.com/api/ubl2.1/config/resolution\"; //llamado a la API REST Dian-laravel\r\n        const respuesta = await fetch(url, {\r\n                                              method: 'PUT',\r\n                                              headers: {\r\n                                                \"Accept\": \"application/json\",\r\n                                                \"Content-Type\": \"application/json\",\r\n                                                \"Authorization\": \"Bearer \"+token\r\n                                              },\r\n                                              body: JSON.stringify(resolition)\r\n                                            });\r\n        const resultado = await respuesta.json();\r\n        return resultado.success;\r\n      } catch (error) {\r\n        console.log(error);\r\n        return false;\r\n      }\r\n      \r\n    }\r\n\r\n\r\n    //////// CREAR RESOLUCION NC PARA INVOICE EN J2 LOCALMENTE ////////////\r\n    async function crearResolucionNCJ2(resolNC:resolconfig, identification_number:string, idcompany:string){\r\n      resolNC.technical_key = identification_number;\r\n      resolNC.idcompany = idcompany;\r\n      try {\r\n          const url = `/admin/api/guardarNCInvoiceJ2`; //llamado a la API para guardar la resolucion NC DIAN de forma local\r\n          const respuesta = await fetch(url,  { method: 'POST',\r\n                                                headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                                body: JSON.stringify(resolNC)\r\n                                              });\r\n          const resultado = await respuesta.json();\r\n          return resultado;\r\n      } catch (error) {\r\n        console.log(error);\r\n      }\r\n    }\r\n\r\n\r\n    ///////    CREAR COMPAÑIA EN J2    ////////\r\n    async function crearCompanyJ2(datoscompañia: Record<string, FormDataEntryValue>, token:string):Promise<string|undefined>{\r\n      datoscompañia.token = token;\r\n      try {\r\n            const url = `/admin/api/crearCompanyJ2`; //llamado a la API para crear la compañia en j2\r\n            const respuesta = await fetch(url,  { method: 'POST',\r\n                                                  headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\" },\r\n                                                  body: JSON.stringify(datoscompañia)\r\n                                                });\r\n            const resultado = await respuesta.json();\r\n            if(resultado.exito !== undefined){\r\n              const tablaCompañias = document.querySelector('#tablaCompañias tbody');\r\n\r\n              const tr = tablaCompañias?.querySelector('tr[id=\"company'+datoscompañia.identification_number+'\"]');\r\n              if(tr){\r\n                tr.remove();\r\n              }\r\n\r\n              tablaCompañias?.insertAdjacentHTML('beforeend', `\r\n                <tr class=\"\" id=\"company${datoscompañia.identification_number}\">\r\n                  <td class=\"\">${resultado.id}</td>\r\n                  <td class=\"\">${datoscompañia.business_name}</td> \r\n                  <td class=\"\">${datoscompañia.identification_number}</td>\r\n                  <td class=\"\">${datoscompañia.idsoftware}</td>\r\n                  <td class=\"\"><div class=\"acciones-btns\">  <button id=\"${resultado.id}\"><span class=\"material-symbols-outlined eliminarcompañia\">delete</span></button> </div></td>\r\n                </tr>`\r\n              );\r\n\r\n              msjalertToast('success', '¡Éxito!', resultado.exito[0]);\r\n              // añadir a los selects de obtener compañia para resoluciones y de set pruebas\r\n              SetCompañiaToSelect(resultado.id, token, datoscompañia.business_name+'');\r\n              companiesAll.push({id:resultado.id, identification_number:datoscompañia.identification_number+'', business_name:datoscompañia.business_name+'', idsoftware:datoscompañia.idsoftware+'', token});\r\n              return resultado.id;\r\n            }else{\r\n              msjalertToast('error', '¡Error!', resultado.error[0]);\r\n            }\r\n          } catch (error) {\r\n              console.log(error);\r\n          }\r\n    }\r\n    \r\n    //Tabla lista de compañias\r\n    document.querySelector('#tablaCompañias tbody')?.addEventListener('click', (e:Event)=>{\r\n      const target = e.target as HTMLElement;\r\n      if(target?.classList.contains(\"eliminarcompañia\")){\r\n        const id = target.parentElement?.id;\r\n        const oneC = companiesAll.find(x=>x.id == id)!;\r\n        eliminarCompañia(id!, oneC?.identification_number, oneC.token);\r\n      }\r\n    });\r\n\r\n    ///////    ELIMINAR COMPAÑIA    ///////\r\n    function eliminarCompañia(id:string, identification_number:string, token:string){\r\n      Swal.fire({\r\n          customClass: {confirmButton: 'sweetbtnconfirm', cancelButton: 'sweetbtncancel'},\r\n          icon: 'question',\r\n          title: 'Desea eliminar la compañia?',\r\n          text: \"La compañia sera eliminado definitivamente.\",\r\n          showCancelButton: true,\r\n          confirmButtonText: 'Si',\r\n          cancelButtonText: 'No',\r\n      }).then((result:any) => {\r\n          if (result.isConfirmed) {\r\n            sendDeleteCompany(id, identification_number, token)\r\n          }\r\n      });\r\n    }\r\n\r\n\r\n    function sendDeleteCompany(id:string, identification_number:string, token:string){\r\n      (async ()=>{ \r\n        try {\r\n          const url = \"https://apidianj2.com/api/ubl2.1/config/deleteCompany\"; //llamado a la API REST Dianlaravel\r\n          const respuesta = await fetch(url, {\r\n                                                method: 'DELETE',\r\n                                                headers: { \"Accept\": \"application/json\", \"Content-Type\": \"application/json\", \"Authorization\": \"Bearer \"+token },\r\n                                                body: JSON.stringify({\"identification_number\": identification_number})\r\n                                              });\r\n          const resultado = await respuesta.json();\r\n          if(resultado.message){\r\n            const urlX = \"/admin/api/eliminarCompanyLocal?id=\"+identification_number; // para eliminar compañia localmente\r\n            const respuestaLocal = await fetch(urlX); \r\n            const resultadoLocal = await respuestaLocal.json(); \r\n            if(!isNaN(Number(id)) && resultadoLocal.exito !== undefined){\r\n              document.querySelector('#company'+identification_number)?.remove();\r\n              msjalertToast('success', '¡Éxito!', resultado.message);\r\n              deleteFromCompany(id);\r\n            }\r\n          }else{\r\n            msjalertToast('error', '¡Error!', 'Error intentalo nuevamente');\r\n          }\r\n        } catch (error) {\r\n          console.log(error);\r\n          return false;\r\n        }\r\n      })();\r\n    }\r\n\r\n\r\n    ///////  eliminar de los select de obtener resolucion y enviar set de pruebas  ///////\r\n    function deleteFromCompany(id:string){\r\n      selectResolucioncompañia.querySelector(`option[value=${id}]`)?.remove();\r\n      selectSetCompañia.querySelector(`option[value=${id}]`)?.remove();\r\n    }\r\n\r\n\r\n    ///////    Set compañia en los select    ///////\r\n    function SetCompañiaToSelect(id:string, token:string, business_name:string){\r\n      selectResolucioncompañia.insertAdjacentHTML('afterbegin', `<option data-token=\"\" value=\"${id}\" >${business_name}</option>`);\r\n      selectSetCompañia.insertAdjacentHTML('afterbegin', `<option data-token=\"${token}\" value=\"${id}\" >${business_name}</option>`);\r\n    }\r\n    \r\n\r\n    function base64(archivo: File):Promise<string>{\r\n      return new Promise((resolve, reject) => {\r\n        const reader = new FileReader();\r\n        reader.onload = () => {\r\n            const base64Completo = reader.result as string;\r\n            const base64Puro = base64Completo.split(',')[1];\r\n            resolve(base64Puro);\r\n        };\r\n        reader.onerror = () => reject(new Error('Error al leer el archivo'));\r\n        reader.readAsDataURL(archivo);\r\n      });\r\n    }\r\n\r\n    /*function getDgv(nit: number): number {\r\n        const multiplicadores = [3, 7, 13, 17, 19, 23, 29, 37, 41, 43, 47, 53, 59, 67, 71];\r\n        const digitos = nit.toString().trim().split('').map(Number);\r\n        let suma = 0;\r\n        digitos.forEach((digito, indice) => {\r\n            const posicionMultiplicador = digitos.length - indice;\r\n            suma += digito * multiplicadores[posicionMultiplicador - 1];\r\n        }); \r\n        const modulo = suma%11;\r\n        return modulo > 1 ?(11 - modulo):modulo;\r\n    }*/\r\n\r\n\r\n    function cerrarDialogoExterno(event:Event) {\r\n      if(event.target === miDialogoAdquirirCompañia || event.target === miDialogoCompañia || event.target === miDialogosetpruebas || event.target === miDialogoGetResolucion || (event.target as HTMLInputElement).value === 'Salir' || (event.target as HTMLInputElement).value === 'Cancelar') {\r\n        miDialogoAdquirirCompañia.close();  \r\n        miDialogoCompañia.close();\r\n        miDialogoGetResolucion.close();\r\n        miDialogosetpruebas.close();\r\n        document.removeEventListener(\"click\", cerrarDialogoExterno);\r\n      }\r\n    }\r\n\r\n    function limpiarformdialog(){\r\n      (document.querySelector('#formCrearUpdateCompañia') as HTMLFormElement)?.reset();\r\n    }\r\n\r\n\r\n    POS.cerrarDialogoExterno = cerrarDialogoExterno;\r\n    POS.crearResolucion = crearResolucion;\r\n    POS.crearCompanyJ2 = crearCompanyJ2;\r\n    POS.crearResolucionNCJ2 = crearResolucionNCJ2;\r\n  }\r\n\r\n})();"]}
